
const embeddedFileData = {"coding":[{"name":"P005-MathematicalMostAskQuestion.md","content":"If you're preparing for **React Native / JavaScript / DSA interviews (HackerRank, IBM, EPAM, TCS, Accenture, Infosys, Wipro, Product Companies)**, these are the most common Mathematical DSA questions from your list.\n\n---\n\n# 1. Even & Odd Number\n\n### Interview Question\n\nCheck whether a number is even or odd.\n\n```javascript\nfunction isEven(num) {\n  return num % 2 === 0;\n}\n```\n\n### HackerRank Variation\n\nCount even numbers in an array.\n\n```javascript\nfunction countEven(arr) {\n  return arr.filter((num) => num % 2 === 0).length;\n}\n```\n\n---\n\n# 2. Prime Number\n\n### Interview Question\n\nCheck if a number is prime.\n\n```javascript\nfunction isPrime(n) {\n  if (n <= 1) return false;\n\n  for (let i = 2; i * i <= n; i++) {\n    if (n % i === 0) return false;\n  }\n\n  return true;\n}\n```\n\n### Follow-up\n\nPrint primes between 1 and N.\n\n```javascript\nfunction printPrimes(n) {\n  for (let i = 2; i <= n; i++) {\n    if (isPrime(i)) console.log(i);\n  }\n}\n```\n\n---\n\n# 3. Composite Number\n\n### Question\n\nCheck whether a number is composite.\n\n```javascript\nfunction isComposite(n) {\n  if (n <= 1) return false;\n\n  for (let i = 2; i * i <= n; i++) {\n    if (n % i === 0) return true;\n  }\n\n  return false;\n}\n```\n\n---\n\n# 4. Factorial\n\n### Interview Question\n\n```javascript\nfunction factorial(n) {\n  let result = 1;\n\n  for (let i = 2; i <= n; i++) {\n    result *= i;\n  }\n\n  return result;\n}\n```\n\n### Recursive\n\n```javascript\nfunction factorial(n) {\n  if (n === 0) return 1;\n  return n * factorial(n - 1);\n}\n```\n\n---\n\n# 5. Divisors / Factors\n\n### Question\n\nFind all divisors of a number.\n\n```javascript\nfunction divisors(n) {\n  let result = [];\n\n  for (let i = 1; i <= Math.sqrt(n); i++) {\n    if (n % i === 0) {\n      result.push(i);\n\n      if (i !== n / i) {\n        result.push(n / i);\n      }\n    }\n  }\n\n  return result.sort((a, b) => a - b);\n}\n```\n\n---\n\n# 6. Multiples\n\n### Question\n\nPrint multiples of N.\n\n```javascript\nfunction multiples(num, limit) {\n  for (let i = 1; i <= limit; i++) {\n    console.log(num * i);\n  }\n}\n```\n\n---\n\n# 7. Armstrong Number\n\n### Interview Question\n\n153 = 1³+5³+3³\n\n```javascript\nfunction isArmstrong(num) {\n  let digits = String(num).split(\"\");\n  let power = digits.length;\n\n  let sum = digits.reduce(\n    (acc, digit) => acc + Math.pow(Number(digit), power),\n    0,\n  );\n\n  return sum === num;\n}\n```\n\n---\n\n# 8. Palindrome Number\n\n### Question\n\n```javascript\nfunction isPalindrome(num) {\n  let str = String(num);\n\n  return str === str.split(\"\").reverse().join(\"\");\n}\n```\n\n---\n\n# 9. Anagram\n\n### Interview Question\n\n```javascript\nfunction isAnagram(str1, str2) {\n  const normalize = (str) => str.toLowerCase().split(\"\").sort().join(\"\");\n\n  return normalize(str1) === normalize(str2);\n}\n```\n\nExample:\n\n```javascript\nisAnagram(\"listen\", \"silent\");\n```\n\n---\n\n# 10. Repeated Digit Sum\n\n### Question\n\n9875\n\n9+8+7+5=29\n\n2+9=11\n\n1+1=2\n\n```javascript\nfunction repeatedDigitSum(n) {\n  while (n >= 10) {\n    let sum = 0;\n\n    while (n > 0) {\n      sum += n % 10;\n      n = Math.floor(n / 10);\n    }\n\n    n = sum;\n  }\n\n  return n;\n}\n```\n\n---\n\n# 11. Base Conversion\n\n### Decimal to Binary\n\n```javascript\nfunction decimalToBinary(n) {\n  return n.toString(2);\n}\n```\n\n### Binary to Decimal\n\n```javascript\nfunction binaryToDecimal(binary) {\n  return parseInt(binary, 2);\n}\n```\n\n---\n\n# 12. Fibonacci\n\n### Iterative\n\n```javascript\nfunction fibonacci(n) {\n  let a = 0,\n    b = 1;\n\n  for (let i = 0; i < n; i++) {\n    console.log(a);\n\n    let temp = a + b;\n\n    a = b;\n    b = temp;\n  }\n}\n```\n\n### Nth Fibonacci\n\n```javascript\nfunction nthFib(n) {\n  let a = 0,\n    b = 1;\n\n  for (let i = 2; i <= n; i++) {\n    let temp = a + b;\n\n    a = b;\n    b = temp;\n  }\n\n  return n === 0 ? 0 : b;\n}\n```\n\n---\n\n# 13. AP (Arithmetic Progression)\n\n### nth Term\n\n```javascript\nfunction apNthTerm(a, d, n) {\n  return a + (n - 1) * d;\n}\n```\n\n---\n\n# 14. GP (Geometric Progression)\n\n```javascript\nfunction gpNthTerm(a, r, n) {\n  return a * Math.pow(r, n - 1);\n}\n```\n\n---\n\n# 15. Mean\n\n```javascript\nfunction mean(arr) {\n  let sum = arr.reduce((a, b) => a + b, 0);\n\n  return sum / arr.length;\n}\n```\n\n---\n\n# 16. Median\n\n```javascript\nfunction median(arr) {\n  arr.sort((a, b) => a - b);\n\n  let mid = Math.floor(arr.length / 2);\n\n  return arr.length % 2 === 0 ? (arr[mid - 1] + arr[mid]) / 2 : arr[mid];\n}\n```\n\n---\n\n# 17. Mode\n\n```javascript\nfunction mode(arr) {\n  let freq = {};\n  let max = 0;\n  let result;\n\n  for (let num of arr) {\n    freq[num] = (freq[num] || 0) + 1;\n\n    if (freq[num] > max) {\n      max = freq[num];\n      result = num;\n    }\n  }\n\n  return result;\n}\n```\n\n---\n\n# 18. nCr (Combination)\n\nFormula:\n\n```text\nnCr = n! / r!(n-r)!\n```\n\n```javascript\nfunction factorial(n) {\n  let result = 1;\n\n  for (let i = 2; i <= n; i++) {\n    result *= i;\n  }\n\n  return result;\n}\n\nfunction nCr(n, r) {\n  return factorial(n) / (factorial(r) * factorial(n - r));\n}\n```\n\n---\n\n# 19. Celsius to Fahrenheit\n\n```javascript\nfunction celsiusToFahrenheit(c) {\n  return (c * 9) / 5 + 32;\n}\n```\n\n---\n\n# 20. GCD (Euclidean Algorithm)\n\n### Most Asked\n\n```javascript\nfunction gcd(a, b) {\n  while (b !== 0) {\n    let temp = b;\n\n    b = a % b;\n\n    a = temp;\n  }\n\n  return a;\n}\n```\n\n---\n\n# 21. LCM\n\n```javascript\nfunction gcd(a, b) {\n  while (b !== 0) {\n    let temp = b;\n\n    b = a % b;\n\n    a = temp;\n  }\n\n  return a;\n}\n\nfunction lcm(a, b) {\n  return (a * b) / gcd(a, b);\n}\n```\n\n---\n\n# 22. Sieve of Eratosthenes\n\n### Print all primes till N\n\n```javascript\nfunction sieve(n) {\n  let prime = new Array(n + 1).fill(true);\n\n  prime[0] = prime[1] = false;\n\n  for (let i = 2; i * i <= n; i++) {\n    if (prime[i]) {\n      for (let j = i * i; j <= n; j += i) {\n        prime[j] = false;\n      }\n    }\n  }\n\n  return prime.map((v, i) => (v ? i : null)).filter(Boolean);\n}\n```\n\n---\n\n# 23. Trailing Zeroes in Factorial\n\n### Very Popular\n\n```javascript\nfunction trailingZeroes(n) {\n  let count = 0;\n\n  while (n > 0) {\n    n = Math.floor(n / 5);\n\n    count += n;\n  }\n\n  return count;\n}\n```\n\n---\n\n# 24. Find All Divisors\n\n```javascript\nfunction allDivisors(n) {\n  let result = [];\n\n  for (let i = 1; i * i <= n; i++) {\n    if (n % i === 0) {\n      result.push(i);\n\n      if (i !== n / i) {\n        result.push(n / i);\n      }\n    }\n  }\n\n  return result.sort((a, b) => a - b);\n}\n```\n\n---\n\n# 25. Number Has Exactly Three Divisors\n\n### Trick\n\nNumber must be square of a prime.\n\n```javascript\nfunction exactlyThreeDivisors(n) {\n  let root = Math.sqrt(n);\n\n  if (root !== Math.floor(root)) return false;\n\n  return isPrime(root);\n}\n```\n\n---\n\n# 26. Number With Most Divisors\n\n### HackerRank Style\n\n```javascript\nfunction maxDivisorCount(limit) {\n  let maxNum = 1;\n  let maxDiv = 1;\n\n  for (let i = 1; i <= limit; i++) {\n    let count = 0;\n\n    for (let j = 1; j * j <= i; j++) {\n      if (i % j === 0) {\n        count += j * j === i ? 1 : 2;\n      }\n    }\n\n    if (count > maxDiv) {\n      maxDiv = count;\n      maxNum = i;\n    }\n  }\n\n  return maxNum;\n}\n```\n\n---\n\n# Top 10 Most Asked in Interviews\n\n1. Prime Number\n2. Palindrome Number\n3. Armstrong Number\n4. Factorial\n5. Fibonacci\n6. Anagram\n7. GCD\n8. LCM\n9. Trailing Zeroes in Factorial\n10. Sieve of Eratosthenes\n\nThese 10 alone cover roughly **80% of mathematical coding questions** asked in JavaScript, React Native, and HackerRank screening rounds.\n","type":"md"},{"name":"P004-Capco.md","content":"You can get `\"Banana\"` by splitting the string and accessing the second element:\n\n```javascript\nlet text = \"Apple, Banana, Kiwi\";\n\nlet result = text.split(\", \")[1];\n\nconsole.log(result); // Banana\n```\n\nOr using destructuring:\n\n```javascript\nlet text = \"Apple, Banana, Kiwi\";\n\nlet [, banana] = text.split(\", \");\n\nconsole.log(banana); // Banana\n```\n\nIf you want to **search for \"Banana\"** instead of accessing it by index, you can use `find()`, `includes()`, or `indexOf()`.\n\n### Using `find()`\n\n```javascript\nlet text = \"Apple, Banana, Kiwi\";\nlet result = text.split(\", \");\n\nlet fruit = result.find((item) => item === \"Banana\");\n\nconsole.log(fruit); // Banana\n```\n\n### Using `includes()`\n\n```javascript\nlet text = \"Apple, Banana, Kiwi\";\nlet result = text.split(\", \");\n\nconsole.log(result.includes(\"Banana\")); // true\n```\n\n### Using `indexOf()`\n\n```javascript\nlet text = \"Apple, Banana, Kiwi\";\nlet result = text.split(\", \");\n\nconsole.log(result.indexOf(\"Banana\")); // 1\n```\n\n### Without `split()`\n\nIf you just want to check whether the string contains `\"Banana\"`:\n\n```javascript\nlet text = \"Apple, Banana, Kiwi\";\n\nconsole.log(text.includes(\"Banana\")); // true\n```\n\nFor interviews, remember:\n\n- `includes()` → returns `true/false`\n- `indexOf()` → returns position or `-1`\n- `find()` → returns the actual element found\n- `filter()` → returns all matching elements in an array.\n\nYou can use `fetch()` like this:\n\n```javascript\nfetch(\"https://dummy-json.mock.beeceptor.com/posts\")\n  .then((response) => response.json())\n  .then((data) => {\n    console.log(data);\n  })\n  .catch((error) => {\n    console.error(\"Error:\", error);\n  });\n```\n\n### Using async/await (modern approach)\n\n```javascript\nasync function getPosts() {\n  try {\n    const response = await fetch(\"https://dummy-json.mock.beeceptor.com/posts\");\n\n    const data = await response.json();\n\n    console.log(data);\n  } catch (error) {\n    console.error(\"Error:\", error);\n  }\n}\n\ngetPosts();\n```\n\n### Print only post titles\n\n```javascript\nasync function getPosts() {\n  try {\n    const response = await fetch(\"https://dummy-json.mock.beeceptor.com/posts\");\n\n    const posts = await response.json();\n\n    posts.forEach((post) => {\n      console.log(post.title);\n    });\n  } catch (error) {\n    console.error(\"Error:\", error);\n  }\n}\n\ngetPosts();\n```\n\nCommon interview follow-up:\n\n- `fetch()` returns a **Promise**.\n- `await fetch()` waits for the HTTP response.\n- `response.json()` also returns a **Promise**, so it needs another `await`.\n- Network errors are caught by `catch`/`try-catch`. HTTP errors like 404/500 do not automatically throw; you should check `response.ok` if needed.\n\n\nIf by \"without predefined function\" you mean **don't use `flat()`**, you can flatten it using recursion:\n\n```javascript\nconst arr = [1, [2, [3, [4]], 5]];\n\nconst result = [];\n\nconst flatten = (input) => {\n  for (const item of input) {\n    if (Array.isArray(item)) {\n      flatten(item);\n    } else {\n      result.push(item);\n    }\n  }\n};\n\nflatten(arr);\n\nconsole.log(result); // [1, 2, 3, 4, 5]\n```\n\n### Interview Version (using reduce)\n\n```javascript\nconst arr = [1, [2, [3, [4]], 5]];\n\nconst flatten = (arr) =>\n  arr.reduce(\n    (acc, curr) =>\n      acc.concat(Array.isArray(curr) ? flatten(curr) : curr),\n    []\n  );\n\nconsole.log(flatten(arr)); // [1, 2, 3, 4, 5]\n```\n\n### If `flat()` is allowed\n\n```javascript\nconst arr = [1, [2, [3, [4]], 5]];\n\nconsole.log(arr.flat(Infinity)); // [1, 2, 3, 4, 5]\n```\n\nFor React Native/JavaScript interviews, the recursive solution is usually what interviewers expect when they say \"flatten nested array without using predefined functions.\"\n\n\n\nconst getPosts = async () => {\n\n    try{\n\n      const response = await fetch(\"https://dummy-json.mock.beeceptor.com/posts\");\n      const posts = await response.json();\n       \n       console.log(posts);\n       posts.forEach(post =>{\n         console.log(JSON.stringify(post))\n\n\n         console.log(post.title)\n       })\n\n    } catch (error) {\n      console.error(\"Error\", error);\n    }\n   }\nuseEffect(()=>{\n  getPosts();\n\n},[])\n","type":"md"},{"name":"P010-chatgpt.md","content":"# IBM HackerRank Preparation Guide\n\n## Senior React Native Developer (9 Years Experience)\n\n---\n\n# Interview Strategy\n\nFor a 60-minute HackerRank round with 2 coding questions:\n\n1. Read both questions completely.\n2. Identify the pattern:\n   - HashMap\n   - Set\n   - Sliding Window\n   - Stack\n   - Two Pointers\n   - Prefix/Suffix\n\n3. Solve Question 1 in 10–15 minutes.\n4. If stuck, write brute force first.\n5. Optimize later.\n\n---\n\n# Must Know JavaScript Methods\n\n```javascript\nmap();\nfilter();\nreduce();\nfind();\nfindIndex();\nsort();\nsplit();\njoin();\nslice();\nsubstring();\nincludes();\nObject.keys();\nObject.values();\nObject.entries();\n```\n\n---\n\n# Must Know Data Structures\n\n```javascript\nObject {}\nMap\nSet\nArray\nStack\nQueue\n```\n\n---\n\n# DSA SECTION\n\n---\n\n## 1. Two Sum ⭐⭐⭐⭐⭐\n\nPattern: HashMap\n\nInput:\n\n```javascript\nnums = [2, 7, 11, 15];\ntarget = 9;\n```\n\nOutput:\n\n```javascript\n[0, 1];\n```\n\nSolution:\n\n```javascript\nfunction twoSum(nums, target) {\n  const map = {};\n\n  for (let i = 0; i < nums.length; i++) {\n    const diff = target - nums[i];\n\n    if (map[diff] !== undefined) {\n      return [map[diff], i];\n    }\n\n    map[nums[i]] = i;\n  }\n\n  return [];\n}\n```\n\nComplexity:\n\n```text\nTime: O(n)\nSpace: O(n)\n```\n\n---\n\n## 2. Contains Duplicate ⭐⭐⭐⭐⭐\n\nPattern: Set\n\nInput:\n\n```javascript\nnums = [1, 2, 3, 1];\n```\n\nOutput:\n\n```javascript\ntrue;\n```\n\n```javascript\nfunction containsDuplicate(nums) {\n  const set = new Set();\n\n  for (const num of nums) {\n    if (set.has(num)) {\n      return true;\n    }\n\n    set.add(num);\n  }\n\n  return false;\n}\n```\n\n---\n\n## 3. Valid Anagram ⭐⭐⭐⭐⭐\n\nPattern: HashMap\n\nInput:\n\n```javascript\ns = \"anagram\";\nt = \"nagaram\";\n```\n\nOutput:\n\n```javascript\ntrue;\n```\n\n```javascript\nfunction isAnagram(s, t) {\n  if (s.length !== t.length) return false;\n\n  const map = {};\n\n  for (const ch of s) {\n    map[ch] = (map[ch] || 0) + 1;\n  }\n\n  for (const ch of t) {\n    if (!map[ch]) return false;\n    map[ch]--;\n  }\n\n  return true;\n}\n```\n\n---\n\n## 4. First Non-Repeating Character ⭐⭐⭐⭐⭐\n\nPattern: Frequency Count\n\nInput:\n\n```javascript\nstr = \"leetcode\";\n```\n\nOutput:\n\n```javascript\n\"l\";\n```\n\n```javascript\nfunction firstUnique(str) {\n  const freq = {};\n\n  for (const ch of str) {\n    freq[ch] = (freq[ch] || 0) + 1;\n  }\n\n  for (const ch of str) {\n    if (freq[ch] === 1) {\n      return ch;\n    }\n  }\n\n  return null;\n}\n```\n\n---\n\n## 5. Move Zeroes ⭐⭐⭐⭐\n\nPattern: Two Pointers\n\nInput:\n\n```javascript\nnums = [0, 1, 0, 3, 12];\n```\n\nOutput:\n\n```javascript\n[1, 3, 12, 0, 0];\n```\n\n```javascript\nfunction moveZeroes(nums) {\n  let index = 0;\n\n  for (let i = 0; i < nums.length; i++) {\n    if (nums[i] !== 0) {\n      nums[index++] = nums[i];\n    }\n  }\n\n  while (index < nums.length) {\n    nums[index++] = 0;\n  }\n\n  return nums;\n}\n```\n\n---\n\n## 6. Longest Substring Without Repeating Characters ⭐⭐⭐⭐⭐\n\nPattern: Sliding Window\n\nInput:\n\n```javascript\nstr = \"abcabcbb\";\n```\n\nOutput:\n\n```javascript\n3; // \"abc\"\n```\n\n```javascript\nfunction lengthOfLongestSubstring(str) {\n  let left = 0;\n  let max = 0;\n\n  const set = new Set();\n\n  for (let right = 0; right < str.length; right++) {\n    while (set.has(str[right])) {\n      set.delete(str[left]);\n      left++;\n    }\n\n    set.add(str[right]);\n\n    max = Math.max(max, right - left + 1);\n  }\n\n  return max;\n}\n```\n\nKey Formula:\n\n```javascript\nwindowLength = right - left + 1;\n```\n\n---\n\n## 7. Maximum Subarray Sum (Kadane) ⭐⭐⭐⭐\n\nPattern: Dynamic Running Sum\n\nInput:\n\n```javascript\nnums = [-2, 1, -3, 4, -1, 2, 1, -5, 4];\n```\n\nOutput:\n\n```javascript\n6; // [4,-1,2,1]\n```\n\n```javascript\nfunction maxSubArray(nums) {\n  let current = nums[0];\n  let max = nums[0];\n\n  for (let i = 1; i < nums.length; i++) {\n    current = Math.max(nums[i], current + nums[i]);\n    max = Math.max(max, current);\n  }\n\n  return max;\n}\n```\n\n---\n\n## 8. Valid Parentheses ⭐⭐⭐⭐\n\nPattern: Stack\n\nInput:\n\n```javascript\nstr = \"()[]{}\";\n```\n\nOutput:\n\n```javascript\ntrue;\n```\n\n```javascript\nfunction isValid(str) {\n  const stack = [];\n\n  const map = {\n    \")\": \"(\",\n    \"]\": \"[\",\n    \"}\": \"{\",\n  };\n\n  for (const ch of str) {\n    if (ch === \"(\" || ch === \"[\" || ch === \"{\") {\n      stack.push(ch);\n    } else if (ch === \")\" || ch === \"]\" || ch === \"}\") {\n      if (stack.pop() !== map[ch]) {\n        return false;\n      }\n    }\n  }\n\n  return stack.length === 0;\n}\n```\n\n---\n\n## 9. Product Of Array Except Self ⭐⭐⭐⭐\n\nPattern: Prefix + Suffix\n\nImportant Concept:\n\n```text\nStore First → Then Multiply\n```\n\nInput:\n\n```javascript\nnums = [1, 2, 3, 4];\n```\n\nOutput:\n\n```javascript\n[24, 12, 8, 6];\n```\n\n```javascript\nfunction productExceptSelf(nums) {\n  const result = new Array(nums.length).fill(1);\n\n  let prefix = 1;\n\n  for (let i = 0; i < nums.length; i++) {\n    result[i] = prefix;\n    prefix *= nums[i];\n  }\n\n  let suffix = 1;\n\n  for (let i = nums.length - 1; i >= 0; i--) {\n    result[i] *= suffix;\n    suffix *= nums[i];\n  }\n\n  return result;\n}\n```\n\n---\n\n## 10. Merge Two Sorted Arrays ⭐⭐⭐⭐\n\nPattern: Two Pointers\n\nInput:\n\n```javascript\narr1 = [1, 3, 5];\narr2 = [2, 4, 6];\n```\n\nOutput:\n\n```javascript\n[1, 2, 3, 4, 5, 6];\n```\n\n```javascript\nfunction mergeSortedArrays(arr1, arr2) {\n  let i = 0;\n  let j = 0;\n\n  const result = [];\n\n  while (i < arr1.length && j < arr2.length) {\n    if (arr1[i] <= arr2[j]) {\n      result.push(arr1[i++]);\n    } else {\n      result.push(arr2[j++]);\n    }\n  }\n\n  while (i < arr1.length) result.push(arr1[i++]);\n  while (j < arr2.length) result.push(arr2[j++]);\n\n  return result;\n}\n```\n\n---\n\n## 11. Flatten Nested Array ⭐⭐⭐⭐⭐\n\nPattern: Recursion\n\nInput:\n\n```javascript\narr = [1, [2, [3, 4], 5], 6];\n```\n\nOutput:\n\n```javascript\n[1, 2, 3, 4, 5, 6];\n```\n\n```javascript\nfunction flatten(arr) {\n  let result = [];\n\n  for (const item of arr) {\n    if (Array.isArray(item)) {\n      result.push(...flatten(item));\n    } else {\n      result.push(item);\n    }\n  }\n\n  return result;\n}\n```\n\nES6:\n\n```javascript\narr.flat(Infinity);\n```\n\n---\n\n## 12. Group Anagrams ⭐⭐⭐⭐\n\nPattern: HashMap\n\nInput:\n\n```javascript\nwords = [\"eat\", \"tea\", \"tan\", \"ate\", \"nat\", \"bat\"];\n```\n\nOutput:\n\n```javascript\n[[\"eat\", \"tea\", \"ate\"], [\"tan\", \"nat\"], [\"bat\"]];\n```\n\n```javascript\nfunction groupAnagrams(words) {\n  const map = {};\n\n  for (const word of words) {\n    const key = word.split(\"\").sort().join(\"\");\n\n    if (!map[key]) {\n      map[key] = [];\n    }\n\n    map[key].push(word);\n  }\n\n  return Object.values(map);\n}\n```\n\n---\n\n# JavaScript Core Section\n\n---\n\n## 13. Closure ⭐⭐⭐⭐⭐\n\n```javascript\nfunction outer() {\n  let count = 0;\n\n  return function inner() {\n    count++;\n    return count;\n  };\n}\n\nconst counter = outer();\n\nconsole.log(counter());\nconsole.log(counter());\n```\n\nInterview Answer:\n\n```text\nInner function remembers variables from outer scope even after outer function finishes execution.\n```\n\n---\n\n## 14. Debounce ⭐⭐⭐⭐⭐\n\n```javascript\nfunction debounce(fn, delay) {\n  let timer;\n\n  return function (...args) {\n    clearTimeout(timer);\n\n    timer = setTimeout(() => {\n      fn.apply(this, args);\n    }, delay);\n  };\n}\n```\n\nUse Cases:\n\n```text\nSearch API\nButton Click\nInput Field\n```\n\n---\n\n## 15. Throttle ⭐⭐⭐⭐⭐\n\n```javascript\nfunction throttle(fn, delay) {\n  let canRun = true;\n\n  return function (...args) {\n    if (!canRun) return;\n\n    fn.apply(this, args);\n\n    canRun = false;\n\n    setTimeout(() => {\n      canRun = true;\n    }, delay);\n  };\n}\n```\n\nUse Cases:\n\n```text\nScroll Event\nGPS Updates\nResize Event\n```\n\n---\n\n## 16. Promise APIs ⭐⭐⭐⭐⭐\n\nPromise.all()\n\n```text\nAll success required\nOne failure = fail\n```\n\nPromise.allSettled()\n\n```text\nWaits for all\nReturns success and failure\n```\n\nPromise.race()\n\n```text\nReturns first settled promise\n```\n\nPromise.any()\n\n```text\nReturns first successful promise\nIgnores failures\n```\n\n---\n\n## 17. Event Loop ⭐⭐⭐⭐⭐\n\n```javascript\nconsole.log(\"1\");\n\nsetTimeout(() => {\n  console.log(\"2\");\n}, 0);\n\nPromise.resolve().then(() => {\n  console.log(\"3\");\n});\n\nconsole.log(\"4\");\n```\n\nOutput:\n\n```text\n1\n4\n3\n2\n```\n\nRemember:\n\n```text\nSync Code\n↓\nMicrotask Queue (Promise)\n↓\nMacrotask Queue (setTimeout)\n```\n\n---\n\n## 18. Object / Array Transformation ⭐⭐⭐⭐⭐\n\nArray → Object\n\n```javascript\nfunction convert(users) {\n  return users.reduce((acc, user) => {\n    acc[user.id] = user;\n    return acc;\n  }, {});\n}\n```\n\nObject → Array\n\n```javascript\nObject.values(usersObj);\n```\n\nRemember:\n\n```text\nArray → Object = reduce()\nObject → Array = Object.values()\nArray → Array = map()\nFilter Array = filter()\nArray → Single Value = reduce()\n```\n\n---\n\n## 19. Group By using reduce()\n\n```javascript\nconst grouped = users.reduce((acc, user) => {\n  if (!acc[user.role]) {\n    acc[user.role] = [];\n  }\n\n  acc[user.role].push(user);\n\n  return acc;\n}, {});\n```\n\n## 20. Retry API Call\n\n```javascript\nasync function fetchWithRetry(url, retries = 3) {\n  while (retries > 0) {\n    try {\n      const response = await fetch(url);\n      return await response.json();\n    } catch {\n      retries--;\n    }\n  }\n\n  throw new Error(\"Failed\");\n}\n```\n\n# FINAL 15 QUESTIONS TO MEMORIZE\n\n1. Two Sum\n2. Contains Duplicate\n3. Valid Anagram\n4. First Non-Repeating Character\n5. Longest Substring Without Repeating Characters\n6. Move Zeroes\n7. Maximum Subarray Sum\n8. Valid Parentheses\n9. Product Except Self\n10. Merge Two Sorted Arrays\n11. Flatten Nested Array\n12. Group Anagrams\n13. Closure\n14. Debounce\n15. Throttle\n\n---\n\n# FINAL 5 JAVASCRIPT TOPICS\n\n1. Promise.all()\n2. Promise.allSettled()\n3. Promise.race()\n4. Event Loop\n5. map/filter/reduce\n\n---\n\n# Expected IBM Patterns\n\nHigh Probability:\n\n```text\nHashMap\nSet\nSliding Window\nStack\nTwo Pointers\nArray Transformations\nJavaScript Fundamentals\n```\n\nLow Probability:\n\n```text\nGraph\nTree\nTrie\nAdvanced Dynamic Programming\nDijkstra\nTopological Sort\n```\n\nIf you can code and explain all topics in this document from memory, you're prepared for the vast majority of React Native / Frontend-oriented HackerRank coding assessments.\n\n# Time Complexity Cheat Sheet ⭐⭐⭐⭐⭐\n\nInterviewers often ask:\n\n```text\nWhat is the time complexity?\nWhat is the space complexity?\nCan you optimize it?\n```\n\n| Complexity | Meaning     | Example             |\n| ---------- | ----------- | ------------------- |\n| O(1)       | Constant    | Array Access        |\n| O(log n)   | Logarithmic | Binary Search       |\n| O(n)       | Linear      | Single Loop         |\n| O(n log n) | Log Linear  | Merge Sort          |\n| O(n²)      | Quadratic   | Nested Loops        |\n| O(2ⁿ)      | Exponential | Recursive Fibonacci |\n| O(n!)      | Factorial   | Permutations        |\n\n---\n\n## Binary Search ⭐⭐⭐\n\nQuestion:\n\nGiven a sorted array and a target value, return its index.\n\nInput:\n\n```javascript\nnums = [1, 2, 3, 4, 5, 6];\ntarget = 4;\n```\n\nOutput:\n\n```javascript\n3;\n```\n\nPattern:\n\n```text\nBinary Search\n```\n\nSolution:\n\n```javascript\nfunction binarySearch(nums, target) {\n  let left = 0;\n  let right = nums.length - 1;\n\n  while (left <= right) {\n    const mid = Math.floor((left + right) / 2);\n\n    if (nums[mid] === target) {\n      return mid;\n    }\n\n    if (nums[mid] < target) {\n      left = mid + 1;\n    } else {\n      right = mid - 1;\n    }\n  }\n\n  return -1;\n}\n```\n\nComplexity:\n\n```text\nTime: O(log n)\nSpace: O(1)\n```\n\n---\n\n## Bit Manipulation (Single Number) ⭐⭐\n\nQuestion:\n\nFind the number that appears only once.\n\nInput:\n\n```javascript\n[2, 2, 1];\n```\n\nOutput:\n\n```javascript\n1;\n```\n\nPattern:\n\n```text\nXOR\n```\n\nRemember:\n\n```javascript\na ^ a = 0\na ^ 0 = a\n```\n\nSolution:\n\n```javascript\nfunction singleNumber(nums) {\n  let result = 0;\n\n  for (const num of nums) {\n    result ^= num;\n  }\n\n  return result;\n}\n```\n\nComplexity:\n\n```text\nTime: O(n)\nSpace: O(1)\n```\n\n---\n\n## Matrix Traversal ⭐⭐\n\nQuestion:\n\nTraverse matrix row by row.\n\nInput:\n\n```javascript\n[\n  [1, 2],\n  [3, 4],\n];\n```\n\nOutput:\n\n```javascript\n1;\n2;\n3;\n4;\n```\n\nPattern:\n\n```text\nNested Loops\n```\n\nSolution:\n\n```javascript\nfunction traverse(matrix) {\n  for (let row = 0; row < matrix.length; row++) {\n    for (let col = 0; col < matrix[row].length; col++) {\n      console.log(matrix[row][col]);\n    }\n  }\n}\n```\n\nComplexity:\n\n```text\nTime: O(rows × cols)\nSpace: O(1)\n```\n\n1. Two Sum\n2. Contains Duplicate\n3. Valid Anagram\n4. First Non-Repeating Character\n5. Move Zeroes\n6. Longest Substring\n7. Maximum Subarray\n8. Valid Parentheses\n9. Product Except Self\n10. Merge Two Sorted Arrays\n11. Binary Search\n12. Flatten Nested Array\n13. Group Anagrams\n14. Single Number (XOR)\n15. Matrix Traversal\n\nFor a JavaScript/React Native interview, you don't need full programs for these. Just remember **what they do + one small example**.\n\n# Array Methods\n\n## 1. map()\n\nUsed to transform every element.\n\n```javascript\nconst nums = [1, 2, 3];\n\nconst result = nums.map((num) => num * 2);\n\nconsole.log(result);\n// [2, 4, 6]\n```\n\n---\n\n## 2. filter()\n\nUsed to keep elements that match a condition.\n\n```javascript\nconst nums = [1, 2, 3, 4, 5];\n\nconst result = nums.filter((num) => num > 3);\n\nconsole.log(result);\n// [4, 5]\n```\n\n---\n\n## 3. reduce()\n\nUsed to convert an array into a single value.\n\n```javascript\nconst nums = [1, 2, 3, 4];\n\nconst sum = nums.reduce((acc, curr) => acc + curr, 0);\n\nconsole.log(sum);\n// 10\n```\n\n---\n\n## 4. find()\n\nReturns first matching element.\n\n```javascript\nconst users = [{ id: 1 }, { id: 2 }];\n\nconst user = users.find((u) => u.id === 2);\n\nconsole.log(user);\n// { id: 2 }\n```\n\n---\n\n## 5. findIndex()\n\nReturns index of first matching element.\n\n```javascript\nconst nums = [10, 20, 30];\n\nconst index = nums.findIndex((num) => num === 20);\n\nconsole.log(index);\n// 1\n```\n\n---\n\n## 6. sort()\n\nSorts array.\n\n```javascript\nconst nums = [5, 1, 3, 2];\n\nnums.sort((a, b) => a - b);\n\nconsole.log(nums);\n// [1, 2, 3, 5]\n```\n\n---\n\n# String Methods\n\n## 7. split()\n\nConverts string into array.\n\n```javascript\nconst str = \"apple,banana,mango\";\n\nconst result = str.split(\",\");\n\nconsole.log(result);\n// [\"apple\", \"banana\", \"mango\"]\n```\n\n---\n\n## 8. join()\n\nConverts array into string.\n\n```javascript\nconst arr = [\"apple\", \"banana\", \"mango\"];\n\nconst result = arr.join(\",\");\n\nconsole.log(result);\n// apple,banana,mango\n```\n\n---\n\n## 9. slice()\n\nExtracts part of string/array.\n\n```javascript\nconst str = \"JavaScript\";\n\nconsole.log(str.slice(0, 4));\n// Java\n```\n\n```javascript\nconst arr = [1, 2, 3, 4, 5];\n\nconsole.log(arr.slice(1, 4));\n// [2,3,4]\n```\n\n---\n\n## 10. substring()\n\n```javascript\nconst str = \"JavaScript\";\n\nconsole.log(str.substring(0, 4));\n// Java\n```\n\n---\n\n## 11. includes()\n\nChecks if value exists.\n\n```javascript\nconst arr = [1, 2, 3];\n\nconsole.log(arr.includes(2));\n// true\n```\n\n```javascript\nconst str = \"Hello World\";\n\nconsole.log(str.includes(\"World\"));\n// true\n```\n\n---\n\n# Object Methods\n\n## 12. Object.keys()\n\n```javascript\nconst user = {\n  name: \"Rajeev\",\n  age: 30,\n};\n\nconsole.log(Object.keys(user));\n\n// [\"name\", \"age\"]\n```\n\n---\n\n## 13. Object.values()\n\n```javascript\nconst user = {\n  name: \"Rajeev\",\n  age: 30,\n};\n\nconsole.log(Object.values(user));\n\n// [\"Rajeev\", 30]\n```\n\n---\n\n## 14. Object.entries()\n\n```javascript\nconst user = {\n  name: \"Rajeev\",\n  age: 30,\n};\n\nconsole.log(Object.entries(user));\n\n// [[\"name\",\"Rajeev\"],[\"age\",30]]\n```\n\n---\n\n# Must Know Data Structures\n\n## 1. Object {}\n\nKey-Value storage.\n\n```javascript\nconst user = {\n  name: \"Rajeev\",\n  age: 30,\n};\n\nconsole.log(user.name);\n// Rajeev\n```\n\nUse when:\n\n- JSON response\n- User data\n- Configurations\n\n---\n\n## 2. Map\n\nAny type can be key.\n\n```javascript\nconst map = new Map();\n\nmap.set(\"name\", \"Candidate\");\nmap.set(1, \"One\");\n\nconsole.log(map.get(\"name\"));\n// Rajeev\n```\n\nInterview Question:\n\n```javascript\nconst map = new Map();\n\nmap.set(\"a\", 1);\nmap.set(\"a\", 2);\n\nconsole.log(map.get(\"a\"));\n// 2\n```\n\n---\n\n## 3. Set\n\nStores unique values.\n\n```javascript\nconst set = new Set([1, 2, 2, 3]);\n\nconsole.log(set);\n\n// {1,2,3}\n```\n\nRemove duplicates:\n\n```javascript\nconst nums = [1, 2, 2, 3, 4, 4];\n\nconst unique = [...new Set(nums)];\n\nconsole.log(unique);\n\n// [1,2,3,4]\n```\n\n---\n\n## 4. Array\n\nMost commonly used.\n\n```javascript\nconst fruits = [\"Apple\", \"Banana\"];\n\nfruits.push(\"Mango\");\n\nconsole.log(fruits);\n\n// [\"Apple\",\"Banana\",\"Mango\"]\n```\n\n---\n\n## 5. Stack (LIFO)\n\nLast In First Out.\n\n```javascript\nconst stack = [];\n\nstack.push(10);\nstack.push(20);\nstack.push(30);\n\nconsole.log(stack.pop());\n// 30\n```\n\nThink:\n\n- Undo operation\n- Browser back button\n\n---\n\n## 6. Queue (FIFO)\n\nFirst In First Out.\n\n```javascript\nconst queue = [];\n\nqueue.push(10);\nqueue.push(20);\nqueue.push(30);\n\nconsole.log(queue.shift());\n// 10\n```\n\nThink:\n\n- Ticket counter\n- Task processing\n\n---\n\n# Most Asked Interview One-Liners\n\n```javascript\n// Remove Duplicates\n[...new Set(arr)]\n\n// String Reverse\nstr.split(\"\").reverse().join(\"\")\n\n// Array Sum\narr.reduce((a,b) => a+b, 0)\n\n// Check Array\nArray.isArray(arr)\n\n// Object to Array\nObject.entries(obj)\n\n// Array to String\narr.join(\",\")\n\n// String to Array\nstr.split(\",\")\n\n// Merge Arrays\n[...arr1, ...arr2]\n\n// Copy Array\n[...arr]\n\n// Copy Object\n{...obj}\n```\n\nIf your HackerRank round is for a React Native developer, these methods plus:\n\n- Closures\n- Hoisting\n- Promises\n- async/await\n- Debounce\n- Throttle\n- Event Loop\n- Set vs Map\n- Contains Duplicate\n- Two Sum\n- Valid Parentheses\n- Reverse String\n- Palindrome\n\ncover about **80–90% of typical JavaScript coding questions**.\n\n====\n\nHere are the most common **JavaScript Promise examples** asked in interviews.\n\n---\n\n# 1. Basic Promise\n\n```js\nconst promise = new Promise((resolve, reject) => {\n  const success = true;\n\n  if (success) {\n    resolve(\"Success\");\n  } else {\n    reject(\"Failed\");\n  }\n});\n\npromise\n  .then((result) => console.log(result))\n  .catch((error) => console.log(error));\n```\n\nOutput:\n\n```js\nSuccess;\n```\n\n---\n\n# 2. Promise with setTimeout\n\n```js\nconst promise = new Promise((resolve) => {\n  setTimeout(() => {\n    resolve(\"Data Loaded\");\n  }, 2000);\n});\n\npromise.then((data) => {\n  console.log(data);\n});\n```\n\nOutput after 2 seconds:\n\n```js\nData Loaded\n```\n\n---\n\n# 3. Promise Reject Example\n\n```js\nconst promise = new Promise((resolve, reject) => {\n  reject(\"Something went wrong\");\n});\n\npromise\n  .then((result) => console.log(result))\n  .catch((error) => console.log(error));\n```\n\nOutput:\n\n```js\nSomething went wrong\n```\n\n---\n\n# 4. Promise Chaining\n\n```js\nPromise.resolve(2)\n  .then((num) => num * 2)\n  .then((num) => num * 3)\n  .then((num) => console.log(num));\n```\n\nOutput:\n\n```js\n12;\n```\n\nFlow:\n\n```text\n2\n↓\n4\n↓\n12\n```\n\n---\n\n# 5. Async/Await with Promise\n\n```js\nfunction getData() {\n  return new Promise((resolve) => {\n    setTimeout(() => {\n      resolve(\"User Data\");\n    }, 1000);\n  });\n}\n\nasync function fetchData() {\n  const result = await getData();\n  console.log(result);\n}\n\nfetchData();\n```\n\nOutput:\n\n```js\nUser Data\n```\n\n---\n\n# 6. Promise.all()\n\nRuns all promises in parallel.\n\n```js\nconst p1 = Promise.resolve(\"A\");\nconst p2 = Promise.resolve(\"B\");\nconst p3 = Promise.resolve(\"C\");\n\nPromise.all([p1, p2, p3]).then((result) => console.log(result));\n```\n\nOutput:\n\n```js\n[\"A\", \"B\", \"C\"];\n```\n\n---\n\n# 7. Promise.all() Failure\n\n```js\nconst p1 = Promise.resolve(\"A\");\nconst p2 = Promise.reject(\"Error\");\nconst p3 = Promise.resolve(\"C\");\n\nPromise.all([p1, p2, p3])\n  .then((result) => console.log(result))\n  .catch((error) => console.log(error));\n```\n\nOutput:\n\n```js\nError;\n```\n\nIf one fails, entire `Promise.all()` fails.\n\n---\n\n# 8. Promise.allSettled()\n\nReturns all results whether success or failure.\n\n```js\nconst p1 = Promise.resolve(\"A\");\nconst p2 = Promise.reject(\"Error\");\n\nPromise.allSettled([p1, p2]).then((result) => console.log(result));\n```\n\nOutput:\n\n```js\n[\n  { status: \"fulfilled\", value: \"A\" },\n  { status: \"rejected\", reason: \"Error\" },\n];\n```\n\n---\n\n# 9. Promise.race()\n\nReturns the first settled promise.\n\n```js\nconst p1 = new Promise((resolve) => setTimeout(() => resolve(\"First\"), 1000));\n\nconst p2 = new Promise((resolve) => setTimeout(() => resolve(\"Second\"), 2000));\n\nPromise.race([p1, p2]).then((result) => console.log(result));\n```\n\nOutput:\n\n```js\nFirst;\n```\n\n---\n\n# 10. Promise.any()\n\nReturns the first successful promise.\n\n```js\nconst p1 = Promise.reject(\"Error\");\nconst p2 = Promise.resolve(\"Success\");\nconst p3 = Promise.resolve(\"Hello\");\n\nPromise.any([p1, p2, p3]).then((result) => console.log(result));\n```\n\nOutput:\n\n```js\nSuccess;\n```\n\n---\n\n# 11. Real API Example\n\n```js\nfunction fetchUser() {\n  return fetch(\"https://jsonplaceholder.typicode.com/users/1\").then(\n    (response) => response.json(),\n  );\n}\n\nfetchUser()\n  .then((user) => console.log(user.name))\n  .catch((error) => console.log(error));\n```\n\n---\n\n# 12. Same API using async/await\n\n```js\nasync function fetchUser() {\n  try {\n    const response = await fetch(\n      \"https://jsonplaceholder.typicode.com/users/1\",\n    );\n\n    const user = await response.json();\n\n    console.log(user.name);\n  } catch (error) {\n    console.log(error);\n  }\n}\n\nfetchUser();\n```\n\n---\n\n# Interview Questions\n\n### What are the states of a Promise?\n\n```text\nPending\nFulfilled (Resolved)\nRejected\n```\n\n---\n\n### Can a Promise change state after resolve/reject?\n\n```js\nconst p = new Promise((resolve, reject) => {\n  resolve(\"Success\");\n  reject(\"Error\");\n});\n```\n\nOutput:\n\n```js\nSuccess;\n```\n\nOnly the first state counts.\n\n---\n\n### Difference between Promise.all and Promise.allSettled?\n\n```text\nPromise.all\n❌ Fails if any promise fails\n\nPromise.allSettled\n✅ Returns all results\n```\n\n---\n\n### Difference between Promise.race and Promise.any?\n\n```text\nPromise.race\nReturns first settled promise\n(success OR failure)\n\nPromise.any\nReturns first successful promise\n```\n\n---\n\n### Promise Interview Cheat Sheet\n\n```text\nthen()         -> Success\ncatch()        -> Error\nfinally()      -> Always runs\n\nPromise.all()        -> All success required\nPromise.allSettled() -> Get all results\nPromise.race()       -> First settled wins\nPromise.any()        -> First success wins\n\nasync/await -> Cleaner syntax for promises\n```\n\nThese are the Promise concepts and examples most commonly asked in React Native, JavaScript, and frontend/mobile developer interviews.\n","type":"md"},{"name":"P012-Kashee.md","content":"Yes. The PDF contains Swift interview coding questions and patterns. I'll convert them into **JavaScript** with examples and expected outputs.\n\n---\n\n# 1. Output of Given Code (GCD Queue Concept → JavaScript Async)\n\n### JavaScript Version\n\n```javascript\nconsole.log(\"A\");\n\nsetTimeout(() => {\n  console.log(\"B\");\n\n  Promise.resolve().then(() => {\n    console.log(\"C\");\n  });\n\n  console.log(\"D\");\n}, 0);\n\nsetTimeout(() => {\n  console.log(\"E\");\n}, 0);\n\nconsole.log(\"F\");\n```\n\n### Possible Output\n\n```text\nA\nF\nB\nD\nC\nE\n```\n\n### Interview Point\n\n- Synchronous code executes first.\n- Microtasks (`Promise.then`) execute before macrotasks (`setTimeout`).\n\n---\n\n# 2. Third Largest Number in Array\n\n### Example\n\n```javascript\nconst nums = [10, 5, 20, 8, 15];\n```\n\n### Solution\n\n```javascript\nfunction thirdLargest(nums) {\n  const unique = [...new Set(nums)].sort((a, b) => b - a);\n\n  return unique.length >= 3 ? unique[2] : null;\n}\n\nconsole.log(thirdLargest([10, 5, 20, 8, 15]));\n```\n\n### Output\n\n```text\n10\n```\n\n### Complexity\n\n```text\nTime: O(n log n)\nSpace: O(n)\n```\n\n---\n\n# 3. Valid Parentheses\n\n### Example\n\n```javascript\nInput: \"()[]{}\";\nOutput: true;\n```\n\n### Solution\n\n```javascript\nfunction isValid(str) {\n  const stack = [];\n\n  const map = {\n    \")\": \"(\",\n    \"]\": \"[\",\n    \"}\": \"{\",\n  };\n\n  for (const ch of str) {\n    if (map[ch]) {\n      if (stack.pop() !== map[ch]) {\n        return false;\n      }\n    } else {\n      stack.push(ch);\n    }\n  }\n\n  return stack.length === 0;\n}\n\nconsole.log(isValid(\"()[]{}\"));\n```\n\n### Output\n\n```text\ntrue\n```\n\n### Complexity\n\n```text\nTime: O(n)\nSpace: O(n)\n```\n\n---\n\n# 4. Prefix Sum Array\n\n### Example\n\n```javascript\nInput: [3, 5, 4, 2, 7, 9];\nOutput: [3, 8, 12, 14, 21, 30];\n```\n\n### Solution\n\n```javascript\nfunction prefixSum(nums) {\n  const prefix = [nums[0]];\n\n  for (let i = 1; i < nums.length; i++) {\n    prefix[i] = prefix[i - 1] + nums[i];\n  }\n\n  return prefix;\n}\n\nconsole.log(prefixSum([3, 5, 4, 2, 7, 9]));\n```\n\n---\n\n# 5. Range Sum Query\n\n### Example\n\n```javascript\nnums = [-2, 0, 3, -5, 2, -1];\n\nsumRange(1, 5);\n```\n\n### Output\n\n```text\n-1\n```\n\n### Solution\n\n```javascript\nclass NumArray {\n  constructor(nums) {\n    this.prefix = [...nums];\n\n    for (let i = 1; i < nums.length; i++) {\n      this.prefix[i] += this.prefix[i - 1];\n    }\n  }\n\n  sumRange(left, right) {\n    if (left === 0) {\n      return this.prefix[right];\n    }\n\n    return this.prefix[right] - this.prefix[left - 1];\n  }\n}\n\nconst obj = new NumArray([-2, 0, 3, -5, 2, -1]);\n\nconsole.log(obj.sumRange(1, 5));\n```\n\n---\n\n# 6. Subarray Sum Equals K\n\n### Example\n\n```javascript\nnums = [1, -1, 0];\nk = 0;\n```\n\n### Output\n\n```text\n3\n```\n\n### Solution\n\n```javascript\nfunction subarraySum(nums, k) {\n  let count = 0;\n  let prefixSum = 0;\n\n  const map = new Map();\n  map.set(0, 1);\n\n  for (const num of nums) {\n    prefixSum += num;\n\n    count += map.get(prefixSum - k) || 0;\n\n    map.set(prefixSum, (map.get(prefixSum) || 0) + 1);\n  }\n\n  return count;\n}\n\nconsole.log(subarraySum([1, -1, 0], 0));\n```\n\n---\n\n# 7. Maximum Size Subarray Sum Equals K\n\n### Example\n\n```javascript\nnums = [1, -1, 5, -2, 3];\nk = 3;\n```\n\n### Output\n\n```text\n4\n```\n\n### Solution\n\n```javascript\nfunction maxSubArrayLen(nums, k) {\n  let prefix = 0;\n  let maxLen = 0;\n\n  const map = new Map();\n  map.set(0, -1);\n\n  for (let i = 0; i < nums.length; i++) {\n    prefix += nums[i];\n\n    if (map.has(prefix - k)) {\n      maxLen = Math.max(maxLen, i - map.get(prefix - k));\n    }\n\n    if (!map.has(prefix)) {\n      map.set(prefix, i);\n    }\n  }\n\n  return maxLen;\n}\n\nconsole.log(maxSubArrayLen([1, -1, 5, -2, 3], 3));\n```\n\n---\n\n# 8. Continuous Subarray Sum\n\n### Example\n\n```javascript\nnums = [23, 2, 6, 4, 7];\nk = 6;\n```\n\n### Output\n\n```text\ntrue\n```\n\n### Solution\n\n```javascript\nfunction checkSubarraySum(nums, k) {\n  let prefix = 0;\n\n  const map = new Map();\n  map.set(0, -1);\n\n  for (let i = 0; i < nums.length; i++) {\n    prefix += nums[i];\n\n    const rem = prefix % k;\n\n    if (map.has(rem)) {\n      if (i - map.get(rem) >= 2) {\n        return true;\n      }\n    } else {\n      map.set(rem, i);\n    }\n  }\n\n  return false;\n}\n```\n\n---\n\n# 9. Two Sum II (Sorted Array)\n\n### Example\n\n```javascript\nnumbers = [2, 7, 11, 15];\ntarget = 9;\n```\n\n### Output\n\n```text\n[1,2]\n```\n\n### Solution\n\n```javascript\nfunction twoSum(numbers, target) {\n  let left = 0;\n  let right = numbers.length - 1;\n\n  while (left < right) {\n    const sum = numbers[left] + numbers[right];\n\n    if (sum === target) {\n      return [left + 1, right + 1];\n    }\n\n    if (sum > target) {\n      right--;\n    } else {\n      left++;\n    }\n  }\n\n  return [];\n}\n```\n\n---\n\n# 10. 3 Sum\n\n### Example\n\n```javascript\nInput: [-1, 0, 1, 2, -1, -4];\n\nOutput: [\n  [-1, -1, 2],\n  [-1, 0, 1],\n];\n```\n\n### Solution\n\n```javascript\nfunction threeSum(nums) {\n  nums.sort((a, b) => a - b);\n\n  const result = [];\n\n  for (let i = 0; i < nums.length - 2; i++) {\n    if (i > 0 && nums[i] === nums[i - 1]) {\n      continue;\n    }\n\n    let left = i + 1;\n    let right = nums.length - 1;\n\n    while (left < right) {\n      const sum = nums[i] + nums[left] + nums[right];\n\n      if (sum === 0) {\n        result.push([nums[i], nums[left], nums[right]]);\n\n        while (left < right && nums[left] === nums[left + 1]) left++;\n        while (left < right && nums[right] === nums[right - 1]) right--;\n\n        left++;\n        right--;\n      } else if (sum < 0) {\n        left++;\n      } else {\n        right--;\n      }\n    }\n  }\n\n  return result;\n}\n```\n\n---\n\n# 11. Container With Most Water\n\n```javascript\nfunction maxArea(height) {\n  let left = 0;\n  let right = height.length - 1;\n  let maxWater = 0;\n\n  while (left < right) {\n    const area = (right - left) * Math.min(height[left], height[right]);\n\n    maxWater = Math.max(maxWater, area);\n\n    if (height[left] < height[right]) {\n      left++;\n    } else {\n      right--;\n    }\n  }\n\n  return maxWater;\n}\n```\n\n---\n\n# 12. Longest Substring Without Repeating Characters\n\n### Example\n\n```javascript\nInput: \"abcabcbb\";\nOutput: 3;\n```\n\n### Solution\n\n```javascript\nfunction lengthOfLongestSubstring(s) {\n  const map = new Map();\n\n  let left = 0;\n  let maxLen = 0;\n\n  for (let right = 0; right < s.length; right++) {\n    if (map.has(s[right])) {\n      left = Math.max(left, map.get(s[right]) + 1);\n    }\n\n    map.set(s[right], right);\n\n    maxLen = Math.max(maxLen, right - left + 1);\n  }\n\n  return maxLen;\n}\n```\n\n---\n\n# 13. Maximum Sum of Distinct Subarrays of Length K\n\n```javascript\nfunction maximumSubarraySum(nums, k) {\n  let left = 0;\n  let currentSum = 0;\n  let maxSum = 0;\n\n  const set = new Set();\n\n  for (let right = 0; right < nums.length; right++) {\n    while (set.has(nums[right])) {\n      set.delete(nums[left]);\n      currentSum -= nums[left];\n      left++;\n    }\n\n    set.add(nums[right]);\n    currentSum += nums[right];\n\n    while (right - left + 1 > k) {\n      set.delete(nums[left]);\n      currentSum -= nums[left];\n      left++;\n    }\n\n    if (right - left + 1 === k) {\n      maxSum = Math.max(maxSum, currentSum);\n    }\n  }\n\n  return maxSum;\n}\n```\n\n---\n\n# 14. Maximum Average Subarray\n\n```javascript\nfunction findMaxAverage(nums, k) {\n  let left = 0;\n  let currentSum = 0;\n  let maxAvg = -Infinity;\n\n  for (let right = 0; right < nums.length; right++) {\n    currentSum += nums[right];\n\n    if (right - left + 1 > k) {\n      currentSum -= nums[left];\n      left++;\n    }\n\n    if (right - left + 1 === k) {\n      maxAvg = Math.max(maxAvg, currentSum / k);\n    }\n  }\n\n  return maxAvg;\n}\n```\n\n---\n\n# 15. Two Sum (Unsorted Array)\n\n### Example\n\n```javascript\nnums = [3, 2, 4];\ntarget = 6;\n```\n\n### Output\n\n```text\n[1,2]\n```\n\n### Solution\n\n```javascript\nfunction twoSum(nums, target) {\n  const map = new Map();\n\n  for (let i = 0; i < nums.length; i++) {\n    const complement = target - nums[i];\n\n    if (map.has(complement)) {\n      return [map.get(complement), i];\n    }\n\n    map.set(nums[i], i);\n  }\n\n  return [];\n}\n```\n\n---\n\n# 16. Add Digits Until Single Digit\n\n### Example\n\n```javascript\nInput: \"123456\";\n```\n\n### Calculation\n\n```text\n1+2+3+4+5+6 = 21\n2+1 = 3\n```\n\n### Output\n\n```text\n3\n```\n\n### Solution\n\n```javascript\nfunction singleDigitSum(str) {\n  let sum = str.split(\"\").reduce((acc, digit) => acc + Number(digit), 0);\n\n  while (sum >= 10) {\n    sum = String(sum)\n      .split(\"\")\n      .reduce((acc, digit) => acc + Number(digit), 0);\n  }\n\n  return sum;\n}\n\nconsole.log(singleDigitSum(\"123456\"));\n```\n\n---\n\nThese are the main Swift interview questions from the PDF converted into JavaScript with examples, outputs, complexity, and interview-ready solutions.\n","type":"md"},{"name":"P006.md","content":"Yes. For an IBM HackerRank (2 coding questions, 60 mins), I would practice these **10 most likely questions first**.\n\n---\n\n# Question 1: Two Sum\n\n### Problem\n\nGiven an array and a target, return indices whose sum equals target.\n\n```javascript\nInput: nums = [2, 7, 11, 15];\ntarget = 9;\n\nOutput: [0, 1];\n```\n\n### Solution\n\n```javascript\nfunction twoSum(nums, target) {\n  const map = {};\n\n  for (let i = 0; i < nums.length; i++) {\n    const diff = target - nums[i];\n\n    if (map[diff] !== undefined) {\n      return [map[diff], i];\n    }\n\n    map[nums[i]] = i;\n  }\n\n  return [];\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 2: Valid Anagram\n\n### Problem\n\n```javascript\nInput: s = \"listen\";\nt = \"silent\";\n\nOutput: true;\n```\n\n### Solution\n\n```javascript\nfunction isAnagram(s, t) {\n  if (s.length !== t.length) return false;\n\n  const map = {};\n\n  for (const ch of s) {\n    map[ch] = (map[ch] || 0) + 1;\n  }\n\n  for (const ch of t) {\n    if (!map[ch]) return false;\n    map[ch]--;\n  }\n\n  return true;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 3: First Non-Repeating Character\n\n### Problem\n\n```javascript\nInput: \"swiss\";\n\nOutput: \"w\";\n```\n\n### Solution\n\n```javascript\nfunction firstUnique(str) {\n  const freq = {};\n\n  for (const ch of str) {\n    freq[ch] = (freq[ch] || 0) + 1;\n  }\n\n  for (const ch of str) {\n    if (freq[ch] === 1) {\n      return ch;\n    }\n  }\n\n  return null;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 4: Move Zeroes\n\n### Problem\n\n```javascript\nInput: [0, 1, 0, 3, 12];\n\nOutput: [1, 3, 12, 0, 0];\n```\n\n### Solution\n\n```javascript\nfunction moveZeroes(nums) {\n  let index = 0;\n\n  for (let i = 0; i < nums.length; i++) {\n    if (nums[i] !== 0) {\n      nums[index++] = nums[i];\n    }\n  }\n\n  while (index < nums.length) {\n    nums[index++] = 0;\n  }\n\n  return nums;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 5: Longest Substring Without Repeating Characters\n\n### Problem\n\n```javascript\nInput: \"abcabcbb\";\n\nOutput: 3;\n```\n\n### Solution\n\n```javascript\nfunction lengthOfLongestSubstring(str) {\n  let left = 0;\n  let max = 0;\n\n  const set = new Set();\n\n  for (let right = 0; right < str.length; right++) {\n    while (set.has(str[right])) {\n      set.delete(str[left]);\n      left++;\n    }\n\n    set.add(str[right]);\n\n    max = Math.max(max, right - left + 1);\n  }\n\n  return max;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 6: Valid Parentheses\n\n### Problem\n\n```javascript\nInput: \"{[()]}\";\n\nOutput: true;\n```\n\n### Solution\n\n```javascript\nfunction isValid(str) {\n  const stack = [];\n\n  const map = {\n    \")\": \"(\",\n    \"]\": \"[\",\n    \"}\": \"{\",\n  };\n\n  for (const ch of str) {\n    if (ch === \"(\" || ch === \"[\" || ch === \"{\") {\n      stack.push(ch);\n    } else {\n      if (stack.pop() !== map[ch]) {\n        return false;\n      }\n    }\n  }\n\n  return stack.length === 0;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 7: Maximum Subarray Sum (Kadane)\n\n### Problem\n\n```javascript\nInput: [-2, 1, -3, 4, -1, 2, 1, -5, 4];\n\nOutput: 6;\n```\n\n### Solution\n\n```javascript\nfunction maxSubArray(nums) {\n  let current = nums[0];\n  let max = nums[0];\n\n  for (let i = 1; i < nums.length; i++) {\n    current = Math.max(nums[i], current + nums[i]);\n\n    max = Math.max(max, current);\n  }\n\n  return max;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 8: Product Of Array Except Self\n\n### Problem\n\n```javascript\nInput: [1, 2, 3, 4];\n\nOutput: [24, 12, 8, 6];\n```\n\n### Solution\n\n```javascript\nfunction productExceptSelf(nums) {\n  const result = new Array(nums.length).fill(1);\n\n  let prefix = 1;\n\n  for (let i = 0; i < nums.length; i++) {\n    result[i] = prefix;\n    prefix *= nums[i];\n  }\n\n  let suffix = 1;\n\n  for (let i = nums.length - 1; i >= 0; i--) {\n    result[i] *= suffix;\n    suffix *= nums[i];\n  }\n\n  return result;\n}\n```\n\nTime: O(n)\n\n---\n\n# Question 9: Group Anagrams\n\n### Problem\n\n```javascript\nInput: [\"eat\", \"tea\", \"tan\", \"ate\", \"nat\", \"bat\"];\n```\n\nOutput\n\n```javascript\n[[\"eat\", \"tea\", \"ate\"], [\"tan\", \"nat\"], [\"bat\"]];\n```\n\n### Solution\n\n```javascript\nfunction groupAnagrams(strs) {\n  const map = {};\n\n  for (const word of strs) {\n    const key = word.split(\"\").sort().join(\"\");\n\n    if (!map[key]) {\n      map[key] = [];\n    }\n\n    map[key].push(word);\n  }\n\n  return Object.values(map);\n}\n```\n\nTime: O(n \\* k log k)\n\n---\n\n# Question 10: Flatten Nested Array\n\n### Problem\n\n```javascript\nInput: [1, [2, [3, [4]], 5]];\n\nOutput: [1, 2, 3, 4, 5];\n```\n\n### Solution\n\n### Recursive\n\n```javascript\nfunction flatten(arr) {\n  let result = [];\n\n  for (const item of arr) {\n    if (Array.isArray(item)) {\n      result.push(...flatten(item));\n    } else {\n      result.push(item);\n    }\n  }\n\n  return result;\n}\n```\n\n### One Line\n\n```javascript\nconst result = arr.flat(Infinity);\n```\n\n---\n\n# IBM Frequently Asked JavaScript Output Questions\n\n### Question\n\n```javascript\nconsole.log([] + []);\n```\n\nOutput\n\n```javascript\n\"\";\n```\n\n---\n\n### Question\n\n```javascript\nconsole.log([] == false);\n```\n\nOutput\n\n```javascript\ntrue;\n```\n\n---\n\n### Question\n\n```javascript\nfor (var i = 0; i < 3; i++) {\n  setTimeout(() => {\n    console.log(i);\n  }, 0);\n}\n```\n\nOutput\n\n```javascript\n3;\n3;\n3;\n```\n\n---\n\n### Question\n\n```javascript\nfor (let i = 0; i < 3; i++) {\n  setTimeout(() => {\n    console.log(i);\n  }, 0);\n}\n```\n\nOutput\n\n```javascript\n0;\n1;\n2;\n```\n\n---\n\nIf you can solve these 10 questions without looking at the answers and explain:\n\n- Time Complexity\n- Space Complexity\n- Why HashMap/Set is used\n- Edge Cases\n\nyou will be well prepared for the typical IBM HackerRank coding round. After you practice these, I can give you a **full 60-minute IBM mock test (2 HackerRank questions + hidden test cases)** exactly like the real assessment.\n","type":"md"},{"name":"P007-IMP-Practice_Questions.md","content":"Absolutely. For a **60-minute TechCorp HackerRank with only 2 coding questions**, I'd memorize these solutions and understand the pattern behind them.\n\n---\n\n# 1. Two Sum ⭐⭐⭐⭐⭐\n\n### Question\n\n```javascript\nnums = [2, 7, 11, 15];\ntarget = 9;\n\nOutput: [0, 1];\n```\n\n### Solution\n\n```javascript\nfunction twoSum(nums, target) {\n  const map = {};\n\n  for (let i = 0; i < nums.length; i++) {\n    const diff = target - nums[i];\n\n    if (map[diff] !== undefined) {\n      return [map[diff], i];\n    }\n\n    map[nums[i]] = i;\n  }\n\n  return [];\n}\n```\n\n### Pattern\n\n```javascript\nHashMap;\n```\n\n### Complexity\n\n```javascript\nTime: O(n);\nSpace: O(n);\n```\n\n---\n\n# 2. Contains Duplicate ⭐⭐⭐⭐⭐\n\n### Question\n\n```javascript\n[1, 2, 3, 1];\n```\n\nOutput\n\n```javascript\ntrue;\n```\n\n### Solution\n\n```javascript\nfunction containsDuplicate(nums) {\n  const set = new Set();\n\n  for (const num of nums) {\n    if (set.has(num)) {\n      return true;\n    }\n\n    set.add(num);\n  }\n\n  return false;\n}\n```\n\n### Complexity\n\n```javascript\nTime: O(n);\nSpace: O(n);\n```\n\n---\n\n# 3. Valid Anagram ⭐⭐⭐⭐⭐\n\n### Question\n\n```javascript\nlisten;\nsilent;\n```\n\nOutput\n\n```javascript\ntrue;\n```\n\n### Solution\n\n```javascript\nfunction isAnagram(s, t) {\n  if (s.length !== t.length) {\n    return false;\n  }\n\n  const map = {};\n\n  for (const ch of s) {\n    map[ch] = (map[ch] || 0) + 1;\n  }\n\n  for (const ch of t) {\n    if (!map[ch]) {\n      return false;\n    }\n\n    map[ch]--;\n  }\n\n  return true;\n}\n```\n\n---\n\n# 4. First Non-Repeating Character ⭐⭐⭐⭐⭐\n\n### Question\n\n```javascript\nswiss;\n```\n\nOutput\n\n```javascript\nw;\n```\n\n### Solution\n\n```javascript\nfunction firstUnique(str) {\n  const freq = {};\n\n  for (const ch of str) {\n    freq[ch] = (freq[ch] || 0) + 1;\n  }\n\n  for (const ch of str) {\n    if (freq[ch] === 1) {\n      return ch;\n    }\n  }\n\n  return null;\n}\n```\n\n---\n\n# 5. Move Zeroes ⭐⭐⭐⭐\n\n### Question\n\n```javascript\n[0, 1, 0, 3, 12];\n```\n\nOutput\n\n```javascript\n[1, 3, 12, 0, 0];\n```\n\n### Solution\n\n```javascript\nfunction moveZeroes(nums) {\n  let index = 0;\n\n  for (let i = 0; i < nums.length; i++) {\n    if (nums[i] !== 0) {\n      nums[index++] = nums[i];\n    }\n  }\n\n  while (index < nums.length) {\n    nums[index++] = 0;\n  }\n\n  return nums;\n}\n```\n\n---\n\n# 6. Longest Substring Without Repeating Characters ⭐⭐⭐⭐⭐\n\n### Question\n\n```javascript\nabcabcbb;\n```\n\nOutput\n\n```javascript\n3;\n```\n\n### Solution\n\n```javascript\nfunction lengthOfLongestSubstring(str) {\n  let left = 0;\n  let max = 0;\n\n  const set = new Set();\n\n  for (let right = 0; right < str.length; right++) {\n    while (set.has(str[right])) {\n      set.delete(str[left]);\n      left++;\n    }\n\n    set.add(str[right]);\n\n    max = Math.max(max, right - left + 1);\n  }\n\n  return max;\n}\n```\n\n### Pattern\n\n```javascript\nSliding Window\n```\n\n---\n\n# 7. Maximum Subarray Sum (Kadane) ⭐⭐⭐⭐\n\n### Question\n\n```javascript\n[-2, 1, -3, 4, -1, 2, 1, -5, 4];\n```\n\nOutput\n\n```javascript\n6;\n```\n\n### Solution\n\n```javascript\nfunction maxSubArray(nums) {\n  let current = nums[0];\n  let max = nums[0];\n\n  for (let i = 1; i < nums.length; i++) {\n    current = Math.max(nums[i], current + nums[i]);\n\n    max = Math.max(max, current);\n  }\n\n  return max;\n}\n```\n\n---\n\n# 8. Valid Parentheses ⭐⭐⭐⭐\n\n### Question\n\n```javascript\n\"{[()]}\";\n```\n\nOutput\n\n```javascript\ntrue;\n```\n\n### Solution\n\n```javascript\nfunction isValid(str) {\n  const stack = [];\n\n  const map = {\n    \")\": \"(\",\n    \"]\": \"[\",\n    \"}\": \"{\",\n  };\n\n  for (const ch of str) {\n    if (ch === \"(\" || ch === \"[\" || ch === \"{\") {\n      stack.push(ch);\n    } else {\n      if (stack.pop() !== map[ch]) {\n        return false;\n      }\n    }\n  }\n\n  return stack.length === 0;\n}\n```\n\n### Pattern\n\n```javascript\nStack;\n```\n\n---\n\n# 9. Product Of Array Except Self ⭐⭐⭐⭐\n\n### Question\n\n```javascript\n[1, 2, 3, 4];\n```\n\nOutput\n\n```javascript\n[24, 12, 8, 6];\n```\n\n### Solution\n\n```javascript\nfunction productExceptSelf(nums) {\n  const result = new Array(nums.length).fill(1);\n\n  let prefix = 1;\n\n  for (let i = 0; i < nums.length; i++) {\n    result[i] = prefix;\n    prefix *= nums[i];\n  }\n\n  let suffix = 1;\n\n  for (let i = nums.length - 1; i >= 0; i--) {\n    result[i] *= suffix;\n    suffix *= nums[i];\n  }\n\n  return result;\n}\n```\n\n---\n\n# 10. Flatten Nested Array ⭐⭐⭐⭐⭐\n\n### Question\n\n```javascript\n[1, [2, [3, [4]], 5]];\n```\n\nOutput\n\n```javascript\n[1, 2, 3, 4, 5];\n```\n\n### Solution 1\n\n```javascript\nfunction flatten(arr) {\n  let result = [];\n\n  for (const item of arr) {\n    if (Array.isArray(item)) {\n      result.push(...flatten(item));\n    } else {\n      result.push(item);\n    }\n  }\n\n  return result;\n}\n```\n\n### Solution 2 (ES6)\n\n```javascript\nconst result = arr.flat(Infinity);\n```\n\n---\n\n# 11. Group Anagrams ⭐⭐⭐\n\n```javascript\nInput: [\"eat\", \"tea\", \"tan\", \"ate\", \"nat\", \"bat\"];\n```\n\nOutput\n\n```javascript\n[[\"eat\", \"tea\", \"ate\"], [\"tan\", \"nat\"], [\"bat\"]];\n```\n\n### Solution\n\n```javascript\nfunction groupAnagrams(words) {\n  const map = {};\n\n  for (const word of words) {\n    const key = word.split(\"\").sort().join(\"\");\n\n    if (!map[key]) {\n      map[key] = [];\n    }\n\n    map[key].push(word);\n  }\n\n  return Object.values(map);\n}\n```\n\n---\n\n# If I Had Only 3 Hours Before IBM Test\n\nPractice in this order:\n\n### Priority 1 (Very High)\n\n1. Two Sum\n2. Valid Anagram\n3. Contains Duplicate\n4. First Non-Repeating Character\n5. Longest Substring Without Repeating Characters\n\n### Priority 2 (High)\n\n6. Move Zeroes\n7. Maximum Subarray Sum\n8. Valid Parentheses\n\n### Priority 3 (Medium)\n\n9. Product Except Self\n10. Flatten Nested Array\n\nIf you can solve the first **8 questions without looking at the answer**, you are in a strong position for a typical TechCorp 2-question HackerRank coding round.\n\nFor a **60-minute TechCorp HackerRank with only 2 coding questions**, I'd say:\n\n### Short Answer\n\n**80-90% yes, but not 100%.**\n\nNobody can guarantee the exact questions, but if you can solve the 10 questions above comfortably, you're covering the most common patterns TechCorp typically uses in \"Standard General Software\" assessments.\n\n---\n\n## What I would add to be safer\n\nPractice these **5 extra questions**:\n\n### 1. Reverse Words in String\n\n```javascript\nInput: \"I Love React Native\";\n\nOutput: \"Native React Love I\";\n```\n\n```javascript\nfunction reverseWords(str) {\n  return str.split(\" \").reverse().join(\" \");\n}\n```\n\n---\n\n### 2. Merge Two Sorted Arrays\n\n```javascript\nInput: [1, 3, 5][(2, 4, 6)];\n\nOutput: [1, 2, 3, 4, 5, 6];\n```\n\n```javascript\nfunction mergeSortedArrays(arr1, arr2) {\n  let i = 0;\n  let j = 0;\n\n  const result = [];\n\n  while (i < arr1.length && j < arr2.length) {\n    if (arr1[i] < arr2[j]) {\n      result.push(arr1[i]);\n      i++;\n    } else {\n      result.push(arr2[j]);\n      j++;\n    }\n  }\n\n  while (i < arr1.length) {\n    result.push(arr1[i]);\n    i++;\n  }\n\n  while (j < arr2.length) {\n    result.push(arr2[j]);\n    j++;\n  }\n\n  return result;\n}\n\nconsole.log(mergeSortedArrays([1, 3, 5], [2, 4, 6]));\n```\n\nPattern:\n\n- Two Pointers\n\n---\n\n### 3. Find Missing Number\n\n```javascript\nInput: [1, 2, 3, 5];\n\nOutput: 4;\n```\n\n```javascript\nfunction missingNumber(arr, n) {\n  const expected = (n * (n + 1)) / 2;\n  const actual = arr.reduce((a, b) => a + b, 0);\n\n  return expected - actual;\n}\n```\n\n---\n\n### 4. Palindrome Check\n\n```javascript\nInput: \"madam\";\n\nOutput: true;\n```\n\n```javascript\nfunction isPalindrome(str) {\n  return str === str.split(\"\").reverse().join(\"\");\n}\n```\n\n---\n\n### 5. Object / Array Transformation\n\nVery common for experienced developers.\n\n```javascript\nconst users = [\n  { id: 1, name: \"Raj\" },\n  { id: 2, name: \"John\" },\n];\n```\n\nConvert to:\n\n```javascript\n{\n 1:{id:1,name:\"Alex\"},\n 2:{id:2,name:\"Sam\"}\n}\n```\n\n```javascript\nfunction convert(users) {\n  return users.reduce((acc, user) => {\n    acc[user.id] = user;\n    return acc;\n  }, {});\n}\n```\n\nFor HackerRank/interviews, they usually want you to **transform the array into an object using `reduce()`**, and then sometimes convert it back to an array.\n\n### Array → Object\n\n```javascript\nfunction convert(users) {\n  return users.reduce((acc, user) => {\n    acc[user.id] = user;\n    return acc;\n  }, {});\n}\n\nconst users = [\n  { id: 1, name: \"Raj\" },\n  { id: 2, name: \"John\" },\n];\n\nconsole.log(convert(users));\n```\n\nOutput:\n\n```javascript\n{\n  1: { id: 1, name: \"Raj\" },\n  2: { id: 2, name: \"John\" }\n}\n```\n\n---\n\n### Object → Array (HackerRank Style)\n\n```javascript\nfunction convertToArray(usersObj) {\n  return Object.values(usersObj);\n}\n\nconst usersObj = {\n  1: { id: 1, name: \"Raj\" },\n  2: { id: 2, name: \"John\" },\n};\n\nconsole.log(convertToArray(usersObj));\n```\n\nOutput:\n\n```javascript\n[\n  { id: 1, name: \"Raj\" },\n  { id: 2, name: \"John\" },\n];\n```\n\n---\n\n### Without `Object.values()` (Interview-Friendly)\n\nSometimes interviewers ask you to do it manually:\n\n```javascript\nfunction convertToArray(usersObj) {\n  const result = [];\n\n  for (const key in usersObj) {\n    result.push(usersObj[key]);\n  }\n\n  return result;\n}\n```\n\n---\n\n### One-Liner Using `reduce()`\n\n```javascript\nfunction convertToArray(usersObj) {\n  return Object.keys(usersObj).reduce((acc, key) => {\n    acc.push(usersObj[key]);\n    return acc;\n  }, []);\n}\n```\n\n---\n\n### What to remember for interviews\n\n| Transformation              | Best Approach     |\n| --------------------------- | ----------------- |\n| Array → Object              | `reduce()`        |\n| Object → Array              | `Object.values()` |\n| Array → Array (modify data) | `map()`           |\n| Array → Single Value        | `reduce()`        |\n| Filter Array                | `filter()`        |\n\nFor React Native/Frontend HackerRank rounds, `map()`, `filter()`, and `reduce()` are among the most frequently tested JavaScript concepts.\n\n---\n\n## If I Were You (React Native, 9 Years Exp)\n\nI would spend my remaining time like this:\n\n### Must Master\n\n✅ Two Sum\n\n✅ Valid Anagram\n\n✅ Contains Duplicate\n\n✅ First Non-Repeating Character\n\n✅ Longest Substring Without Repeating Characters\n\n✅ Move Zeroes\n\n✅ Maximum Subarray Sum\n\n✅ Valid Parentheses\n\n---\n\n### Learn Once\n\n✅ Flatten Nested Array\n\n✅ Product Except Self\n\n✅ Group Anagrams\n\n✅ Missing Number\n\n✅ Reverse Words\n\n---\n\n## What I think IBM is most likely to ask\n\n### Scenario A\n\nQuestion 1:\n\n```text\nArray + HashMap\n(Two Sum / Duplicate / Frequency Count)\n```\n\nQuestion 2:\n\n```text\nSliding Window\n(Longest Substring)\n```\n\n---\n\n### Scenario B\n\nQuestion 1:\n\n```text\nString Manipulation\n(Anagram / Palindrome)\n```\n\nQuestion 2:\n\n```text\nData Transformation\n(Grouping / Flatten Array)\n```\n\n---\n\n### Scenario C\n\nQuestion 1:\n\n```text\nMaximum Subarray\n```\n\nQuestion 2:\n\n```text\nValid Parentheses\n```\n\n---\n\nIf you can solve **all 15 questions (10 + 5 extra)** from scratch in JavaScript and explain the approach, I'd estimate you're prepared for **around 90%+ of the likely IBM HackerRank question patterns** for this assessment format. The remaining risk is an unexpected medium-level problem, but the underlying patterns (HashMap, Set, Sliding Window, Stack, Two Pointers) would still help you solve it.\n\nYou're welcome, Candidate.\n\nFor your specific situation (**TechCorp HackerRank → 2 coding questions → 60 minutes**), my final recommendation is:\n\n### Before the Test\n\nPractice these until you can code them without looking:\n\n1. Two Sum\n2. Contains Duplicate\n3. Valid Anagram\n4. First Non-Repeating Character\n5. Longest Substring Without Repeating Characters\n6. Move Zeroes\n7. Maximum Subarray Sum (Kadane)\n8. Valid Parentheses\n9. Flatten Nested Array\n10. Group Anagrams\n\n### During the Test\n\n**First 5 minutes**\n\n- Read both questions completely.\n- Identify the pattern (HashMap, Set, Sliding Window, Stack, Two Pointers).\n\n**Question 1**\n\n- Target: 10–15 minutes.\n- Don't overthink.\n- Get all test cases passing.\n\n**Question 2**\n\n- Spend remaining time.\n- Write brute force first if stuck.\n- Optimize afterward.\n\n### JavaScript Methods to Remember\n\n```javascript\nmap();\nfilter();\nreduce();\nfind();\nfindIndex();\nsort();\nsplit();\njoin();\nsubstring();\nslice();\nincludes();\nhas();\n```\n\n### Data Structures to Remember\n\n```javascript\nObject {}\nMap\nSet\nArray\nStack (Array)\nQueue (Array)\n```\n\n### If You Get Stuck\n\nAsk yourself:\n\n```text\nCan I use a HashMap?\nCan I use a Set?\nCan I use Sliding Window?\nCan I use Two Pointers?\nCan I use a Stack?\n```\n\nMore than half of HackerRank medium questions can be solved using one of those patterns.\n\n### Confidence Check\n\nIf you can solve these from memory:\n\n- Two Sum\n- Valid Anagram\n- Longest Substring Without Repeating Characters\n- Maximum Subarray Sum\n- Valid Parentheses\n\nthen you're in good shape for this IBM assessment.\n\nBest of luck on the test. Given your **9 years of development experience and 5 years in React Native**, your biggest advantage is problem decomposition and debugging speed—use that during the assessment. 🚀\n\n---\n\nYes, **absolutely possible**, especially because you're applying as a **Senior React Native Developer (9 years)**.\n\nFor experienced frontend/mobile roles, companies sometimes use HackerRank to test **JavaScript fundamentals** rather than pure DSA.\n\n### They can ask:\n\n#### 1. Closures\n\n```javascript\nfunction outer() {\n  let count = 0;\n\n  return function () {\n    count++;\n    return count;\n  };\n}\n\nconst counter = outer();\n\nconsole.log(counter()); // 1\nconsole.log(counter()); // 2\n```\n\nOr:\n\n> Implement a counter using closures.\n\n---\n\n#### 2. Debounce\n\nVery common for React/React Native.\n\n```javascript\nfunction debounce(fn, delay) {\n  let timer;\n\n  return function (...args) {\n    clearTimeout(timer);\n\n    timer = setTimeout(() => {\n      fn.apply(this, args);\n    }, delay);\n  };\n}\n```\n\nPossible question:\n\n> Implement debounce without using lodash.\n\n---\n\n#### 3. Throttle\n\nAlso common.\n\n```javascript\nfunction throttle(fn, delay) {\n  let canRun = true;\n\n  return function (...args) {\n    if (!canRun) return;\n\n    fn.apply(this, args);\n    canRun = false;\n\n    setTimeout(() => {\n      canRun = true;\n    }, delay);\n  };\n}\n```\n\nPossible question:\n\n> Implement throttle for a scroll event.\n\n---\n\n#### 4. Polyfills\n\nVery popular in frontend interviews.\n\nImplement:\n\n```javascript\nArray.prototype.myMap;\nArray.prototype.myFilter;\nArray.prototype.myReduce;\n```\n\nExample:\n\n```javascript\nArray.prototype.myMap = function (cb) {\n  const result = [];\n\n  for (let i = 0; i < this.length; i++) {\n    result.push(cb(this[i], i, this));\n  }\n\n  return result;\n};\n```\n\n---\n\n#### 5. Promise Implementation\n\n```javascript\nPromise.all();\nPromise.allSettled();\nPromise.race();\n```\n\nExample:\nThese are very common React Native / JavaScript interview questions.\n\n---\n\n# 1. Promise.all() ⭐⭐⭐⭐⭐\n\n### What it does\n\n- Runs all promises in parallel.\n- Waits for all to succeed.\n- If **any one fails**, the whole Promise.all fails.\n\n---\n\n### Example\n\n```js\nconst p1 = Promise.resolve(\"API 1\");\nconst p2 = Promise.resolve(\"API 2\");\nconst p3 = Promise.resolve(\"API 3\");\n\nPromise.all([p1, p2, p3])\n  .then((result) => {\n    console.log(result);\n  })\n  .catch((error) => {\n    console.log(error);\n  });\n```\n\nOutput:\n\n```js\n[\"API 1\", \"API 2\", \"API 3\"];\n```\n\n---\n\n### If One Fails\n\n```js\nconst p1 = Promise.resolve(\"API 1\");\nconst p2 = Promise.reject(\"API 2 Failed\");\nconst p3 = Promise.resolve(\"API 3\");\n\nPromise.all([p1, p2, p3])\n  .then((result) => console.log(result))\n  .catch((error) => console.log(error));\n```\n\nOutput:\n\n```js\nAPI 2 Failed\n```\n\n---\n\n### Real React Native Example\n\n```js\nPromise.all([fetch(\"/profile\"), fetch(\"/posts\"), fetch(\"/notifications\")]);\n```\n\nLoad all APIs together before rendering screen.\n\n---\n\n# 2. Promise.allSettled() ⭐⭐⭐⭐⭐\n\n### What it does\n\n- Waits for all promises.\n- Doesn't fail if one fails.\n- Returns success and failure status for every promise.\n\n---\n\n### Example\n\n```js\nconst p1 = Promise.resolve(\"API 1\");\nconst p2 = Promise.reject(\"API 2 Failed\");\nconst p3 = Promise.resolve(\"API 3\");\n\nPromise.allSettled([p1, p2, p3]).then((result) => {\n  console.log(result);\n});\n```\n\nOutput:\n\n```js\n[\n  {\n    status: \"fulfilled\",\n    value: \"API 1\",\n  },\n  {\n    status: \"rejected\",\n    reason: \"API 2 Failed\",\n  },\n  {\n    status: \"fulfilled\",\n    value: \"API 3\",\n  },\n];\n```\n\n---\n\n### Real React Native Example\n\nDashboard screen:\n\n```js\nProfile API\nPosts API\nAds API\n```\n\nEven if Ads API fails:\n\n```js\nProfile ✔\nPosts ✔\nAds ❌\n```\n\nScreen can still render.\n\n---\n\n# 3. Promise.race() ⭐⭐⭐⭐\n\n### What it does\n\nReturns the first promise that settles.\n\n- First success → returns success\n- First failure → returns failure\n\n---\n\n### Example\n\n```js\nconst p1 = new Promise((resolve) => setTimeout(() => resolve(\"API 1\"), 3000));\n\nconst p2 = new Promise((resolve) => setTimeout(() => resolve(\"API 2\"), 1000));\n\nPromise.race([p1, p2]).then((result) => console.log(result));\n```\n\nOutput:\n\n```js\nAPI 2\n```\n\nBecause p2 finished first.\n\n---\n\n### Real Example (Timeout)\n\n```js\nconst apiCall = fetch(\"/users\");\n\nconst timeout = new Promise((_, reject) =>\n  setTimeout(() => reject(\"Request Timeout\"), 5000),\n);\n\nPromise.race([apiCall, timeout])\n  .then((result) => console.log(result))\n  .catch((error) => console.log(error));\n```\n\nIf API takes more than 5 seconds:\n\n```js\nRequest Timeout\n```\n\n---\n\n# Interview Comparison\n\n| Method             | Waits For     | If One Fails                  |\n| ------------------ | ------------- | ----------------------------- |\n| Promise.all        | All promises  | Entire promise fails          |\n| Promise.allSettled | All promises  | Returns status of all         |\n| Promise.race       | First promise | Returns first success/failure |\n\n---\n\n# Frequently Asked Follow-Up\n\n### Run all promises and get results even if one fails?\n\nUse:\n\n```js\nPromise.allSettled();\n```\n\n---\n\n### Run all promises and stop immediately if one fails?\n\nUse:\n\n```js\nPromise.all();\n```\n\n---\n\n### Get fastest response?\n\nUse:\n\n```js\nPromise.race();\n```\n\n---\n\n# Bonus: Promise.any() ⭐⭐⭐⭐\n\nMany interviews now ask this too.\n\n### What it does\n\nReturns the first successful promise.\n\nIgnores failures.\n\n```js\nconst p1 = Promise.reject(\"Error 1\");\nconst p2 = Promise.resolve(\"Success\");\nconst p3 = Promise.resolve(\"Another Success\");\n\nPromise.any([p1, p2, p3]).then((result) => console.log(result));\n```\n\nOutput:\n\n```js\nSuccess;\n```\n\n---\n\n### One-Line Interview Answers\n\n- **Promise.all()** → \"Waits for all promises; fails if any promise fails.\"\n- **Promise.allSettled()** → \"Waits for all promises and returns both successes and failures.\"\n- **Promise.race()** → \"Returns the first promise that settles.\"\n- **Promise.any()** → \"Returns the first promise that fulfills, ignoring failures.\"\n\n---\n\n#### 6. Array/Object Transformation\n\nVery common.\n\n```javascript\nconst users = [\n  { id: 1, name: \"Raj\" },\n  { id: 2, name: \"John\" },\n];\n```\n\nConvert to:\n\n```javascript\n{\n  1:{id:1,name:\"Raj\"},\n  2:{id:2,name:\"John\"}\n}\n```\n\nUsing:\n\n```javascript\nreduce();\n```\n\n---\n\n#### 7. Flatten Nested Array\n\n```javascript\n[1, [2, [3, [4]], 5]];\n```\n\nOutput:\n\n```javascript\n[1, 2, 3, 4, 5];\n```\n\n---\n\n#### 8. Event Loop Output\n\n```javascript\nconsole.log(\"1\");\n\nsetTimeout(() => {\n  console.log(\"2\");\n}, 0);\n\nPromise.resolve().then(() => {\n  console.log(\"3\");\n});\n\nconsole.log(\"4\");\n```\n\nOutput:\n\n```javascript\n1;\n4;\n3;\n2;\n```\n\n---\n\n#### 9. Custom Memoize\n\n```javascript\nfunction memoize(fn) {\n  const cache = {};\n\n  return function (n) {\n    if (cache[n]) return cache[n];\n\n    const result = fn(n);\n    cache[n] = result;\n\n    return result;\n  };\n}\n```\n\n---\n\n### What is MORE likely for IBM HackerRank?\n\nBased on:\n\n- 60 minutes\n- 2 questions\n- \"General Software\" assessment\n- Senior React Native profile\n\nI would estimate:\n\n| Type                | Probability |\n| ------------------- | ----------- |\n| Arrays / Strings    | 40%         |\n| HashMap / Set       | 25%         |\n| Sliding Window      | 10%         |\n| Data Transformation | 10%         |\n| Closures            | 5%          |\n| Debounce / Throttle | 5%          |\n| Promise Polyfill    | 5%          |\n\n### What I would revise in the last few hours\n\n#### DSA\n\n- Two Sum\n- Contains Duplicate\n- Anagram\n- Longest Substring\n- Kadane\n- Valid Parentheses\n\n#### JavaScript\n\n- Closure\n- Debounce\n- Throttle\n- Event Loop\n- Promise.all\n- map/filter/reduce\n- Array flattening\n\n## If IBM decides to make the test more JavaScript-centric because of your React Native background, **Debounce, Throttle, Closure, Promise.all, Array Flattening, and Event Loop** are the highest-value concepts to know. They are much more likely than advanced trees, graphs, or dynamic programming for a frontend/mobile developer assessment.\n\nYes, for a **Senior React Native / Frontend Developer HackerRank round**, I would prioritize these topics over Trees, Graphs, and Advanced DP.\n\n### Tier 1 (Must Know - Highest Probability)\n\n#### Arrays + HashMap\n\n```javascript\nTwo Sum\nContains Duplicate\nFrequency Count\nMajority Element\n```\n\n#### Strings\n\n```javascript\nAnagram\nPalindrome\nReverse Words\nFirst Non-Repeating Character\n```\n\n#### Sliding Window\n\n```javascript\nLongest Substring Without Repeating Characters\nMaximum Sum Subarray\n```\n\n#### JavaScript Core\n\n```javascript\nClosures\nDebounce\nThrottle\nEvent Loop\nPromise.all\nPromise.allSettled\nAsync/Await\n```\n\n#### Data Transformation\n\n```javascript\nmap()\nfilter()\nreduce()\n\nGroup By\nFlatten Array\nObject Transformations\n```\n\n---\n\n### Tier 2 (Good to Know)\n\n#### Stack\n\n```javascript\nValid Parentheses\nMin Stack\n```\n\n#### Two Pointers\n\n```javascript\nMove Zeroes\nMerge Sorted Arrays\n```\n\n#### Recursion\n\n```javascript\nFactorial\nFibonacci\nFlatten Nested Array\n```\n\n---\n\n### Tier 3 (Low Probability for IBM RN Role)\n\n#### Binary Tree\n\n```javascript\nInorder Traversal\nLevel Order Traversal\n```\n\n#### Graph\n\n```javascript\nBFS;\nDFS;\n```\n\n#### Dynamic Programming\n\n```javascript\nClimbing Stairs\nCoin Change\nLongest Increasing Subsequence\n```\n\n---\n\n## If I had ONLY 1 day left\n\nI would make sure I can code these from memory:\n\n### DSA\n\n```javascript\n1. Two Sum\n2. Contains Duplicate\n3. Valid Anagram\n4. First Non-Repeating Character\n5. Longest Substring Without Repeating Characters\n6. Move Zeroes\n7. Maximum Subarray Sum (Kadane)\n8. Valid Parentheses\n9. Flatten Nested Array\n10. Group Anagrams\n```\n\n### JavaScript\n\n```javascript\n11. Closure\n12. Debounce\n13. Throttle\n14. Promise.all\n15. Event Loop Output Questions\n16. map/filter/reduce polyfills\n17. Array flattening\n18. Object grouping using reduce\n```\n\nIf you can confidently solve and explain these **18 topics**, you're covering what I would expect for **90–95% of React Native/Frontend-oriented HackerRank assessments**, including IBM-style screening rounds. The remaining 5–10% is usually a surprise variant of one of these patterns rather than an entirely new advanced topic.\n\nFor your profile, I'd spend **60% of preparation time on DSA patterns** and **40% on JavaScript fundamentals (closures, promises, debounce/throttle, event loop)**. That's the best risk-reward balance.\n\nYes, in real-life applications you often **ignore non-bracket characters** and validate only the brackets.\n\nFor example:\n\n```javascript\n\"{abc(def)[123]}\";\n```\n\nMost parsers would consider this **valid** because the brackets are balanced.\n\nIn that case:\n\n```javascript\nfunction isValid(str) {\n  const stack = [];\n\n  const map = {\n    \")\": \"(\",\n    \"]\": \"[\",\n    \"}\": \"{\",\n  };\n\n  for (const ch of str) {\n    if (ch === \"(\" || ch === \"[\" || ch === \"{\") {\n      stack.push(ch);\n    } else if (ch === \")\" || ch === \"]\" || ch === \"}\") {\n      if (stack.pop() !== map[ch]) {\n        return false;\n      }\n    }\n    // Ignore all other characters\n  }\n\n  return stack.length === 0;\n}\n```\n\n### Examples\n\n```javascript\nisValid(\"{abc(def)[123]}\"); // true\nisValid(\"(hello world)\"); // true\nisValid(\"{abc(]def}\"); // false\nisValid(\"abc\"); // true\n```\n\n### Interview Answer\n\nIf asked:\n\n> What if the string contains other characters?\n\nYou can say:\n\n> It depends on the requirements. If only brackets are allowed, I'd return false for any other character. If the goal is just to validate bracket matching (like parsing expressions or code), I'd ignore non-bracket characters and process only `()[]{}`.\n\nThat answer shows you understand both the algorithm and real-world usage.\n\nFor HackerRank/interviews, they usually want you to transform the array into an object using reduce(), and then sometimes convert it back to an array.\n\nArray → Object\nfunction convert(users) {\nreturn users.reduce((acc, user) => {\nacc[user.id] = user;\nreturn acc;\n}, {});\n}\n\nconst users = [\n{ id: 1, name: \"Raj\" },\n{ id: 2, name: \"John\" },\n];\n\nconsole.log(convert(users));\n\nOutput:\n\n{\n1: { id: 1, name: \"Raj\" },\n2: { id: 2, name: \"John\" }\n}\nObject → Array (HackerRank Style)\nfunction convertToArray(usersObj) {\nreturn Object.values(usersObj);\n}\n\nconst usersObj = {\n1: { id: 1, name: \"Alex\" },\n2: { id: 2, name: \"Sam\" }\n};\n\nconsole.log(convertToArray(usersObj));\n\nOutput:\n\n[\n{ id: 1, name: \"Raj\" },\n{ id: 2, name: \"John\" }\n]\nWithout Object.values() (Interview-Friendly)\n\nSometimes interviewers ask you to do it manually:\n\nfunction convertToArray(usersObj) {\nconst result = [];\n\nfor (const key in usersObj) {\nresult.push(usersObj[key]);\n}\n\nreturn result;\n}\nOne-Liner Using reduce()\nfunction convertToArray(usersObj) {\nreturn Object.keys(usersObj).reduce((acc, key) => {\nacc.push(usersObj[key]);\nreturn acc;\n}, []);\n}\nWhat to remember for interviews\nTransformation Best Approach\nArray → Object reduce()\nObject → Array Object.values()\nArray → Array (modify data) map()\nArray → Single Value reduce()\nFilter Array filter()\n\nFor React Native/Frontend HackerRank rounds, map(), filter(), and reduce() are among the most frequently tested JavaScript concepts.\n","type":"md"},{"name":"P011-ExtraDSA.md","content":"Yes. If you get extra time, these are the **most common interview-style versions** of those topics. But remember: for your TechCorp React Native round, these are **backup topics**, not primary topics.\n\n---\n\n# 1. BFS (Breadth First Search) ⭐⭐\n\n### Question\n\nGiven a graph, print all nodes using BFS.\n\n```js\ngraph = {\n  A: [\"B\", \"C\"],\n  B: [\"D\"],\n  C: [\"E\"],\n  D: [],\n  E: [],\n};\n```\n\nOutput:\n\n```js\nA B C D E\n```\n\n### Pattern\n\n```text\nQueue\n```\n\n### Solution\n\n```js\nfunction bfs(graph, start) {\n  const queue = [start];\n  const visited = new Set();\n\n  visited.add(start);\n\n  while (queue.length) {\n    const node = queue.shift();\n\n    console.log(node);\n\n    for (const neighbor of graph[node]) {\n      if (!visited.has(neighbor)) {\n        visited.add(neighbor);\n        queue.push(neighbor);\n      }\n    }\n  }\n}\n```\n\n---\n\n# 2. DFS (Depth First Search) ⭐⭐\n\n### Question\n\nTraverse graph using DFS.\n\n### Pattern\n\n```text\nRecursion\n```\n\n### Solution\n\n```js\nfunction dfs(graph, node, visited = new Set()) {\n  visited.add(node);\n\n  console.log(node);\n\n  for (const neighbor of graph[node]) {\n    if (!visited.has(neighbor)) {\n      dfs(graph, neighbor, visited);\n    }\n  }\n}\n```\n\n---\n\n# 3. Number Of Islands (Most Common Graph Question) ⭐⭐⭐\n\n### Question\n\n```js\n[\n  [\"1\", \"1\", \"0\"],\n  [\"1\", \"0\", \"0\"],\n  [\"0\", \"1\", \"1\"],\n];\n```\n\nOutput:\n\n```js\n2;\n```\n\n### Pattern\n\n```text\nDFS\n```\n\n### Solution\n\n```js\nfunction numIslands(grid) {\n  let count = 0;\n\n  function dfs(r, c) {\n    if (\n      r < 0 ||\n      c < 0 ||\n      r >= grid.length ||\n      c >= grid[0].length ||\n      grid[r][c] === \"0\"\n    ) {\n      return;\n    }\n\n    grid[r][c] = \"0\";\n\n    dfs(r + 1, c);\n    dfs(r - 1, c);\n    dfs(r, c + 1);\n    dfs(r, c - 1);\n  }\n\n  for (let r = 0; r < grid.length; r++) {\n    for (let c = 0; c < grid[0].length; c++) {\n      if (grid[r][c] === \"1\") {\n        count++;\n        dfs(r, c);\n      }\n    }\n  }\n\n  return count;\n}\n```\n\n---\n\n# 4. Dijkstra ⭐\n\n### Question\n\nFind shortest path from source.\n\n```js\nA -> B = 1\nA -> C = 4\nB -> C = 2\n```\n\nOutput:\n\n```js\nA to C = 3\n```\n\n### Interview Note\n\nFor frontend/mobile interviews, usually only:\n\n```text\nDijkstra = Shortest Path Algorithm\nUses Priority Queue\nTime O(E log V)\n```\n\nis enough.\n\nI would not spend time memorizing the full implementation.\n\n---\n\n# 5. Trie ⭐\n\n### Question\n\nImplement search suggestions.\n\n```js\ninsert(\"apple\");\nsearch(\"apple\");\n```\n\nOutput:\n\n```js\ntrue;\n```\n\n### Basic Structure\n\n```js\nclass TrieNode {\n  constructor() {\n    this.children = {};\n    this.end = false;\n  }\n}\n```\n\n### Interview Note\n\nUsually appears in:\n\n```text\nAutocomplete\nDictionary Search\nPrefix Search\n```\n\nLow probability for RN.\n\n---\n\n# 6. Segment Tree ⭐\n\n### Question\n\nRange Sum Query\n\n```js\nnums = [1, 2, 3, 4];\nsum(1, 3);\n```\n\nOutput:\n\n```js\n9;\n```\n\n### Interview Note\n\nRemember only:\n\n```text\nSegment Tree\nRange Queries\nUpdate + Query in O(log n)\n```\n\nDon't spend time implementing.\n\n---\n\n# 7. Dynamic Programming - Climbing Stairs ⭐⭐\n\n### Question\n\n```js\nn = 5;\n```\n\nOutput:\n\n```js\n8;\n```\n\n### Solution\n\n```js\nfunction climbStairs(n) {\n  if (n <= 2) return n;\n\n  let a = 1;\n  let b = 2;\n\n  for (let i = 3; i <= n; i++) {\n    const temp = a + b;\n\n    a = b;\n    b = temp;\n  }\n\n  return b;\n}\n```\n\nPattern:\n\n```text\nDP\nFibonacci\n```\n\n---\n\n# 8. Floyd Cycle Detection ⭐\n\n### Question\n\nFind duplicate number.\n\n```js\n[1, 3, 4, 2, 2];\n```\n\nOutput:\n\n```js\n2;\n```\n\n### Solution\n\n```js\nfunction findDuplicate(nums) {\n  let slow = nums[0];\n  let fast = nums[0];\n\n  do {\n    slow = nums[slow];\n    fast = nums[nums[fast]];\n  } while (slow !== fast);\n\n  slow = nums[0];\n\n  while (slow !== fast) {\n    slow = nums[slow];\n    fast = nums[fast];\n  }\n\n  return slow;\n}\n```\n\nPattern:\n\n```text\nTortoise and Hare\n```\n\nLow probability.\n\n---\n\n# 9. Custom Promise Implementation ⭐\n\n### Question\n\nImplement a simplified Promise.\n\n### Basic Version\n\n```js\nfunction createPromise() {\n  let callbacks = [];\n\n  return {\n    then(cb) {\n      callbacks.push(cb);\n    },\n\n    resolve(value) {\n      callbacks.forEach((cb) => cb(value));\n    },\n  };\n}\n```\n\nUsage:\n\n```js\nconst p = createPromise();\n\np.then((data) => console.log(data));\n\np.resolve(\"Success\");\n```\n\nOutput:\n\n```js\nSuccess;\n```\n\n---\n\n# If I Were Prioritizing\n\n### Study First (Already In Your Document)\n\n```text\nTwo Sum\nContains Duplicate\nValid Anagram\nLongest Substring\nMove Zeroes\nMaximum Subarray\nValid Parentheses\nProduct Except Self\nMerge Sorted Arrays\nFlatten Array\nGroup Anagrams\nClosure\nDebounce\nThrottle\nPromises\nEvent Loop\n```\n\n### Only If Extra Time\n\n```text\nNumber Of Islands\nBFS\nDFS\nClimbing Stairs\n```\n\n### Last Priority\n\n```text\nDijkstra\nTrie\nSegment Tree\nFloyd Cycle\nCustom Promise\n```\n\nFor your TechCorp Senior React Native assessment, I'd estimate the probability of seeing one of the \"last priority\" topics is under 10%, while the topics already in your document account for the vast majority of likely coding questions.\n","type":"md"},{"name":"P009-gemini-20.md","content":"Here is the complete, consolidated list of all 20 HackerRank-ready solutions. They are formatted exactly how the HackerRank compiler expects them—as clean, optimized, self-contained pure functions with zero external dependencies.\n\n---\n\n## Section 1: Core Logic & Array Manipulation (DSA)\n\n### Q1: Two-Sum Target Match ($O(N)$ Optimization)\n\n```typescript\nexport function twoSum(numbers: number[], targetSum: number): number[] {\n  // Key: the number we need to find, Value: the index of the current number\n  const complementMap = new Map<number, number>();\n\n  for (let i = 0; i < numbers.length; i++) {\n    const currentNum = numbers[i];\n    const requiredComplement = targetSum - currentNum;\n\n    // If we've already seen the required complement, return its index and current index\n    if (complementMap.has(requiredComplement)) {\n      return [complementMap.get(requiredComplement)!, i];\n    }\n\n    // Otherwise, save the current number and its index to the map\n    complementMap.set(currentNum, i);\n  }\n\n  return []; // Return empty array if no match is found\n}\n```\n\n### Q2: Valid Parentheses / Token Balancer\n\n```javascript\nfunction isValidConfigTokens(s) {\n  if (!s || s.length === 0) return true;\n  if (s.length % 2 !== 0) return false;\n\n  const stack = [];\n  const bracketMap = {\n    \")\": \"(\",\n    \"]\": \"[\",\n    \"}\": \"{\",\n  };\n\n  for (let i = 0; i < s.length; i++) {\n    const char = s.charAt(i);\n\n    if (bracketMap[char]) {\n      const topElement = stack.length > 0 ? stack.pop() : \"#\";\n      if (bracketMap[char] !== topElement) {\n        return false;\n      }\n    } else {\n      stack.push(char);\n    }\n  }\n\n  return stack.length === 0;\n}\n```\n\n### Q3: Longest Substring Without Repeating Characters (Sliding Window)\n\n```javascript\nfunction longestUniqueSubstringLength(s) {\n  if (!s || s.length === 0) return 0;\n\n  let maxLength = 0;\n  let leftPointer = 0;\n  const seenCharsMap = new Map();\n\n  for (let rightPointer = 0; rightPointer < s.length; rightPointer++) {\n    const currentChar = s.charAt(rightPointer);\n\n    if (\n      seenCharsMap.has(currentChar) &&\n      seenCharsMap.get(currentChar) >= leftPointer\n    ) {\n      leftPointer = seenCharsMap.get(currentChar) + 1;\n    }\n\n    seenCharsMap.set(currentChar, rightPointer);\n    maxLength = Math.max(maxLength, rightPointer - leftPointer + 1);\n  }\n\n  return maxLength;\n}\n```\n\n### Q4: Merge Overlapping Intervals\n\n```typescript\nexport function mergeIntervals(intervals: number[][]): number[][] {\n  if (intervals.length <= 1) return intervals;\n\n  // Sort intervals based on their start values\n  intervals.sort((a, b) => a[0] - b[0]);\n\n  const merged: number[][] = [];\n  let currentInterval = intervals[0];\n  merged.push(currentInterval);\n\n  for (let i = 1; i < intervals.length; i++) {\n    const nextInterval = intervals[i];\n    const currentEnd = currentInterval[1];\n    const nextStart = nextInterval[0];\n    const nextEnd = nextInterval[1];\n\n    if (currentEnd >= nextStart) {\n      currentInterval[1] = Math.max(currentEnd, nextEnd);\n    } else {\n      currentInterval = nextInterval;\n      merged.push(currentInterval);\n    }\n  }\n\n  return merged;\n}\n```\n\n### Q5: Find the Single Duplicate Element ($O(N)$ Time, $O(1)$ Space)\n\n```javascript\nfunction findDuplicate(nums) {\n  if (nums.length <= 1) return -1;\n\n  let tortoise = nums[0];\n  let hare = nums[0];\n\n  // Phase 1: Locate cycle intersection point\n  do {\n    tortoise = nums[tortoise];\n    hare = nums[nums[hare]];\n  } while (tortoise !== hare);\n\n  // Phase 2: Find the entrance point to the cycle (the duplicate)\n  tortoise = nums[0];\n  while (tortoise !== hare) {\n    tortoise = nums[tortoise];\n    hare = nums[hare];\n  }\n\n  return tortoise;\n}\n```\n\n### Q6: Deep Flatten an Array (Recursive Approach)\n\n```javascript\nfunction deepFlatten(nestedArray) {\n  let result = [];\n\n  for (let i = 0; i < nestedArray.length; i++) {\n    if (Array.isArray(nestedArray[i])) {\n      result = result.concat(deepFlatten(nestedArray[i]));\n    } else {\n      result.push(nestedArray[i]);\n    }\n  }\n\n  return result;\n}\n```\n\n### Q7: Group Object Arrays by Key (Data Transformation)\n\n```javascript\nfunction groupLogsByPlatform(logs) {\n  if (!Array.isArray(logs)) return {};\n\n  return logs.reduce((grouped, log) => {\n    const platform = log?.platform || \"Unknown\";\n\n    if (!grouped[platform]) {\n      grouped[platform] = [];\n    }\n\n    grouped[platform].push(log);\n    return grouped;\n  }, {});\n}\n```\n\n### Q8: Object Property Diff Analyzer\n\n```typescript\nexport function getObjectDiff(\n  objA: Record<string, any>,\n  objB: Record<string, any>,\n): string[] {\n  const divergingKeys = new Set<string>();\n  const collectiveKeys = [...Object.keys(objA), ...Object.keys(objB)];\n\n  for (const key of collectiveKeys) {\n    if (objA[key] !== objB[key]) {\n      divergingKeys.add(key);\n    }\n  }\n\n  return Array.from(divergingKeys).sort();\n}\n```\n\n### Q9: Version Control String Comparator\n\n```typescript\nexport function compareVersions(versionA: string, versionB: string): number {\n  const segmentsA = versionA.split(\".\").map(Number);\n  const segmentsB = versionB.split(\".\").map(Number);\n  const maxLength = Math.max(segmentsA.length, segmentsB.length);\n\n  for (let i = 0; i < maxLength; i++) {\n    const numA = segmentsA[i] || 0;\n    const numB = segmentsB[i] || 0;\n\n    if (numA > numB) return 1;\n    if (numB > numA) return -1;\n  }\n\n  return 0;\n}\n```\n\n### Q10: String Subsequence Checker\n\n```javascript\nfunction isSubsequence(t, s) {\n  let tIndex = 0;\n  let sIndex = 0;\n\n  while (tIndex < t.length && sIndex < s.length) {\n    if (t.charAt(tIndex) === s.charAt(sIndex)) {\n      tIndex++;\n    }\n    sIndex++;\n  }\n\n  return tIndex === t.length;\n}\n```\n\n---\n\n## Section 2: Asynchronous Operations & REST APIs\n\n### Q11: Paginated Transaction Amount Aggregator\n\n```javascript\nconst fetch = require(\"node-fetch\");\n\nasync function getDebitAmountSum(targetUserId) {\n  let currentPage = 1;\n  let totalPages = 1;\n  let runningDebitSum = 0;\n\n  try {\n    while (currentPage <= totalPages) {\n      const endpointUrl = `https://jsonmock.hackerrank.com/api/transactions?page=${currentPage}`;\n      const apiResponse = await fetch(endpointUrl);\n      if (!apiResponse.ok) break;\n\n      const payload = await apiResponse.json();\n\n      if (currentPage === 1) {\n        totalPages = payload.total_pages || 1;\n      }\n\n      const transactionsList = payload.data || [];\n\n      for (const item of transactionsList) {\n        if (\n          String(item.userId) === String(targetUserId) &&\n          item.txnType === \"debit\"\n        ) {\n          let numericAmount = 0;\n          if (typeof item.amount === \"string\") {\n            numericAmount = parseFloat(item.amount.replace(/[^0-9.]/g, \"\"));\n          } else if (typeof item.amount === \"number\") {\n            numericAmount = item.amount;\n          }\n          runningDebitSum += numericAmount || 0;\n        }\n      }\n      currentPage++;\n    }\n  } catch (err) {\n    return 0;\n  }\n\n  return Math.round(runningDebitSum);\n}\n```\n\n### Q12: User Post Count Filter\n\n```javascript\nconst fetch = require(\"node-fetch\");\n\nasync function countHighSubmissionUsers(threshold) {\n  let page = 1;\n  let totalPages = 1;\n  let totalUsersCount = 0;\n\n  try {\n    while (page <= totalPages) {\n      const res = await fetch(\n        `https://jsonmock.hackerrank.com/api/users?page=${page}`,\n      );\n      if (!res.ok) break;\n\n      const parsedPayload = await res.json();\n\n      if (page === 1) {\n        totalPages = parsedPayload.total_pages || 1;\n      }\n\n      const dataArray = parsedPayload.data || [];\n\n      for (const user of dataArray) {\n        if (user && user.submission_count !== undefined) {\n          const submissionValue =\n            typeof user.submission_count === \"string\"\n              ? parseInt(user.submission_count, 10)\n              : user.submission_count;\n\n          if (submissionValue > threshold) {\n            totalUsersCount++;\n          }\n        }\n      }\n      page++;\n    }\n  } catch (e) {\n    return 0;\n  }\n\n  return totalUsersCount;\n}\n```\n\n### Q13: High-Rated Movie Filter\n\n```javascript\nconst fetch = require(\"node-fetch\");\n\nasync function getFilteredMovieTitles(titleQuery) {\n  let page = 1;\n  let totalPages = 1;\n  const filteredTitles = [];\n\n  try {\n    while (page <= totalPages) {\n      const response = await fetch(\n        `https://jsonmock.hackerrank.com/api/movies/search/?Title=${titleQuery}&page=${page}`,\n      );\n      if (!response.ok) break;\n\n      const payload = await response.json();\n\n      if (page === 1) {\n        totalPages = payload.total_pages || 1;\n      }\n\n      const movies = payload.data || [];\n\n      for (const movie of movies) {\n        if (movie && movie.year >= 2000) {\n          filteredTitles.push(movie.title);\n        }\n      }\n      page++;\n    }\n  } catch (error) {\n    return [];\n  }\n\n  return filteredTitles.sort();\n}\n```\n\n### Q14: Concurrent Request Coordinator (`Promise.allSettled`)\n\n```typescript\nasync function fetchDashboardPayloads(urls: string[]): Promise<any[]> {\n  try {\n    const fetchPromises = urls.map((url) =>\n      fetch(url).then((res) => {\n        if (!res.ok) throw new Error(\"HTTP_FAIL\");\n        return res.json();\n      }),\n    );\n\n    const settlementStatuses = await Promise.allSettled(fetchPromises);\n    const resolvedData: any[] = [];\n\n    for (const item of settlementStatuses) {\n      if (item.status === \"fulfilled\") {\n        resolvedData.push(item.value);\n      }\n    }\n\n    return resolvedData;\n  } catch (err) {\n    return [];\n  }\n}\n```\n\n### Q15: Async Network Retry Wrapper\n\n```typescript\nasync function fetchWithRetries(\n  url: string,\n  maxRetries: number = 3,\n): Promise<any> {\n  let attemptsLeft = maxRetries;\n\n  while (attemptsLeft > 0) {\n    try {\n      const response = await fetch(url);\n      if (!response.ok) throw new Error(`HTTP ${response.status}`);\n      return await response.json();\n    } catch (error) {\n      attemptsLeft--;\n      if (attemptsLeft === 0) {\n        throw new Error(`Failed after ${maxRetries} attempts: ${error}`);\n      }\n    }\n  }\n}\n```\n\n### Q16: API Race with Execution Timeout\n\n```javascript\nasync function fetchWithTimeout(url, maxWaitTimeMs = 3000) {\n  const timeoutAnchor = new Promise((_, reject) => {\n    setTimeout(() => reject(new Error(\"NETWORK_TIMEOUT\")), maxWaitTimeMs);\n  });\n\n  try {\n    const finalResolvedResult = await Promise.race([fetch(url), timeoutAnchor]);\n\n    if (!finalResolvedResult.ok) throw new Error(\"BAD_SERVER_RESPONSE\");\n    return await finalResolvedResult.json();\n  } catch (error) {\n    throw error;\n  }\n}\n```\n\n### Q17: Batch Chunk Processing (Network Throttling Strategy)\n\n```typescript\ntype AsyncTaskGenerator = () => Promise<any>;\n\nasync function processTasksInChunks(\n  tasks: AsyncTaskGenerator[],\n  chunkSize: number,\n): Promise<any[]> {\n  const results: any[] = [];\n\n  for (let i = 0; i < tasks.length; i += chunkSize) {\n    const chunk = tasks.slice(i, i + chunkSize);\n    const chunkPromises = chunk.map((taskTrigger) => taskTrigger());\n    const chunkResults = await Promise.all(chunkPromises);\n\n    results.push(...chunkResults);\n  }\n\n  return results;\n}\n```\n\n### Q18: Custom Promise/Deferred Micro-Framework\n\n```javascript\nfunction createCustomDeferred() {\n  let status = \"PENDING\";\n  let value = undefined;\n  const successCallbacks = [];\n  const failureCallbacks = [];\n\n  return {\n    resolve: (result) => {\n      if (status !== \"PENDING\") return;\n      status = \"RESOLVED\";\n      value = result;\n      successCallbacks.forEach((callback) => callback(value));\n    },\n    reject: (error) => {\n      if (status !== \"PENDING\") return;\n      status = \"REJECTED\";\n      value = error;\n      failureCallbacks.forEach((callback) => callback(value));\n    },\n    then: (onSuccess, onFailure) => {\n      if (status === \"RESOLVED\" && onSuccess) onSuccess(value);\n      if (status === \"REJECTED\" && onFailure) onFailure(value);\n\n      if (status === \"PENDING\") {\n        if (onSuccess) successCallbacks.push(onSuccess);\n        if (onFailure) failureCallbacks.push(onFailure);\n      }\n    },\n  };\n}\n```\n\n### Q19: Cache-Control Interceptor Layer\n\n```javascript\nconst memoryCacheMap = new Map();\n\nasync function fetchCachedDataWithTTL(url, timeToLiveMs = 60000) {\n  const currentTime = Date.now();\n\n  if (memoryCacheMap.has(url)) {\n    const cachedItem = memoryCacheMap.get(url);\n    if (currentTime - cachedItem.timestamp < timeToLiveMs) {\n      return cachedItem.data;\n    }\n  }\n\n  const response = await fetch(url);\n  if (!response.ok) throw new Error(\"FETCH_FAILED\");\n\n  const operationalData = await response.json();\n\n  memoryCacheMap.set(url, {\n    timestamp: currentTime,\n    data: operationalData,\n  });\n\n  return operationalData;\n}\n```\n\n### Q20: Async Input Stream Tokenizer (Sequential Promise Pipelines)\n\n```javascript\nasync function executePromisePipeline(initialInputValue, pipelineFunctions) {\n  let trackingValue = initialInputValue;\n\n  for (const asyncFunc of pipelineFunctions) {\n    if (typeof asyncFunc === \"function\") {\n      trackingValue = await asyncFunc(trackingValue);\n    }\n  }\n\n  return trackingValue;\n}\n```\n","type":"md"},{"name":"P008.md","content":"Since this 60-minute assessment is the absolute final hurdle standing between you and the offer, IBM will use these two distinct coding slots to evaluate both your baseline problem-solving efficiency and your real-world asynchronous API mastery.\n\nBecause you are targeting a React Native space with JavaScript/TypeScript, they want to ensure you don’t write code that freezes mobile UI threads or handles API payloads incorrectly.\n\nHere is a highly targeted, realistic set of interview questions modeled exactly after what IBM looks for in these two specific HackerRank slots.\n\n---\n\n## Coding (Standard) 1: Core JS/TS Data Structures & Logic\n\n_This section tests clean data parsing, optimization, and edge-case validation. Expect variations of array manipulation and lookups._\n\n### 1. The Mobile Device Token Deduplicator\n\n**The Problem:** Your React Native app collects push notification tokens from different active sessions. Due to network retries, the payload contains duplicate, outdated, or corrupted values (`null` or `undefined`).\n\nWrite a function `cleanTokens(sessions)` that takes an array of session objects, extracts all valid string tokens, removes duplicates, and returns them sorted alphabetically.\n\n#### The JavaScript / TypeScript Solution:\n\n```typescript\ninterface Session {\n  sessionId: string;\n  token?: string | null;\n  meta?: { isActive: boolean };\n}\n\nexport function cleanTokens(sessions: Session[]): string[] {\n  if (!sessions || !Array.isArray(sessions)) return [];\n\n  const uniqueTokens = new Set<string>();\n\n  for (const session of sessions) {\n    // Safe check for null, undefined, empty strings, and session state\n    if (\n      session &&\n      typeof session.token === \"string\" &&\n      session.token.trim().length > 0\n    ) {\n      if (session.meta?.isActive !== false) {\n        uniqueTokens.add(session.token.trim());\n      }\n    }\n  }\n\n  // Convert Set back to array and sort alphabetically\n  return Array.from(uniqueTokens).sort();\n}\n```\n\n- **Why TechCorp asks this:** Mobile apps frequently deal with cleaning up dirty payload data before storing it locally or sending it to registration servers.\n\n---\n\n### 2. State Diff Tracker (Object Comparison)\n\n**The Problem:** To prevent unnecessary re-rendering of a heavy React Native component list, you need to track exactly which values changed between the `previousState` object and the `currentState` object.\n\nWrite a function `getChangedKeys(previousState, currentState)` that returns an array of keys whose values are different. Assume a flat object structure (key-value pairs of strings or numbers).\n\n#### The JavaScript / TypeScript Solution:\n\n```javascript\nfunction getChangedKeys(previousState, currentState) {\n  if (!previousState || !currentState) return [];\n\n  const changedKeys = [];\n\n  // Combine all unique keys from both states to ensure we catch additions/deletions\n  const allKeys = new Set([\n    ...Object.keys(previousState),\n    ...Object.keys(currentState),\n  ]);\n\n  for (const key of allKeys) {\n    if (previousState[key] !== currentState[key]) {\n      changedKeys.push(key);\n    }\n  }\n\n  return changedKeys.sort();\n}\n```\n\n- **Why TechCorp asks this:** Emulates deep lifecycle tuning and virtualized list optimizations inside complex React Native ecosystems.\n\n---\n\n## Coding (Standard) 2: Asynchronous API Processing & Aggregation\n\n_This section requires querying a live paginated endpoint (usually `https://jsonmock.hackerrank.com`) using `async/await`. You must parse multiple pages and aggregate numerical data._\n\n### 3. Paginated API Filtering (The \"Classic\" HackerRank)\n\n**The Problem:** Fetch transaction details from the paginated endpoint: `https://jsonmock.hackerrank.com/api/transactions?page=X`.\n\nCalculate the total transaction amount spent across **all pages** by a specific user (`userId`) where the transaction status is `\"success\"`.\n\n#### The JavaScript / Node.js Solution:\n\n```javascript\n// Note: HackerRank provides 'node-fetch' natively in its execution context\nconst fetch = require(\"node-fetch\");\n\nasync function getTotalUserSpent(targetUserId) {\n  let currentPage = 1;\n  let totalPages = 1;\n  let totalSpent = 0;\n\n  try {\n    while (currentPage <= totalPages) {\n      const url = `https://jsonmock.hackerrank.com/api/transactions?page=${currentPage}`;\n      const response = await fetch(url);\n\n      if (!response.ok) break; // Gracefully exit if an API page errors out\n\n      const jsonPayload = await response.json();\n\n      // Dynamically lock down total pages from the initial payload metadata\n      if (currentPage === 1) {\n        totalPages = jsonPayload.total_pages || 1;\n      }\n\n      const transactions = jsonPayload.data || [];\n\n      for (const item of transactions) {\n        // Ensure type safety since IDs can arrive as strings or numbers from mock databases\n        if (\n          String(item.userId) === String(targetUserId) &&\n          item.status === \"success\"\n        ) {\n          // Extract numerical value, stripping out currency formatting symbols like '$' or ',' if present\n          const sanitizedAmount =\n            typeof item.amount === \"string\"\n              ? parseFloat(item.amount.replace(/[^0-9.]/g, \"\"))\n              : item.amount;\n\n          totalSpent += sanitizedAmount || 0;\n        }\n      }\n\n      currentPage++;\n    }\n  } catch (error) {\n    // Return 0 instead of crashing the assessment execution path completely\n    return 0;\n  }\n\n  return Math.round(totalSpent);\n}\n```\n\n- **Why TechCorp asks this:** This is the most standardized real-world setup HackerRank uses. It assesses how cleanly you handle Promises, API boundaries, and unexpected string-to-number mutations.\n\n---\n\n### 4. API Request Race with Timeout Fallback\n\n**The Problem:** Mobile devices face unstable internet connectivity. Write an async helper function `fetchWithTimeout(url, timeoutMs)` that races a standard HTTP `fetch` call against a timeout promise. If the endpoint doesn't respond within `timeoutMs`, the function should reject with a custom message `\"REQUEST_TIMEOUT\"`.\n\n#### The JavaScript Solution:\n\n```javascript\nasync function fetchWithTimeout(url, timeoutMs = 5000) {\n  // 1. Create the timeout anchor\n  const timeoutTrigger = new Promise((_, reject) => {\n    setTimeout(() => reject(new Error(\"REQUEST_TIMEOUT\")), timeoutMs);\n  });\n\n  // 2. Race the network fetch execution block against the timer anchor\n  try {\n    const networkResponse = await Promise.race([fetch(url), timeoutTrigger]);\n\n    if (!networkResponse.ok) throw new Error(\"FETCH_ERROR\");\n    return await networkResponse.json();\n  } catch (error) {\n    // Bubble up error to be intercepted by parent component boundary wrappers\n    throw error;\n  }\n}\n```\n\n---\n\n## 🎯 Final Mental Checklists Prior to Hitting \"Start\"\n\n1. **Beware of Hidden Null Values:** In JavaScript HackerRank paths, hidden test cases explicitly drop keys out of object items (e.g., a transaction object without an `amount` property). Always guard data entry chains with optional chaining (`item?.meta?.value`) or logical fallbacks (`|| 0`).\n2. **Read the Environment's Node Version:** If you prefer TypeScript, verify the language dropdown selector is toggled to **TypeScript** instead of legacy **JavaScript (Node.js)** before writing types.\n3. **Print Statements are Your Friend:** If your logic gets stuck, drop `console.log()` lines across code checkpoints. The log output will display clearly beneath the test case execution dashboard.\n","type":"md"},{"name":"P003-Flatlist-sample.js","content":"import React, { memo, useCallback, useEffect, useMemo, useState } from \"react\";\n\nimport {\n  FlatList,\n  ScrollView,\n  StyleSheet,\n  Text,\n  TextInput,\n  TouchableOpacity,\n  View,\n} from \"react-native\";\n\n/**\n * =====================================================\n * CONSTANTS\n * =====================================================\n */\n\nconst ITEM_HEIGHT = 110;\n\nconst CATEGORIES = [\"Electronics\", \"Fashion\", \"Home\", \"Sports\", \"Books\"];\n\nconst SORT_OPTIONS = [\n  {\n    label: \"Default\",\n    value: \"DEFAULT\",\n  },\n  {\n    label: \"Name A-Z\",\n    value: \"NAME_ASC\",\n  },\n  {\n    label: \"Name Z-A\",\n    value: \"NAME_DESC\",\n  },\n  {\n    label: \"Category A-Z\",\n    value: \"CATEGORY_ASC\",\n  },\n  {\n    label: \"Category Z-A\",\n    value: \"CATEGORY_DESC\",\n  },\n];\n\n/**\n * =====================================================\n * MOCK DATA\n * =====================================================\n */\n\nconst PRODUCTS = Array.from({ length: 50000 }, (_, index) => ({\n  id: String(index + 1),\n  name: `Product ${index + 1}`,\n  category: CATEGORIES[index % CATEGORIES.length],\n}));\n\n/**\n * =====================================================\n * PRODUCT MAP\n * Faster selected lookup\n * =====================================================\n */\n\nconst PRODUCT_MAP = PRODUCTS.reduce((acc, item) => {\n  acc[item.id] = item;\n  return acc;\n}, {});\n\n/**\n * =====================================================\n * PRECOMPUTED SORTS\n * Avoid re-sorting 50k items repeatedly\n * =====================================================\n */\n\nconst SORTED_PRODUCTS = {\n  DEFAULT: PRODUCTS,\n\n  NAME_ASC: [...PRODUCTS].sort((a, b) => a.name.localeCompare(b.name)),\n\n  NAME_DESC: [...PRODUCTS].sort((a, b) => b.name.localeCompare(a.name)),\n\n  CATEGORY_ASC: [...PRODUCTS].sort((a, b) =>\n    a.category.localeCompare(b.category),\n  ),\n\n  CATEGORY_DESC: [...PRODUCTS].sort((a, b) =>\n    b.category.localeCompare(a.category),\n  ),\n};\n\n/**\n * =====================================================\n * DEBOUNCE HOOK\n * =====================================================\n */\n\nconst useDebounce = (value, delay) => {\n  const [debouncedValue, setDebouncedValue] = useState(value);\n\n  useEffect(() => {\n    const timer = setTimeout(() => {\n      setDebouncedValue(value);\n    }, delay);\n\n    return () => {\n      clearTimeout(timer);\n    };\n  }, [value, delay]);\n\n  return debouncedValue;\n};\n\n/**\n * =====================================================\n * PRODUCT CARD\n * =====================================================\n */\n\nconst ProductItem = memo(\n  ({ item, isSelected, onToggle }) => {\n    const handlePress = useCallback(() => {\n      onToggle(item.id);\n    }, [item.id, onToggle]);\n\n    return (\n      <TouchableOpacity\n        activeOpacity={0.9}\n        onPress={handlePress}\n        style={[styles.productCard, isSelected && styles.selectedProductCard]}\n      >\n        <View style={styles.cardTopRow}>\n          <View style={styles.cardContent}>\n            <Text style={styles.productName}>{item.name}</Text>\n\n            <View style={styles.categoryBadge}>\n              <Text style={styles.categoryText}>{item.category}</Text>\n            </View>\n          </View>\n\n          {isSelected && (\n            <View style={styles.checkContainer}>\n              <Text style={styles.checkText}>✓</Text>\n            </View>\n          )}\n        </View>\n      </TouchableOpacity>\n    );\n  },\n\n  /**\n   * Prevent unnecessary rerenders\n   */\n  (prev, next) => {\n    return prev.isSelected === next.isSelected && prev.item.id === next.item.id;\n  },\n);\n\nProductItem.displayName = \"ProductItem\";\n\n/**\n * =====================================================\n * MAIN SCREEN\n * =====================================================\n */\n\nconst ProductSelectionScreen = () => {\n  /**\n   * =====================================================\n   * STATE\n   * =====================================================\n   */\n\n  const [search, setSearch] = useState(\"\");\n\n  const debouncedSearch = useDebounce(search, 400);\n\n  const [sortType, setSortType] = useState(\"DEFAULT\");\n\n  const [selectedIds, setSelectedIds] = useState(new Set());\n\n  /**\n   * =====================================================\n   * TOGGLE SELECTION\n   * =====================================================\n   */\n\n  const toggleSelection = useCallback((id) => {\n    setSelectedIds((prev) => {\n      const updated = new Set(prev);\n\n      if (updated.has(id)) {\n        updated.delete(id);\n      } else {\n        updated.add(id);\n      }\n\n      return updated;\n    });\n  }, []);\n\n  /**\n   * =====================================================\n   * CLEAR SELECTIONS\n   * =====================================================\n   */\n\n  const clearSelections = useCallback(() => {\n    setSelectedIds(new Set());\n  }, []);\n\n  /**\n   * =====================================================\n   * SORTED PRODUCTS\n   * =====================================================\n   */\n\n  const sortedProducts = useMemo(() => {\n    return SORTED_PRODUCTS[sortType];\n  }, [sortType]);\n\n  /**\n   * =====================================================\n   * FILTERED PRODUCTS\n   * =====================================================\n   */\n\n  const filteredProducts = useMemo(() => {\n    const value = debouncedSearch.trim().toLowerCase();\n\n    if (!value) {\n      return sortedProducts;\n    }\n\n    return sortedProducts.filter(\n      (product) =>\n        product.name.toLowerCase().includes(value) ||\n        product.category.toLowerCase().includes(value),\n    );\n  }, [debouncedSearch, sortedProducts]);\n\n  /**\n   * =====================================================\n   * SELECTED PRODUCTS\n   * =====================================================\n   */\n\n  const selectedProducts = useMemo(() => {\n    return Array.from(selectedIds).map((id) => PRODUCT_MAP[id]);\n  }, [selectedIds]);\n\n  /**\n   * =====================================================\n   * GET ITEM LAYOUT\n   * =====================================================\n   */\n\n  const getItemLayout = useCallback(\n    (_, index) => ({\n      length: ITEM_HEIGHT,\n      offset: ITEM_HEIGHT * index,\n      index,\n    }),\n    [],\n  );\n\n  /**\n   * =====================================================\n   * KEY EXTRACTOR\n   * =====================================================\n   */\n\n  const keyExtractor = useCallback((item) => item.id, []);\n\n  /**\n   * =====================================================\n   * RENDER ITEM\n   * =====================================================\n   */\n\n  const renderItem = useCallback(\n    ({ item }) => {\n      return (\n        <ProductItem\n          item={item}\n          isSelected={selectedIds.has(item.id)}\n          onToggle={toggleSelection}\n        />\n      );\n    },\n    [selectedIds, toggleSelection],\n  );\n\n  /**\n   * =====================================================\n   * HEADER\n   * =====================================================\n   */\n\n  const renderHeader = useMemo(() => {\n    return (\n      <>\n        {/* Header */}\n        <View style={styles.headerContainer}>\n          <Text style={styles.headerTitle}>Products</Text>\n\n          <Text style={styles.headerSubtitle}>{selectedIds.size} selected</Text>\n        </View>\n\n        {/* Search */}\n        <View style={styles.searchContainer}>\n          <Text style={styles.searchIcon}>🔍</Text>\n\n          <TextInput\n            placeholder=\"Search products\"\n            placeholderTextColor=\"#999\"\n            value={search}\n            onChangeText={setSearch}\n            style={styles.searchInput}\n            autoCorrect={false}\n            autoCapitalize=\"none\"\n          />\n        </View>\n\n        {/* Sort */}\n        <ScrollView\n          horizontal\n          showsHorizontalScrollIndicator={false}\n          contentContainerStyle={styles.filterContainer}\n        >\n          {SORT_OPTIONS.map((option) => {\n            const active = option.value === sortType;\n\n            return (\n              <TouchableOpacity\n                key={option.value}\n                activeOpacity={0.8}\n                onPress={() => setSortType(option.value)}\n                style={[styles.filterChip, active && styles.activeFilterChip]}\n              >\n                <Text\n                  style={[styles.filterText, active && styles.activeFilterText]}\n                >\n                  {option.label}\n                </Text>\n              </TouchableOpacity>\n            );\n          })}\n        </ScrollView>\n\n        {/* Selected Items */}\n        {selectedProducts.length > 0 && (\n          <View style={styles.selectedSection}>\n            <View style={styles.selectedTopRow}>\n              <Text style={styles.selectedHeading}>Selected Items</Text>\n\n              <TouchableOpacity onPress={clearSelections}>\n                <Text style={styles.clearButtonText}>Clear</Text>\n              </TouchableOpacity>\n            </View>\n\n            <ScrollView horizontal showsHorizontalScrollIndicator={false}>\n              {selectedProducts.map((product) => (\n                <TouchableOpacity\n                  key={product.id}\n                  activeOpacity={0.8}\n                  style={styles.selectedChip}\n                  onPress={() => toggleSelection(product.id)}\n                >\n                  <Text style={styles.selectedChipText}>{product.name}</Text>\n\n                  <Text style={styles.removeIcon}>✕</Text>\n                </TouchableOpacity>\n              ))}\n            </ScrollView>\n          </View>\n        )}\n      </>\n    );\n  }, [\n    clearSelections,\n    search,\n    selectedIds.size,\n    selectedProducts,\n    sortType,\n    toggleSelection,\n  ]);\n\n  /**\n   * =====================================================\n   * UI\n   * =====================================================\n   */\n\n  return (\n    <View style={styles.container}>\n      <FlatList\n        data={filteredProducts}\n        renderItem={renderItem}\n        keyExtractor={keyExtractor}\n        ListHeaderComponent={renderHeader}\n        initialNumToRender={10}\n        windowSize={5}\n        removeClippedSubviews\n        getItemLayout={getItemLayout}\n        keyboardShouldPersistTaps=\"handled\"\n        showsVerticalScrollIndicator={false}\n        contentContainerStyle={styles.listContent}\n      />\n    </View>\n  );\n};\n\nexport default ProductSelectionScreen;\n\n/**\n * =====================================================\n * STYLES\n * =====================================================\n */\n\nconst styles = StyleSheet.create({\n  container: {\n    flex: 1,\n    backgroundColor: \"#F4F6FA\",\n  },\n\n  listContent: {\n    padding: 16,\n    paddingTop: 56,\n    paddingBottom: 40,\n  },\n\n  /**\n   * Header\n   */\n\n  headerContainer: {\n    marginBottom: 20,\n  },\n\n  headerTitle: {\n    fontSize: 34,\n    fontWeight: \"800\",\n    color: \"#111\",\n  },\n\n  headerSubtitle: {\n    marginTop: 4,\n    fontSize: 16,\n    color: \"#666\",\n    fontWeight: \"500\",\n  },\n\n  /**\n   * Search\n   */\n\n  searchContainer: {\n    flexDirection: \"row\",\n    alignItems: \"center\",\n    backgroundColor: \"#FFF\",\n    borderRadius: 18,\n    paddingHorizontal: 16,\n    marginBottom: 18,\n    height: 58,\n\n    shadowColor: \"#000\",\n    shadowOffset: {\n      width: 0,\n      height: 2,\n    },\n    shadowOpacity: 0.04,\n    shadowRadius: 8,\n\n    elevation: 2,\n  },\n\n  searchIcon: {\n    fontSize: 18,\n    marginRight: 10,\n  },\n\n  searchInput: {\n    flex: 1,\n    fontSize: 16,\n    color: \"#111\",\n  },\n\n  /**\n   * Filter Chips\n   */\n\n  filterContainer: {\n    paddingBottom: 18,\n  },\n\n  filterChip: {\n    backgroundColor: \"#FFF\",\n    borderRadius: 24,\n    paddingVertical: 10,\n    paddingHorizontal: 16,\n    marginRight: 10,\n\n    shadowColor: \"#000\",\n    shadowOffset: {\n      width: 0,\n      height: 1,\n    },\n    shadowOpacity: 0.03,\n    shadowRadius: 4,\n\n    elevation: 1,\n  },\n\n  activeFilterChip: {\n    backgroundColor: \"#1677FF\",\n  },\n\n  filterText: {\n    color: \"#333\",\n    fontWeight: \"600\",\n  },\n\n  activeFilterText: {\n    color: \"#FFF\",\n  },\n\n  /**\n   * Selected Section\n   */\n\n  selectedSection: {\n    marginBottom: 18,\n  },\n\n  selectedTopRow: {\n    flexDirection: \"row\",\n    justifyContent: \"space-between\",\n    alignItems: \"center\",\n    marginBottom: 12,\n  },\n\n  selectedHeading: {\n    fontSize: 18,\n    fontWeight: \"700\",\n    color: \"#111\",\n  },\n\n  clearButtonText: {\n    color: \"#FF4D4F\",\n    fontWeight: \"700\",\n  },\n\n  selectedChip: {\n    flexDirection: \"row\",\n    alignItems: \"center\",\n    backgroundColor: \"#1677FF\",\n    borderRadius: 24,\n    paddingVertical: 10,\n    paddingHorizontal: 14,\n    marginRight: 10,\n  },\n\n  selectedChipText: {\n    color: \"#FFF\",\n    fontWeight: \"600\",\n    marginRight: 6,\n  },\n\n  removeIcon: {\n    color: \"#FFF\",\n    fontWeight: \"700\",\n  },\n\n  /**\n   * Product Card\n   */\n\n  productCard: {\n    backgroundColor: \"#FFF\",\n    borderRadius: 20,\n    padding: 18,\n    marginBottom: 14,\n\n    shadowColor: \"#000\",\n    shadowOffset: {\n      width: 0,\n      height: 2,\n    },\n    shadowOpacity: 0.04,\n    shadowRadius: 10,\n\n    elevation: 2,\n  },\n\n  selectedProductCard: {\n    borderWidth: 2,\n    borderColor: \"#1677FF\",\n  },\n\n  cardTopRow: {\n    flexDirection: \"row\",\n    justifyContent: \"space-between\",\n    alignItems: \"center\",\n  },\n\n  cardContent: {\n    flex: 1,\n  },\n\n  productName: {\n    fontSize: 20,\n    fontWeight: \"700\",\n    color: \"#111\",\n    marginBottom: 12,\n  },\n\n  /**\n   * Category Badge\n   */\n\n  categoryBadge: {\n    alignSelf: \"flex-start\",\n    backgroundColor: \"#EDF4FF\",\n    borderRadius: 16,\n    paddingVertical: 6,\n    paddingHorizontal: 12,\n  },\n\n  categoryText: {\n    color: \"#1677FF\",\n    fontWeight: \"600\",\n    fontSize: 13,\n  },\n\n  /**\n   * Check Icon\n   */\n\n  checkContainer: {\n    width: 32,\n    height: 32,\n    borderRadius: 16,\n    backgroundColor: \"#1677FF\",\n    justifyContent: \"center\",\n    alignItems: \"center\",\n  },\n\n  checkText: {\n    color: \"#FFF\",\n    fontWeight: \"700\",\n  },\n});\n","type":"js"},{"name":"P001-classcomponent.js","content":"import React, { Component } from \"react\";\nimport { Text, View, BackHandler } from \"react-native\";\n\nclass UserProfile extends Component {\n  constructor(props) {\n    super(props);\n    this.state = { loading: true, userData: null };\n  }\n\n  // 1. Mount\n  componentDidMount() {\n    this.fetchUserData();\n    this.backHandler = BackHandler.addEventListener(\n      \"hardwareBackPress\",\n      this.handleBack,\n    );\n  }\n\n  // 2. Update Optimization\n  shouldComponentUpdate(nextProps, nextState) {\n    return (\n      nextState.userData !== this.state.userData ||\n      nextState.loading !== this.state.loading\n    );\n  }\n\n  // 3. Update execution\n  componentDidUpdate(prevProps) {\n    if (prevProps.userId !== this.props.userId) {\n      this.fetchUserData(); // Refetch if prop changed\n    }\n  }\n\n  // 4. Unmount / Cleanup\n  componentWillUnmount() {\n    this.backHandler.remove();\n  }\n\n  fetchUserData = () => {\n    /* API Fetch Logic */\n  };\n  handleBack = () => {\n    return true;\n  };\n\n  render() {\n    return (\n      <View>\n        {this.state.loading ? (\n          <Text>Loading...</Text>\n        ) : (\n          <Text>Welcome User</Text>\n        )}\n      </View>\n    );\n  }\n}\nexport default UserProfile;\n","type":"js"},{"name":"P002-FunctionalComponent.js","content":"import React, { useState, useEffect, memo } from \"react\";\nimport { Text, View, BackHandler } from \"react-native\";\n\nconst UserProfile = ({ userId }) => {\n  const [loading, setLoading] = useState(true);\n  const [userData, setUserData] = useState(null);\n\n  useEffect(() => {\n    // 1. Mount & Update Logic\n    const fetchUserData = () => {\n      /* API Fetch Logic */\n    };\n    fetchUserData();\n\n    const handleBack = () => {\n      return true;\n    };\n    const backHandler = BackHandler.addEventListener(\n      \"hardwareBackPress\",\n      handleBack,\n    );\n\n    // 2. Unmount / Cleanup Logic\n    return () => {\n      backHandler.remove(); // This acts as componentWillUnmount\n    };\n  }, [userId]); // Triggers refetch if userId changes (componentDidUpdate)\n\n  return (\n    <View>{loading ? <Text>Loading...</Text> : <Text>Welcome User</Text>}</View>\n  );\n};\n\n// Replaces shouldComponentUpdate for performance\nexport default memo(UserProfile);\n","type":"js"}],"theory":[{"name":"032-YarnNPM.md","content":"Both **npm** (Node Package Manager) and **yarn** (Yet Another Resource Negotiator) are package managers used to install, manage, and share JavaScript/TypeScript dependencies in your projects.\n\nWhile they serve the exact same purpose, they differ under the hood in terms of architecture, speed, security, and disk space management.\n\n---\n\n## The Key Differences at a Glance\n\n| Feature                 | npm (Modern v7+)      | Yarn (Classic v1)         | Yarn (Modern v2+)                 |\n| ----------------------- | --------------------- | ------------------------- | --------------------------------- |\n| **Created By**          | Node.js Community     | Facebook / Meta           | Yarn Community                    |\n| **Lockfile Name**       | `package-lock.json`   | `yarn.lock`               | `yarn.lock`                       |\n| **Installation Speed**  | Fast (uses caching)   | Fast (parallel downloads) | Extremely Fast (Plug'n'Play)      |\n| **Monorepo Workspaces** | Native support        | Native support            | Advanced support                  |\n| **Storage Model**       | `node_modules` folder | `node_modules` folder     | PnP (Zero `node_modules` default) |\n\n---\n\n## Detailed Architectural Differences\n\n### 1. Storage and Installation Model (The `node_modules` Problem)\n\n- **npm & Yarn Classic:** Both download packages from the registry and extract them into a physical `node_modules` folder inside your project. This folder can quickly grow into gigabytes of duplicate files across different projects on your machine.\n- **Yarn Modern (Plug'n'Play / PnP):** Yarn modern completely re-engineered this by eliminating the `node_modules` folder. Instead, it generates a single `.pnp.cjs` mapping file and caches dependencies globally as compressed `.zip` archives.\n\n### 2. Speed and Parallelism\n\n- **npm:** Historically executed installations sequentially (one package after another), making it slow. Modern versions of npm use internal optimization algorithms, but it still executes certain lifecycle scripts sequentially.\n- **Yarn:** Designed from day one to fetch and install packages **simultaneously (parallel downloading)**. If a package is already cached on your machine, Yarn bypasses the network entirely to pull it out of local storage instantly.\n\n### 3. Monorepo and Workspace Management\n\nBoth package managers support **Workspaces**, allowing you to manage multiple packages or sub-projects (like separating your UI layer from your core API logic) within a single root repository.\n\n- **Yarn** is generally favored by large engineering teams for monorepos because its workspace dependency resolution algorithms handle complex, deeply nested cross-dependencies more smoothly than npm.\n\n---\n\n## Common Commands Comparison\n\nIf you are switching between the two package managers, here is how the syntax translates:\n\n| Action                          | npm command                 | Yarn command             |\n| ------------------------------- | --------------------------- | ------------------------ |\n| **Initialize Project**          | `npm init`                  | `yarn init`              |\n| **Install Everything**          | `npm install`               | `yarn`                   |\n| **Add a Production Dependency** | `npm install axios`         | `yarn add axios`         |\n| **Add a Dev Dependency**        | `npm install -D typescript` | `yarn add -D typescript` |\n| **Remove a Package**            | `npm uninstall lodash`      | `yarn remove lodash`     |\n| **Run a Custom Script**         | `npm run test`              | `yarn test`              |\n\n---\n\n## Which One Should You Choose?\n\n- **Choose npm if:** You want zero configuration out of the box. Because npm comes pre-installed with Node.js, you don’t need to configure external tools, making it the safest option for standard or smaller projects.\n- **Choose Yarn if:** You are managing a large-scale **enterprise monorepo**, need highly predictable installation times across CI/CD pipelines, or want to take advantage of zero-install configurations to preserve local disk space .\n","type":"md"},{"name":"013-redux-toolkit-react-query.md","content":"To help you master this for your IBM interview, we will implement the exact same real-world scenario across three different architectural patterns: **React Query Alone**, **Redux Toolkit Alone**, and the **Production Hybrid Combo**.\n\n### The Unified Scenario:\n\n1. **Dashboard Data (Parallel/ASAP):** We fetch `Profile` and `MarketRates` concurrently. They are completely independent and should render **ASAP** without waiting for each other.\n2. **Fintech Verification (Sequential/Dependent):** We fetch `AccountDetails`. This endpoint strictly requires the `accountId` returned from the `Profile` API. It must wait.\n\n---\n\n## Program 1: The React Query Way (Declarative Server-State)\n\nIn this approach, React Query handles caching and server orchestration. Parallel tasks run independently and render ASAP, while dependent tasks use the `enabled` configuration flag.\n\n```javascript\nimport React from \"react\";\nimport { View, Text, ActivityIndicator } from \"react-native\";\nimport { useQuery, useQueries } from \"@tanstack/react-query\";\n\n// Mock Mock API Endpoints\nconst fetchProfile = async () =>\n  (await fetch(\"https://api.com/profile\")).json(); // Returns { id: 'user_101', name: 'Rajeev' }\nconst fetchMarketRates = async () =>\n  (await fetch(\"https://api.com/rates\")).json(); // Returns { crypto: '+5.4%' }\nconst fetchAccountDetails = async (id) =>\n  (await fetch(`https://api.com/account/${id}`)).json(); // Returns { balance: 75000 }\n\nexport function ReactQueryArchitecture() {\n  // 1. PARALLEL FLOW (ASAP Rendering)\n  // Both requests fire concurrently. If 'rates' responds faster than 'profile', its UI updates instantly.\n  const [profileQuery, ratesQuery] = useQueries({\n    queries: [\n      { queryKey: [\"profile\"], queryFn: fetchProfile },\n      { queryKey: [\"rates\"], queryFn: fetchMarketRates },\n    ],\n  });\n\n  const accountId = profileQuery.data?.id;\n\n  // 2. SEQUENTIAL / DEPENDENT FLOW\n  // This query remains completely dormant until accountId is available.\n  const accountQuery = useQuery({\n    queryKey: [\"account\", accountId],\n    queryFn: () => fetchAccountDetails(accountId),\n    enabled: !!accountId, // The gatekeeper flag\n  });\n\n  return (\n    <View style={{ padding: 20 }}>\n      {/* ASAP Render Component for Market Rates */}\n      {ratesQuery.isLoading ? (\n        <ActivityIndicator />\n      ) : (\n        <Text>Market: {ratesQuery.data?.crypto}</Text>\n      )}\n\n      {/* ASAP Render Component for Profile */}\n      {profileQuery.isLoading ? (\n        <ActivityIndicator />\n      ) : (\n        <Text>User: {profileQuery.data?.name}</Text>\n      )}\n\n      {/* Sequential Component that waits for the upstream ID */}\n      {accountQuery.isLoading && accountId && <Text>Verifying ledger...</Text>}\n      {accountQuery.data && (\n        <Text>Wallet Balance: ${accountQuery.data?.balance}</Text>\n      )}\n    </View>\n  );\n}\n```\n\n---\n\n## Program 2: The Redux Toolkit Way (Imperative Client-State)\n\nIn Redux Toolkit, asynchronous logic is managed inside Thunks using Java-style lifecycle promises. Parallel tasks use `Promise.all` but the thunk payload waits for both to resolve before updating global state, while sequential workflows are written line-by-line using standard `await` syntax.\n\n```javascript\nimport {\n  createSlice,\n  createAsyncThunk,\n  configureStore,\n} from \"@reduxjs/toolkit\";\n\n// Thunk 1: Parallel Dashboard Operations\nexport const fetchDashboardData = createAsyncThunk(\n  \"dashboard/fetch\",\n  async () => {\n    // Both requests hit the network infrastructure at the exact same millisecond\n    const [profile, rates] = await Promise.all([\n      fetch(\"https://api.com/profile\").then((res) => res.json()),\n      fetch(\"https://api.com/rates\").then((res) => res.json()),\n    ]);\n    return { profile, rates };\n  },\n);\n\n// Thunk 2: Sequential Payment Verification Operations\nexport const verifyFintechAccount = createAsyncThunk(\n  \"account/verify\",\n  async (accountId) => {\n    // Line-by-line blocking sequence execution\n    const accountDetails = await fetch(\n      `https://api.com/account/${accountId}`,\n    ).then((res) => res.json());\n    return accountDetails;\n  },\n);\n\nconst appSlice = createSlice({\n  name: \"appState\",\n  initialState: {\n    profile: null,\n    rates: null,\n    account: null,\n    loadingDashboard: false,\n  },\n  reducers: {},\n  extraReducers: (builder) => {\n    builder\n      .addCase(fetchDashboardData.pending, (state) => {\n        state.loadingDashboard = true;\n      })\n      .addCase(fetchDashboardData.fulfilled, (state, action) => {\n        state.loadingDashboard = false;\n        state.profile = action.payload.profile;\n        state.rates = action.payload.rates;\n      })\n      .addCase(verifyFintechAccount.fulfilled, (state, action) => {\n        state.account = action.payload;\n      });\n  },\n});\n\nexport const store = configureStore({ reducer: { fintech: appSlice.reducer } });\n```\n\nTo run this inside your presentation views, you dispatch the actions conditionally:\n\n```javascript\nimport React, { useEffect } from \"react\";\nimport { View, Text, Button } from \"react-native\";\nimport { useDispatch, useSelector } from \"react-redux\";\nimport { fetchDashboardData, verifyFintechAccount } from \"./store\";\n\nexport function ReduxToolkitArchitecture() {\n  const dispatch = useDispatch();\n  const { profile, rates, account } = useSelector((state) => state.fintech);\n\n  useEffect(() => {\n    dispatch(fetchDashboardData());\n  }, [dispatch]);\n\n  // Sequential Step Triggered manually or via conditional hook checks\n  const handleVerification = () => {\n    if (profile?.id) {\n      dispatch(verifyFintechAccount(profile.id));\n    }\n  };\n\n  return (\n    <View style={{ padding: 20 }}>\n      <Text>User: {profile?.name}</Text>\n      <Text>Rates: {rates?.crypto}</Text>\n      <Button title=\"Verify Wallet\" onPress={handleVerification} />\n      {account && <Text>Balance: ${account?.balance}</Text>}\n    </View>\n  );\n}\n```\n\n---\n\n## Program 3: The Hybrid Combo (Production Standard)\n\nThis is the ultimate corporate design choice for senior roles. You use **React Query** for caching and streaming the remote network transactions ASAP, and use a synchronous **Redux Toolkit Reducer Action** to pipe data down into global tracking mechanisms for your cross-platform components.\n\n```javascript\nimport { createSlice, configureStore } from \"@reduxjs/toolkit\";\n\n// Redux handles tracking client status values synchronously\nconst telemetrySlice = createSlice({\n  name: \"telemetry\",\n  initialState: { activeUser: null, globalNotification: \"\" },\n  reducers: {\n    syncActiveUser: (state, action) => {\n      state.activeUser = action.payload; // Saves global session tracking reference\n      state.globalNotification = `Session initiated for ${action.payload.name}`;\n    },\n  },\n});\n\nexport const { syncActiveUser } = telemetrySlice.actions;\nexport const comboStore = configureStore({\n  reducer: { system: telemetrySlice.reducer },\n});\n```\n\nHere is how React Query streams the network requests seamlessly while interacting with your Redux slice synchronization callbacks:\n\n```javascript\nimport React from \"react\";\nimport { View, Text } from \"react-native\";\nimport { useQuery } from \"@tanstack/react-query\";\nimport { useDispatch } from \"react-redux\";\nimport { syncActiveUser } from \"./telemetrySlice\";\n\nexport function ProductionComboArchitecture() {\n  const dispatch = useDispatch();\n\n  // 1. Async Parallel Query A (Renders ASAP independently)\n  const ratesQuery = useQuery({\n    queryKey: [\"rates\"],\n    queryFn: () => fetch(\"https://api.com/rates\").then((res) => res.json()),\n  });\n\n  // 2. Async Parallel Query B (Fires together, syncs into Redux on success)\n  const profileQuery = useQuery({\n    queryKey: [\"profile\"],\n    queryFn: () => fetch(\"https://api.com/profile\").then((res) => res.json()),\n    onSuccess: (data) => {\n      // Synchronous cross-over step: dispatching server payload to global client state\n      dispatch(syncActiveUser(data));\n    },\n  });\n\n  const accountId = profileQuery.data?.id;\n\n  // 3. Sequential Async Query (Waits for Account ID output data cascade)\n  const accountQuery = useQuery({\n    queryKey: [\"accountDetails\", accountId],\n    queryFn: () =>\n      fetch(`https://api.com/account/${accountId}`).then((res) => res.json()),\n    enabled: !!accountId, // Waits until profile resolves\n  });\n\n  return (\n    <View style={{ padding: 20 }}>\n      {/* ASAP Rendering UI blocks */}\n      <Text>\n        {ratesQuery.data\n          ? `Rates: ${ratesQuery.data.crypto}`\n          : \"Loading Rates...\"}\n      </Text>\n      <Text>\n        {profileQuery.data\n          ? `User: ${profileQuery.data.name}`\n          : \"Loading Profile...\"}\n      </Text>\n\n      {/* Sequential UI block */}\n      <Text>\n        {accountQuery.data\n          ? `Ledger Balance: $${accountQuery.data.balance}`\n          : \"Awaiting Verification...\"}\n      </Text>\n    </View>\n  );\n}\n```\n\n---\n\n## 🎯 Final Technical Recap for the IBM Interview\n\n- **When asked about React Query:** Emphasize **declarative data synchronization**. It handles performance optimizations like caching and background revalidation natively via focus controls.\n- **When asked about Redux Toolkit:** Emphasize **predictable transactional management**. It acts as a single source of truth for tracking complex UI states across independent app components.\n- **The Hybrid Combo justification:** State that enterprise applications use React Query to manage high-volume server data streams cleanly without writing boilerplate code, while offloading client configurations to Redux Toolkit.\n","type":"md"},{"name":"028-customHoom-useNetwrok.md","content":"A **Custom Hook** is simply a JavaScript function whose name starts with **`use`** and that can call other React hooks (like `useState`, `useEffect`, `useCallback`, etc.).\n\nIn enterprise architecture, custom hooks are used to **extract business logic out of the UI presentation components** so that the logic can be tested independently and reused across multiple screens.\n\nHere is a complete, real-world example of a custom hook that tracks **network connectivity status** in React Native. This is essential for fintech dashboards to prevent users from making transactions when their internet drops.\n\n---\n\n### Step 1: Writing the Custom Hook (`useNetworkStatus.ts`)\n\nThis hook handles the event listener registration, maintains the local state, and cleans up memory when the component unmounts.\n\n```typescript\nimport { useState, useEffect } from \"react\";\nimport NetInfo from \"@react-native-community/netinfo\";\n\nexport function useNetworkStatus() {\n  // 1. Maintain internal reactive states\n  const [isConnected, setIsConnected] = useState<boolean | null>(true);\n  const [connectionType, setConnectionType] = useState<string | null>(\n    \"unknown\",\n  );\n\n  useEffect(() => {\n    // 2. Subscribe to the native operating system's network event listener\n    const unsubscribe = NetInfo.addEventListener((state) => {\n      setIsConnected(state.isConnected);\n      setConnectionType(state.type);\n    });\n\n    // 3. Mandatory Memory Cleanup\n    // This return closure acts exactly like 'componentWillUnmount'.\n    // If the screen unmounts, we drop the native listener to prevent native heap memory leaks!\n    return () => {\n      unsubscribe();\n    };\n  }, []); // Empty array ensures this listener binds exactly ONCE on mount\n\n  // 4. Return the calculated values as a clean object API for our UI components\n  return {\n    isConnected,\n    connectionType,\n    isCellular: connectionType === \"cellular\",\n    isWifi: connectionType === \"wifi\",\n  };\n}\n```\n\n---\n\n### Step 2: How We Consume/Call It in a Component\n\nNow, our UI components can consume this network state machine with a single line of code. The UI remains completely \"dumb\" and presentation-focused—it doesn't care _how_ NetInfo tracks the hardware; it just reads the variables.\n\n```typescript\nimport React from 'react';\nimport { View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';\n// Import our custom logic module\nimport { useNetworkStatus } from './useNetworkStatus';\n\nexport default function CheckoutScreen() {\n  // CALLING THE CUSTOM HOOK: Deconstruct the real-time values instantly\n  const { isConnected, isCellular } = useNetworkStatus();\n\n  const handlePaymentSubmit = () => {\n    // Enforce business logic boundary condition using hook state metrics\n    if (!isConnected) {\n      Alert.alert('Sync Halted', 'No network detected. Please restore connectivity to process escrow.');\n      return;\n    }\n    Alert.alert('Success', 'Transaction payload broadcasted safely.');\n  };\n\n  return (\n    <View style={styles.container}>\n      {/* 1. Real-time dynamic banner bar based on Custom Hook values */}\n      {!isConnected && (\n        <View style={styles.offlineBanner}>\n          <Text style={styles.bannerText}>Operating Offline Mode</Text>\n        </View>\n      )}\n\n      <Text style={styles.title}>Payment Checkout Gateway</Text>\n      <Text style={styles.subText}>\n        Network Protocol: {isConnected ? (isCellular ? 'Mobile Data (LTE/5G)' : 'Wi-Fi') : 'Disconnected'}\n      </Text>\n\n      <TouchableOpacity\n        style={[styles.button, !isConnected && styles.buttonDisabled]}\n        onPress={handlePaymentSubmit}\n      >\n        <Text style={styles.buttonText}>Authorize Transaction</Text>\n      </TouchableOpacity>\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  container: { flex: 1, justifyContent: 'center', padding: 24, backgroundColor: '#F8FAFC' },\n  offlineBanner: { position: 'absolute', top: 50, left: 0, right: 0, backgroundColor: '#EF4444', padding: 10, alignItems: 'center' },\n  bannerText: { color: '#FFF', fontWeight: 'bold' },\n  title: { fontSize: 24, fontWeight: '700', color: '#1E293B', marginBottom: 8 },\n  subText: { fontSize: 14, color: '#64748B', marginBottom: 24 },\n  button: { height: 52, backgroundColor: '#1677FF', borderRadius: 12, justifyContent: 'center', alignItems: 'center' },\n  buttonDisabled: { backgroundColor: '#CBD5E1' },\n  buttonText: { color: '#FFF', fontWeight: '600', fontSize: 16 }\n});\n\n```\n\n---\n\n### Why Custom Hooks are crucial under the hood:\n\n1. **Shared State Logic, Separate State Instances:** If you import and call `useNetworkStatus()` on the `CheckoutScreen` and also inside a `ProfileScreen` at the same time, **they do not share the same data state**. Each custom hook execution allocates its own completely isolated memory sandbox allocation inside the React rendering tree.\n2. **Seamless Triggering of Re-renders:** When the device connectivity shifts (e.g., you walk out of Wi-Fi range), the internal `setIsConnected` function inside the custom hook triggers. Because it updates React state, **it automatically forces any parent UI component currently calling that custom hook to instantly re-render** with the fresh data coordinates, guaranteeing UI sync across the whole app.\n","type":"md"},{"name":"027-upcoming-questions-guide.md","content":"Since your first round was a quick 30-minute screening that covered core syntax, snippet evaluation, and baseline framework mechanics, your upcoming **1-hour deep-dive technical round** with the same interviewer will pivot significantly.\n\nThe interviewer already knows you understand loops, hooks, and basic architectural definitions. In a 1-hour round, an IBM panel wants to see how you think as a **Lead/Senior Engineer**. They will challenge you on **system scalability, edge-case production debugging, native platform integration, and real-time live coding or refactoring.**\n\nPrepare for these four main areas, based on the questions they have already asked you:\n\n---\n\n## Topic 1: Advanced Async State Machine & Cache Invalidation\n\nSince you discussed parallel vs. sequential fetching in Redux and React Query, they will take this scenario further and ask how to handle it in a production environment under network stress.\n\n- **Expected Follow-up Question:** _\"You explained that `enabled: !!accountId` cascades our payment queries. But what happens if the user rapidly switches tabs, or the profile lookup succeeds but the network fails midway through the sequential chain? How do you prevent layout flashing or a dead state?\"_\n- **How to answer:** Explain how you use **`initialData` or placeholder caching** to prevent UI layout shifts. Discuss configuring explicit **`retry` and `retryDelay` back-off strategies** in React Query so the app smoothly heals from temporary network drops rather than failing immediately. Mention managing global toast notifications or rollback states via a client state engine like Redux if a critical transactional sequential step fails.\n\n---\n\n## Topic 2: Hardcore Performance Profiling & Memory Leak Auditing\n\nYou touched on the Garbage Collector, Hermes, and the native heap. They will now give you a practical production emergency to solve.\n\n- **Expected Follow-up Question:** _\"Our app is crashing on older Android devices with an Out-of-Memory (OOM) error after a user scrolls through our investment list for 5 minutes. Walk me through exactly how you diagnose, trace, and patch this issue.\"_\n- **How to answer:** Break your debugging pipeline down into concrete senior steps:\n\n1. **Isolate:** Boot the app inside **Android Studio Memory Profiler** or **Xcode Instruments (Allocations/Leaks)** to watch the native memory heap graph.\n2. **Inspect:** Look at the JavaScript heap using the **Hermes Profiler** to check if the total object count keeps climbing.\n3. **Identify:** Pinpoint the common culprits: uncleaned event listeners inside custom hooks, massive uncached raster images sitting inside a `<ScrollView>` instead of a recycled cell layout, or long-running interval timers that weren't cleared inside a `useEffect` return cleanup block.\n\n---\n\n## Topic 3: Live Refactoring / Coding (The Class-to-Hook Transformation)\n\nGiven your discussion on legacy Class Component lifecycles and modern Functional Components, be prepared for a **live coding or pseudo-coding exercise** where they hand you a messy legacy class and ask you to refactor it.\n\n- **Expected Follow-up Question:** _\"Here is a 300-line legacy Class component handling a continuous WebSocket stream for market rates. It uses `componentDidMount`, `componentDidUpdate` to check if tokens changed, and `componentWillUnmount` to close the socket. Refactor this cleanly into a functional component using Hooks.\"_\n- **What they are looking for:** They want to see if you can successfully map `this.setState` to functional state transitions without causing infinite loops. Make sure you place the WebSocket closing method (`socket.close()`) inside the **cleanup return function** of a targeted `useEffect` hook to demonstrate that you protect the garbage collection engine from leaving phantom sockets open in the background.\n\n---\n\n## Topic 4: Native Interoperability & Build Pipeline Customization\n\nSince you covered Babel, Metro, Yoga, and Expo prebuilding, they will test your comfort level with native project layers.\n\n- **Expected Follow-up Question:** _\"We need to add a specialized payment security library from IBM that is written natively in Java for Android and Swift for iOS. We are using an Expo configuration. How do you integrate this library into our universal codebase without losing our folderless workflow?\"_\n- **How to answer:** Explain that you would build a custom **Expo Config Plugin**. Instead of running `npx expo prebuild` and hacking the generated `/android` and `/ios` folders manually, you write a JavaScript setup script that tells Expo's compilation system how to programmatically inject the native frameworks, modify properties, and register permissions automatically during the build phase. This approach keeps the source code clean and fully universal.\n\n---\n\n## 🎯 Pro-Tips for Managing the 1-Hour Round with the Same Person\n\n1. **Reference Your First Round:** When explaining a concept, build upon your previous answers. Say things like, _\"As we established yesterday with the Hermes bytecode execution model...\"_ This reinforces your technical consistency and shows you remember the technical foundation you laid down.\n2. **Think Out Loud (Whiteboarding):** If they give you a system design puzzle, do not stay silent while figuring it out. Speak through your thought process: _\"First, I am evaluating the thread cost here. If I run this calculation on the main JS thread, it might block Fabric from processing layout commitments, so I would offload this to a custom native Worklet instead...\"_\n3. **Focus on Scale and Business Value:** Every time you suggest a technical choice (like using an atomic CSS structure in React Native Web or optimizing image formats to WebP), explain _why_ it matters to the company—such as lowering customer drop-off rates on slow networks, reducing app store binary size, or accelerating time-to-market with shared codebases.\n\nFor a great visual breakdown of how these advanced architecture components interconnect during production profiling sessions, you can refer to this clear engineering explanation.\n\n## This advanced guide on performance optimizations covers exactly how senior engineers use profiling suites to catch active thread blocking and minimize bundle overhead. You have all the core engineering theory fresh in your mind, Rajeev. Go into this extended technical round and clear it smoothly!\n\nHere is a highly strategic preparation guide for your 1-hour technical round with the same interviewer. Because they already know your baseline knowledge, they will likely use a **Scenario-Based Interviewing** technique.\n\nBelow are the exact production-level questions, deeply technical answers, and the tricky follow-up questions your interviewer is likely to throw at you to test your limits.\n\n---\n\n## Scenario 1: State Orchestration under Network Stress (React Query + Redux)\n\n### **The Main Question:**\n\n> _\"In your last round, you mentioned using React Query to sequentially fetch a user account and then their payment profile using the `enabled` flag. Let’s look at a production edge case: What happens if the profile query succeeds, but while the payment query is in-flight, the user's internet drops or they switch screens rapidly? How do you handle this state machine cleanly without causing the UI to lock up or display a blank screen?\"_\n\n#### **Your Senior-Level Answer:**\n\n\"To handle this gracefully, I look at three layers: **Cache Preservation, UI Stability, and Network Resilience**.\n\n1. **Cache Preservation (Using `placeholderData` or `initialData`):** If the user is navigating back and forth between screens, I don't want the UI to completely tear down and show a loading spinner again. I configure the query with `placeholderData: keepPreviousData`. This ensures that the user sees the old data on screen while the fresh background fetch is attempting to resolve.\n2. **Network Resilience (Exponential Backoff):** I never let a query fail on the first network drop. I configure a custom retry strategy:\n\n```javascript\nretry: 3,\nretryDelay: (attempt) => Math.min(1000 * 2 ** attempt, 30000) // Exponential backoff\n\n```\n\n````\n3. **State Machine Management:** If the payment fetch ultimately fails after retries, I don't leave the app in a broken state. I utilize React Query's `onError` handler (or an active `useEffect` listening to the query's `isError` status) to dispatch a clear rollback action to my global Redux store, triggering an offline banner or a localized 'Retry Payment Fetch' button, keeping the rest of the app functional.\"\n\n### **The Interviewer's Expected Follow-up:**\n> *\"That works for data, but what if it's a mutation (like a user clicking a 'Pay Now' button) and the network cuts out mid-flight? How do you prevent double-spending or corrupt state?\"*\n\n#### **Your Follow-up Answer:**\n\"For mutations like payments, we must enforce **Idempotency** and **Optimistic/Pessimistic State Updates**.\n* First, I enforce a **Pessimistic UI loading state**—disabling the 'Pay Now' button the millisecond it's clicked to prevent double-tapping.\n* Second, every payment mutation request payload generates a unique `idempotency-key` (usually a UUID attached to that specific checkout session state). Even if the network drops and React Native retries the request, the backend server detects the identical key, drops the second transaction request, and simply returns the status of the first one safely.\"\n\n---\n\n## Scenario 2: Memory Leak Auditing (The Garbage Collector Deep-Dive)\n\n### **The Main Question:**\n> *\"You talked about the Hermes Garbage Collector and how it uses Mark-and-Sweep. Suppose our fintech dashboard app is experiencing severe performance degradation and eventually crashes due to an Out-of-Memory (OOM) exception after a user has been scrolling a list of live stock tickers for 5 minutes. Walk me through your step-by-step pipeline to find and fix this memory leak.\"*\n\n#### **Your Senior-Level Answer:**\n\"An OOM crash after scrolling a live ticker list usually indicates that older items or network subscription objects are not being collected by the Hermes GC because something is holding onto their references. Here is my diagnostic pipeline:\n\n1. **Isolate and Replicate:** I generate a release-staged build with debugging symbols enabled. I run the app on an emulator/device and hook it up to **Android Studio Profiler (Memory Canvas)** or **Xcode Instruments (Allocations)**. I look at the heap growth graph. If the memory footprint line has a continuous upward staircase shape without dropping when the user idle-waits, we have a confirmed leak.\n2. **Analyze JavaScript Heap:** I open **Chrome DevTools** hooked into the Hermes engine and take two **Heap Snapshots**: Snapshot A at launch, and Snapshot B after scrolling for 3 minutes. I use the 'Comparison' view to look for objects whose delta allocation count continuously jumps.\n3. **Common Culprits & Fixes in this Scenario:**\n   * **The Problem:** The stock ticker likely opens a `WebSocket` or a `DeviceEventEmitter` listener inside a list row component. If the row scrolls off-screen and unmounts, but the listener cleanup function isn't invoked, the global event listener array holds a strong reference to the row component's closure. The GC can never clean it up.\n   * **The Code Fix:** I ensure that the hook managing the ticker stream explicitly returns a cleanup function:\n     ```javascript\n     useEffect(() => {\n       const sub = StockStream.subscribe(tickerId, handleData);\n       return () => sub.unsubscribe(); // CRITICAL: Releases reference for GC\n     }, [tickerId]);\n```\"\n\n### **The Interviewer's Expected Follow-up:**\n> *\"What if the memory leak isn't in JavaScript, but on the native side? How does your interaction with FlatList change to prevent native view memory accumulation?\"*\n\n#### **Your Follow-up Answer:**\n\"If the heap snapshot shows JavaScript memory is flat, but native memory is climbing, the native views themselves are being retained. This happens if you wrap list items in standard `<ScrollView>` layers, which render all rows instantly and keep them in the native view hierarchy.\nTo fix this, I swap it for Shopify's **`FlashList`** or a tuned React Native **`FlatList`**. I enforce strict **Row Recycling** by providing a precise `getItemLayout` property so the native layer doesn't have to dynamically measure components on the fly, and I keep `maxToRenderPerBatch` limited to 10 items. This allows native view allocations to stay constant as elements scroll off-screen.\"\n\n---\n\n## Scenario 3: Live Refactoring Challenge (Class to Functional Hooks)\n\n### **The Main Question:**\n> *\"Let's test your migration strategies. I'm going to describe a legacy Class Component that handles a biometric authentication countdown timer. It initiates a native countdown inside `componentDidMount`, compares time intervals inside `componentDidUpdate`, and wipes the native timer inside `componentWillUnmount`. Tell me exactly how you refactor this safely into a modern Functional Component using Hooks without introducing race conditions.\"*\n\n#### **Your Senior-Level Answer:**\n\"Refactoring a timer class requires translating instance properties (`this.timer`) and distinct lifecycle hooks into a unified, state-decoupled hook.\n\n```javascript\nimport React, { useState, useEffect, useRef } from 'react';\nimport { View, Text, Alert } from 'react-native';\n\nexport function ModernBiometricTimer({ isActive }) {\n  const [seconds, setSeconds] = useState(60);\n\n  // CRITICAL STEP: We use a useRef to hold the mutable native timer ID reference.\n  // Storing it in local state would trigger infinite loops, and storing it as a standard\n  // global variable would leak across multiple instances of the component.\n  const timerRef = useRef(null);\n\n  useEffect(() => {\n    // 1. Replaces 'componentDidMount' and conditional 'componentDidUpdate' check\n    if (isActive && seconds > 0) {\n      timerRef.current = setInterval(() => {\n        setSeconds((prev) => prev - 1);\n      }, 1000);\n    } else if (seconds === 0) {\n      Alert.alert(\"Timeout\", \"Biometric window expired.\");\n    }\n\n    // 2. Replaces 'componentWillUnmount' and cleanups before subsequent updates\n    return () => {\n      if (timerRef.current) {\n        clearInterval(timerRef.current);\n      }\n    };\n  }, [isActive, seconds]); // Re-runs targetedly when these values mutate\n\n  return (\n    <View>\n      <Text>Time Remaining: {seconds}s</Text>\n    </View>\n  );\n}\n\n````\n\n---\n\n## Scenario 4: The New Architecture & Universal Build Pipelines (Expo CNG)\n\n### **The Main Question:**\n\n> _\"You explained that Expo uses a Continuous Native Generation (CNG) prebuild process to generate native code dynamically based on `app.json`. Suppose we need to build our app for iOS, Android, and Web, but our web version needs a specific hover dashboard effect, while our mobile versions need a native Swift/Java secure-storage encryption library. How do you design this architecture without breaking the build for any platform?\"_\n\n#### **Your Senior-Level Answer:**\n\n\"To handle this universal complexity cleanly, I apply the **Strategy Pattern** combined with **Platform File Extensions**.\n\n1. **For the UI (Hover on Web vs. Tap on Mobile):** Instead of scattering `if (Platform.OS === 'web')` everywhere, I isolate styles and pointer actions. I leverage React Native's standard pointer interaction properties or utilize platform-specific style split objects:\n\n```javascript\nconst styles = StyleSheet.create({\n  card: {\n    ...Platform.select({\n      web: { cursor: \"pointer\", transition: \"0.2s\" },\n      default: { elevation: 2 }, // Android/iOS native dropshadow\n    }),\n  },\n});\n```\n\n```\n2. **For the Heavy Native Library (Storage/Encryption):** I isolate the platform-native wrappers completely using file-split boundaries:\n   * I create a unified interface component contract file: `SecureStorage.interface.ts`.\n   * I implement `SecureStorage.native.ts` where I safely import our Java/Swift native module via **TurboModules**. The Metro bundler will route this strictly during mobile compilations.\n   * I implement `SecureStorage.web.ts` where I substitute the native layer with the browser's standard Web Crypto API or encrypted IndexedDB rules. The bundler maps this for web deployment, ensuring our native mobile code blocks never leak into the web bundle and cause browser compilation faults.\"\n\n### **The Interviewer's Expected Follow-up:**\n> *\"Excellent. Now tell me, how does the New Architecture's Codegen module help us ensure that the data structures sent to that native Swift/Java secure-storage module don't cause type-mismatch crashes at runtime?\"*\n\n#### **Your Follow-up Answer:**\n\"**Codegen** acts as our compile-time type-safety guard. Before my code ever compiles into a native package, I am forced to write a strict, strongly-typed TypeScript interface specifying exactly what parameters our secure-storage library accepts (e.g., `encryptToken(alias: string, payload: string): Promise<boolean>`).\nDuring the build phase, Codegen reads this spec file and automatically writes the low-level C++ structural binding layers. If an engineer accidentally passes an array or integer from JavaScript code, the Codegen task will catch the discrepancy and fail our build process immediately on our laptops or CI pipeline, rather than letting a data-type corruption trigger a native runtime NullPointer exception on the user's phone.\"\n\n---\n\n## Final Quick-Reference Checklist for the Interview:\n1. **Never use the word \"Bridge\" without qualifying it as \"Legacy\":** Emphasize that you work natively with **JSI, Fabric, and TurboModules** now.\n2. **State management is split:** Remember to maintain that server data belongs in **React Query** (cache-driven) and local UI configuration flags belong in **Redux** (client-driven).\n3. **Always link performance back to business metrics:** (e.g., *\"Reducing memory leaks stops app drop-out rates\"*, *\"Using WebP shrinks app size which drives higher play store installation conversions\"*).\n\n```\n\nTo make absolutely sure nothing catches you off guard, let’s fortify your preparation.\n\nWe will address this in three tactical sections:\n\n1. **Redemption Strategy:** Re-answering the Round 1 questions you felt shaky on, but with 100% accurate, senior-level precision.\n2. **IBM Core Standard Questions:** Enterprise behavioral-technical hybrid questions standard to IBM's engineering rubrics.\n3. **General Strategy/Curveball Questions:** System design and edge-case scenarios in case the interviewer pivots.\n\n---\n\n## Part 1: Round 1 Redemption (Fixing the Shaky Answers)\n\nIf you didn't give a 100% perfect answer yesterday on certain topics, the interviewer will likely poke at them again to see if you went home, researched, and learned. Here is how you crush those follow-ups.\n\n### Shaky Topic 1: Parallel vs. Sequential Fetches (React Query vs. Redux Toolkit)\n\n- **What you might have missed:** Explaining exactly _how_ React Query automates this via caching and rendering optimization compared to manual Redux thunks.\n- **The Perfect Answer:**\n  > \"To clarify the difference between the state managers: In **Redux Toolkit (RTK)**, handling parallel or sequential fetches requires writing manual, imperative code inside asynchronous Thunks. If I need parallel data, I have to orchestrate `Promise.all([fetchA(), fetchB()])` manually. If sequential, I must await the first dispatch, catch the payload, and feed it into the next query.\n  > **React Query (TanStack Query)** shifts this entirely to a declarative paradigm. For **parallel fetches**, I simply call multiple `useQuery` hooks simultaneously; React Query tracks their states independently and fetches them over the network in parallel. For **sequential fetches**, it introduces a dependent query architecture using the `enabled` configuration property. By passing `enabled: !!userData`, React Query blocks the second API transaction request entirely until the primary user object resolves into the local cache, optimizing network overhead out of the box.\"\n\n### Shaky Topic 2: Class Component Lifecycles vs. Functional Hooks\n\n- **What you might have missed:** Explaining the exact mapping of `componentDidUpdate` dependencies and why `componentWillUnmount` memory safety is different.\n- **The Perfect Answer:**\n  > \"While Class Components break lifecycle states into explicit, isolated methods, Functional Components use a single unified primitive: the `useEffect` hook.\n  >\n  > - `componentDidMount` maps directly to a `useEffect` with an **empty dependency array `[]**`.\n  > - `componentDidUpdate` maps to `useEffect` with **explicit dependencies `[variable]**`. In a Class, you have to write a verbose conditional block (`if (prevState.id !== this.state.id)`). In a Hook, the React runtime handles this comparison automatically before executing the effect block.\n  > - `componentWillUnmount` maps straight to the **cleanup return function closure** inside `useEffect`. In legacy code, failing to clear native intervals or event listeners inside `componentWillUnmount` directly causes native heap leaks. In Functional components, the return closure acts as the automatic garbage collection helper, executing every time right before the component unmounts or before the dependency array re-evaluates.\"\n\n---\n\n## Part 2: IBM Standard Technical-Behavioral Questions\n\nIBM values architecture, compliance, code maintainability, and global scalability. Expect questions that test how you handle enterprise constraints.\n\n### Question 1: Managing Global Security & Compliance (Fintech Context)\n\n> _\"At IBM, we deal with highly regulated applications. How do you handle securing sensitive data (like authentication tokens or financial metrics) both in transit and at rest inside a React Native mobile and web application?\"_\n\n- **Your Answer:**\n  \"Security requires a strict multi-layer framework:\n\n1. **Data at Rest (Mobile):** I never store raw auth tokens, refresh keys, or user data inside standard `AsyncStorage` or `localStorage`, because they write to unencrypted plaintext files on the disk. On mobile, I use **`react-native-keychain`** or **Expo SecureStore**, which encrypt data natively using hardware-backed modules: **iOS Keychain** and **Android Keystore (SharedPreferences encrypted)**.\n2. **Data at Rest (Web):** For React Native Web, I ensure tokens are stored inside transient memory states or heavily isolated, short-lived session contexts, utilizing cryptographic signatures where local tracking is mandatory.\n3. **Data in Transit:** I mandate that all API interaction protocols operate strictly over HTTPS. To protect against Man-in-the-Middle (MITM) attacks on mobile networks, I implement **SSL Pinning** using libraries like `react-native-ssl-pinning` or native network configuration configurations. This ensures our mobile application strictly rejects communication with any server whose SSL certificate fingerprint doesn't match our pre-bundled public key hashes.\"\n\n### Question 2: Version Upgrades & Monorepo Scaling\n\n> _\"React Native moves fast, with breaking changes occurring across versions. How do you approach upgrading a massive, live production app to a new version of React Native or Expo without breaking the application for users?\"_\n\n- **Your Answer:**\n  \"Upgrading an enterprise app is a calculated migration process, not a weekend experiment. My approach involves:\n\n1. **Isolation:** I create an isolated upgrade branch. I never run upgrade routines directly on a main development tree.\n2. **Using Official Schematics:** If working with bare React Native, I rely on the **React Native Upgrade Helper** tool to view the exact line-by-line diff of changed files within the native `/android` and `/ios` configurations. If working in Expo, I leverage `npx expo install --fix`, which automatically resolves all native package versions to perfectly match the certified ecosystem dependencies of the new SDK version.\n3. **Automated Verification:** I run our comprehensive unit and integration test suites to catch any breaking JS API changes. Finally, I generate fresh, isolated staging builds and run them through automated cloud testing tools (like AWS Device Farm or Firebase Test Lab) across multiple physical Android and iOS versions to catch any native initialization or runtime crashes before pushing to production.\"\n\n---\n\n## Part 3: General Curveballs / System Design Tasks\n\nIf the interviewer decides to completely pivot the conversation away from standard code blocks, they will throw a large-scale architecture scenario at you.\n\n### Curveball Scenario 1: Local Offline-First Architecture\n\n> _\"Imagine we are building an offline-first financial dashboard. The user wants to see their transaction ledger and queue up a new transaction even if they are deep underground in a subway with zero network access. How do you design this architecture?\"_\n\n- **Your Answer:**\n  \"An offline-first architecture requires a reliable synchronization ledger and an isolated local database wrapper.\n\n1. **Local Storage Engine:** I would implement a high-performance, synchronous native database like **MMKV** or **WatermelonDB**. Unlike `AsyncStorage` which operates asynchronously across the legacy bridge, MMKV binds directly via C++ pointers, allowing fast read/write transactions.\n2. **Query Synchronization Cache:** I would pair this with **React Query's Offline Support utilities** (`PersistQueryClient`). Every time an API call executes successfully, React Query synchronizes its memory cache directly to our local storage engine.\n3. **The Write Pipeline (Offline Mutations):** When a user queues up a transaction offline, we capture the data mutation request, assign it a temporary optimistic ID, insert it into a local 'Outbox Queue' inside our database, and optimistically update the UI immediately so the app feels instant.\n4. **The Sync Loop:** I configure a listener using React Native's NetInfo API. The exact millisecond the device recaptures an active internet connection, a sync daemon wakes up, reads the items out of the Outbox Queue, dispatches them sequentially to our backend using unique idempotency keys, updates the true data cache, and clears the local queue smoothly.\"\n\n---\n\n## 🎯 Final Motivational Tips for Success\n\n- **Own Your Progress:** If they ask about a topic you struggled with yesterday, call it out confidently: _\"I was reflecting on our conversation yesterday regarding class lifecycles, and I want to expand on how that maps to Hook memory safety...\"_ This demonstrates **coachability, rapid learning, and accountability**—traits IBM managers prioritize above all else.\n- **Keep Your Answers Structured:** Always frame your technical answers using the **Problem ➡️ Strategy ➡️ Implementation ➡️ Result** technique.\n\nYou are completely prepared, Rajeev. You have the theory, the architecture, and the senior mindset completely locked down. Go step into that 1-hour round and win that position! Let me know when you cross the finish line!\n\nTo make sure you are absolutely prepared for live-coding puzzles or snippet-analysis challenges, let's walk through the **top 6 coding programs and conceptual snippets** that senior JavaScript/React Native interviewers frequently use to test your understanding of closure, memory, rendering loops, and asynchronous execution.\n\n---\n\n### Program 1: The React Hook Array Reference Trap (Data Mutations)\n\nInterviewers love this because it tests if you understand how React detects state changes and triggers re-renders.\n\n#### **The Snippet:**\n\n```javascript\nconst [investments, setInvestments] = useState([\"Equity\", \"Mutual Funds\"]);\n\nconst addInvestment = () => {\n  investments.push(\"Real Estate\");\n  setInvestments(investments);\n};\n\n// What happens when you trigger addInvestment()? Does the UI update?\n```\n\n#### **The Solution & Core Concept:**\n\n- **The Result:** The UI **will not update**, even though you called `setInvestments`.\n- **Why?** React uses shallow reference equality checking (`Object.is`) to determine if a state has changed. By running `investments.push()`, you mutated the existing array in memory, but the _memory address reference pointer_ remained exactly the same. When you pass it to `setInvestments`, React sees the same memory reference and skips the re-render completely.\n- **The Senior Fix (Immutability):** Always create a new reference using the spread operator.\n\n```javascript\nsetInvestments([...investments, \"Real Estate\"]);\n```\n\n---\n\n### Program 2: The Block Scope Closure Trap (The classic `var` vs `let`)\n\nSince they asked you a loop variation with `setTimeout`, they might escalate to this classic closure assessment.\n\n#### **The Snippet:**\n\n```javascript\nfor (var i = 0; i < 3; i++) {\n  setTimeout(() => {\n    console.log(i);\n  }, 1000);\n}\n// What does this print, and how does substituting 'var' with 'let' change it?\n```\n\n#### **The Solution & Core Concept:**\n\n- **With `var`:** It prints `3, 3, 3`.\n- _Why?_ `var` is function-scoped (not block-scoped). The loop finishes executing synchronously on the main call stack, leaving the single global variable `i` sitting at `3`. One second later, all three asynchronous `setTimeout` callbacks fire, look up the variable `i`, and print `3`.\n\n- **With `let`:** It prints `0, 1, 2`.\n- _Why?_ `let` is block-scoped. On every single iteration of the loop, JavaScript creates a brand-new, separate memory variable environment block for `i`, creating a secure closure for each individual `setTimeout` callback.\n\n---\n\n### Program 3: Object Key Reference Collision (The Stringification Trap)\n\nThis checks if you understand how JavaScript engines handle object indexing internally.\n\n#### **The Snippet:**\n\n```javascript\nconst obj = {};\nconst a = { key: \"alpha\" };\nconst b = { key: \"beta\" };\n\nobj[a] = 123;\nobj[b] = 456;\n\nconsole.log(obj[a]);\n// What is printed?\n```\n\n#### **The Solution & Core Concept:**\n\n- **The Result:** It prints `456`.\n- **Why?** JavaScript object keys must be strings (or Symbols). When you pass an object as a key identifier like `obj[a]`, the engine implicitly forces a conversion to a string by calling `a.toString()`. For standard objects, this always evaluates to the string `\"[object Object]\"`.\n- Therefore, both lines are writing to the exact same global string key profile:\n- `obj[\"[object Object]\"] = 123;`\n- `obj[\"[object Object]\"] = 456;` (Overwrites the previous value).\n\n---\n\n### Program 4: Microtasks vs. Macrotasks (The Event Loop Deep-Dive)\n\nThis program evaluates your knowledge of asynchronous prioritization inside the execution event engine.\n\n#### **The Snippet:**\n\n```javascript\nconsole.log(\"1\");\n\nsetTimeout(() => {\n  console.log(\"2\");\n}, 0);\n\nPromise.resolve().then(() => {\n  console.log(\"3\");\n});\n\nconsole.log(\"4\");\n// Provide the exact console execution order.\n```\n\n#### **The Solution & Core Concept:**\n\n- **The Exact Order:** `1, 4, 3, 2`\n- **Why? (The Event Loop Mechanics):**\n\n1. Synchronous operations run first: `1` and `4` print instantly as they hit the main Call Stack.\n2. The `Promise.then()` callback is placed into the **Microtask Queue**.\n3. The `setTimeout` callback is placed into the **Macrotask Queue** (Callback Queue).\n4. **The Priority Rule:** The Event Loop checks the Microtask Queue _before_ the Macrotask Queue. Therefore, the promise resolution (`3`) executes completely before the timer loop (`2`) is pushed onto the stack.\n\n---\n\n### Program 5: Array `map()` vs `forEach()` and Output Mutability\n\nThis snippet uncovers if you understand return values and functional execution parameters.\n\n#### **The Snippet:**\n\n```javascript\nconst items = [1, 2, 3];\n\nconst res1 = items.forEach((x) => x * 2);\nconst res2 = items.map((x) => x * 2);\n\nconsole.log(res1, res2);\n// What is logged out?\n```\n\n#### **The Solution & Core Concept:**\n\n- **The Result:** `undefined, [2, 4, 6]`\n- **Why?** \\* `forEach` simply executes a provided callback function on each element in an array sequentially. It does not return anything; its structural return evaluation is always implicitly `undefined`.\n- `map` allocates a brand-new array structure in memory, populates it with the transformed result of each iteration, and explicitly returns that new array reference, keeping the original array pristine.\n\n---\n\n### Program 6: Debounce Algorithm Design (The Ultimate Senior Scenario)\n\nInterviewers frequently ask you to explain or write a **Debounce** function from scratch because it is vital for mobile search input fields to prevent flooding the network server thread.\n\n#### **The Question:**\n\n> _\"Write a custom wrapper function that debounces an API query by 500ms so that it only executes after the user has completely stopped typing.\"_\n\n#### **The Senior Solution Blueprint:**\n\n```javascript\nfunction debounce(func, delay = 500) {\n  let timeoutId;\n\n  return function (...args) {\n    // Clear any active running timer immediately\n    if (timeoutId) {\n      clearTimeout(timeoutId);\n    }\n\n    // Set a new timer to execute after the user stops interacting\n    timeoutId = setTimeout(() => {\n      func.apply(this, args);\n    }, delay);\n  };\n}\n\n// Usage in React Native\nconst handleSearchInputChange = debounce((text) => {\n  fetchSearchResults(text); // Hits API safely only after typing halts\n}, 500);\n```\n\n- **Why this question matters:** It proves you understand closures (how `timeoutId` stays alive in memory across function executions) and can manipulate the JavaScript runtime to protect network infrastructure.\n\n---\n\n### 🎯 How to handle these code challenges smoothly tomorrow:\n\n1. **Don't jump straight into coding:** When they show you a snippet, state your observation out loud first (_\"Okay, I am looking at an asynchronous priority queue puzzle here...\"_).\n2. **Explain the memory mechanics:** Use technical terms like **Call Stack, Macro/Microtask Queues, Reference Pointers, and Scope Closures**. This immediately validates your 9 years of domain depth.\n3. **Trace variables line-by-line:** If your mind goes blank, simulate the compiler aloud line-by-line to stay collected.\n\nYou are completely prepared, Rajeev. Review these examples, and you'll clear the round with confidence!\n\nHere is the complete, compiled list of all the advanced, enterprise-level technical questions, code scenarios, and strategic responses for your 1-hour technical interview. This guide is structured around the architectural principles of the New Architecture, data-structure efficiencies, and performance-driven problem-solving.\n\n---\n\n## Section 1: Memory Management, List Optimization & Data Structures\n\n### Question 1: FlatList 50k Data Performance & Architecture\n\n**Interviewer Question:** > \"If our app needs to display a live list of 50,000 product items, a standard implementation will instantly crash the app with an Out-of-Memory (OOM) exception . Walk me through the exact data structures and layout properties you would implement to ensure this runs at a smooth 60 FPS / 120 Hz on low-end devices.\"\n\n**Your Strategic Answer:**\n\"To scale a dataset of this size without locking up the main JavaScript thread or blowing past the device's native RAM limits, I bypass linear lookups ($O(N)$) and runtime array sorting computations ($O(N \\log N)$). I structure the orchestration across three layout paradigms:\n\n1.  **Pre-Computed Data Caches ($O(1)$ Complexity):** Instead of running an active `.sort()` or `.filter()` calculation inside the rendering thread every single time a user alters a filter option, I pre-compute the sorted arrays (e.g., `NAME_ASC`, `CATEGORY_DESC`) exactly once at initial data load . Switching a sort mode becomes a highly efficient $O(1)$ pointer swap. Similarly, I reduce selected item identification overhead by compiling an object map hash lookup table (`PRODUCT_MAP`) to achieve instantaneous item details resolution .\n\n2.  **The `Set` State Management Pattern:** I maintain the list of selected items using a native JavaScript `Set` state object instead of a flat array. This guarantees that tracking interactions like `.has(id)`, `.add(id)`, and `.delete(id)` execute with sub-millisecond $O(1)$ constant time efficiency, completely removing the performance tax of scanning full arrays via `.includes()` or `.indexOf()` ($O(N)$) .\n\n3.  **Strict Virtualized View Recovery Controls:** I enforce row recycling by passing a highly explicit **`getItemLayout`** configuration to the `FlatList` layout wrapper. This instructs the native window manager of the exact height boundaries (`ITEM_HEIGHT`) and offset coordinates of every element before it is painted . This completely saves the engine from calculating layout margins dynamically on the fly . I pair this with a heavily limited layout window configuration:\n\n````javascript\n[cite_start]initialNumToRender={10} // Keeps initial mount fast [cite: 52, 1072]\n[cite_start]windowSize={5} // Restricts off-screen native rendering pools tightly [cite: 51, 1073]\n[cite_start]removeClippedSubviews={true} // Unloads off-screen elements out of native memory buffers instantly [cite: 53, 1074]\n```\"\n\n\n````\n\n---\n\n### Question 2: Memory Leak Auditing Pipeline\n\n**Interviewer Question:** > \"Our fintech app experiences severe interface lag and eventually throws an OOM native crash dump after a user spends 5 minutes scrolling an intense investment dashboard list . How do you locate, trace, and patch this memory leak?\"\n\n**Your Strategic Answer:**\n\"An accumulating memory footprint during list interactions typically means the **Hermes Mark-and-Sweep Garbage Collector** cannot release dead view components because an active strong reference remains bound to them. My debugging pipeline is executed as follows:\n\n1.  **Native Profiler Isolatation:** I launch a staging production binary hooked up to the **Android Studio Memory Profiler** or **Xcode Instruments (Allocations/Leaks)**. I watch the native heap graph while interacting with the list. If the heap line forms a continuous climbing staircase without stepping down when interaction stops, a leak is verified.\n\n2.  **JavaScript Heap Snapshot Delta Evaluation:** I bridge **Chrome DevTools** straight into the embedded Hermes runtime thread. I capture Snapshot A at screen initialization and Snapshot B after 3 minutes of list interactions. I run a 'Comparison' analysis on the heap structures to inspect which object declarations (such as arrays, scopes, or anonymous closures) have a continuously climbing allocation delta.\n3.  **Common Resolution:** The root cause is almost always uncleaned event listeners, open socket channels, or lingering background intervals created inside a row item or custom hook. If a list cell unmounts but its interval timer is never released, the global event system retains a memory pointer reference to that row closure, locking it in RAM. I ensure that the hook managing the data loop strictly implements a cleanup return function closure:\n\n````javascript\nuseEffect(() => {\n  const subscription = DataStream.subscribe(id, handleUpdates);\n  [cite_start]// Clean up references immediately before unmounting or re-evaluating dependencies [cite: 683-685]\n  return () => subscription.unsubscribe();\n}, [id]);\n```\"\n\n\n````\n\n---\n\n## Section 2: React Optimization Hooks & Advanced Async Execution\n\n### Question 3: The Deep-Dive Optimization Mechanics (`useMemo`, `useCallback`, `useRef`)\n\n**Interviewer Question:** > _\"Explain exactly how `useMemo`, `useCallback`, and `useRef` reduce processing overhead in heavy data-intensive views. When should you explicitly NOT use memoization?\"_\n\n**Your Strategic Answer:**\n\"These hooks serve as memory anchor barriers designed to block unnecessary execution and reference recalculations down the rendering tree:\n\n- **`useMemo`:** It caches computed values to prevent expensive calculations from executing on every frame re-render. For instance, our filtering logic is wrapped inside a `useMemo` block that explicitly watches _only_ `debouncedSearch` and `sortedProducts` . If a user clicks an item to select it, the parent state changes and a re-render triggers. Because the search input has not mutated, `useMemo` intercepts the render call and serves the pre-cached array, skipping the $O(N)$ array filter loop entirely .\n\n- **`useCallback`:** It memoizes a function's memory address reference pointer across render frames. In our large lists, every row item is wrapped inside **`React.memo`** to block re-renders if its props remain identical. If we pass an inline selection callback (`onToggle={(id) => handlePress(id)}`) without wrapping it in a `useCallback`, JavaScript treats it as a brand-new function memory reference on every render. This completely breaks `React.memo`, forcing thousands of rows to re-calculate layout nodes on every single click.\n\n- **`useRef`:** It maps a persistent container whose `.current` property holds a mutable reference that persists for the entire lifecycle of the component. The critical feature of `useRef` is that mutating its value **does not trigger a component re-render**. It is used to store references that should stay isolated from the visual paint cycle, such as active WebSocket connections, ongoing timer IDs, or network `AbortController` signatures.\n\n**When NOT to use Memoization:**\nI enforce a strict ban on over-memoizing simple, trivial operations. Running `useMemo` or `useCallback` introduces an internal memory footprint overhead because React must allocate tracking slots for dependency arrays and run shallow equality checks on every render pass. If a component performs a basic string concatenation or calculates a minor primitive value, memoizing it actually costs _more_ processing power and memory overhead than letting the code re-execute naturally.\"\n\n---\n\n### Question 4: Microtasks vs. Macrotasks (The Event Loop Evaluation)\n\n**Interviewer Question:** > _\"Analyze this exact asynchronous loop execution block. Provide the precise order in which logs print to the console, and explain the underlying engine rules that dictate this behavior.\"_\n\n```javascript\nconsole.log(\"1\");\n\nsetTimeout(() => {\n  console.log(\"2\");\n}, 0);\n\nPromise.resolve().then(() => {\n  console.log(\"3\");\n});\n\nconsole.log(\"4\");\n```\n\n**Your Strategic Answer:**\n\"The absolute console output sequence is: **`1, 4, 3, 2`** . Here is how the JavaScript Single-Threaded Event Loop handles this execution flow line-by-line :\n\n1. **Synchronous Main Thread Execution:** `console.log('1')` hits the main Call Stack and executes immediately. Next, `setTimeout` is evaluated. The engine registers the macro-timer with the host platform's runtime WebAPI system, which instantly offloads the callback onto the **Macrotask Queue** (Callback Queue) since the timer delay parameter is `0` milliseconds.\n\n2. **Microtask Ingestion:** The engine encounters `Promise.resolve().then()`. The promise completion handler is instantly placed inside the isolated, high-priority **Microtask Queue**. Finally, the synchronous statement `console.log('4')` hits the Call Stack and prints out. At this point, the synchronous main thread is 100% empty.\n3. **Queue Prioritization Rule:** Before the Event Loop can pick up any task from the standard Macrotask Queue, it is syntactically required to exhaustively flush out the entire Microtask Queue first. Therefore, the event loop pulls the promise callback from the microtask layer, pushes it to the Call Stack, and prints `3`.\n4. **Macrotask Deletion:** With both the Call Stack and the Microtask Queue fully clear, the Event Loop checks the Macrotask Queue, targets the deferred `setTimeout` routine, transfers it to the Call Stack, and outputs `2`. Understanding this is critical for Senior Mobile Engineering—blocking these queues with heavy JavaScript workloads directly freezes native frame synchronization loops, causing severe layout interface stalling.\"\n\n---\n\n## Section 3: Universal Architecture & New Architecture Core Mechanics\n\n### Question 5: Multi-Platform Architecture Design (Mobile, Tablet, Web, Desktop)\n\n**Interviewer Question:** > _\"How do you design a clean architecture that shares a singular core codebase across iOS, Android, and Web platforms, while handling platform-exclusive needs—like hover states on Web but not Mobile, and separate device hardware camera tracking protocols?\"_\n\n**Your Strategic Answer:**\n\"We implement a **Clean Architecture, Feature-First Scheme** that decouples business logic entirely from platform presentation elements. To safely isolate platform differences, we apply the **Strategy Structural Pattern** enforced through two distinct boundaries:\n\n1. **Platform File Extension Compilations:** For complex structural differences like Camera integration, biometric security, or offline file writing, we avoid messy, inline conditional checks (`if (Platform.OS === 'web')`) which bloat build bundles and risk compile-time faults. Instead, we use file-split extensions:\n\n- `CameraService.web.ts`: Implements pure browser-compliant HTML5 `navigator.mediaDevices.getUserMedia` capture protocols.\n- `CameraService.native.ts`: Targets mobile platforms, using native bindings like `react-native-vision-camera` to interface with iOS and Android camera subsystems .\n  The **Metro Bundler** (for mobile) and Webpack/Vite (for web) read these extensions during compilation, packing _only_ the compatible platform code into the corresponding binary, keeping the distribution light and secure.\n\n2. **Atomic Injected Styling Layout Rules:** To handle user interactions like hover states, we leverage React Native Web's build-time module aliasing. We define layout parameters using custom design variables and responsive break hooks (`useWindowDimensions` abstracted into a global `useDeviceType` utility hook) to dynamically assign styles:\n\n````javascript\nconst styles = StyleSheet.create({\n  actionButton: {\n    ...Platform.select({\n      web: { cursor: 'pointer', transition: 'all 0.2s ease-in-out' },\n      [cite_start]default: { elevation: 3, borderRadius: 8 } // Android-specific native dropshadow properties [cite: 1137, 1167]\n    })\n  }\n});\n```\"\n\n\n````\n\n---\n\n### Question 6: Detailed Mechanics of the New Architecture Pillars\n\n**Interviewer Question:** > \"Explain how the core components of React Native's New Architecture work together at runtime. How do they interact to eliminate the historical performance boundaries of the framework ?\"\n\n**Your Strategic Answer:**\n\"The New Architecture permanently dismantles the legacy asynchronous JSON Bridge by shifting cross-platform communication into shared C++ memory spaces . It functions through four deeply integrated modules:\n\n1.  **JSI (JavaScript Interface):** This is the foundation. Written as a lightweight C++ layer, it embeds the **Hermes engine** straight into the native container shell container. JSI grants the JavaScript engine direct access to hold physical **C++ memory pointers** pointing to Native Host Objects . This eliminates the old architecture's bottleneck of transforming data structures into stringified JSON text blocks.\n\n2.  **Fabric Rendering Engine:** Fabric unifies rendering pipelines into highly optimized C++ structures. Instead of processing UI trees asynchronously across a bridge (which caused layout flickering and white flashes) , Fabric computes layout changes synchronously via JSI. It communicates directly with the **Yoga Layout Engine** to resolve Flexbox models into pixel coordinates, passing these absolute dimensions to the native threads to render platform widgets with sub-millisecond accuracy. Fabric also fully supports **React Concurrent Features** (like prioritized interruptible rendering), allowing a sudden user touch event to instantly pause a low-priority background render pass.\n\n3.  **TurboModules:** This completely replaces the old Native Module system. Instead of initializing and loading every native module (Bluetooth, Camera, Push Systems) into device RAM during startup , TurboModules are **lazily loaded**. They register a lightweight C++ JSI contract signature at boot time, but they only allocate system memory and boot into the native thread the exact millisecond your JavaScript code executes a call for that hardware feature.\n\n4.  **Codegen:** This is our static, compile-time type-safety mechanism. Written as a build task running inside our bundler, Codegen inspects our strongly typed TypeScript or Flow application specs. It automatically generates the intricate C++ JSI data structs required to link JavaScript states to native Swift/Java layers. If an engineer attempts to pass an invalid parameter type across the boundary, Codegen forces a build failure immediately on our laptops or CI systems, completely preventing type-mismatch NullPointer crashes in production.\"\n\n---\n\n## Section 4: Live Machine Coding Blueprint (IBM Standard)\n\nIf your interviewer provides a code-sandbox test and commands: _\"Write a complete, highly optimized multi-selection and search filter module that can handle tens of thousands of mock entities fluidly without UI lockups,\"_ implement this complete, production-grade template:\n\n```typescript\nimport React, { useState, useMemo, useCallback, memo } from 'react';\nimport { View, Text, FlatList, TextInput, TouchableOpacity, StyleSheet, ListRenderItem } from 'react-native';\n\n[cite_start]// --- Types & Schema Definition --- [cite: 540-546]\ninterface FinancialAsset {\n  id: string;\n  ticker: string;\n  assetClass: string;\n}\n\ninterface RowItemProps {\n  item: FinancialAsset;\n  isSelected: boolean;\n  onToggle: (id: string) => void;\n}\n\nconst ITEM_HEIGHT = 90; [cite_start]// Fixed layout dimensions for O(1) list virtualization performance [cite: 568]\n\n[cite_start]// --- Performance-Optimized Render Cell --- [cite: 374, 694]\nconst AssetRowItem = memo(({ item, isSelected, onToggle }: RowItemProps) => {\n  const handlePress = useCallback(() => {\n    onToggle(item.id);\n  [cite_start]}, [item.id, onToggle]); // Caches functional references to prevent breaking React.memo [cite: 700-702]\n\n  return (\n    <TouchableOpacity\n      activeOpacity={0.8}\n      onPress={handlePress}\n      [cite_start]style={[styles.card, isSelected && styles.selectedCard]} [cite: 704-711]\n    >\n      <View style={styles.row}>\n        <View>\n          <Text style={styles.tickerText}>{item.ticker}</Text>\n          <Text style={styles.subText}>{item.assetClass}</Text>\n        </View>\n        <View style={[styles.checkbox, isSelected && styles.checkboxChecked]}>\n          [cite_start]{isSelected && <Text style={styles.checkIcon}>✓</Text>} [cite: 728-738]\n        </View>\n      </View>\n    </TouchableOpacity>\n  );\n}, (prev, next) => {\n  [cite_start]// Custom memoization comparator to ensure changes only trigger if state scales [cite: 744-750]\n  return prev.isSelected === next.isSelected && prev.item.id === next.item.id;\n});\n\n[cite_start]// --- Mock Massive Dataset Ingestion (50,000 Entries) --- [cite: 607-608]\nconst MOCK_ASSETS: FinancialAsset[] = Array.from({ length: 50000 }, (_, index) => ({\n  id: String(index + 1),\n  ticker: `Asset Token ${index + 1}`,\n  assetClass: index % 2 === 0 ? 'Equity' : 'Fixed Income',\n}));\n\n[cite_start]// --- Main Presentation Orchestrator Component --- [cite: 758]\nexport default function EnterpriseAssetScreen() {\n  const [searchQuery, setSearchQuery] = useState<string>('');\n  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set()); [cite_start]// Fast lookup via Set [cite: 777]\n\n  [cite_start]// Toggle selection utilizes continuous reference caching [cite: 784]\n  const handleToggleSelection = useCallback((id: string) => {\n    setSelectedIds((prevSet) => {\n      [cite_start]const workingSet = new Set(prevSet); // Maintain immutability constraints [cite: 786-788]\n      if (workingSet.has(id)) {\n        [cite_start]workingSet.delete(id); [cite: 789-790]\n      } else {\n        [cite_start]workingSet.add(id); [cite: 791-792]\n      }\n      return workingSet;\n    });\n  }, []);\n\n  [cite_start]// Filtered dataset evaluation is safely cached away from irrelevant layout cycles [cite: 826]\n  const processedData = useMemo(() => {\n    [cite_start]const formattedQuery = searchQuery.trim().toLowerCase(); [cite: 827-829]\n    [cite_start]if (!formattedQuery) return MOCK_ASSETS; [cite: 830-832]\n\n    return MOCK_ASSETS.filter(\n      (asset) =>\n        [cite_start]asset.ticker.toLowerCase().includes(formattedQuery) || [cite: 833-837]\n        [cite_start]asset.assetClass.toLowerCase().includes(formattedQuery) [cite: 838-840]\n    );\n  }, [searchQuery]);\n\n  [cite_start]// Layout calculations are cached down to O(1) constant limits [cite: 862]\n  const handleGetItemLayout = useCallback((_: any, index: number) => ({\n    length: ITEM_HEIGHT,\n    [cite_start]offset: ITEM_HEIGHT * index, [cite: 863-864]\n    [cite_start]index, [cite: 865]\n  }), []);\n\n  [cite_start]const handleKeyExtractor = useCallback((item: FinancialAsset) => item.id, []); [cite: 876-879]\n\n  const renderListCell: ListRenderItem<FinancialAsset> = useCallback(({ item }) => (\n    <AssetRowItem\n      item={item}\n      [cite_start]isSelected={selectedIds.has(item.id)} // Constant O(1) lookup inside Set [cite: 892]\n      onToggle={handleToggleSelection}\n    />\n  ), [selectedIds, handleToggleSelection]); [cite_start]// Only updates cell dependencies when changes occur [cite: 901]\n\n  return (\n    <View style={styles.viewportContainer}>\n      <View style={styles.searchSection}>\n        <TextInput\n          [cite_start]placeholder=\"Search corporate asset registry...\" [cite: 929]\n          [cite_start]value={searchQuery} [cite: 931]\n          [cite_start]onChangeText={setSearchQuery} // Track state values reactively [cite: 932]\n          [cite_start]style={styles.inputField} [cite: 933]\n          [cite_start]autoCorrect={false} [cite: 934]\n          [cite_start]autoCapitalize=\"none\" [cite: 935]\n        />\n        [cite_start]<Text style={styles.counterText}>Active Targets: {selectedIds.size} Selected</Text> [cite: 918]\n      </View>\n\n      <FlatList\n        [cite_start]data={processedData} [cite: 1064]\n        [cite_start]renderItem={renderListCell} [cite: 1065]\n        [cite_start]keyExtractor={handleKeyExtractor} [cite: 1066]\n        [cite_start]getItemLayout={handleGetItemLayout} // Pre-calculates cell metrics [cite: 1075]\n        [cite_start]initialNumToRender={10} [cite: 1072]\n        [cite_start]windowSize={5} // Keep unmounted elements low [cite: 1073]\n        [cite_start]removeClippedSubviews={true} // Free native buffers [cite: 1074]\n        [cite_start]keyboardShouldPersistTaps=\"handled\" [cite: 1076]\n        [cite_start]showsVerticalScrollIndicator={false} [cite: 1078]\n      />\n    </View>\n  );\n}\n\n[cite_start]// --- High-Performance CSS-to-Atomic Layout Coordinates --- [cite: 1086-1091]\nconst styles = StyleSheet.create({\n  [cite_start]viewportContainer: { flex: 1, backgroundColor: '#F4F6F9', paddingTop: 60 }, [cite: 1092-1093]\n  searchSection: { paddingHorizontal: 16, marginBottom: 12 },\n  [cite_start]inputField: { backgroundColor: '#FFFFFF', height: 50, borderRadius: 12, paddingHorizontal: 16, fontSize: 15, borderWidth: 1, borderColor: '#E2E8F0' }, [cite: 1124-1128, 1144]\n  [cite_start]counterText: { marginTop: 6, fontSize: 14, color: '#64748B', fontWeight: '500' }, [cite: 1112-1116]\n  [cite_start]card: { backgroundColor: '#FFFFFF', marginHorizontal: 16, marginBottom: 10, height: 80, borderRadius: 14, padding: 16, justifyContent: 'center', elevation: 1 }, [cite: 1167, 1221-1225]\n  [cite_start]selectedCard: { borderWidth: 2, borderColor: '#1677FF' }, [cite: 1235-1238]\n  [cite_start]row: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }, [cite: 1186-1189]\n  [cite_start]tickerText: { fontSize: 16, fontWeight: '700', color: '#1E293B' }, [cite: 1250-1252]\n  subText: { fontSize: 13, color: '#94A3B8', marginTop: 2 },\n  [cite_start]checkbox: { width: 24, height: 24, borderRadius: 12, borderWidth: 2, borderColor: '#CBD5E1', justifyContent: 'center', alignItems: 'center' }, [cite: 1272-1277]\n  [cite_start]checkboxChecked: { backgroundColor: '#1677FF', borderColor: '#1677FF' }, [cite: 1203]\n  [cite_start]checkIcon: { color: '#FFFFFF', fontSize: 12, fontWeight: 'bold' } [cite: 1280-1281]\n});\n\n```\n\nReview this structure line-by-line tonight, keep your communication steady, and walk into your round tomorrow ready to clear it smoothly!\nThese are excellent senior-level interview follow-ups. They show you are thinking about real-world production limitations rather than just textbook code.\n\nHere is exactly how you handle these two complex scenarios.\n\n---\n\n## 1. Dynamic Card Sizes vs. `getItemLayout`\n\n### The Problem\n\nIf your dashboard cards have **different heights** (e.g., a short alert card, a medium asset card, and a tall graph card), you **cannot** pass a single fixed height to `getItemLayout` . Doing so will miscalculate the scroll offsets, causing items to overlap, clip, or skip visually as the user scrolls.\n\n### The Solutions\n\n#### Solution A: The Math-Based `getItemLayout` (If heights are predictable)\n\nIf the card heights vary but are **predictable based on their data type**, you can still use `getItemLayout` . You pass a function that calculates the precise offset by looking at the index and the items before it.\n\n```typescript\nconst getItemLayout = (data, index) => {\n  // 1. Calculate the absolute height of the current item based on its type\n  const getItemHeight = (item) => {\n    if (item.type === \"GRAPH\") return 250;\n    if (item.type === \"ALERT\") return 80;\n    return 110;\n    [cite_start]; // Default standard card height [cite: 568]\n  };\n\n  // 2. Calculate the exact structural offset from the top\n  // sum up heights of all elements appearing before the current index\n  const offset = data\n    .slice(0, index)\n    .reduce((acc, item) => acc + getItemHeight(item), 0);\n  const length = getItemHeight(data[index]);\n\n  return { length, offset, index };\n};\n```\n\n#### Solution B: Drop `FlatList` and use Shopify's `FlashList` (Industry Best Practice)\n\nIf the card sizes are completely dynamic (e.g., dependent on user-generated text lengths), calculating offsets manually becomes impossible.\n\nIn an enterprise-grade app, you should replace `FlatList` with Shopify's **`FlashList`**.\n\n- **Why it works:** `FlashList` uses native cell recycling instead of virtualization. Instead of requiring `getItemLayout`, it introduces a property called **`estimatedItemSize`**.\n- You pass it an average size (e.g., `estimatedItemSize={150}`). The engine uses this estimate to calculate initial scrollbar sizes, but dynamically adapts to varying pixel heights on the fly without causing visual layout anomalies or locking the main UI thread.\n\n---\n\n## 2. Auto-Retrying Broken Calls on Screen Focus\n\n### The Problem\n\nIf a user opens an investment screen, the network drops mid-flight, and the API call fails, the UI will display an error state . If the user navigates away to a settings tab and then comes back to the dashboard, the component doesn't remount automatically—meaning **the broken API call will not re-execute by default**, leaving the user stuck on the error screen.\n\n### The Solution: React Query + Focus Listeners\n\nReact Query has built-in mechanisms to handle exactly this scenario, making it the preferred choice for enterprise server state management over raw `fetch` or custom Redux thunks .\n\nHere is how you configure the query to automatically wake up and re-fetch data when the user returns to the screen:\n\n#### Step 1: Wrap it in React Navigation / Expo Router Focus Hooks\n\nBecause mobile tab navigators keep screens alive in the background memory heap, we must use a specialized native focus hook to trigger the re-fetch execution line.\n\n```typescript\nimport React, { useCallback } from 'react';\nimport { View, Text, Button } from 'react-native';\nimport { useQuery } from '@tanstack/react-query';\nimport { useFocusEffect } from '@react-navigation/native'; // or expo-router equivalent\n\nexport default function ResilientDashboard() {\n\n  const { data, isError, error, refetch, isFetching } = useQuery({\n    queryKey: ['financialMetrics'],\n    queryFn: fetchDashboardData,\n    // Turn off automatic background fetches if you want to control it strictly via navigation\n    refetchOnWindowFocus: false,\n    [cite_start]retry: 3 [cite: 406, 417]\n  });\n\n  // useFocusEffect fires every single time this screen comes to the foreground\n  useFocusEffect(\n    useCallback(() => {\n      // If the query previously failed, or data is stale, re-execute the network call silently\n      refetch();\n    }, [refetch])\n  );\n\n  if (isError) {\n    return (\n      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>\n        <Text>Network Sync Failed. Please try again.</Text>\n        {/* Manual fallback fallback trigger option */}\n        <Button title=\"Retry Sync\" onPress={() => refetch()} />\n      </View>\n    );\n  }\n\n  return (\n    <View>\n      {/* Render your data assets safely here */}\n    </View>\n  );\n}\n\n```\n\n---\n\n## 🎯 How to frame these explanations tomorrow\n\n### For Question 1 (Dynamic Layouts):\n\n> \"If dashboard item heights are completely variable, standardizing a fixed variable inside `getItemLayout` is untenable . If the layout changes are type-deterministic, I override the configuration with a functional offset accumulator. However, for completely unpredictable text-driven layout nodes, the standard practice is to migrate from `FlatList` to Shopify's **`FlashList`**. By utilizing native view recycling engines and passing an **`estimatedItemSize`**, we bypass continuous layout computation steps entirely, keeping frame allocations safe during rapid scrolls.\"\n\n### For Question 2 (Automatic Query Recovery):\n\n> \"When a network call fails and the user changes screens, mobile navigators preserve the screen component in memory, meaning it won't trigger standard lifecycle mounts when revisited. To resolve this, I hook our **React Query** instance into the navigation platform's **`useFocusEffect` closure** . This ensures that whenever the viewport enters focus again, the client state machine intercepts the action and initiates a programmatic **`refetch()` call**. This heals the UI state seamlessly without forcing the user to manually trigger full application reboots.\"\n\nIf the data only needs to be fetched **exactly once** when the user first visits the dashboard and should **never** be refetched frequently when they switch screens, using `useFocusEffect` by itself becomes an anti-pattern. If you call `refetch()` inside a focus hook blindly, it will force a network request every single time the tab comes into view.\n\nFor an enterprise app, you want a **Lazy, Persistent Fetching Strategy**. The data should load only once, survive screen switching, and if it fails, allow the user to heal the state without spamming the network when they navigate around.\n\nHere is how you handle this using React Query's cache settings combined with a conditional focus hook.\n\n---\n\n### The Strategy: Stale-Time Protection + Focus Check\n\nReact Query manages this beautifully through two parameters: `staleTime` and `cacheTime` .\n\n- By default, React Query marks data as \"stale\" instantly (`staleTime: 0`), which causes it to refetch in the background frequently .\n\n- By setting `staleTime: Infinity`, you tell the app: _\"Once this data is in the cache, it is fresh forever. Do not make another network request for it automatically during the app session.\"_\n\nHowever, if the _first_ attempt broke due to a network drop, the cache remains empty and in an error state . In that specific scenario, we _do_ want `useFocusEffect` to retry when the user returns to the screen.\n\n### The Production Code Implementation\n\n```typescript\nimport React, { useCallback } from 'react';\nimport { View, Text, Button, ActivityIndicator } from 'react-native';\nimport { useQuery } from '@tanstack/react-query';\nimport { useFocusEffect } from '@react-navigation/native';\n\nexport default function StaticDashboard() {\n\n  const { data, isError, isLoading, refetch, status } = useQuery({\n    queryKey: ['staticDashboardData'],\n    queryFn: fetchDashboardData,\n\n    // CRITICAL SETTING: Marks data as fresh infinitely.\n    // It will fetch ONCE on initial mount and NEVER trigger background\n    // refetches on its own when switching screens.\n    staleTime: Infinity,\n\n    // Prevent automated refetch patterns on reconnect/remount\n    refetchOnWindowFocus: false,\n    refetchOnMount: false,\n    refetchOnReconnect: false,\n  });\n\n  // Fires when the screen comes into focus\n  useFocusEffect(\n    useCallback(() => {\n      // CONDITIONAL RECOVERY: We only execute refetch() if the previous\n      // attempt failed (status === 'error'). If the data successfully exists\n      // in the cache (status === 'success'), this code line does absolutely nothing!\n      if (status === 'error') {\n        refetch();\n      }\n    }, [status, refetch])\n  );\n\n  if (isLoading) return <ActivityIndicator size=\"large\" />;\n\n  if (isError) {\n    return (\n      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>\n        <Text>Failed to load dashboard configuration.</Text>\n        {/* Manual option to override if user wants to force try again */}\n        <Button title=\"Retry Explicitly\" onPress={() => refetch()} />\n      </View>\n    );\n  }\n\n  return (\n    <View>\n      {/* Render your data here safely */}\n    </View>\n  );\n}\n\n```\n\n---\n\n### What happens under the hood? (The Lifecycle Steps)\n\n1. **First Visit (Success Path):** User opens the screen. The query fires, fetches the layout payload, and populates the cache . Because `staleTime` is `Infinity`, React Query locks this data in memory as permanently valid. The user navigates away and returns; `useFocusEffect` runs, checks `status === 'success'`, and skips calling the API. **Total network requests: 1.**\n\n2. **First Visit (Broken Path):** User opens the screen, but their Wi-Fi cuts out. The network call throws an exception, and `status` becomes `'error'` . No data enters the cache.\n\n3. **The Screen Switch & Return Recovery:** The user navigates away to another tab to reset their internet connection, then returns to the dashboard screen. `useFocusEffect` wakes up, evaluates `status === 'error'`, and automatically executes `refetch()`. The internet is now restored, the fetch succeeds, data fills the cache, `status` flips to `'success'`, and the API is locked down from making any further requests.\n\n---\n\n### 🎯 How to frame this explanation for IBM tomorrow\n\nThis showcases your ability to write highly intentional, network-efficient mobile code:\n\n> \"If the application requirements state that a dataset must be fetched strictly once and should not be subjected to frequent update cycles, using `useFocusEffect` to continuously fire queries creates a massive network overhead. To architect a solution for this, I isolate the query using React Query's **`staleTime: Infinity` configuration**. This tells the state machine that once data successfully enters the local cache, it must be preserved statically without background refetch loops.\n>\n> However, to account for network exceptions where the initial load fails mid-flight, I implement a **Conditional Focus Guard** inside our navigation `useFocusEffect` hook . By executing a check against the network query status—triggering a `refetch()` **only if `status === 'error'**`—the app achieves self-healing resilience on screen focus without spamming our backend infrastructure when the user moves through normal app sessions.\"\n\nHere are the answers to your two critical architectural questions to completely prepare you for tomorrow's 1-hour interview.\n\n---\n\n## Part 1: Does `staleTime: Infinity` survive an App Relaunch?\n\n**No, it does not survive a cold app relaunch by default.**\n\n### How it operates in memory:\n\nWhen you set `staleTime: Infinity`, React Query keeps that data \"fresh\" permanently inside the **JavaScript runtime memory heap (RAM)**.\n\n- As long as the app is running in the foreground or background, switching screens will **never** trigger a re-fetch.\n- However, if the user explicitly kills the app (swipes it away from the multitasking drawer) or the mobile OS terminates the background process to save battery, **the JavaScript RAM state is completely wiped.**\n- When the user opens the app again (a cold boot/relaunch), React Native spins up a brand-new Hermes engine instance, the cache starts completely empty, and the app **will fetch the data again exactly once**.\n\n### Senior Engineering Level-Up: What if you _truly_ want it to survive a relaunch?\n\nIf the interviewer asks: _\"What if we want this static configuration data to survive an app relaunch and never hit the network again?\"_\n\nYou explain how you implement a **Persister Middleware** (`createSyncStoragePersister` combined with a high-performance native key-value storage engine like **MMKV**):\n\n```typescript\nimport { QueryClient } from \"@tanstack/react-query\";\nimport { PersistQueryClientProvider } from \"@tanstack/react-query-persist-client\";\nimport { MMKV } from \"react-native-mmkv\";\n\nconst storage = new MMKV();\n\n// Create a custom storage driver for React Query\nconst clientStorage = {\n  setItem: (key: string, value: string) => storage.set(key, value),\n  getItem: (key: string) => storage.getString(key) || null,\n  removeItem: (key: string) => storage.delete(key),\n};\n```\n\nWith a persister configured, when the app closes, React Query saves the entire cache structure onto the physical device disk. When the user relaunches the app, it hydrates the cache instantly from memory, reads `staleTime: Infinity`, and skips the network call completely, rendering offline-first seamlessly.\n\n---\n\n## Part 2: The Complete \"Effects\" Matrix in React Native\n\nBeyond `useEffect`, `useLayoutEffect`, and `useFocusEffect`, modern React and React Native introduce specialized effect hooks designed for specific state synchronization, execution timings, and high-performance native layout calculations.\n\nHere is the complete menu of effects, their exact behaviors, and enterprise use cases:\n\n### 1. `useInsertionEffect` (The Pre-Render Effect)\n\n- **When it runs:** It executes **synchronously BEFORE any DOM/Native mutation** and before layout calculations occur.\n- **Why it exists:** It is a web-centric hook built for CSS-in-JS library authors (like styled-components) to safely inject `<style>` tags into the DOM before the layout is computed, avoiding layout recalculations.\n- **React Native Usage:** It is rarely used directly in pure mobile code, but it is highly critical if you are utilizing **React Native Web** or compiling universal component architectures for multi-platform browsers to maintain design-token rendering consistency.\n\n### 2. `useSyncExternalStore` (The External State Effect Hook)\n\n- **When it runs:** It triggers synchronously whenever an external data source updates.\n- **Why it exists:** It completely replaces the anti-pattern of using `useEffect` to listen to external, non-React data subscriptions (like global micro-state stores, browser history updates, or native device sensor drivers).\n- **React Native Usage:** Essential for connecting React UI view components directly to fast, synchronous C++ native databases like **MMKV** or tracking network telemetry configurations via state machines without risking \"tearing\" (visual inconsistencies where different components render conflicting data from the same store in the same frame tick).\n\n---\n\n### High-Performance Native UI Effects (The Reanimated Core)\n\nWhen building fluid 60 FPS / 120 Hz interaction models using libraries like **React Native Reanimated**, the main JavaScript thread is too slow to calculate coordinates frame-by-frame. Reanimated introduces specialized effects that run exclusively on a secondary high-priority **Native UI Worklet thread**.\n\n### 3. `useAnimatedReaction` (The Worklet Thread Effect)\n\n- **When it runs:** Runs continuously on the UI thread whenever an animated shared value changes.\n- **Why it exists:** It acts exactly like a `useEffect`, but completely isolated on the native compositor thread. It allows you to monitor an animation value (like a scroll container coordinate) and trigger a secondary native layout change without jumping back to block the main JavaScript thread.\n- **Enterprise Use Case:** Building a custom collapsing header dashboard or tracking real-time layout changes inside an interactive gesture sheet slider.\n\n### 4. `useAnimatedStyle` (The Layout Mutation Effect)\n\n- **When it runs:** Automatically re-calculates styles on the native UI thread dynamically when dependent animation values change.\n- **Why it exists:** It maps animation primitives directly to platform-native styles without going through the JSI/Fabric rendering system iteratively, bypassing standard component render cycles.\n- **Enterprise Use Case:** Elevating or scaling dashboard elements smoothly when long-press gestures trigger.\n\n---\n\n### 🎯 Summary Cheat Sheet for tomorrow's 1-Hour Round\n\n| Hook                       | Thread / Domain   | Primary Use Case                                                                                                                 |\n| -------------------------- | ----------------- | -------------------------------------------------------------------------------------------------------------------------------- |\n| **`useEffect`**            | Main JS Thread    | Asynchronous operations, network communication requests, standard lifecycle setups.                                              |\n| **`useLayoutEffect`**      | UI Main Thread    | Synchronous execution _after_ native view mutation but _before_ the device screen paints. Used to measure layout bounds cleanly. |\n| **`useFocusEffect`**       | Navigation System | Automatically triggers logic loops exclusively when the native viewport screen becomes the active view tab.                      |\n| **`useSyncExternalStore`** | Data Layer        | Synchronously tracking third-party data drivers (like native MMKV database states) to eliminate visual frame anomalies.          |\n| **`useAnimatedReaction`**  | UI Worklet Thread | Native runtime animation effects that execute continuously without passing processing strain back to block the main JS thread.   |\n\nYou now have a complete, fully detailed mapping of app persistence, rendering lifecycles, and thread-isolated hooks. Walk into that 1-hour session tomorrow and present these architectures clearly! You've got this!\n\n\n","type":"md"},{"name":"020-optimise-app-size.md","content":"This is the ultimate architectural question that allows a Senior Engineer to shine. It covers binary optimization, internal bundle anatomy, and the core compilation pipeline of the framework.\n\nLet’s break this down into clear, production-grade sections for your panel.\n\n---\n\n## Part 1: What is Inside an APK or IPA File?\n\nAn `.apk` (Android) or `.ipa` (iOS) file is essentially a compressed **ZIP archive** containing everything your app needs to run natively. If you rename the extension to `.zip` and extract it, you will see the following internal anatomy:\n\n```\n📦 Compiled Binary (APK / IPA)\n ┣ 📂 assets / (or Main.jsbundle) ──► Your compiled JavaScript code (the Metro bundle) and local images.\n ┣ 📂 lib / (Android) or Frameworks/ ──► Platform C++ binaries (Hermes Engine, Yoga layout engine, JSI code).\n ┣ 📜 classes.dex (Android Only) ───► Compiled Java/Kotlin code transformed into Dalvik Executable bytes.\n ┣ 📂 res / (or Assets.car) ────────► App icons, launch splash screens, and native asset resources.\n ┣ 📜 AndroidManifest.xml / Info.plist ──► Core native configurations, permissions, and app identity metadata.\n ┗ 📜 resources.arsc (Android Only) ──► Pre-compiled native resources, strings, and layout XML references.\n\n```\n\n---\n\n## Part 2: End-to-End Guide to Reducing and Optimizing App Size\n\nTo reduce your binary size dramatically (often saving 50% to 70% of total megabytes), you must optimize each asset category inside that archive.\n\n### 1. JavaScript & Runtime Optimization\n\n- **Enable the Hermes Engine:** Ensure your build is explicitly running the Hermes engine. Hermes pre-compiles your JavaScript into highly optimized **bytecode** at build time on your laptop/server. This drastically shrinks the final file size compared to shipping raw text strings.\n- **Tree Shaking & Dead Code Elimination:** Review your imports. Avoid bringing in massive utility libraries (like the full `lodash` suite) if you only use one function. Use modular, tree-shakable packages.\n- **Audit Dependencies:** Run tools like `react-native-bundle-visualizer` to see exactly which npm packages are eating up space in your final Metro bundle.\n\n### 2. Native Code & Configuration Optimizations\n\n- **Enable ProGuard / R8 (Android):** In your `android/app/build.gradle` file, turn on shrinking and obfuscation:\n\n```groovy\n\n```\n\ndef enableProguardInReleaseBuilds = true\n\n```\n    R8 goes through your compiled Java bytecode (`classes.dex`), identifies native code blocks that your app never invokes, and deletes them from the final APK.\n*   **Generate Android App Bundles (.aab):** Never upload a raw `.apk` to the Google Play Store. Upload an `.aab`. Google Play will use the bundle to split your app dynamically, serving users a custom APK tailored to their specific device architecture (e.g., `arm64-v8a`) and screen density, saving up to 50% of the download size.\n\n### 3. Asset & Media Optimizations\n*   **Convert Images to WebP:** Replace heavy `.png` and `.jpg` local assets with `.webp`. WebP compresses images up to 30% smaller than JPEGs and PNGs without noticeable quality loss.\n*   **Vector Graphics (SVGs):** Avoid using raster images for icons. Use `react-native-svg` to render resolution-independent vectors that take up mere kilobytes of text code.\n*   **Move Large Media to a Content Delivery Network (CDN):** If your app uses large onboarding videos, audio tracks, or massive PDF guides, **do not bundle them locally**. Host them on AWS S3 or a secure cloud server and stream them dynamically.\n\n---\n\n## Part 3: End-to-End: How React Native Works and Creates an Application\n\nTo explain how code travels from your keyboard to a user's phone, you must break down the compilation and runtime execution pipelines.\n\n### Phase A: The Compilation Phase (Build Time)\n\n\n```\n\n[ JavaScript / TS / JSX Code ] ──► ( Metro Bundler + Babel ) ──► index.bundle (Hermes Bytecode)\n│\n[ Native Java / Swift Code ] ──► ( Gradle / Xcode Compiler ) ──► classes.dex / Machine Binary\n│\n▼\n[ Merged Single .apk / .ipa Archive ]\n\n```\n\n1.  **JavaScript Bundling:** The **Metro Bundler** processes your source tree. **Babel** transforms your JSX, TS, and modern ESNext code down to cross-platform safe syntax. The **Hermes compiler** then takes this code and compiles it into specialized binary bytecode.\n2.  **Native Compilation:**\n    *   **On Android:** Gradle reads your dependencies, merges your Java/Kotlin source files, and builds the Android native wrappers.\n    *   **On iOS:** Xcode compiles your Objective-C/Swift code and static frameworks into binary executable files.\n3.  **Packaging:** The native compilation tools combine the compiled bytecode bundle, the local asset folders, and the native machine code into a cryptographically signed `.apk` or `.ipa` archive ready for deployment.\n\n---\n\n### Phase B: The Runtime Phase (When the User Opens the App)\n\nReact Native modern applications use the **New Architecture** to run code seamlessly across platforms.\n\n\n```\n\n┌─────────────────────────────────┐ JSI (C++ Direct Memory Access) ┌─────────────────────────────────┐\n│ JavaScript Environment │ ◄────────────────────────────────────────► │ Native Environment │\n│ (Hermes Executing Bytecode Tree)│ (Fabric UI / TurboModules) │ (OS Main Rendering Thread) │\n└─────────────────────────────────┘ └─────────────────────────────────┘\n\n````\n\n1.  **Bootstrap:** The phone operating system boots the native container application shell. The shell initializes the **Hermes JavaScript Engine** instance.\n2.  **The JSI Core:** React Native sets up the **JavaScript Interface (JSI)**. JSI is a lightweight C++ engine layer that allows the JavaScript runtime to hold direct, physical memory pointer references to native host objects. This removes the old architecture's bottleneck of serializing data into slow JSON strings across an asynchronous bridge.\n3.  **UI Layout Management (Fabric & Yoga):** When a screen updates, React creates a structural tree of virtual shadow nodes. The **Yoga Layout Engine** (written in pure C++) calculates the absolute dimensions down to the pixel coordinate. **Fabric** then uses these coordinates to draw actual native platform elements synchronously on the main thread.\n4.  **Native Actions (TurboModules):** When you invoke a device feature (like checking network access or triggering a biometric scan), **TurboModules** leverage JSI to invoke the native Java or Swift code execution routines instantly with zero serialization lag.\n\n---\n\n## Part 4: Crucial Configurations You MUST Handle Natively\n\nWhen shipping a real-world enterprise app, you cannot rely entirely on default setups. You must manage several critical configurations directly within the native wrappers:\n\n1.  **Proguard Obfuscation Mapping (`proguard-rules.pro`):** If you use native libraries (like payment gateways, biometric systems, or analytical trackers), Proguard might accidentally delete their internal API blocks because it thinks they are unused code. You must explicitly configure \"keep\" rules to white-list those files.\n2.  **Android Configuration Management (`configChanges`):** To stop the Android OS from crashing your running JavaScript state when a user rotates their device or switches themes, you must update the `MainActivity` wrapper inside your `AndroidManifest.xml` with:\n    ```xml\n    android:configChanges=\"keyboard|keyboardHidden|orientation|screenSize|uiMode\"\n\n````\n\n3. **Runtime Permission Strings (`Info.plist` & Manifest):** If your code imports a camera or location access package, your app will be rejected instantly by Apple and Google if you do not supply human-readable rationale strings. You must configure descriptions like `NSCameraUsageDescription` inside your iOS `Info.plist` to state exactly why the permission is needed.\n\n---\n\n## 🎯 How to Summarize This for the IBM Panel\n\n> \"Optimizing mobile binaries requires a multi-pronged approach: leveraging **Hermes bytecode compilation** for JavaScript efficiency, configuring **R8 Proguard rules** to prune dead Java code, compiling architectures via **Android App Bundles (.aab)**, and aggressively moving bulky static media out of the binary into **CDNs**.\n> Under the hood, modern React Native operates via a high-performance **JSI (JavaScript Interface) C++ architecture**. By granting JavaScript direct memory pointer access to Native Host Objects, we eliminate older asynchronous JSON string serialization bottlenecks. This allows the **Yoga C++ engine** to resolve responsive layouts instantly, while frameworks like **Fabric and TurboModules** execute complex rendering updates directly on the native host pipeline with sub-millisecond precision.\"\n","type":"md"},{"name":"019-metro.md","content":"## 1. What is Metro?\n\n**Metro** is the official, open-source **JavaScript bundler** built specifically for React Native by Meta (formerly Facebook).\n\nIf you are coming from a traditional web development background, you can think of Metro as the React Native equivalent of **Webpack, Vite, Turbopack, or Rollup**.\n\n---\n\n## 2. Why is Metro Important in React Native?\n\nWhen you build a React Native application, your project contains hundreds of separate files: `.js` files, `.tsx` components, assets like `.png` images, and configuration utilities.\n\nA mobile device cannot run a project structured like this. Android and iOS engines need a single, optimized stream of instructions. Metro's job is to take that mountain of isolated files and **bundle them into one single JavaScript file** (typically called `index.bundle`).\n\nWithout Metro, React Native cannot function. Here are its core responsibilities:\n\n### A. Sub-Second Hot Reloading (Fast Refresh)\n\nMetro includes an incredibly fast file-watcher. The moment you save a file in your IDE, Metro calculates the exact difference, recompiles _only_ that changed file, and injects it instantly into the running JavaScript runtime on your connected phone or emulator. This allows you to see UI updates in milliseconds without rebuilding the native app binary.\n\n### B. Asset Resolution & Management\n\nWeb bundles resolve images using URLs, but mobile apps resolve them using native resource identifiers. When you write `require('./assets/logo.png')` inside your React Native code, Metro intercepts it, optimizes the image, and maps it safely so the native Android drawable or iOS asset catalog can display it.\n\n### C. Shaving Down Bundle Size (Tree Shaking & Optimization)\n\nMetro strips out dead code, processes modern syntax modules, and minifies your codebase. This ensures the footprint of your app remains small, which directly improves download speeds from the App Store or Google Play Store.\n\n---\n\n## 3. How Metro Operates: The 3-Stage Pipeline\n\nMetro executes its bundling magic using three distinct, highly optimized phases:\n\n```\n[ Your Source Files ]\n        │\n        ▼\n 1. RESOLUTION   ───► Maps out the dependency graph (Finds all files)\n        │\n        ▼\n 2. TRANSFORMATION ─► Passes code to Babel (JSX/TS ➡️ Safe JS)\n        │\n        ▼\n 3. SERIALIZATION  ──► Merges everything into a single 'index.bundle' file\n\n```\n\n### Stage 1: Resolution (Building the Graph)\n\nMetro starts from your root entry point (usually `index.js` or `App.js`). It reads the file, looks for any `import` or `require` statements, and recursively follows them to find every file your app depends on. It uses this data to construct a massive **Dependency Graph**.\n\n### Stage 2: Transformation (The Pipeline to Babel)\n\nOnce Metro knows which files are required, it processes them. Metro itself doesn't know how to translate TypeScript or JSX—so it sends every file through **Babel** (using your `babel.config.js`). Babel transpile the modern layout syntax down into standard, cross-platform JavaScript, and passes it back to Metro.\n\n### Stage 3: Serialization (The Final Merge)\n\nMetro takes all the transformed, individual code modules, sorts them chronologically so that dependencies load in the correct order, and merges them into one massive, continuous string of text. This unified asset is your final application bundle.\n\n---\n\n## 4. Metro Configurations (`metro.config.js`)\n\nAs a Senior Developer, you will often need to customize Metro to handle specialized file formats (like SVGs) or optimize large monorepo structures.\n\nHere is what a production-grade Metro configuration looks like:\n\n```javascript\n// metro.config.js\nconst { getDefaultConfig } = require(\"@expo/metro-config\"); // If using Expo\nconst { mergeConfig } = require(\"@react-native/metro-config\"); // If using Bare RN\n\nconst config = {\n  transformer: {\n    // Tells Metro to minify the code for production builds\n    minifierPath: \"metro-minify-terser\",\n  },\n  resolver: {\n    // Allows Metro to recognize specialized file types like .web.js or .native.js\n    sourceExts: [\"js\", \"jsx\", \"json\", \"ts\", \"tsx\", \"cjs\"],\n    // Ignores massive node_modules folders during file-watching to save CPU memory\n    blacklistRE: /node_modules\\/.*\\/node_modules\\/.*/,\n  },\n};\n\nmodule.exports = mergeConfig(getDefaultConfig(__dirname), config);\n```\n\n---\n\n## 🎯 How to frame this explanation for IBM\n\nThis answer rounds out your senior profile by demonstrating a thorough understanding of the mobile build pipeline:\n\n> \"Metro is the specialized JavaScript bundler acting as the foundational compilation bridge for React Native. Operating during development and production build phases, Metro parses our codebase entry points to construct a structural **Dependency Graph**. It orchestrates the **Resolution** of file modules, pipes code blocks directly into **Babel for syntax transformation**, and **Serializes** the entire asset collection into a single, highly optimized `index.bundle` file. Its custom architectural features—such as asset resolution pipelines and sub-second Fast Refresh syncing—ensure that our JavaScript runtime transfers smoothly onto native Android and iOS host shells without manual build interference.\"\n","type":"md"},{"name":"010-useEffectwithoutdependcy.md","content":"Let’s look closely at how this specific code behaves.\n\n```javascript\nuseEffect(() => {\n  console.log(\"a\");\n}); // ⚠️ Notice: No dependency array at all!\n```\n\nBecause you have **completely omitted the dependency array** (there is no `[]` at the end), this hook is in its most aggressive mode.\n\nHere is exactly when it will execute in your application lifecycle:\n\n---\n\n## 1. When will it call on the current screen?\n\nIt will print `'a'` to your console:\n\n1. **On Initial Mount:** The exact millisecond the component is first loaded and painted onto the screen.\n2. **On Every Single Re-render:** Every time _any_ local state changes, _any_ prop updates, or the parent component re-renders.\n\nIf a user is typing into a text input field and updating state on every keystroke, this `useEffect` will fire and print `'a'` on **every single character typed**.\n\n---\n\n## 2. If we go to the second screen, will it call?\n\n**No, it will not call when you navigate away to the second screen.** ### Why?\nWhen you navigate from Screen A to Screen B using a library like **React Navigation**, Screen A is frozen and pushed into the background stack.\n\n- Because it is in the background, it stops rendering.\n- Since no state or prop changes are happening on Screen A while you are on Screen B, the hook remains completely silent and will **not** log `'a'`.\n\n---\n\n## 3. What if we come BACK from the second screen to this screen?\n\n**It still will not call.** When you hit the back button to return to Screen A, Screen A is already mounted in the background stack. React Navigation simply uncovers it.\n\n- It does **not** trigger a fresh component mount.\n- It does **not** automatically change props or state.\n- Therefore, this hook will remain quiet when you come back. It will only start logging `'a'` again if you interact with the UI on Screen A and force a new state change/re-render.\n\n---\n\n## 🎯 Pro-Tip for your IBM Interview:\n\nIf an interviewer shows you this code snippet, point out the performance risk immediately:\n\n> \"Leaving a `useEffect` without a dependency array is a major anti-pattern in production mobile apps. It forces side-effect logic to execute on every single frame calculation, which can lock up the JavaScript thread during heavy UI updates. We should always supply a strict dependency array—either empty `[]` to run only on mount, or populated with specific variables to target precise updates.\"\n\n---\n\nSince we are down to the final hours before your round, what is the next question or scenario you want to test? I'm ready.\n","type":"md"},{"name":"014-GC-GarbageCollector-MemoryLeak.md","content":"In React Native, the **Garbage Collector (GC)** is an automated memory management system that monitors allocated heap memory, identifies chunks of data that the application no longer needs, and reclaims that space so the device doesn't run out of RAM.\n\nFor a Senior Developer role at IBM, you need to understand that React Native's architecture manages **two completely separate environments concurrently**, meaning there are actually two independent garbage collection engines operating under the hood.\n\n---\n\n## 1. How It Works in React Native\n\nBecause your application runs JavaScript logic but renders actual native mobile interfaces (like Android `android.view.View` and iOS `UIView`), memory is tracked across a dual-engine architecture:\n\n### Engine A: The JavaScript Heap (The Hermes Engine)\n\nModern React Native uses the **Hermes JavaScript Engine**. Hermes uses a highly optimized, mobile-first **Generational Mark-and-Sweep** Garbage Collector.\n\n1. **The Mark Phase:** The GC stops execution briefly and traces all active references starting from the \"root\" (global variables, active component states, currently executing call stacks). Every object reachable through this tree is marked as \"alive.\"\n2. **The Sweep Phase:** The GC scans the entire JavaScript memory heap. Any object that lacks a \"live\" mark is considered unreachable dead code and its memory allocation is instantly wiped.\n3. **Generational Optimization:** Hermes splits memory into a \"Young\" generation (temporary rendering variables) and an \"Old\" generation (persistent state). It performs micro-sweeps on the young generation incredibly fast, keeping UI interactions smooth and free of frame drops.\n\n### Engine B: The Native Heap (Android ART & iOS ARC)\n\nWhen your JavaScript components cross over the native bridge or invoke JSI host objects, memory is allocated on the device's native side.\n\n- **On Android:** The Android Runtime (ART) handles memory using its own Java/Kotlin virtual machine garbage collector.\n- **On iOS:** iOS does not use a traditional runtime garbage collector. Instead, it utilizes **ARC (Automatic Reference Counting)**. ARC tracks reference pointers in real time and deletes objects from memory the exact millisecond their reference count hits zero.\n\n### The Connection (JSI)\n\nIn modern React Native, the **JavaScript Interface (JSI)** links these two environments. JavaScript variables hold direct C++ memory pointers to Native Host Objects. When the Hermes GC sweeps a JavaScript object, the underlying C++ destructor triggers automatically, telling iOS or Android to immediately de-allocate the corresponding native view asset.\n\n---\n\n## 2. Why We Need It\n\nWithout automated Garbage Collection, mobile applications would face severe stability and performance problems:\n\n- **Preventing Out-of-Memory (OOM) Crashes:** Mobile devices have strict physical RAM limitations. If memory isn't reclaimed, the operating system will forcefully crash the app.\n- **Maintaining 60FPS / 120Hz Fluidity:** Unmanaged memory build-ups cause high latency. A smart generational garbage collector like Hermes ensures that memory chunks are cleaned up incrementally, preventing micro-stutters during fast scrolling or complex animations.\n\n---\n\n## 3. How Can We Call It? (Can we force GC?)\n\n### Can you call it programmatically?\n\n**Technically yes, but practically no.** \\* In pure JavaScript environments, you **cannot** force garbage collection via code. There is no standard function like `window.gc()` or `global.gc()` available in production runtimes.\n\n- In a local development environment, you can run node or v8 flags (like `--expose-gc`), or trigger memory collections manually via debugging profiling suites inside tools like **Flipper**, **Chrome DevTools**, or **Xcode / Android Studio Memory Profilers**.\n- On the native side, you can imperatively hint at a collection (e.g., calling `System.gc()` in Java/Android), but the mobile operating system treats this as a mere suggestion, not a command.\n\n### Why you should NEVER try to call it manually in production:\n\nGarbage collection is an incredibly expensive computational process because it requires a phase known as **\"Stop-the-World.\"** The engine must pause active JavaScript or Native UI execution threads to safely map out memory references without data shifting mid-flight.\n\nIf you were to trigger garbage collection manually within your code loop, you would introduce severe UI stuttering. The runtime engines are explicitly designed to monitor system heuristics and execute cleanups during ideal, idle frame windows automatically.\n\n---\n\n## 4. Senior Developer Practice: Helping the GC Avoid Memory Leaks\n\nWhile the Garbage Collector is automated, it can only clean up data if **all references to it are broken**. If your code maintains a hidden reference path to an unused component, the GC cannot clear it. This is a **Memory Leak**.\n\nAs a Senior Engineer, you ensure the GC can do its job by writing defensive code:\n\n### 1. Cleaning up Native Listeners\n\n```javascript\nuseEffect(() => {\n  const onKeyboardShow = () => {\n    /* Logic */\n  };\n  const sub = Keyboard.addListener(\"keyboardDidShow\", onKeyboardShow);\n\n  // CRITICAL CLEANUP: If you don't return this, the native module\n  // keeps a reference to the component, blocking the GC permanently!\n  return () => sub.remove();\n}, []);\n```\n\n### 2. Aborting Async Operations\n\nIf a screen starts a 5-second API call and the user immediately leaves that screen, the active network promise still retains a closure link to the screen's local component state hooks. The GC is forced to keep the entire dead screen trapped in RAM until the network call returns or times out.\n\n- **The Fix:** Use `AbortController` inside your `useEffect` cleanups or utilize server-state tools like **React Query** to abort and decouple background actions natively.\n\n### 3. Row Recycling in High-Volume Lists\n\nRendering massive datasets via standard `<ScrollView>` wrappers forces every single row child element to sit inside the active memory footprint indefinitely.\n\n- **The Fix:** Use `FlatList` or `FlashList`. They recycle native cell views as they scroll out of the active viewport, changing the cell data dynamically rather than generating new memory elements, allowing the native GC to remain lightweight.\n","type":"md"},{"name":"001-native_library.md","content":"To give you a clear, side-by-side comparison, let’s build a simple native module called **`DeviceCrypto`** that exposes a single synchronous method: `sha256(message: string)`.\n\nThis is a perfect example for an IBM interview because cryptographic hashing is a heavy operation that benefits from native speed, and it highlights exactly how the **Old Architecture (Bridge)** differs from the **New Architecture (JSI / TurboModules)**.\n\n---\n\n## 1. The Legacy Way: The Old Architecture (The Bridge)\n\nIn the old architecture, data must be serialized into JSON, passed asynchronously across the bridge, deserialized on the native side, executed, and sent back the same way.\n\n### Android Implementation (Java)\n\nFirst, you create the Module class:\n\n```java\npackage com.devicecrypto;\n\nimport com.facebook.react.bridge.ReactApplicationContext;\nimport com.facebook.react.bridge.ReactContextBaseJavaModule;\nimport com.facebook.react.bridge.ReactMethod;\nimport com.facebook.react.bridge.Promise;\nimport java.security.MessageDigest;\n\npublic class DeviceCryptoModule extends ReactContextBaseJavaModule {\n\n    public DeviceCryptoModule(ReactApplicationContext reactContext) {\n        super(reactContext);\n    }\n\n    // This defines the name used in JavaScript: NativeModules.DeviceCrypto\n    @Override\n    public String getName() {\n        return \"DeviceCrypto\";\n    }\n\n    // Exposing the method asynchronously via the Bridge using Promises\n    @ReactMethod\n    public void sha256(String message, Promise promise) {\n        try {\n            MessageDigest digest = MessageDigest.getInstance(\"SHA-256\");\n            byte[] hash = digest.digest(message.getBytes(\"UTF-8\"));\n            StringBuilder hexString = new StringBuilder();\n            for (byte b : hash) {\n                String hex = Integer.toHexString(0xff & b);\n                if(hex.length() == 1) hexString.append('0');\n                hexString.append(hex);\n            }\n            promise.resolve(hexString.toString());\n        } catch (Exception e) {\n            promise.reject(\"SHA256_ERROR\", e.getMessage());\n        }\n    }\n}\n\n```\n\nThen, you must wrap it in a `ReactPackage` and register it in your `MainApplication.java`.\n\n### JavaScript Usage (Old)\n\n```javascript\nimport { NativeModules } from \"react-native\";\n\nconst { DeviceCrypto } = NativeModules;\n\n// Calling it requires an asynchronous await because it crosses the Bridge\nasync function hashData() {\n  try {\n    const hashedString = await DeviceCrypto.sha256(\"Hello IBM\");\n    console.log(hashedString);\n  } catch (error) {\n    console.error(error);\n  }\n}\n```\n\n---\n\n## 2. The Modern Way: The New Architecture (TurboModules & JSI)\n\nIn the New Architecture, we eliminate the asynchronous JSON bridge entirely. JavaScript invokes the native C++ method **synchronously and directly** via JSI memory references.\n\n### Step A: Define the Type Specification (TypeScript)\n\nYou must create a strictly typed specification file. The file name must start with `Spec` (e.g., `SpecDeviceCrypto.ts`).\n\n```typescript\nimport { TurboModule, TurboModuleRegistry } from \"react-native\";\n\nexport interface Spec extends TurboModule {\n  // Note: This can now return a synchronous string directly! No Promise required!\n  sha256(message: string): string;\n}\n\nexport default TurboModuleRegistry.getEnrolled<Spec>(\n  \"DeviceCrypto\",\n) as Spec | null;\n```\n\n### Step B: The Codegen Layer (Automatic)\n\nWhen you build the app, React Native's **Codegen** scans this file and automatically generates C++ code and an abstract Java class named `NativeDeviceCryptoSpec`.\n\n### Step C: Android Implementation (Java/Kotlin)\n\nInstead of extending `ReactContextBaseJavaModule`, your native class extends the **Codegen-generated specification class**.\n\n```java\npackage com.devicecrypto;\n\nimport androidx.annotation.NonNull;\nimport com.devicecrypto.NativeDeviceCryptoSpec; // Generated by Codegen\nimport com.facebook.react.bridge.ReactApplicationContext;\nimport java.security.MessageDigest;\n\npublic class DeviceCryptoModule extends NativeDeviceCryptoSpec {\n\n    public static final String NAME = \"DeviceCrypto\";\n\n    public DeviceCryptoModule(ReactApplicationContext reactContext) {\n        super(reactContext);\n    }\n\n    @Override\n    @NonNull\n    public String getName() {\n        return NAME;\n    }\n\n    // Implements the synchronous signature defined in TypeScript\n    @Override\n    public String sha256(String message) {\n        try {\n            MessageDigest digest = MessageDigest.getInstance(\"SHA-256\");\n            byte[] hash = digest.digest(message.getBytes(\"UTF-8\"));\n            StringBuilder hexString = new StringBuilder();\n            for (byte b : hash) {\n                String hex = Integer.toHexString(0xff & b);\n                if(hex.length() == 1) hexString.append('0');\n                hexString.append(hex);\n            }\n            return hexString.toString(); // Returns directly to JS instantly\n        } catch (Exception e) {\n            return \"\";\n        }\n    }\n}\n\n```\n\n### JavaScript Usage (New)\n\n```javascript\n// Import directly from your typed specification file\nimport DeviceCryptoSpec from \"./SpecDeviceCrypto\";\n\nfunction hashData() {\n  // Synchronous execution! It behaves exactly like a native JS function\n  // because JS has a direct memory pointer to the C++ translation layer.\n  const hashedString = DeviceCryptoSpec?.sha256(\"Hello IBM\");\n  console.log(hashedString);\n}\n```\n\n---\n\n## 💡 Key Takeaways for your IBM Interview:\n\n1. **Type Safety:** The Old Architecture relies on arbitrary string lookups (`NativeModules.DeviceCrypto`) which can fail at runtime if misspelled. The New Architecture enforces compile-time type safety via **Codegen**.\n2. **Synchronous Execution:** In the Old Architecture, you had to use Promises or Callbacks because the Bridge is completely asynchronous. TurboModules allow **direct synchronous execution** for performance-critical functions.\n3. **Memory/Performance:** The Old Architecture copies and serializes data into strings over a queue. The New Architecture uses C++ host objects, making data transfers significantly cheaper and faster.\n\n---\n\nWhat first-round question should we break down next? Let me know!\n","type":"md"},{"name":"030-someinportantqa.md","content":"Reviewing your guide against IBM’s typical 1-hour senior rubrics, there are **2 specific architectural topics** and **2 tricky coding scenarios** that are highly likely to come up but are missing or brief in your document.\n\nAdding these will ensure you are 100% covered.\n\n---\n\n## Part 1: Missing Architectural Topics\n\n### 1. Error Boundaries & Component Crash Recovery\n\n- **Why it's needed:** At a senior level, IBM wants to know what happens when code _fails_. If a single dashboard card crashes due to a null data property, does it crash the entire application for the investor?\n- **The Concept:** You must explain **Error Boundaries**. While functional components handle most things, Error Boundaries still require a **Class Component** (using `componentDidCatch` and `getDerivedStateFromError`).\n- **The Strategy:** You wrap major feature modules or individual dashboard components in an Error Boundary wrapper. If a component fails, the error is caught, sent to Crashlytics, and the UI fallback renders a localized \"Widget failed to load\" card instead of completely crashing the app to a dead black screen.\n\n### 2. Deep Linking & Navigation State Synchronization\n\n- **Why it's needed:** Essential for push notifications and email alerts (e.g., clicking an email alert about a balance update should open the app directly to that specific transaction screen).\n- **The Concept:** You must explain how navigation routing engines (like `React Navigation` or `Expo Router`) parse incoming URI schemes (`app://dashboard/payments/123`).\n- **The Senior Nuance:** Explain how you handle **Conditional Deep Linking** for protected screens. If the app is closed and a deep link opens it, the routing system must pause the navigation tree, query the global state engine to verify if an active authentication token exists, route the user to the Login screen if unauthenticated, and then resume routing to the deep link target destination _after_ a successful login session.\n\n---\n\n## Part 2: Missing Coding Programs (The Advanced Variants)\n\nYour current coding list has standard array/string manipulations, but interviewers frequently use **nested structural modifications** to test your depth with references and memory.\n\n### 1. Deep Clone an Object (Bypassing Reference Leaks)\n\nInterviewers often ask how to completely clone a deeply nested object without using `JSON.parse(JSON.stringify(obj))`—because that method destroys functions, symbols, and `Date` objects.\n\n#### **The Program:**\n\n```javascript\nfunction deepClone(obj) {\n  // Handle primitives, null, or undefined\n  if (obj === null || typeof obj !== \"object\") {\n    return obj;\n  }\n\n  // Handle Date objects\n  if (obj instanceof Date) {\n    return new Date(obj.getTime());\n  }\n\n  // Handle Array instances\n  if (Array.isArray(obj)) {\n    return obj.map((item) => deepClone(item));\n  }\n\n  // Handle Object instances\n  const clonedObj = {};\n  for (let key in obj) {\n    if (obj.hasOwnProperty(key)) {\n      clonedObj[key] = deepClone(obj[key]); // Recursive deep copy pass\n    }\n  }\n\n  return clonedObj;\n}\n\nconst original = { asset: \"Equity\", details: { id: 101, dates: new Date() } };\nconst copy = deepClone(original);\n```\n\n### 2. Two-Sum Target Index Lookup ($O(N)$ Hash Mapping)\n\nA classic optimization puzzle used to check if a candidate can optimize a nested `for` loop ($O(N^2)$) down to a single linear pass ($O(N)$).\n\n#### **The Program:**\n\n```javascript\nfunction twoSum(nums, target) {\n  // Map index tracking matrix: Key = Value needed, Value = Current Index\n  const map = new Map();\n\n  for (let i = 0; i < nums.length; i++) {\n    const complement = target - nums[i];\n\n    // If the required value already exists in our map, match found!\n    if (map.has(complement)) {\n      return [map.get(complement), i]; // Return stored index and current index\n    }\n\n    // Otherwise, store current value and its index location\n    map.set(nums[i], i);\n  }\n  return [];\n}\n\nconsole.log(twoSum([2, 7, 11, 15], 9)); // Output: [0, 1] (because 2 + 7 = 9)\n```\n\n---\n\n## 🎯 Ready to Go!\n\nWith your updated guide, your 50k product list optimization blueprint, and these advanced edge cases, you have covered everything.\n\nYou are fully prepared to answer any technical, structural, or algorithmic question they throw at you. Go in tomorrow, take your time, and show them what 9 years of senior expertise looks like. Good luck, Rajeev! Let me know how it goes!\n\nHere is the detailed structural breakdown for **Part 1 (Error Boundaries and Deep Linking Navigation)**, complete with production-grade, senior-level code samples and explanations that you can present to the IBM panel.\n\n---\n\n## Part 1: Detailed Architectures & Enterprise Code Samples\n\n### Topic 1: Error Boundaries & Component Crash Recovery\n\n#### The Concept\n\nIf a single transaction card or stock widget crashes due to an unexpected null property or unhandled type error from an API, a standard React Native application will crash straight to a dead screen or close entirely.\n\nTo prevent this, you wrap individual features or layout sections inside a specialized **Class Component Error Boundary**. If a component fails, the error is isolated, caught, sent to your analytics provider (like Firebase Crashlytics), and a clean, local fallback card is shown instead of crashing the whole application.\n\n#### Production-Grade Code Sample (`ErrorBoundary.tsx`)\n\n```typescript\nimport React, { Component, ErrorInfo, ReactNode } from 'react';\nimport { View, Text, StyleSheet, TouchableOpacity } from 'react-native';\n\ninterface Props {\n  children: ReactNode;\n  fallbackMessage?: string;\n}\n\ninterface State {\n  hasError: boolean;\n}\n\nexport class ErrorBoundary extends Component<Props, State> {\n  public state: State = {\n    hasError: false\n  };\n\n  // 1. Invoked during a crash to modify the state tree\n  public static getDerivedStateFromError(_: Error): State {\n    return { hasError: true };\n  }\n\n  // 2. Used to log the stack trace to your production monitor systems\n  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {\n    console.error(\"ErrorBoundary intercepted a component crash:\", error, errorInfo);\n    // Real-world integration example:\n    // crashlytics().recordError(error);\n  }\n\n  private handleReset = () => {\n    this.setState({ hasError: false });\n  };\n\n  public render() {\n    if (this.state.hasError) {\n      return (\n        <View style={styles.errorContainer}>\n          <Text style={styles.errorTitle}>Widget Loading Error</Text>\n          <Text style={styles.errorSub}>\n            {this.props.fallbackMessage || \"This widget is temporarily unavailable.\"}\n          </Text>\n          <TouchableOpacity style={styles.retryBtn} onPress={this.handleReset}>\n            <Text style={styles.retryText}>Reload Component</Text>\n          </TouchableOpacity>\n        </View>\n      );\n    }\n\n    return this.props.children;\n  }\n}\n\nconst styles = StyleSheet.create({\n  errorContainer: { padding: 16, backgroundColor: '#FEF2F2', borderRadius: 12, borderWidth: 1, borderColor: '#FCA5A5', alignItems: 'center', margin: 16 },\n  errorTitle: { fontSize: 16, fontWeight: '700', color: '#991B1B' },\n  errorSub: { fontSize: 13, color: '#7F1D1D', marginTop: 4, textAlign: 'center', marginBottom: 12 },\n  retryBtn: { paddingVertical: 6, paddingHorizontal: 12, backgroundColor: '#DC2626', borderRadius: 6 },\n  retryText: { color: '#FFF', fontWeight: '600', fontSize: 12 }\n});\n\n```\n\n#### How you implement it inside a Dashboard screen:\n\n```typescript\nimport React from 'react';\nimport { ScrollView } from 'react-native';\nimport { ErrorBoundary } from './ErrorBoundary';\nimport LiveStockTicker from './LiveStockTicker';\nimport PortfolioBalanceCard from './PortfolioBalanceCard';\n\nexport default function InvestorDashboard() {\n  return (\n    <ScrollView>\n      {/* If the ticker component crashes due to WebSocket network errors,\n          the balance card below it remains perfectly visible and functional! */}\n      <ErrorBoundary fallbackMessage=\"Failed to load real-time market data tickers.\">\n        <LiveStockTicker />\n      </ErrorBoundary>\n\n      <ErrorBoundary fallbackMessage=\"Unable to calculate portfolio balances.\">\n        <PortfolioBalanceCard />\n      </ErrorBoundary>\n    </ScrollView>\n  );\n}\n\n```\n\n---\n\n### Topic 2: Deep Linking & Conditional Auth State Routing\n\n#### The Concept\n\nWhen an enterprise user clicks a deep link (e.g., from a push notification or email alert like `mybankingapp://dashboard/payment/550`), the application must dynamically parse that route string.\n\nHowever, at a senior level, you must account for **Authentication Guards**. If the user's local session token is missing or expired, the app must intercept the deep link path, drop them on the Login screen, and then route them straight to the intended deep link view _only after_ a successful login.\n\n#### Production-Grade Configuration Sample (`NavigationContainer` Configuration)\n\n```typescript\nimport React from \"react\";\nimport { Linking } from \"react-native\";\nimport {\n  NavigationContainer,\n  createNavigationContainerRef,\n} from \"@react-navigation/native\";\n\n// Global reference pointer to interact with navigation outside of standard hook scopes\nexport const navigationRef = createNavigationContainerRef();\n\nconst linkingConfig = {\n  // 1. Register application tracking schemes\n  prefixes: [\"mybankingapp://\", \"https://*.mybankingapp.com\"],\n\n  // 2. Map route string parameters directly to your screen stacks\n  config: {\n    screens: {\n      AuthStack: \"login\",\n      MainTabs: {\n        screens: {\n          DashboardTab: \"dashboard\",\n          PaymentDetailTab: \"dashboard/payment/:transactionId\", // Capture dynamic parameters\n        },\n      },\n    },\n  },\n\n  // 3. Senior Custom Ingestion Guard: Intercept the deep link before routing it\n  async getStateFromPath(path: string, config: any) {\n    // A. Query your global secure store or state engine to check if a token exists\n    const hasActiveSession = await checkSecureTokenStorage();\n\n    if (!hasActiveSession) {\n      console.log(\n        \"Deep link intercepted: User unauthorized. Redirecting to auth gate.\",\n      );\n\n      // B. Force modify the routing state map to return the Login stack,\n      // but append the original path as a parameter so the login screen can route them after passing the gate\n      return {\n        routes: [\n          {\n            name: \"AuthStack\",\n            params: { targetRedirectPath: path },\n          },\n        ],\n      };\n    }\n\n    // C. If verified, fall back to standard built-in parsing logic\n    return {\n      routes: [\n        {\n          name: \"MainTabs\",\n          state: {\n            routes: [\n              {\n                name: \"PaymentDetailTab\",\n                params: { transactionId: path.split(\"/\").pop() },\n              },\n            ],\n          },\n        },\n      ],\n    };\n  },\n};\n\n// Dummy utility helper function for demonstration\nasync function checkSecureTokenStorage(): Promise<boolean> {\n  // In real life, check Keychain or Keystore encrypted files\n  return false;\n}\n```\n\n---\n\n### 🎯 How to communicate these advanced architectures tomorrow\n\nWhen the IBM team begins exploring production edge cases, frame your answers around system resilience:\n\n1. **On App Crashes:** _\"I don't leave application stabilization down to global error loops. I enforce atomic UI containment using Class Component **Error Boundaries** around distinct feature modules. This limits runtime faults to a specific widget wrapper while preserving the operational health of the surrounding UI tree.\"_\n2. **On Deep Linking Execution:** _\"Deep linking isn't just about route string matching. For regulated enterprise apps, security boundaries are paramount. I override standard link state configurations by injecting an explicit **Session Validation Guard** directly inside the deep link state calculation lifecycle. This prevents unauthorized deep links from exposing internal screens, cleanly routing users through an authentication fallback loop before fulfilling the deep link request.\"_\n\nIn React and React Native, a true Error Boundary **must be written as a Class Component**. It **cannot** be written as a pure Functional Component.\n\nThe explanation for this requirement relies on specific framework lifecycle methods and can be broken down into clear mechanical details:\n\n---\n\n## Why Error Boundaries Must Be Class Components\n\nReact's runtime engine catches errors within the component tree using two specialized lifecycle methods:\n\n1. `static getDerivedStateFromError(error)`\n2. `componentDidCatch(error, errorInfo)`\n\nAs of the current version of React, **there are no functional hook equivalents for these two methods** (such as a hypothetical `useErrorBoundary` or `useComponentDidCatch`). Because functional hooks like `useEffect` or `useMemo` execute _after_ or _during_ the standard rendering process, they are structurally unable to catch errors that occur mid-render inside their child component trees.\n\nIf a child component throws an error during its render phase, only a parent Class Component implementing these lifecycle methods can intercept the exception before it bubbles up and crashes the entire application shell.\n\n---\n\n## The Hybrid Alternative: Using `react-error-boundary`\n\nIf an enterprise workflow requires keeping the entire codebase functional without writing custom Class structures, the industry standard is to implement a hybrid approach using the popular, highly optimized third-party library: **`react-error-boundary`**.\n\nThis library wraps the required legacy Class Component logic under the hood and exposes a clean, modern **Functional Component wrapper** with hooks for your presentation code.\n\n### Production-Grade Code Sample (The Functional Wrapper)\n\n```typescript\nimport React from 'react';\nimport { View, Text, StyleSheet, TouchableOpacity } from 'react-native';\nimport { ErrorBoundary } from 'react-error-boundary'; // Standard community library\nimport LiveStockTicker from './LiveStockTicker';\n\n// 1. Define a clean, functional Fallback Component\nfunction ErrorFallback({ error, resetErrorBoundary }: { error: Error; resetErrorBoundary: () => void }) {\n  return (\n    <View style={styles.errorContainer}>\n      <Text style={styles.errorTitle}>Widget Loading Error</Text>\n      <Text style={styles.errorSub}>{error.message || \"This widget is temporarily unavailable.\"}</Text>\n      <TouchableOpacity style={styles.retryBtn} onPress={resetErrorBoundary}>\n        <Text style={styles.retryText}>Reload Component</Text>\n      </TouchableOpacity>\n    </View>\n  );\n}\n\nexport default function InvestorDashboard() {\n  return (\n    <View style={{ flex: 1, padding: 16 }}>\n\n      {/* 2. Consume the ErrorBoundary as a standard functional element */}\n      <ErrorBoundary\n        FallbackComponent={ErrorFallback}\n        onReset={() => {\n          // Reset internal states or clear API caches here\n          console.log(\"Error boundary cache flushed.\");\n        }}\n        onError={(error, info) => {\n          // Log directly to enterprise tracking metrics\n          console.error(\"Logged to Crashlytics:\", error, info);\n        }}\n      >\n        <LiveStockTicker />\n      </ErrorBoundary>\n\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  errorContainer: { padding: 16, backgroundColor: '#FEF2F2', borderRadius: 12, borderWidth: 1, borderColor: '#FCA5A5', alignItems: 'center' },\n  errorTitle: { fontSize: 16, fontWeight: '700', color: '#991B1B' },\n  errorSub: { fontSize: 13, color: '#7F1D1D', marginTop: 4, marginBottom: 12, textAlign: 'center' },\n  retryBtn: { paddingVertical: 6, paddingHorizontal: 12, backgroundColor: '#DC2626', borderRadius: 6 },\n  retryText: { color: '#FFF', fontWeight: '600', fontSize: 12 }\n});\n\n```\n\n---\n\n## 🎯 How to explain this to the IBM Panel\n\nIf they ask you whether an Error Boundary can be functional, use this direct, technically authoritative response to show your deep understanding of React's engine internals:\n\n> \"An Error Boundary **strictly requires a Class Component implementation**. This is because the core React reconciliation engine relies on `static getDerivedStateFromError` and `componentDidCatch` to intercept rendering exceptions before they bubble up to the native layer. Currently, no functional hooks exist to replicate these specific lifecycle boundaries.\n>\n> However, to align with clean coding and functional design patterns in an enterprise repository, the standard pattern is to use the **`react-error-boundary`** abstraction library. This utility handles the Class lifecycle mechanics under the hood, allowing developers to declaratively pass functional fallback views and error tracking routines (`onError`) via props, keeping our presentation layer modern and consistent.\"\n\nYou are completely right, Rajeev—great catch! I did overlook **`componentDidCatch`** when detailing the legacy Class Component updates earlier.\n\nAt a senior level, leaving that out misses a critical part of how the native error-handling lifecycle works. Let’s correct that completely so your Class Component knowledge is flawless for your interview.\n\n---\n\n## The Missing Piece: Error Handling Lifecycles\n\nIn legacy Class Components, error handling isn't done via standard `try/catch` blocks around the UI. Instead, React provides **Error Boundary Lifecycles** to catch unhandled errors anywhere in a child component tree.\n\nThere are two distinct methods that work together, and it is vital to know the exact difference between them:\n\n### 1. `static getDerivedStateFromError(error)`\n\n- **The Role:** This method is invoked **during the \"Render phase\"** after a child component crashes.\n- **How it works:** It must run synchronously and return an object to update the local component `state` (e.g., `{ hasError: true }`). Because it runs during the render phase, **you are strictly forbidden from running side effects here** (like logging to a server or tracking analytics). Its sole job is to let React render a fallback UI on the very next frame tick before the app crashes.\n\n### 2. `componentDidCatch(error, errorInfo)`\n\n- **The Role:** This method is invoked **during the \"Commit phase\"** _after_ the fallback UI has been successfully mounted.\n- **How it works:** Because it executes in the commit phase, **this is the exact and safe place to perform side effects**.\n- **Primary Uses:** This is where you pass the stack trace data to your remote crash-reporting tools, such as **Firebase Crashlytics** or Sentry. It captures two arguments:\n\n- `error`: The actual error object that was thrown.\n- `errorInfo`: An object containing a `componentStack` key, which gives you the exact line-by-line native component tree hierarchy trace of where the failure originated.\n\n---\n\n## Where It Fits in the Full Class Lifecycle Matrix\n\nTo ensure you can visualize the whole picture, here is where error capturing officially fits within the classic three-phase architecture:\n\n### Phase 1: The Mounting Phase (Birth)\n\n- `constructor()`\n- `static getDerivedStateFromProps()`\n- `render()`\n- `componentDidMount()`\n\n### Phase 2: The Updating Phase (Growth)\n\n- `static getDerivedStateFromProps()`\n- `shouldComponentUpdate()`\n- `render()`\n- `getSnapshotBeforeUpdate()`\n- `componentDidUpdate()`\n\n### Phase 3: The Unmounting Phase (Death)\n\n- `componentWillUnmount()`\n\n### Phase 4: The Error Handling Phase (Safety Net) 🌟\n\n- `static getDerivedStateFromError()`\n- `componentDidCatch()`\n\n---\n\n## 🎯 How to weave this correction into your IBM response\n\nIf they ask you to detail Class Component lifecycles or error strategies, wrap it up like this:\n\n> \"When handling legacy Class environments, managing operational resilience requires hooking into the Error Handling lifecycles. While `static getDerivedStateFromError` acts synchronously during the render phase to immediately pivot local states and render a fallback UI container, **`componentDidCatch` operates during the commit phase**. This makes `componentDidCatch` the designated, thread-safe location to capture the component stack trace and dispatch the crash analytics payload directly to **Firebase Crashlytics**, allowing us to monitor production regressions without interrupting the client runtime session.\"\n","type":"md"},{"name":"003-NativeEquivalentPerformance.md","content":"This is a classic second-round question for a Senior Engineer. The interviewer wants to see if you have moved past the old marketing pitch (\"write once, run everywhere\") and truly understand the deep technical trade-offs of the framework.\n\nAs a Senior Developer with native background, your answer should be nuanced. **Yes, with the mainstream adoption of the New Architecture, we can achieve native-equivalent performance for 95% of standard applications—but there are still architectural and thread-level limitations** that separate it from absolute Native Swift/Kotlin.\n\nHere is exactly how you should structure your answer to impress the IBM panel:\n\n---\n\n## 1. The Short Answer (The Hook)\n\n> \"Yes, for the vast majority of applications—including heavy consumer and fintech apps—React Native now achieves parity with native apps. This is because **React Native renders actual native UI views** (like `UIView` on iOS and `android.view.View` on Android), it doesn't run in a WebView. Furthermore, the **New Architecture** has eliminated the biggest historical performance bottleneck: the asynchronous JSON Bridge.\"\n\n---\n\n## 2. Why it feels Native now (The \"New Architecture\" Era)\n\nYou must explain _why_ performance has caught up. Talk about the fundamental pillars:\n\n- **JSI (JavaScript Interface) over Memory:** Instead of serializing data into JSON strings to pass across an asynchronous bridge (which used to cause frame drops in fast scrolling or animations), JSI allows the JavaScript engine (Hermes) to hold **direct C++ memory references** to native host objects. Communication is now instantaneous and synchronous when needed.\n- **Fabric Renderer & Synchronous Layouts:** Fabric allows synchronous UI mutations. In the old architecture, if you calculated a layout (like a tooltip or sticky header), the asynchronous nature caused a \"visual jump/flash\". Fabric solves this, aligning layout commits perfectly with the native rendering threads.\n- **TurboModules (Lazy Loading):** In old React Native, all native modules were eagerly loaded at startup, killing TTI (Time to Interactive). TurboModules load native code lazily, only when a feature is used, making startup times incredibly fast and competitive with native apps.\n\n---\n\n## 3. The Core Remaining Limitations (Where Native Still Wins)\n\nA senior engineer acknowledges the limits. This is where you bring your Native Android experience into play:\n\n### A. The Single-Threaded JS Runtime (No True Multi-Threading)\n\n- **The Problem:** React Native executes JavaScript logic on a **single JS thread**.\n- **The Limitation:** If you run heavy mathematical computations, complex cryptography (crucial for IBM/Fintech), large-scale data filtering, or real-time image processing on the JS thread, **it blocks the UI**.\n- **The Native Advantage:** Native iOS/Android can effortlessly spawn background worker threads (`DispatchQueue` in Swift or Coroutines in Kotlin) to run heavy data processing without ever stuttering the UI.\n- _(💡 Senior Tip to mention)_: You can state that tools like `react-native-worklets` or writing custom C++ TurboModules are fixing this by allowing parallel threads, but it requires architectural effort compared to native out-of-the-box threading.\n\n### B. Memory Overhead and Garbage Collection (GC)\n\n- **The Problem:** You are running two environments simultaneously: the native runtime (JVM/Art or Swift runtime) and the JavaScript Virtual Machine (Hermes).\n- **The Limitation:** Memory footprint will inherently be larger than a purely native app. When the JavaScript Garbage Collector triggers to clean up memory, it can occasionally cause micro-stutters if the app is holding massive amounts of data in memory.\n\n### C. Extreme UI Complexity (120Hz Fluidity & Deep Gestures)\n\n- While libraries like `Software Mansion's Reanimated` and `Gesture Handler` move animations to the native thread, extremely intricate canvas drawings, heavy 3D rendering, or complex custom video editing/processing tools still hit a performance ceiling in React Native compared to pure Metal (iOS) or Vulkan (Android).\n\n---\n\n## 🎯 How to Conclude Your Answer\n\nSummarize with a pragmatic business engineering mindset:\n\n> \"As an architect, the decision comes down to the use case. For an enterprise app handling payments, dashboarding, form management, and standard media, React Native's performance is indistinguishable from Native, while cutting time-to-market in half. However, if I am building a video editing tool, a heavy 3D game, or an app requiring intensive background multi-threaded cryptography, pure Native remains the right choice.\"\n\n---\n\n### What is the next first-round question you want to break down? Ready when you are!\n","type":"md"},{"name":"004-diffrencebetweenclassand functionalcomponent.md","content":"While we touched on how their life cycles differ, an IBM interviewer asking for the direct **difference** between Class and Functional components wants to see you break it down across several architectural pillars: **Syntax, State Management, Reusability, Memory/Performance, and Testing.**\n\nHere is the ultimate senior-level breakdown, structured for clarity.\n\n---\n\n## 📊 The Core Technical Differences\n\n| Feature                       | Class Components                                                                        | Functional Components (with Hooks)                                                          |\n| ----------------------------- | --------------------------------------------------------------------------------------- | ------------------------------------------------------------------------------------------- |\n| **Definition**                | An ES6 class that extends `React.Component`.                                            | A standard JavaScript function that returns JSX.                                            |\n| **State Handling**            | Uses a single, mutable `this.state` object. Updated via `this.setState()`.              | Uses the `useState` hook. State variables are independent and immutable.                    |\n| **Life Cycle**                | Managed via explicit, dedicated lifecycle methods (e.g., `componentDidMount`).          | Managed uniformly via the `useEffect` hook.                                                 |\n| **The `this` Keyword**        | Heavily relies on `this`. Requires manual binding of event handlers in the constructor. | Completely avoids `this`. Works within standard JavaScript lexical scoping.                 |\n| **Code Reusability**          | Uses complex patterns like Higher-Order Components (HOCs) or Render Props.              | Uses **Custom Hooks**, making it incredibly easy to share stateful logic across components. |\n| **Bundle Size & Performance** | Slightly larger bundle size. Classes don't minify well during the build process.        | More lightweight. Functions minify perfectly, resulting in slightly better performance.     |\n\n---\n\n## 🔍 Deep Dive: Key Differences Explained\n\n### 1. State Management Paradigm\n\n- **Class Component:** State updates are **shallowly merged**. When you call `this.setState({ user: 'Rajeev' })`, React only updates the `user` key and leaves the rest of the state object intact.\n- **Functional Component:** State updates are **replaced**. If you have an object in a `useState` hook, calling the setter function overwrites the entire state unless you manually spread the old state: `setUser(prevState => ({ ...prevState, name: 'Rajeev' }))`.\n\n### 2. Separation of Concerns (The \"Messy Room\" Problem)\n\n- **Class Component:** You are forced to group unrelated logic together based on _when_ it executes. For example, in `componentDidMount`, you might fetch user data **and** set up a Push Notification listener at the same time.\n- **Functional Component:** You group logic by _what it does_. You can have one `useEffect` strictly for fetching data, and a completely separate `useEffect` handling the notification listener. This makes code clean and maintainable.\n\n### 3. Captured Values (The Closures Advantage)\n\nThis is a high-level nuance that interviewers love:\n\n- **Functional components capture the rendered values.** Because a functional component is essentially a function execution, the `props` and `state` inside it are locked into that specific render cycle's closure.\n- **Class components do not capture values.** Because `this.props` is mutable, React updates `this` to point to the newest props. If an asynchronous operation (like a `setTimeout` or network request) takes 3 seconds to complete, a Class component might read the _newest_ props instead of the props that were active when the operation started, leading to race-condition bugs.\n\n---\n\n## 🎯 How to frame your preference for IBM\n\nConclude your answer by showcasing your practical, modern development approach:\n\n> \"While I have deep experience maintaining legacy Class components in older codebases, my absolute preference is **Functional Components with Hooks**. They promote clean code separation, allow us to write highly reusable **Custom Hooks** for complex logic, avoid the pitfalls of the `this` keyword scope, and result in a more lightweight production bundle.\"\n\n---\n\nAre there any other first-round questions you want to dissect before we jump into the architecture of your specific fintech projects? Let's keep moving!\n","type":"md"},{"name":"018-Yoga.md","content":"In React Native, **Yoga** is an open-source, cross-platform layout engine developed by Meta (formerly Facebook). It is written in C++ and its sole responsibility is to calculate the precise size, spacing, and coordinates of UI components.\n\nFor your upcoming IBM interview, understanding Yoga is essential because it is the engine that allows React Native to implement web-standard **Flexbox styling** on native mobile devices—even though iOS and Android do not understand Flexbox natively.\n\n---\n\n## 1. Why React Native Needs Yoga\n\nThe UI frameworks of the host mobile operating systems are entirely different from the web:\n\n- **Android** layouts rely on native constructs like `LinearLayout`, `RelativeLayout`, or `ConstraintLayout`.\n- **iOS** layouts rely heavily on `Auto Layout` constraints and frames.\n\nBecause they speak different layout languages, you cannot pass a JavaScript style object like `{ flexDirection: 'row', justifyContent: 'center' }` directly to iOS or Android.\n\nYoga serves as the **unifying translation engine**. It takes web-modeled Flexbox styles, calculates exactly where every element should sit down to the individual pixel coordinate, and hands those absolute positioning metrics over to the native UI threads to render actual platform-native widgets.\n\n---\n\n## 2. How Yoga Operates Under the Hood\n\nWhen working with modern implementations (especially React Native's New Architecture with Fabric), Yoga forms a critical part of the rendering pipeline:\n\n1. **Tree Construction:** When a screen component executes in JavaScript, the framework builds a corresponding virtual tree called **Shadow Nodes**.\n2. **Yoga Node Binding:** Every visible Shadow Node is bound directly to a **C++ Yoga Node**.\n3. **Layout Computation:** Yoga parses your Flexbox styles (`flexGrow`, `padding`, `margin`, `gap`) and walks the layout node tree. It handles computations rapidly because it is written in pure C++, utilizing advanced internal structural caching to skip calculating frames that haven't changed size.\n4. **Native Output:** Yoga outputs an absolute layout solution containing precise boundaries: `Width`, `Height`, `Top`, and `Left`. Fabric passes these pixel boundaries straight to the native OS container views via the JavaScript Interface (JSI), bypassing older, slower serialization layers entirely.\n\n---\n\n## 3. Real-World Code Example\n\nLet’s look at a standard component layout. We will write the React Native component style and look at exactly how Yoga interprets and maps it into absolute boundaries for the native platforms.\n\n### What you write in React Native (JavaScript/TypeScript)\n\n```javascript\nimport React from \"react\";\nimport { View, StyleSheet } from \"react-native\";\n\nexport default function BalancedCard() {\n  return (\n    <View style={styles.parentContainer}>\n      <View style={styles.boxLeft} />\n      <View style={styles.boxRight} />\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  parentContainer: {\n    width: 300,\n    height: 100,\n    flexDirection: \"row\", // Arranges children horizontally\n    justifyContent: \"space-between\", // Pushes child components to opposite edges\n    alignItems: \"center\", // Vertically aligns components in the center\n    padding: 10,\n    backgroundColor: \"#eee\",\n  },\n  boxLeft: {\n    width: 50,\n    height: 50,\n    backgroundColor: \"blue\",\n  },\n  boxRight: {\n    width: 80,\n    height: 50,\n    backgroundColor: \"green\",\n  },\n});\n```\n\n### What Yoga Calculates Behind the Scenes (C++ Engine)\n\nWhen Yoga executes its layout pass on a 300x100 viewport size, it evaluates the constraints and mathematically derives the exact physical bounding coordinates for the elements:\n\n- **`parentContainer` Nodes:** Absolute bounds set to `Width: 300`, `Height: 100`, `Left: 0`, `Top: 0`.\n- **`boxLeft` Node:** \\* _Padding Constraint:_ Since the parent container has a padding of `10`, the box starts at `Left: 10`.\n- _Vertical Alignment (`center`):_ The parent container height is `100`, and the box height is `50`. Yoga subtracts the box height from the parent height (`100 - 50 = 50`) and splits the difference evenly, resulting in `Top: 25`.\n- _Yoga Frame Output:_ `{ width: 50, height: 50, left: 10, top: 25 }`\n\n- **`boxRight` Node:**\n- _Horizontal Alignment (`space-between`):_ Yoga calculates the total width (`300`), subtracts the outer paddings (`10 + 10 = 20`), and subtracts the combined widths of both boxes (`50 + 80 = 130`). The remaining available empty horizontal real estate is `300 - 20 - 130 = 150`. Because it's `space-between`, Yoga places that entire `150px` gap directly between the two blocks.\n- _Yoga Frame Output:_ `{ width: 80, height: 50, left: 210, top: 25 }` (Calculated as: 10 parent padding + 50 boxLeft width + 150 dynamic spacing gap).\n\nYoga hands these absolute dimensions down to Android’s rendering framework and iOS's Core Animation layers to draw the corresponding blue and green shapes seamlessly.\n\n---\n\n## 4. Crucial Differences: Yoga Flexbox vs. Web CSS Flexbox\n\nTo display an advanced understanding during an interview, point out that Yoga does **not** support 100% of the web's CSS specifications due to the performance overhead of mobile hardware.\n\n1. **Default Flex Direction:** On the web, `flexDirection` defaults to `row`. In React Native (via Yoga), it defaults to `column` to better suit the vertical orientation of mobile devices.\n2. **No Text-Based Wrapping Constraints:** Yoga cannot perform advanced inline text element shape calculations directly inside its engine. Text measuring is offloaded back to native multi-threaded layout engines (like Android’s `StaticLayout`) and then injected back into Yoga to finalize container boxes.\n3. **Recent Enhancements (Yoga 3.0 / React Native 0.74+):** Historically, Yoga had subtle bugs where applying properties like `margin` or `padding` to `row-reverse` components caused edge calculations to flip incorrectly compared to web standards. The introduction of Yoga 3.0 resolved these layout bugs, ensuring exact parity with Web standards and adding properties like `alignContent: 'space-evenly'`.\n\n---\n\n## 🎯 How to frame this explanation for IBM\n\n> \"Yoga is the cross-platform layout engine that acts as the core blueprint for React Native's presentation views. Written in highly optimized C++, it acts as a layout translation layer. It parses our declarative JavaScript Flexbox styling configurations and constructs a high-performance tree of layout frames. By executing advanced coordinate and margin calculation algorithms natively, Yoga bypasses platform layout discrepancies—transforming abstract Flexbox rules into exact pixel positions (`Width`, `Height`, `Top`, `Left`) that the native Android and iOS graphic pipelines render synchronously.\"\n\n---\n\nFor a deeper look into the low-level mechanics of Yoga nodes and architectural changes in the layout system, you can check out this [Technical Overview of Yoga in React Native](https://www.youtube.com/watch?v=Ttp83rVUTeQ). This discussion covers the transition from JSX to native elements and how the rendering pipeline has evolved to improve app speed.\n","type":"md"},{"name":"000-Components.md","content":"In React Native, components are the fundamental building blocks of the user interface. Both **Class Components** and **Functional Components** serve the same purpose—rendering UI and managing data—but they use completely different syntaxes, states, and architectural paradigms.\n\nIBM interviewers use this question to evaluate if you understand the evolution of React Native and if you know how memory, cleanups, and side effects are managed under the hood.\n\n---\n\n## 1. Class Components vs. Functional Components (The Core Difference)\n\n- **Class Components:** These are ES6 classes that extend `React.Component`. They maintain local state via a mutable `this.state` object and rely on explicit life cycle methods.\n- **Functional Components:** These are standard JavaScript functions that accept `props` as an argument and return JSX. Originally stateless, they now handle state and side effects using **Hooks** (like `useState` and `useEffect`).\n\n---\n\n## 2. Component Life Cycles: End-to-End\n\nA component’s life cycle is split into three main phases: **Mounting** (creation), **Updating** (re-rendering due to data changes), and **Unmounting** (destruction).\n\nHere is how both components handle these phases side by side:\n\n### Phase 1: Mounting (Born)\n\nThis is when the component is being initialized and inserted into the application tree.\n\n- **Class Component Methods (Executed in order):**\n\n1. `constructor()`: Initializes local state and binds event handlers.\n2. `static getDerivedStateFromProps()`: A rare method used to update state based on prop changes before rendering.\n3. `render()`: Evaluates the JSX. _Must be a pure function._\n4. `componentDidMount()`: Invoked immediately after the component mounts. **This is where you trigger API calls, setup subscriptions, or add EventListeners.**\n\n- **Functional Component Hook Equivalent:**\n- The function body itself acts as the initialization step.\n- `useEffect(() => { ... }, [])`: Passing an **empty dependency array `[]**`mirrors`componentDidMount`. It executes exactly once after the initial render.\n\n### Phase 2: Updating (Living)\n\nThis happens when a component's `props` or `state` change, triggering a re-render.\n\n- **Class Component Methods (Executed in order):**\n\n1. `static getDerivedStateFromProps()`\n2. `shouldComponentUpdate(nextProps, nextState)`: Returns a boolean (`true`/`false`). **Crucial for performance optimization.** You can compare old vs. new props to block unnecessary re-renders.\n3. `render()`: Re-evaluates and redraws the UI.\n4. `getSnapshotBeforeUpdate()`: Captures UI info (like scroll position) right before the DOM/Native view updates.\n5. `componentDidUpdate(prevProps, prevState)`: Invoked immediately after updating. Perfect for making network calls based on data changes (e.g., refetching an API if a user ID changes).\n\n- **Functional Component Hook Equivalent:**\n- `useEffect(() => { ... }, [dependency])`: Runs every time the variables inside the dependency array change. This acts like a combined `componentDidMount` and `componentDidUpdate`.\n- For `shouldComponentUpdate`, functional components use **`React.memo`** to wrap the component and prevent unnecessary re-renders unless props change.\n\n### Phase 3: Unmounting (Dying)\n\nThis occurs when a component is removed from the application screen (e.g., navigating away or closing a modal).\n\n- **Class Component Method:**\n- `componentWillUnmount()`: Invoked immediately before a component is destroyed. **This is where you clear timers, cancel network requests, and remove event listeners to prevent memory leaks.**\n\n- **Functional Component Hook Equivalent:**\n- The **Cleanup Function** inside `useEffect`. If your `useEffect` returns a function, React executes it when the component unmounts.\n\n---\n\n## Code Comparison: End-to-End Implementation\n\nHere is a side-by-side example of how to build a component that fetches data, tracks state, and listens to a native back-button event.\n\n### The Class Component Way\n\n```javascript\nimport React, { Component } from \"react\";\nimport { Text, View, BackHandler } from \"react-native\";\n\nclass UserProfile extends Component {\n  constructor(props) {\n    super(props);\n    this.state = { loading: true, userData: null };\n  }\n\n  // 1. Mount\n  componentDidMount() {\n    this.fetchUserData();\n    this.backHandler = BackHandler.addEventListener(\n      \"hardwareBackPress\",\n      this.handleBack,\n    );\n  }\n\n  // 2. Update Optimization\n  shouldComponentUpdate(nextProps, nextState) {\n    return (\n      nextState.userData !== this.state.userData ||\n      nextState.loading !== this.state.loading\n    );\n  }\n\n  // 3. Update execution\n  componentDidUpdate(prevProps) {\n    if (prevProps.userId !== this.props.userId) {\n      this.fetchUserData(); // Refetch if prop changed\n    }\n  }\n\n  // 4. Unmount / Cleanup\n  componentWillUnmount() {\n    this.backHandler.remove();\n  }\n\n  fetchUserData = () => {\n    /* API Fetch Logic */\n  };\n  handleBack = () => {\n    return true;\n  };\n\n  render() {\n    return (\n      <View>\n        {this.state.loading ? (\n          <Text>Loading...</Text>\n        ) : (\n          <Text>Welcome User</Text>\n        )}\n      </View>\n    );\n  }\n}\nexport default UserProfile;\n```\n\n### The Functional Component Way (Modern & Preferred)\n\n```javascript\nimport React, { useState, useEffect, memo } from \"react\";\nimport { Text, View, BackHandler } from \"react-native\";\n\nconst UserProfile = ({ userId }) => {\n  const [loading, setLoading] = useState(true);\n  const [userData, setUserData] = useState(null);\n\n  useEffect(() => {\n    // 1. Mount & Update Logic\n    const fetchUserData = () => {\n      /* API Fetch Logic */\n    };\n    fetchUserData();\n\n    const handleBack = () => {\n      return true;\n    };\n    const backHandler = BackHandler.addEventListener(\n      \"hardwareBackPress\",\n      handleBack,\n    );\n\n    // 2. Unmount / Cleanup Logic\n    return () => {\n      backHandler.remove(); // This acts as componentWillUnmount\n    };\n  }, [userId]); // Triggers refetch if userId changes (componentDidUpdate)\n\n  return (\n    <View>{loading ? <Text>Loading...</Text> : <Text>Welcome User</Text>}</View>\n  );\n};\n\n// Replaces shouldComponentUpdate for performance\nexport default memo(UserProfile);\n```\n\n---\n\n## 🎯 What IBM Looks for in a Senior Answer:\n\nIf they ask why the industry shifted to functional components, mention these 3 architectural advantages:\n\n1. **Code Splitting / Separation of Concerns:** In class components, unrelated logic (API calls + EventListeners) are forced into the single `componentDidMount` block. Hooks allow you to split individual features into separate `useEffect` declarations.\n2. **No `this` binding issues:** Functional components avoid the confusing JavaScript scope of the `this` keyword, reducing bugs in callbacks.\n3. **Better Minification:** Classes do not minify well in JavaScript compilation pipelines, making functional bundles slightly more lightweight.\n\n---\n\nWhat is the next first-round question we should tackle? Let me know!\n","type":"md"},{"name":"026-NewFramework.md","content":"The \"New Architecture\" of React Native is the unified, high-performance foundation for the entire framework. Moving away from experimental opt-ins, the **Legacy Architecture (the async JSON Bridge) has been permanently removed from the runtime** (starting with versions like 0.82 and Expo SDK 55), making the New Architecture mandatory for modern application development.\n\nThe New Architecture was engineered to solve the historical bottleneck of cross-platform apps: **the serialization lag of sending data over a bridge**.\n\n---\n\n## The Four Core Pillars of the New Architecture\n\nThe framework relies on four deeply integrated systems written primarily in C++ that replace the old bridge entirely:\n\n```\n┌────────────────────────────────────────────────────────────────────────┐\n│                        JSI (JavaScript Interface)                      │\n│               Direct C++ Memory Pointers (No JSON Bridge)              │\n└───────────────────┬────────────────────────────────┬───────────────────┘\n                    ▼                                ▼\n┌──────────────────────────────────────┐ ┌───────────────────────────────┐\n│       Fabric Rendering Engine        │ │         TurboModules          │\n│  Synchronous, UI Thread Concurrency  │ │  Lazy-Loaded Native Features  │\n└───────────────────▲──────────────────┘ └───────────────▲───────────────┘\n                    │                                    │\n                    └─────────────────┬──────────────────┘\n                                      │\n                         ┌────────────┴────────────┐\n                         │         Codegen         │\n                         │ Type-Safe Native Guilds │\n                         └─────────────────────────┘\n\n```\n\n### 1. JSI (JavaScript Interface) — The Foundation\n\nThe legacy architecture relied on a literal asynchronous \"Bridge.\" Every layout instruction, click event, or hardware callback had to be converted into a stringified JSON payload, queued up, passed across the thread boundary, and deserialized on the other side.\n\n- **What it is:** JSI is a lightweight C++ open-source abstraction API that completely removes the bridge. It embeds the JavaScript engine (like Hermes) directly into the native runtime app shell.\n- **How it works:** Instead of sending text strings, JSI allows the JavaScript engine to hold **direct, physical C++ memory pointer references** to Native Host Objects, and vice-versa.\n- **Primary Uses:** It enables synchronous execution. JavaScript can call a native phone method (like a cryptographic process or data calculation) and receive the return payload immediately on the exact same thread line, slashing invocation latency by 30% to 50%. It is the engine that allows high-frequency real-time frames (like data visualization or camera streaming buffers) to pass seamlessly to JS.\n\n### 2. Fabric — The New Rendering Engine\n\nIn the old system, UI layouts were calculated asynchronously via the `UIManager`, resulting in a common visual bug: \"layout thrashing\" or a visible flicker/white flash when scrolling heavy lists or firing complex animations quickly.\n\n- **What it is:** Fabric is React Native’s modern C++ UI rendering engine that replaces the legacy view managers.\n- **How it works:** Fabric unifies rendering logic into a cross-platform C++ tree. When a state shifts, Fabric computes layout trees directly via JSI. Because it is synchronous, it can query and read exact view pixel boundaries mid-flight during layout commitments.\n- **Primary Uses:** Fabric brings full native support for **React Concurrent Rendering features** (such as `Suspense`, `Transitions`, and automatic batching). It introduces **Priority-Based Rendering**, meaning lower-priority background UI operations can be safely interrupted by higher-priority user events (like a swipe gesture or screen tap), preventing frame drops.\n\n### 3. TurboModules — On-Demand Native Features\n\nPreviously, when a user opened an application, React Native was forced to boot every single custom or third-party native plugin (Camera, Bluetooth, Storage, Location) straight into device memory during startup, even if the user never navigated to those features.\n\n- **What it is:** TurboModules is the completely overhauled native device framework interaction module.\n- **How it works:** Backed by JSI, TurboModules are written with strict platform boundaries and are **lazily loaded**.\n- **Primary Uses:** When your application initializes, TurboModules register a lightweight blueprint layout of device APIs but allocate zero physical device hardware RAM. The native modules are only initialized and loaded into memory the exact millisecond a JavaScript hook calls for them. This optimization decreases cold-boot startup times by up to 40% in large-scale applications.\n\n### 4. Codegen — The Static Type-Safety Guard\n\nA major pain point in older cross-platform development was runtime native exceptions. If JavaScript passed an `int` parameter but the Objective-C or Java module expected a `string`, the app would crash instantly in production.\n\n- **What it is:** Codegen is an automated, build-time compilation tool embedded right inside the bundler workflow.\n- **How it works:** Instead of letting you write loose object structures, Codegen acts as a gatekeeper. It forces you to declare explicit interface structures using strongly typed TypeScript or Flow. During the build phase, Codegen reads these files and automatically generates the highly complex C++ data-struct binding layers required to bridge JavaScript types to native types.\n- **Primary Uses:** It eliminates type mismatch bugs completely before your app leaves your laptop. If a native contract structure breaks, your build fails immediately at compile time rather than causing unexpected crashes on a user's phone.\n\n---\n\n## Real-World Architectural Advantages\n\nReal-world production metrics show clear optimization across metrics when running completely on this modern layout:\n\n- **Drastic Memory Drop:** Eliminating bridge-side data serialization drops internal RAM usage by 20% to 30%.\n- **Thread Concurrency Engine (Worklets):** The New Architecture enables tools like React Native Worklets. Heavy operations (like real-time calculations or cryptography) can run inside isolated secondary runtimes off the main JavaScript thread. This keeps your main interface ticking at a fluid, stutter-free 60 FPS / 120 Hz pace.\n- **Web Alignment Parity:** The architecture unifies concepts with web engines. Initiatives like _React Strict DOM_ let engineers target web and mobile applications with highly identical styling layout specifications, streamlining the universal workspace.\n\n---\n\n## 🎯 How to explain this to an IBM Panel\n\n> \"The New Architecture is a complete ground-up re-engineering of React Native's internal communication runtime. By replacing the legacy asynchronous JSON Bridge with a **C++ JSI foundation**, the framework enables direct memory synchronization between JavaScript and the host platforms. This allows **TurboModules** to load native capabilities lazily on demand, while the **Fabric engine** computes synchronous layout paths via **Yoga** to support React concurrent rendering structures. Guarded by **Codegen's compile-time type-safety validation**, this framework eliminates the traditional performance boundaries of hybrid platforms, allowing us to build native-tier applications with clean enterprise-level maintainability.\"\n","type":"md"},{"name":"021-oldVsNewArchitecture.md","content":"This is the ultimate architectural showdown question. Interviewers at IBM ask this to see if a candidate genuinely understands how React Native transitioned from a web-centric hybrid framework to a high-performance, native-tier engineering ecosystem.\n\nTo give a world-class answer, we will map out the **Old Architecture**, the **New Architecture**, and break down every single module’s **Role, Responsibility, Mechanism, and Timing**.\n\n---\n\n### The Big Picture: Old vs. New Architecture\n\nTo understand the individual modules, you first need to see how the entire system layout changed.\n\n```\nOLD ARCHITECTURE:\n[JS Engine] <--- (Async JSON Serialization) ---> [ The Bridge ] <--- (Async JSON Deserialization) ---> [Native UI / Modules]\n* Bottleneck: Everything had to be converted into JSON strings and queued up across a single asynchronous bridge.\n\nNEW ARCHITECTURE:\n[JS Engine (Hermes)] <===============> [ JavaScript Interface (JSI) ] <===============> [Native Platform UI / Core]\n                                         (Direct C++ Memory Pointers)\n\n```\n\nIn the New Architecture, the slow JSON Bridge is completely removed. JavaScript can now talk directly to C++ and Native code with zero conversion lag.\n\n---\n\n### End-to-End Module Breakdown\n\nHere is the precise profile of every core module, sorted by where and when they execute.\n\n| Module Name                    | Core Role & Responsibility                                  | What It Does / How It Works                                                                                                                                                                              | When It Works (Timing)                                                                              |\n| ------------------------------ | ----------------------------------------------------------- | -------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- | --------------------------------------------------------------------------------------------------- |\n| **Babel**                      | Source-to-source compiler (Transpiler).                     | Transforms modern JavaScript (ESNext), JSX layout components, and TypeScript definitions into standard backward-compatible ES5 JavaScript code.                                                          | **Build Time** (Runs on your computer/CI server inside the bundler before deployment).              |\n| **Metro**                      | JavaScript Bundler.                                         | Resolves file dependencies starting from `index.js`, coordinates with Babel for code transformation, maps asset files (like PNGs), and merges thousands of files into one optimized `index.bundle` file. | **Build Time** (And instantly during development for **Fast Refresh** hot reloading).               |\n| **Proguard / R8**              | Java bytecode optimizer and shrinker.                       | Inspects compiled Java bytecode (`classes.dex`), deletes unused code paths from third-party SDKs, and obfuscates class names to shrink the final APK size and prevent reverse-engineering.               | **Build Time** (Executes strictly during the native release build compiling phase on Android).      |\n| **Yoga**                       | Cross-platform Layout Engine.                               | A high-performance engine written in C++ that maps web-standard Flexbox styles (`flexDirection`, `gap`, `padding`) into absolute geometric pixel coordinates (`Width`, `Height`, `Top`, `Left`).         | **Runtime** (Executes continuously on the rendering thread whenever layout boundaries shift).       |\n| **JSI (JavaScript Interface)** | The foundational translation layer of the New Architecture. | A lightweight C++ abstraction layer that exposes Native Host Objects directly to the JavaScript runtime environment. It allows JS to hold direct memory pointers to C++ functions.                       | **Runtime** (Operates continuously from the millisecond the app boots up until it closes).          |\n| **Fabric**                     | The New Architecture's conceptual Rendering System.         | Replaces the old \"UI Manager.\" It manages the creation of Shadow UI trees directly in C++ via JSI, allowing UI changes to be executed synchronously on any thread, eliminating visual \"glitches.\"        | **Runtime** (Triggers whenever state changes force a visual interface layout calculation).          |\n| **TurboModules**               | The New Architecture's Native Module system.                | Replaces legacy Native Modules. It allows JavaScript to lazily load and call native device APIs (Camera, Bluetooth, Biometrics) instantly as standard synchronous C++ functions.                         | **Runtime** (Executes lazily—only boots into memory the exact millisecond code requests a feature). |\n\n---\n\n### Deep-Dive: How They Work Together (The Step-by-Step Lifecycles)\n\nLet's look at two real-world scenarios to see how these modules orchestrate tasks together under the hood.\n\n#### Scenario 1: The Build and Startup Sequence (From Code to Screen)\n\n1. **Compilation Phase:** You run a release build. **Metro** maps your project files. It feeds them to **Babel**, which strips TypeScript and turns JSX into `React.createElement` syntax. The **Hermes** compiler takes that clean JavaScript code and pre-compiles it into highly optimized bytecode.\n2. **Native Compression Phase:** On Android, **Proguard/R8** strips out dead Java modules. Everything is packed tightly into a signed APK/IPA bundle.\n3. **App Launch Phase:** The user opens the app. The native OS container boots and initializes the **Hermes engine**.\n4. **JSI Initialization Phase:** Hermes hooks into the **JSI** layer. JSI creates global C++ pointer configurations, binding JavaScript references to the native hardware APIs and the rendering threads.\n5. **Initial Layout Phase:** JavaScript evaluates the initial screen layout tree. **Fabric** intercepts the virtual elements and transfers them to **Yoga** via JSI. Yoga instantly solves the Flexbox mathematics, calculates the exact pixel bounds, and Fabric passes those absolute bounds to the OS main thread to paint the native UI widgets instantly.\n\n---\n\n#### Scenario 2: Invoking a Device Feature (e.g., Triggering a Fingerprint Scan)\n\nLet's contrast how this action executes between the Old Architecture and the New Architecture to show your technical depth:\n\n**In the Old Architecture (The Legacy Way):**\n\n1. Your JavaScript code called `BiometricModule.authenticate()`.\n2. The React Native framework intercepted the call, serialized the method name and arguments into a text JSON string: `\"[ 'BiometricModule', 'authenticate', [] ]\"`.\n3. This string was pushed into an asynchronous queue on **The Bridge**.\n4. The Native thread pulled the string out of the queue, parsed the JSON text back into memory, looked up the native Java/Swift class, and finally triggered the sensor.\n\n- _The Flaw:_ If the bridge was clogged with heavy scroll graphics data, your biometric sensor call would lag arbitrarily.\n\n**In the New Architecture (The Modern Way):**\n\n1. Your JavaScript code calls `BiometricModule.authenticate()`.\n2. Because of **JSI**, `BiometricModule` isn't an abstract identifier—it is a direct JavaScript wrapper pointing to a C++ Host Object managed by **TurboModules**.\n3. JavaScript invokes the method. The call immediately jumps through the C++ memory pointer directly into the native Java/Swift execution block.\n4. The biometric sensor fires instantly with **zero serialization, zero string translation, and zero queue delays**.\n\n---\n\n### 🎯 How to bring this home for the IBM Panel\n\nWhen summarizing this total layout, wrap it up with this high-level response:\n\n> \"The evolution of React Native centers on moving from an asynchronous, decoupled text-translation pipeline to a highly unified, memory-synchronized architecture. By using **Metro and Babel** at build-time to optimize bundles, and **Hermes with Proguard** to strip weight, we deliver minimal binary footprints.\n> At runtime, the framework is anchored by the **C++ JSI layer**, which completely removes the legacy JSON bridge. This allows **TurboModules** to execute native hardware capabilities synchronously via direct memory pointers, while **Fabric pairs with the Yoga layout engine** to compute and commit interface frame calculations directly on native threads. The result is a unified system that matches the speed, predictability, and memory safety of pure native compilation.\"\n","type":"md"},{"name":"023-justfycontent-alignitems.md","content":"In React Native (and web development), **`justifyContent`** and **`alignItems`** are the two foundational Flexbox properties used to align and distribute child elements inside a parent container.\n\nTo understand exactly how they work, you must first understand the concept of **Axes (the Main Axis and the Cross Axis)**. How these properties behave depends entirely on your **`flexDirection`**.\n\n---\n\n## 1. The Core Rule: Understanding the Axes\n\nFlexbox handles alignment along two invisible lines:\n\n1. **Main Axis:** The primary direction in which child items are laid out.\n2. **Cross Axis:** The line running exactly perpendicular (at a 90-degree angle) to the Main Axis.\n\n### The React Native Default\n\nIn web development, the main axis defaults to horizontal (`row`). However, **in React Native, the default layout is vertical (`column`)** to match the vertical screen orientation of mobile devices.\n\n- If `flexDirection: 'column'` (Default): The Main Axis is **Vertical (Top to Bottom)** and the Cross Axis is **Horizontal (Left to Right)**.\n- If `flexDirection: 'row'`: The Main Axis is **Horizontal (Left to Right)** and the Cross Axis is **Vertical (Top to Bottom)**.\n\n---\n\n## 2. `justifyContent` (Aligns along the Main Axis)\n\n`justifyContent` is responsible for distributing empty space and aligning child items along the **Main Axis**.\n\n### Common Values and How They Work:\n\n- **`flex-start` (Default):** Items are grouped tightly at the start of the main axis (e.g., at the top for columns, or the left for rows).\n- **`center`:** Items are grouped tightly right in the exact middle of the main axis.\n- **`flex-end`:** Items are grouped tightly at the end of the main axis (e.g., at the bottom for columns, or the right for rows).\n- **`space-between`:** Items are spread out evenly across the entire main axis. The first item goes to the absolute start, the last item goes to the absolute end, and the remaining space is divided equally between the items in the middle.\n- **`space-around`:** Items are spread out evenly, but each item gets an equal amount of blank space on _both_ sides of it. (The gap between two items will look twice as wide as the gap at the outer edges).\n- **`space-evenly`:** Items are distributed so that the spacing between any two items, and the spacing from the items to the outer edges, is exactly identical.\n\n---\n\n## 3. `alignItems` (Aligns along the Cross Axis)\n\n`alignItems` is responsible for aligning child items along the **Cross Axis** (perpendicular to how they are flowing).\n\n### Common Values and How They Work:\n\n- **`stretch` (Default):** Items are stretched out to fill the entire width or height of the cross axis (unless you give the child a hardcoded width/height, which overrides the stretch).\n- **`flex-start`:** Items are aligned to the start of the cross axis (e.g., aligned to the left edge if your main axis is a vertical column).\n- **`center`:** Items are centered perfectly along the cross axis line.\n- **`flex-end`:** Items are aligned to the trailing end of the cross axis (e.g., aligned to the right edge if your main axis is a vertical column).\n\n---\n\n## 4. Visual Code Example: Putting Them Together\n\nLet's look at a common production scenario: Centering an investment balance card perfectly on a mobile dashboard screen.\n\n```javascript\nimport React from \"react\";\nimport { View, Text, StyleSheet } from \"react-native\";\n\nexport default function CenteredCard() {\n  return (\n    <View style={styles.screenContainer}>\n      <View style={styles.balanceCard}>\n        <Text style={styles.text}>Wallet Balance</Text>\n        <Text style={styles.amount}>$45,000</Text>\n      </View>\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  screenContainer: {\n    flex: 1,\n    backgroundColor: \"#f5f5f5\",\n\n    // 1. By default, flexDirection is 'column' (Main Axis = Vertical, Cross Axis = Horizontal)\n\n    // 2. Centering vertically along the Main Axis (Moves card to the vertical middle of the screen)\n    justifyContent: \"center\",\n\n    // 3. Centering horizontally along the Cross Axis (Moves card to the horizontal middle of the screen)\n    alignItems: \"center\",\n  },\n  balanceCard: {\n    width: 300,\n    height: 120,\n    backgroundColor: \"#0052cc\",\n    borderRadius: 12,\n    padding: 20,\n\n    // Inside the card, let's change the axis to row!\n    flexDirection: \"row\",\n    // Now: Main Axis = Horizontal (Left to Right), Cross Axis = Vertical (Top to Bottom)\n\n    // Pushes the text label to the left and amount to the far right edge horizontally\n    justifyContent: \"space-between\",\n\n    // Centers the text and amount vertically so they line up cleanly in the middle of the card\n    alignItems: \"center\",\n  },\n  text: { color: \"#fff\", fontSize: 16 },\n  amount: { color: \"#fff\", fontSize: 22, fontWeight: \"bold\" },\n});\n```\n\n---\n\n## 🎯 How Yoga and JSI Process This (For Your IBM Interview)\n\nTo tie this back to the architectural concepts you mastered earlier, here is how you can explain the mechanics of these two properties to an interviewer:\n\n> \"`justifyContent` and `alignItems` are declarative Flexbox alignment structures. When we declare them in JavaScript, they don't map directly to native Android or iOS XML styling parameters. Instead, the **Yoga layout engine** parses these style objects.\n> Yoga reads the `flexDirection` to establish the Main and Cross axes. If we use `justifyContent: 'space-between'`, Yoga's C++ core calculates the total viewport size, subtracts the widths of the inner elements, divides the remaining pixel space, and assigns absolute `Top` and `Left` coordinate bounding boxes. The **Fabric rendering system** then passes these exact pixel numbers across the **JSI memory layer** to the main OS thread to instantly paint the native views exactly where they belong.\"\n","type":"md"},{"name":"034-TestingTypes.md","content":"In React Native, testing is split into clear layers. The closer you get to a real device, the more confidence you get, but the tests also get slower and tougher to maintain.\n\nMost React Native apps use a default stack: **Jest** (comes built-in for running JavaScript tests) paired with **React Native Testing Library (RNTL)** for components, and tools like **Maestro** or **Detox** for full-device automation.\n\n---\n\n## 1. Unit Testing (Functions & Logic)\n\n**What it is:** Testing the smallest, isolated parts of your code—like helper functions, utility methods, or custom hooks—without rendering any UI.\n\n- **Primary Tool:** Jest (built into React Native by default).\n\n### The Code (`utils.js`)\n\n```javascript\nexport const formatCurrency = (amount) => {\n  if (typeof amount !== \"number\") return \"$0.00\";\n  return `$${amount.toFixed(2)}`;\n};\n```\n\n### The Test (`utils.test.js`)\n\n```javascript\nimport { formatCurrency } from \"./utils\";\n\ndescribe(\"formatCurrency\", () => {\n  it(\"formats a number into a dollar currency string\", () => {\n    expect(formatCurrency(10.5)).toBe(\"$10.50\");\n  });\n\n  it(\"returns a fallback string if given an invalid input\", () => {\n    expect(formatCurrency(\"invalid\")).toBe(\"$0.00\");\n  });\n});\n```\n\n---\n\n## 2. Component/Interaction Testing\n\n**What it is:** Verifying that your React components render correctly and respond properly when users interact with them (e.g., typing or tapping).\n\n- **Primary Tool:** Jest + `@testing-library/react-native` (RNTL).\n\n### The Code (`Counter.js`)\n\n```javascript\nimport React, { useState } from \"react\";\nimport { StyleSheet, Text, TouchableOpacity, View } from \"react-native\";\n\nexport default function Counter() {\n  const [count, setCount] = useState(0);\n\n  return (\n    <View style={styles.container}>\n      <Text testID=\"count-text\">Count: {count}</Text>\n      <TouchableOpacity onPress={() => setCount(count + 1)}>\n        <Text>Increment</Text>\n      </TouchableOpacity>\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({ container: { padding: 20 } });\n```\n\n### The Test (`Counter.test.js`)\n\n```javascript\nimport React from \"react\";\nimport { render, fireEvent } from \"@testing-library/react-native\";\nimport Counter from \"./Counter\";\n\ndescribe(\"<Counter />\", () => {\n  it(\"increments the count when the button is pressed\", () => {\n    // 1. Render the component in memory\n    const { getByText, getByTestId } = render(<Counter />);\n\n    // 2. Query elements from the UI\n    const countLabel = getByTestId(\"count-text\");\n    const button = getByText(\"Increment\");\n\n    // 3. Assert initial state\n    expect(countLabel.props.children).container(\"Count: \", 0);\n\n    // 4. Simulate a real user tap\n    fireEvent.press(button);\n\n    // 5. Assert updated state\n    expect(countLabel.props.children).container(\"Count: \", 1);\n  });\n});\n```\n\n---\n\n## 3. Snapshot Testing\n\n**What it is:** Taking a look at the rendered HTML-like output of your component and saving it to a file. Next time the test runs, Jest makes sure nobody accidentally changed the layout structure.\n\n- **Primary Tool:** Jest.\n\n### The Test (`CounterSnapshot.test.js`)\n\n```javascript\nimport React from \"react\";\nimport render from \"react-test-renderer\";\nimport Counter from \"./Counter\";\n\ntest(\"Counter renders consistently\", () => {\n  const tree = render.create(<Counter />).toJSON();\n  expect(tree).toMatchSnapshot();\n});\n```\n\n> **A quick heads-up on Snapshots:** They are great for simple components, but they break easily if you change minor things like styling or text. Avoid relying too heavily on them for dynamic UIs.\n\n---\n\n## 4. Integration Testing (API / Network Calls)\n\n**What it is:** Testing a user flow across multiple components or screens that rely on external data. Instead of hitting the actual production servers, you mock (fake) the network requests to keep tests fast and predictable.\n\n- **Primary Tool:** Jest + RNTL + MSW (Mock Service Worker) or `jest.mock`.\n\n### The Test with a Mocked API (`UserList.test.js`)\n\n```javascript\nimport React from \"react\";\nimport { render, waitFor } from \"@testing-library/react-native\";\nimport UserList from \"./UserList\";\n\n// Mocking global fetch API\nglobal.fetch = jest.fn(() =>\n  Promise.resolve({\n    json: () => Promise.resolve([{ id: 1, name: \"Alex\" }]),\n  }),\n);\n\ndescribe(\"<UserList />\", () => {\n  it(\"fetches data and lists users successfully\", async () => {\n    const { getByText } = render(<UserList />);\n\n    // Wait for the async API hook to complete and render the text\n    await waitFor(() => {\n      expect(getByText(\"Alex\")).toBeTruthy();\n    });\n  });\n});\n```\n\n---\n\n## 5. End-to-End (E2E) Testing\n\n**What it is:** Running tests like a robot on a real iOS/Android simulator or physical device. It launches the actual built app binaries, boots them up, and navigates through real user journeys (Sign-up, checkout, etc.).\n\n- **Primary Tools:** **Maestro** (highly recommended for modern setup due to simplicity) or **Detox** (the classic gray-box testing library for React Native).\n\n### Maestro Example (`flows/login.yaml`)\n\nMaestro doesn't use JavaScript for tests; it uses a dead-simple declarative YAML script:\n\n```yaml\nappId: com.example.myapp\n---\n- launchApp\n- tapOn: \"Email Input\"\n- inputText: \"user@example.com\"\n- tapOn: \"Password Input\"\n- inputText: \"securePassword123\"\n- tapOn: \"Login Button\"\n- assertVisible: \"Welcome back, User!\"\n```\n\n---\n\n### Which one should you prioritize?\n\nIf you are wondering where to focus your energy first, look at the classic Testing Pyramid strategy:\n\n- **70% Component & Unit Tests:** Keep these fast, run them automatically on every code commit. They cover your main logic and user interactions.\n- **20% Integration/Screen Tests:** Cover key flows that connect multiple views or require API mocking.\n- **10% E2E Tests:** Run these strictly on critical application lifelines (like making sure a user can successfully finish a checkout checkout or account registration). They are slower but give you the highest confidence.\n","type":"md"},{"name":"017-Babel.md","content":"## 1. What is Babel? (Is it a Compiler?)\n\nYes, **Babel is a JavaScript compiler**—specifically, a **source-to-source compiler** or **transpiler**.\n\nBabel does not compile your JavaScript into machine code or binary code (like `01010`). Instead, it compiles modern, cutting-edge JavaScript syntax (ES6, ES7, ESNext), JSX, and TypeScript into a backward-compatible version of JavaScript that older JavaScript engines (like older V8 engines, Safari's JavaScriptCore, or legacy environments) can understand without crashing.\n\n---\n\n## 2. Why Does React Native Need Babel?\n\nReact Native relies on Babel for three critical reasons:\n\n- **JSX Transformation:** React Native uses JSX syntax (e.g., `<View><Text>Hello</Text></View>`). JavaScript engines have absolutely no idea what JSX is; it is a syntax error. Babel intercepts this and converts it into pure JavaScript function calls (`React.createElement` or modern JSX runtime equivalents).\n- **Language Feature Bridging:** Modern mobile applications use advanced JavaScript capabilities like Optional Chaining (`user?.profile?.name`), Nullish Coalescing (`??`), Async/Await, and modern decorator classes. Older runtime engines on legacy Android/iOS versions cannot parse these natively. Babel converts them down to standard ES5 compatible code.\n- **TypeScript & Flow Compilation:** If you write your React Native application in TypeScript, Babel handles striping away the static type definitions instantly, turning it into clean, executable JavaScript.\n\n---\n\n## 3. How Does Babel Work Under the Hood?\n\nBabel parses and transforms your code using a highly calculated **three-step pipeline**:\n\n### Phase 1: Parsing (Source Code ➡️ AST)\n\nBabel takes your raw source code strings and processes them through a lexical analyzer. It converts the code into a deeply nested JSON data structure called an **Abstract Syntax Tree (AST)**. The AST maps out the exact structural meaning of your code line-by-line.\n\n> **Example:** A simple line like `const arrowFunc = () => {};` is broken down into an AST mapping: _VariableDeclaration ➡️ VariableDeclarator ➡️ ArrowFunctionExpression_.\n\n### Phase 2: Transformation (AST ➡️ Modified AST)\n\nThe core of Babel does absolutely nothing by itself; it relies entirely on **Plugins** and **Presets** (bundles of plugins).\nDuring this phase, Babel traverses the AST. When a plugin encounters a specific modern syntax block (like an Arrow Function), it modifies that specific branch of the AST JSON tree into an older syntax structure (a standard anonymous `function` expression).\n\n### Phase 3: Generation (Modified AST ➡️ Compiled Code)\n\nBabel reads the newly modified AST and serializes it back into a standard string of JavaScript source code, while generating your crucial debugging **Source Maps** simultaneously.\n\n---\n\n## 4. How React Native Uses Babel in Production\n\nIn a React Native architecture, Babel does not run on the user's phone. It runs completely on your development computer or CI/CD build server inside the **Metro Bundler** (React Native's specialized JavaScript packager).\n\n### The Execution Workflow:\n\n1. When you boot your environment using `npx react-native start` or `npx expo start`, the Metro Bundler boots up.\n2. Every time Metro reads a `.js`, `.jsx`, `.ts`, or `.tsx` file from your codebase, it feeds that file straight into the **Babel engine** before compiling it into the final `index.bundle` asset bundle.\n3. Babel uses a specialized, pre-configured file found in your project root called **`babel.config.js`**.\n\n### The React Native Babel Config Blueprint:\n\nIn a production-grade React Native app, your configuration file looks like this:\n\n```javascript\n// babel.config.js\nmodule.exports = {\n  // Presets are pre-packaged groups of plugins managed by the core team\n  presets: [\"module:metro-react-native-babel-preset\"],\n\n  // Plugins handle isolated specific compiler tasks\n  plugins: [\n    \"react-native-reanimated/plugin\", // Custom macro injected for high-performance native UI animations\n  ],\n};\n```\n\n### The Real-World Visual Code Transformation:\n\nHere is exactly how Babel changes your source code behind the scenes during the Metro bundle phase:\n\n**What you write in your IDE:**\n\n```javascript\nimport React from \"react\";\nimport { View, Text } from \"react-native\";\n\nexport const UserCard = ({ user }) => {\n  const name = user?.name ?? \"Guest\";\n  return (\n    <View>\n      <Text>{name}</Text>\n    </View>\n  );\n};\n```\n\n**What Babel outputs into the compiled JavaScript bundle:**\n\n```javascript\n\"use strict\";\n\nObject.defineProperty(exports, \"__esModule\", { value: true });\nexports.UserCard = void 0;\nvar _react = _interopRequireDefault(require(\"react\"));\nvar _reactNative = require(\"react-native\");\n\nvar UserCard = function UserCard(_ref) {\n  var _user$name;\n  var user = _ref.user;\n  // Optional chaining and nullish coalescing compiled down to basic ternary checks\n  var name =\n    (_user$name = user === null || user === void 0 ? void 0 : user.name) !==\n      null && _user$name !== void 0\n      ? _user$name\n      : \"Guest\";\n\n  // JSX transformed into raw element creation parameters\n  return _react.default.createElement(\n    _reactNative.View,\n    null,\n    _react.default.createElement(_reactNative.Text, null, name),\n  );\n};\nexports.UserCard = UserCard;\n```\n\n---\n\n## 🎯 How to frame this explanation for IBM\n\nThis answer rounds out your senior profile by showcasing compiler-level architecture expertise:\n\n> \"Babel is a source-to-source JavaScript compiler critical to the React Native building pipeline. Operating directly inside the **Metro Bundler orchestration layer**, Babel takes our ultra-modern JSX, TypeScript, and modern JavaScript syntax, passes it through an **Abstract Syntax Tree (AST)** translation pipeline, and compiles it down to cross-platform safe code. By utilizing standard presets like `module:metro-react-native-babel-preset`, it ensures that advanced structural paradigms—like Optional Chaining or native animation library hooks—translate seamlessly into standard execution streams that mobile JavaScript engines like Hermes can process cleanly without runtime compiler faults.\"\n","type":"md"},{"name":"035-git-commands.md","content":"Think of **Git** as a high-powered time machine for your project's files, and a **CI/CD pipeline** as the automated conveyor belt that tests and delivers your project to the world.\n\nEven if you aren't writing software, Git is incredibly useful for tracking changes in any text-based project (like writing a book, managing configuration files, or keeping track of complex datasets).\n\n---\n\n## Part 1: Why Do We Use Git?\n\nWithout Git, managing project versions usually looks like this:\n\n- `project_final.txt`\n- `project_final_v2.txt`\n- `project_final_FINAL_actual_version.txt`\n\n**Git solves this by:**\n\n- **Tracking History:** It remembers exactly who changed what line, and when.\n- **Safety Net:** You can instantly revert your project back to a working state if something breaks.\n- **Collaboration:** Multiple people can work on the exact same files simultaneously without overwriting each other's work.\n\n---\n\n## Part 2: The Essential Git Commands (Daily Life Flow)\n\nHere is the exact lifecycle of how you use Git every day, broken down into the most important commands.\n\n### 1. Setting Up\n\n- `git init`\n- **What it does:** Creates a brand-new, empty Git repository in your current folder.\n- **Why use it:** To start tracking a new project from scratch.\n\n- `git clone <url>`\n- **What it does:** Downloads an existing project from the cloud (like GitHub or GitLab) to your computer.\n- **Why use it:** To start working on a project that already exists.\n\n### 2. The Daily Work Loop (Saving Changes)\n\nImagine Git as a camera. You don't just take a picture of everything instantly; you arrange the subjects first, then snap the photo.\n\n- `git status`\n- **What it does:** Shows you which files have been modified, created, or deleted.\n- **Why use it:** Your starting point. Run this to see \"what is the current state of my folder?\"\n\n- `git add <filename>` (or `git add .` for all files)\n- **What it does:** Moves changes to the **Staging Area** (arranging the subjects for the photo).\n- **Why use it:** To tell Git exactly which changes you want to include in your next save point.\n\n- `git commit -m \"Your descriptive message\"`\n- **What it does:** Snaps the photo. It permanently saves your staged changes into the local history with a message explaining _why_ you made the change.\n- **Why use it:** To create a checkpoint you can return to later if needed.\n\n### 3. Collaboration & Sharing\n\n- `git push origin <branch-name>`\n- **What it does:** Uploads your local commits to the cloud (GitHub/GitLab).\n- **Why use it:** To share your work with your team or back it up safely online.\n\n- `git pull`\n- **What it does:** Downloads the latest changes from the cloud and merges them into your computer.\n- **Why use it:** To make sure you have your teammates' latest updates before you start working.\n\n### 4. Branching (Working in Parallel)\n\n- `git checkout -b <new-branch-name>`\n- **What it does:** Creates and switches to a \"parallel universe\" called a branch.\n- **Why use it:** So you can experiment with a new feature without breaking the main, working version of the project (usually called `main` or `master`).\n\n---\n\n## Part 3: What is a CI/CD Pipeline?\n\nOnce you `git push` your code to GitHub, the **CI/CD Pipeline** kicks in. It stands for **Continuous Integration / Continuous Deployment**.\n\nThink of it as an automated quality-control factory.\n\n### The Breakdown:\n\n1. **Continuous Integration (CI):** \\* Every time you `git push` new code, an automated server grabs it, builds it, and runs **automated tests**.\n\n- **Why we use it:** To catch bugs immediately. If you broke something, the pipeline \"fails\" and alerts you before your broken code can affect anyone else.\n\n2. **Continuous Deployment (CD):**\n\n- If all the tests pass, the pipeline automatically takes that code and deploys (publishes) it straight to the live website or server.\n- **Why we use it:** It eliminates human error. No one has to manually log into a server to copy-paste files; the robots handle it safely and instantly.\n\n### Summary of the Whole Flow:\n\nYou write code $\\rightarrow$ You run `git add` and `git commit` $\\rightarrow$ You run `git push` $\\rightarrow$ The **CI/CD Pipeline** automatically tests it $\\rightarrow$ If successful, the pipeline deploys it to the live website.\n\nWhat kind of project are you planning to use Git for? I can give you a specific workflow tailored to it.\n\n\nHere are some of the most useful \"next-level\" Git commands that you will inevitably need as you start working on bigger projects or collaborating with others. These commands help you surgically move code around, fix mistakes, and mark important milestones.\n\n---\n\n## 1. `git cherry-pick <commit-hash>` (The Code Thief)\n\nImagine you are working on two different branches: `Feature-A` and `Bug-Fix`. You accidentally wrote a brilliant, unrelated fix inside `Feature-A`, but you need it over in `Bug-Fix` *right now* without moving all your other messy, unfinished feature work.\n\n* **What it does:** It copies a **single specific commit** from one branch and applies it onto your current branch.\n* **Why use it:** It saves you from copy-pasting code manually between branches or being forced to merge an entire branch just for one good change.\n\n> **How to use it:** > 1. Find the ID (hash) of the commit you want (e.g., `a1b2c3d`) using `git log`.\n> 2. Switch to the branch where you *want* the code to go (`git checkout Bug-Fix`).\n> 3. Run: `git cherry-pick a1b2c3d`\n\n---\n\n## 2. \"Git Omit\" — How to Actually Undo Things\n\nThere isn't a direct command called `git omit`, but in Git, \"omitting\" or undoing things usually takes three different forms depending on what you want to achieve:\n\n### A. `git reset` (The Time Rewinder)\n\n* **What it does:** Moves your current branch backward in time to a specific older commit, erasing the newer commits from your history.\n* **Why use it:** Use this if you made a mistake locally, haven't shared it with anyone yet, and want to completely wipe those commits from existence.\n* *Warning:* Running `git reset --hard` will permanently delete your uncommitted work.\n\n### B. `git revert <commit-hash>` (The Public Undo)\n\n* **What it does:** Instead of deleting history, it creates a *brand new commit* that does the exact opposite of the bad commit. (e.g., If commit A added a line, revert creates commit B that deletes that line).\n* **Why use it:** **This is the safest way to undo a mistake if you have already pushed your code to GitHub.** It doesn't rewrite history, so it won't mess up your teammates' computers.\n\n### C. `.gitignore` file (The Selective Blindfold)\n\n* **What it does:** This isn't a command, but a special file you create in your folder. You type file names or folder paths inside it (like `node_modules/`, `.env`, or `secrets.txt`).\n* **Why use it:** To tell Git to **permanently ignore and omit** these files from ever being tracked. This keeps log files, system junk, and private passwords out of your public repository.\n\n---\n\n## 3. `git tag` (The Milestone Marker)\n\nWhen you are building a project, your commit history becomes a massive, long list of messages. It's hard to tell which commit was the one you actually released to the public.\n\n* **What it does:** Assigns a permanent, human-readable label (like `v1.0.0` or `v2.1-beta`) to a specific moment in your Git history.\n* **Why use it:** It acts like a bookmark. Instead of searching through thousands of lines of history for \"the version we released in May,\" you can just look for the tag. It is also heavily used by **CI/CD pipelines**—many pipelines are set up to automatically deploy your code to production *only* when you create a new version tag.\n\n> **How to use it:**\n> * Create a tag: `git tag -a v1.0.0 -m \"First official release\"`\n> * Push tags to GitHub: `git push origin --tags`\n> \n> \n\n---\n\n## Summary of Advanced Power Moves\n\n| Situation | Command to Use |\n| --- | --- |\n| **Grab just one specific change** from another branch | `git cherry-pick <commit-id>` |\n| **Safely undo a mistake** that is already on GitHub | `git revert <commit-id>` |\n| **Wipe out recent local commits** completely | `git reset --hard <commit-id>` |\n| **Keep passwords or junk files out** of Git | Add them to a `.gitignore` file |\n| **Mark a major release version** for your CI/CD pipeline | `git tag -a v1.0.0` |\n\n\n\n","type":"md"},{"name":"036-pushnotificaition.md","content":"At an architecture level, push notifications in React Native work almost the same way as native Android/iOS apps. React Native is only the UI layer; the actual notification delivery is handled by the operating systems and push services.\n\n## High-Level Flow\n\n```text\nReact Native App\n       │\n       ▼\nGets Device Token\n       │\n       ▼\nBackend Server\n       │\n       ▼\nPush Provider\n(FCM / APNs)\n       │\n       ▼\nAndroid / iOS Device\n       │\n       ▼\nReact Native App\n```\n\n## 1. App Registration\n\nWhen the app starts:\n\n### Android\n\nThe app registers with Google via Firebase Cloud Messaging (FCM).\n\n### iOS\n\nThe app registers with Apple Push Notification Service (APNs).\n\nThe OS returns a unique **device token**.\n\n```js\nconst token = await messaging().getToken();\nconsole.log(token);\n```\n\nExample:\n\n```text\neD23x4AAbc123...\n```\n\n---\n\n## 2. Send Token to Backend\n\nYour React Native app sends this token to your backend.\n\n```json\n{\n  \"userId\": 101,\n  \"deviceToken\": \"eD23x4AAbc123...\"\n}\n```\n\nStore it in your database.\n\n```text\nUsers\n---------------------------\nid    name     deviceToken\n101   Rajeev   eD23x4AAbc\n```\n\n---\n\n## 3. Backend Triggers Notification\n\nSuppose a new order is assigned.\n\nBackend logic:\n\n```text\nNew Order Created\n       │\n       ▼\nFind Delivery Boy\n       │\n       ▼\nGet Device Token\n       │\n       ▼\nSend Notification\n```\n\nExample Node.js:\n\n```js\nawait admin.messaging().send({\n  token: deviceToken,\n  notification: {\n    title: \"New Order\",\n    body: \"You have a new delivery.\",\n  },\n});\n```\n\n---\n\n## 4. FCM/APNs Deliver Notification\n\nThe push provider:\n\n- Finds the device\n- Wakes it up\n- Sends the payload\n\n```json\n{\n  \"title\": \"New Order\",\n  \"body\": \"You have a new delivery\"\n}\n```\n\n---\n\n## 5. Device Receives Notification\n\n### App Closed (Killed)\n\nOS shows notification automatically.\n\n```text\n🔔 New Order\nYou have a new delivery\n```\n\nUser taps notification → App opens.\n\n---\n\n### App Background\n\nNotification appears in notification tray.\n\nReact Native can process the notification when opened.\n\n---\n\n### App Foreground\n\nBy default notification is not shown automatically.\n\nReact Native receives an event:\n\n```js\nmessaging().onMessage(async (remoteMessage) => {\n  console.log(remoteMessage);\n});\n```\n\nYou typically show a local notification.\n\n---\n\n## Architecture for Production Apps\n\n```text\nReact Native App\n        │\n        ▼\nFirebase Messaging SDK\n        │\n        ▼\nDevice Token\n        │\n        ▼\nNode.js Backend\n        │\n        ▼\nNotification Service\n        │\n        ├── Order Notifications\n        ├── Chat Notifications\n        ├── Promotion Notifications\n        └── Reminder Notifications\n        │\n        ▼\nFCM / APNs\n        │\n        ▼\nUser Device\n```\n\n## Common React Native Libraries\n\n- `@react-native-firebase/messaging`\n- `notifee`\n- `react-native-push-notification` (older projects)\n\nFor new React Native projects, the most common production setup is:\n\n```text\nReact Native\n    +\nFirebase Messaging\n    +\nNotifee\n    +\nNode.js Backend\n```\n\n## For Your Delivery App\n\nSince you're building a delivery application, a typical notification flow would be:\n\n```text\nMerchant Creates Order\n          │\n          ▼\nBackend\n          │\n          ▼\nAssign Delivery Agent\n          │\n          ▼\nSend Push Notification\n          │\n          ▼\nAgent Accepts Order\n          │\n          ▼\nNotify Customer\n```\n\nThis setup scales well for order updates, chat messages, live delivery tracking, and promotional notifications.\n\nBecause your backend **cannot directly send notifications to a user's phone**.\n\nFCM and APNs act as the official notification gateways maintained by Google and Apple.\n\n## Without FCM/APNs\n\nImagine your backend wants to notify a user's phone:\n\n```text\nBackend\n   │\n   ▼\nUser Phone ❌\n```\n\nProblems:\n\n- Phone may be offline\n- Phone IP address changes frequently\n- App may be closed or killed\n- Millions of devices need to be tracked\n- Android and iOS have strict battery-saving policies\n\nYour server cannot reliably wake up an app on a device.\n\n---\n\n## With FCM/APNs\n\n```text\nBackend\n   │\n   ▼\nFCM/APNs\n   │\n   ▼\nUser Phone\n```\n\nGoogle and Apple already maintain a persistent connection with every device.\n\n### Android\n\nEvery Android device maintains a connection to Google's servers.\n\n```text\nAndroid Phone\n      │\n      ▼\nGoogle FCM Servers\n```\n\n### iOS\n\nEvery iPhone maintains a connection to Apple's servers.\n\n```text\niPhone\n   │\n   ▼\nApple APNs Servers\n```\n\nWhen your backend sends a notification:\n\n```text\nBackend\n   │\n   ▼\nFCM/APNs\n   │\n   ▼\nDevice\n```\n\nGoogle/Apple know exactly where the device is and can wake it efficiently.\n\n---\n\n## Why Not Use WebSockets?\n\nYou might think:\n\n```text\nBackend\n   │\n   ▼\nWebSocket\n   │\n   ▼\nPhone\n```\n\nThis works only when:\n\n- App is open\n- Internet is active\n- OS hasn't killed the app\n\nIf the app is closed or killed:\n\n```text\nWebSocket ❌ Disconnected\n```\n\nNo notification can be delivered.\n\nPush notifications work even when:\n\n- App is closed\n- App is in background\n- Phone is locked\n\nbecause the OS trusts FCM/APNs.\n\n---\n\n## Why Does iOS Require APNs?\n\nApple does not allow third-party servers to directly wake apps.\n\nAll notifications must go through:\n\nApple APNs\n\n```text\nBackend\n   │\n   ▼\nAPNs\n   │\n   ▼\niPhone\n```\n\nIf you try to bypass APNs, it won't work.\n\n---\n\n## Why Do Many Apps Use FCM for Both Android and iOS?\n\nFirebase can act as a unified layer:\n\n```text\nBackend\n   │\n   ▼\nFCM\n   │\n   ├── Android → FCM → Device\n   │\n   └── iOS → APNs → Device\n```\n\nBenefits:\n\n- One API for Android and iOS\n- Token management\n- Topic subscriptions\n- Analytics\n- Retry handling\n\nThat's why most React Native apps use:\n\n- `@react-native-firebase/messaging`\n- FCM for Android\n- FCM + APNs for iOS\n\nEven on iOS, FCM ultimately forwards notifications to APNs behind the scenes.\n","type":"md"},{"name":"005-useEffect.md","content":"In React and React Native, **`useEffect`** is the most powerful and heavily used Hook. It allows functional components to handle **side effects**—which are operations that interact with the outside world or happen outside the scope of a standard UI render calculation.\n\nBecause a standard React component must be a \"pure function\" (meaning it only calculates JSX based on inputs), any operation that changes state, communicates with a server, or modifies native modules must be safely wrapped inside a `useEffect`.\n\n---\n\n## 1. What Exactly is a \"Side Effect\"?\n\nIn mobile app development, you cannot build a dynamic application without side effects. Common examples include:\n\n- Fetching data from a backend REST API (like your work with fintech APIs at LetsVenture).\n\n- Manually manipulating native elements or subscribing to native device features (Push Notifications, Geolocation, or deep linking via Branch).\n\n- Setting up analytical tracking triggers (like PostHog).\n\n- Setting up intervals or timers (`setTimeout` / `setInterval`).\n\nIf you run these actions directly inside the body of a functional component, they will execute on _every single render cycle_, causing infinite networks loops, memory leaks, and severe performance degradation.\n\n---\n\n## 2. The Syntax Anatomy\n\nThe `useEffect` hook takes two arguments: **a callback function** where you write your logic, and an optional **dependency array**.\n\n```javascript\nuseEffect(\n  () => {\n    // 1. Your side effect code lives here\n\n    return () => {\n      // 2. Your cleanup code lives here (Optional)\n    };\n  },\n  [\n    /* 3. Dependency Array (Optional) */\n  ],\n);\n```\n\n---\n\n## 3. The 3 Lifecycle Modes of `useEffect`\n\nDepending on how you configure that second argument (the dependency array), `useEffect` transforms to match different lifecycle behaviors.\n\n### Mode A: No Dependency Array (Runs on Every Render)\n\n```javascript\nuseEffect(() => {\n  console.log(\"I run on every single render!\");\n});\n```\n\n- **Behavior:** React runs this effect after the initial mount _and_ after every single state or prop change update.\n- **Use Case:** Highly uncommon in production. You should generally avoid this because it can cause performance bottlenecks.\n\n### Mode B: Empty Dependency Array `[]` (Mount Only)\n\n```javascript\nuseEffect(() => {\n  console.log(\"Component mounted!\");\n  fetchData();\n}, []); // Empty array\n```\n\n- **Behavior:** React runs the effect **exactly once**, immediately after the component is rendered to the screen for the first time. This mirrors the old Class component method `componentDidMount`.\n- **Use Case:** Initial API lookups, setting up event listeners, pulling secure tokens from storage on app boot.\n\n### Mode C: With Specific Dependencies `[prop, state]` (Runs on Updates)\n\n```javascript\nuseEffect(() => {\n  console.log(`User ID changed to: ${userId}. Fetching new wallet data...`);\n  fetchUserWallet(userId);\n}, [userId]); // Triggers only when userId changes\n```\n\n- **Behavior:** React runs this effect after the initial mount, and then skips execution on subsequent renders _unless_ the value of `userId` changes between renders. This mirrors the Class component method `componentDidUpdate`.\n- **Use Case:** Refetching data when a route parameter changes, validating a form dynamically as a user types into a text input.\n\n---\n\n## 4. The Critical \"Cleanup Function\" (Preventing Memory Leaks)\n\nOne of the most important concepts for a Senior Engineer to articulate is the **cleanup function**. If your effect establishes an ongoing connection or subscription, it must clear itself when the component goes away.\n\nIf you return a function from your `useEffect`, React will execute that function right before the component unmounts (destroys itself), mirroring `componentWillUnmount`.\n\n### Real-World Mobile Example:\n\n```javascript\nimport { useEffect } from \"react\";\nimport { BackHandler } from \"react-native\";\n\nconst MyScreen = () => {\n  useEffect(() => {\n    const handleBackButton = () => {\n      // Custom back navigation logic\n      return true;\n    };\n\n    // 1. Setup the listener when the screen mounts\n    const subscription = BackHandler.addEventListener(\n      \"hardwareBackPress\",\n      handleBackButton,\n    );\n\n    // 2. Return the cleanup function to tear it down\n    return () => {\n      subscription.remove();\n      console.log(\"Listener removed safely. No memory leaks!\");\n    };\n  }, []); // Run once on mount, clean up on unmount\n};\n```\n\n> **⚠️ What happens if you forget the cleanup?** If the user navigates away from `MyScreen`, the screen component is destroyed, but the Native Android back-handler event remains active in memory. If they press the back button on a completely different screen, your old, destroyed screen's logic will try to fire, causing your app to crash or behave unpredictably.\n\n---\n\n## 🎯 Senior Interview Golden Rules for `useEffect`\n\nIf IBM digs deeper into your React expertise during your second round, bring up these advanced rules to demonstrate deep architectural mastery:\n\n1. **Don't Fetch Directly with Async/Await in the Root:** You cannot make the callback function of `useEffect` an `async` function directly (e.g., `useEffect(async () => ...)`). This is because async functions automatically return a Promise, but `useEffect` is strictly designed to only expect nothing or a cleanup _function_ in return. Instead, declare an async function _inside_ the hook and call it:\n\n```javascript\nuseEffect(() => {\n  const loadData = async () => {\n    const res = await apiCall();\n  };\n  loadData();\n}, []);\n```\n\n2. **Every State Used Must Be Declared:** If you reference a variable or state inside your effect, it _must_ be included in your dependency array (unless it is a stable setter like `setLoading`). Skipping dependencies leads to stale closures, where your effect reads outdated memory states.\n3. **Prefer Specialized Libraries for Complex State:** In enterprise architectures like those you build, instead of chaining multiple `useEffect` statements to manage complex API data state caching, it is cleaner and more optimal to use **React Query** (which you already have on your resume!). React Query abstract away the need for raw `useEffect` blocks for data fetching, handling refetches and garbage collection out of the box.\n\n---\n\nWe have broken down performance parity, native modules, component types, and `useEffect`. What is the next first-round question you would like to analyze before we wrap up?\n\nThis is a brilliant follow-up and a very common trap question in senior interviews. Let’s break down both of your questions directly.\n\n---\n\n## 1. Is `useEffect` Synchronous or Asynchronous?\n\n**`useEffect` itself is strictly synchronous.**\n\nReact executes the body of your `useEffect` callback synchronously right after the layout and paint phases are completed on the screen.\n\nBecause it is synchronous, **you cannot make the root callback function `async` directly.** For example, this will throw a runtime error or a severe warning:\n\n```javascript\n// ❌ WRONG: Do NOT do this\nuseEffect(async () => {\n  const res = await apiCall();\n}, []);\n```\n\n### Why can't the root function be async?\n\nIn JavaScript, an `async` function automatically returns a `Promise`. However, React’s architecture explicitly expects the `useEffect` callback to return either **nothing (`undefined`)** or a **cleanup function**. If you pass an async function, React gets a Promise instead of a cleanup function, breaking its internal lifecycle engine.\n\nTo run asynchronous operations (like API calls) safely, you must do exactly what you wrote in your example: declare a nested async function _inside_ the synchronous hook and invoke it immediately.\n\n---\n\n## 2. In this specific function, do we need to use `return`?\n\nIn the exact code block you provided:\n\n```javascript\nuseEffect(() => {\n  const loadData = async () => {\n    const res = await apiCall();\n  };\n  loadData();\n}, []);\n```\n\n**No, you do not need to use a `return` statement here.**\n\nSince you are just fetching data and assigning it locally, the component mounts, fires the asynchronous network request, finishes its execution, and leaves the hook cleanly. React defaults to returning `undefined`, which is perfectly valid.\n\n---\n\n## 💡 When WOULD you need a `return` in this async setup?\n\nAs a Senior Developer, you should mention the one scenario where an async `useEffect` **does** need a return statement: **Race Conditions / Abort Controls.**\n\nIf a user opens a screen, your API call starts. If the user quickly navigates away _before_ the API call finishes, the component unmounts. When the API response finally arrives 2 seconds later, it will try to update the state of a destroyed component, causing an error or memory leak.\n\nTo fix this, you use a `return` statement to cancel or ignore the async operation if the component unmounts mid-flight.\n\n### The Senior Implementation (Handling Unmounts):\n\n```javascript\nuseEffect(() => {\n  // Create a flag to track if the component is active\n  let isMounted = true;\n\n  const loadData = async () => {\n    const res = await apiCall();\n\n    // Only update state if the user is still on this screen!\n    if (isMounted) {\n      setLocalState(res.data);\n    }\n  };\n\n  loadData();\n\n  // CLEANUP FUNCTION: Runs when the component unmounts\n  return () => {\n    isMounted = false; // Prevents updating state after unmount\n  };\n}, []);\n```\n\nAlternatively, you could return an `AbortController.abort()` function to physically kill the network request through `fetch` or `axios` if the component unmounts.\n\n---\n\n### What is the next question from your first round? Or are you ready to transition to step 3 and map out your Fintech project architecture for IBM?\n","type":"md"},{"name":"011-redux.md","content":"## 1. What is Redux Toolkit (RTK)?\n\n**Redux Toolkit (RTK)** is the modern, official, and recommended way to write Redux logic. Traditional Redux was heavily criticized for requiring massive amounts of boilerplate code (actions, action types, reducers, switch cases, and store configurations). RTK was built to solve these pain points, offering a streamlined, opinionated ecosystem out of the box.\n\n### Core Pillars of RTK:\n\n- **`configureStore()`**: Automatically sets up the Redux store with sane defaults, including combining your reducers, adding development middleware (like Redux DevTools), and turning on stability checks.\n- **`createSlice()`**: The biggest time-saver. It allows you to define your initial state, reducers, and action creators all in one single, centralized file.\n- **Immer Integration**: In traditional Redux, you had to carefully write nested object spreads to maintain state immutability (e.g., `{ ...state, user: { ...state.user, age: 30 } }`). RTK includes **Immer**, which allows you to write \"mutating\" code safely (like `state.user.age = 30`). Immer intercepts this and tracks a secure, immutable copy behind the scenes.\n- **`createAsyncThunk()`**: The built-in middleware mechanism for handling asynchronous side effects (like API requests). It automatically generates three action lifecycles for your network actions: `pending`, `fulfilled`, and `rejected`.\n\n---\n\n## 2. Theoretical Breakdown: Parallel vs. Sequential API Calls\n\nWhen architecting a production mobile application—such as the fintech platforms you managed at LetsVenture—managing data synchronization is critical. RTK handles async orchestration inside its Thunk functions.\n\n### A. Parallel Architecture (e.g., The Dashboard)\n\n- **The Concept:** When a user lands on a home dashboard, you need to pull independent blocks of data (e.g., user profile metadata and investment portfolio metrics). Firing these sequentially creates a slow UI experience.\n\n- **The RTK Solution:** Inside a single Async Thunk, we initiate both network requests simultaneously using JavaScript's native **`Promise.all()`**. The native threads fire both requests over the network hardware at the exact same millisecond, waiting for the combined responses before updating the Redux state.\n\n### B. Sequential Architecture (e.g., The Payment Gateway)\n\n- **The Concept:** For secure, transactional operations (e.g., checking a shopping cart, executing a payment transaction via Razorpay/Cashfree, validating the order status, and generating an invoice), order matters. You cannot run these concurrently because each step strictly requires the resulting payload data from the previous step.\n\n- **The RTK Solution:** Inside the Async Thunk, we use sequential line-by-line **`await`** statements. If any middle step fails or returns an error, execution stops immediately, protecting the transaction flow from data corruption.\n\n---\n\n## 3. Production-Grade Example\n\nLet’s implement a full Redux Toolkit module containing a store, a dashboard slice (parallel execution), and a checkout slice (sequential execution).\n\n### Step A: The Dashboard Slice (Parallel API Blueprint)\n\n```javascript\nimport { createSlice, createAsyncThunk } from \"@reduxjs/toolkit\";\n\n// Simulating API endpoints\nconst fetchProfileAPI = () =>\n  fetch(\"https://api.com/profile\").then((res) => res.json());\nconst fetchPortfolioAPI = () =>\n  fetch(\"https://api.com/portfolio\").then((res) => res.json());\n\n// Thunk for parallel dashboard execution\nexport const fetchDashboardData = createAsyncThunk(\n  \"dashboard/fetchData\",\n  async (_, { rejectWithValue }) => {\n    try {\n      // Both actions fire concurrently over the native network thread\n      const [profileData, portfolioData] = await Promise.all([\n        fetchProfileAPI(),\n        fetchPortfolioAPI(),\n      ]);\n\n      // Returns the merged payload to the fulfilled reducer\n      return { profile: profileData, portfolio: portfolioData };\n    } catch (error) {\n      return rejectWithValue(error.message);\n    }\n  },\n);\n\nconst dashboardSlice = createSlice({\n  name: \"dashboard\",\n  initialState: { profile: null, portfolio: null, loading: false, error: null },\n  reducers: {},\n  extraReducers: (builder) => {\n    builder\n      .addCase(fetchDashboardData.pending, (state) => {\n        state.loading = true;\n        state.error = null;\n      })\n      .addCase(fetchDashboardData.fulfilled, (state, action) => {\n        state.loading = false;\n        // Immer allows us to update state values directly\n        state.profile = action.payload.profile;\n        state.portfolio = action.payload.portfolio;\n      })\n      .addCase(fetchDashboardData.rejected, (state, action) => {\n        state.loading = false;\n        state.error = action.payload;\n      });\n  },\n});\n\nexport const dashboardReducer = dashboardSlice.reducer;\n```\n\n### Step B: The Payment Slice (Sequential API Blueprint)\n\n```javascript\n// Simulating sequential fintech API steps\nconst verifyCartAPI = (items) =>\n  fetch(\"https://api.com/verify-cart\", {\n    method: \"POST\",\n    body: JSON.stringify(items),\n  }).then((res) => res.json());\nconst chargeCardAPI = (amount) =>\n  fetch(\"https://api.com/charge\", {\n    method: \"POST\",\n    body: JSON.stringify({ amount }),\n  }).then((res) => res.json());\nconst createInvoiceAPI = (txId) =>\n  fetch(\"https://api.com/invoice\", {\n    method: \"POST\",\n    body: JSON.stringify({ txId }),\n  }).then((res) => res.json());\n\n// Thunk for strict sequential validation\nexport const executePaymentWorkflow = createAsyncThunk(\n  \"payment/processOrder\",\n  async (cartItems, { rejectWithValue }) => {\n    try {\n      // Step 1: Validate Cart\n      const cartStatus = await verifyCartAPI(cartItems);\n      if (!cartStatus.isValid) throw new Error(\"Cart verification failed.\");\n\n      // Step 2: Process Charge (depends on cart verification output)\n      const paymentReceipt = await chargeCardAPI(cartStatus.totalAmount);\n      if (!paymentReceipt.success)\n        throw new Error(\"Transaction declined by gateway.\");\n\n      // Step 3: Issue Invoice (depends on payment receipt output)\n      const finalInvoice = await createInvoiceAPI(paymentReceipt.transactionId);\n\n      return { invoice: finalInvoice, receipt: paymentReceipt };\n    } catch (error) {\n      return rejectWithValue(error.message);\n    }\n  },\n);\n\nconst paymentSlice = createSlice({\n  name: \"payment\",\n  initialState: {\n    invoice: null,\n    processing: false,\n    error: null,\n    success: false,\n  },\n  reducers: {\n    resetPaymentState: (state) => {\n      state.invoice = null;\n      state.error = null;\n      state.success = false;\n    },\n  },\n  extraReducers: (builder) => {\n    builder\n      .addCase(executePaymentWorkflow.pending, (state) => {\n        state.processing = true;\n        state.error = null;\n        state.success = false;\n      })\n      .addCase(executePaymentWorkflow.fulfilled, (state, action) => {\n        state.processing = false;\n        state.success = true;\n        state.invoice = action.payload.invoice;\n      })\n      .addCase(executePaymentWorkflow.rejected, (state, action) => {\n        state.processing = false;\n        state.success = false;\n        state.error = action.payload;\n      });\n  },\n});\n\nexport const { resetPaymentState } = paymentSlice.actions;\nexport const paymentReducer = paymentSlice.reducer;\n```\n\n### Step C: Setting up the Store Configurations\n\n```javascript\nimport { configureStore } from \"@reduxjs/toolkit\";\n\nexport const store = configureStore({\n  reducer: {\n    dashboard: dashboardReducer,\n    payment: paymentReducer,\n  },\n  // configureStore automatically configures the Thunk middleware and DevTools out-of-the-box\n});\n```\n\n### Step D: Using the State Ecosystem in React Native\n\n```javascript\nimport React, { useEffect } from \"react\";\nimport { View, Text, Button, ActivityIndicator } from \"react-native\";\nimport { useDispatch, useSelector } from \"react-redux\";\nimport { fetchDashboardData } from \"./dashboardSlice\";\nimport { executePaymentWorkflow } from \"./paymentSlice\";\n\nexport default function AppDashboard() {\n  const dispatch = useDispatch();\n\n  // Select values directly from the combined store slices\n  const { profile, portfolio, loading } = useSelector(\n    (state) => state.dashboard,\n  );\n  const { processing, success, error } = useSelector((state) => state.payment);\n\n  // 1. Parallel loading triggered on initial application mount\n  useEffect(() => {\n    dispatch(fetchDashboardData());\n  }, [dispatch]);\n\n  const handleCheckout = () => {\n    const mockCart = [{ id: \"equity_deal_1\", price: 5000 }];\n    // 2. Dispatch the sequential validation chain action\n    dispatch(executePaymentWorkflow(mockCart));\n  };\n\n  if (loading) return <ActivityIndicator size=\"large\" />;\n\n  return (\n    <View style={{ flex: 1, justifyContent: \"center\", padding: 20 }}>\n      <Text>Welcome, {profile?.name}</Text>\n      <Text>Total Portfolio Value: ${portfolio?.totalValue}</Text>\n\n      <Button\n        title={processing ? \"Processing Transaction...\" : \"Invest Now\"}\n        onPress={handleCheckout}\n      />\n\n      {success && (\n        <Text style={{ color: \"green\" }}>\n          Investment confirmed successfully!\n        </Text>\n      )}\n      {error && <Text style={{ color: \"red\" }}>Error: {error}</Text>}\n    </View>\n  );\n}\n```\n\n---\n\n## 🎯 How to frame this answer for IBM\n\nConclude with a high-level summary that brings your senior engineering mindset to the forefront:\n\n> \"Redux Toolkit acts as our centralized global state engine. When building data-intensive applications, I leverage **`createAsyncThunk`** to isolate side-effect workflows cleanly from our UI presentation code. For layout updates like home dashboards, I orchestrate concurrent fetches via **`Promise.all`** to prevent UI-blocking waterfalls. Conversely, for critical payment pipelines where data consistency is non-negotiable, I construct sequential, linear **`await`** patterns coupled with strict catch boundaries to ensure that if any upstream transaction component fails, state modifications are safely aborted.\"\n","type":"md"},{"name":"006-Hooks.md","content":"React Hooks were introduced to allow functional components to manage state, lifecycle methods, and optimization without writing ES6 classes. Under the hood, React tracks Hooks based on their execution order during a component's render phase.\n\nHere is the comprehensive, end-to-end guide to the core hooks, structured with their **definitions, primary use cases, and inner workings** to prepare you for the IBM panel.\n\n---\n\n## 1. State Hooks\n\n### A. `useState`\n\n- **Definition:** A hook that allows you to add local state to a functional component.\n- **How it Works:** It returns an array with exactly two elements: the current state value and a setter function to update it. When the setter function is called, React schedules a re-render of the component with the new state value.\n- **Common Use Cases:**\n- Toggling a modal visibility (`true`/`false`).\n- Storing the text input from a search bar.\n- Handling a simple counter.\n\n### B. `useReducer`\n\n- **Definition:** An alternative to `useState` designed for managing complex state logic that involves multiple sub-values or when the next state depends heavily on the previous one.\n- **How it Works:** It uses a Redux-like pattern. It accepts a reducer function `(state, action) => newState` and an initial state. It returns the current state and a `dispatch` function. When you dispatch an action, the reducer calculates the next state deterministically.\n- **Common Use Cases:**\n- Complex multi-step checkout forms (e.g., handling shipping address, payment tokens, and validation flags in one object).\n- Game states or intricate local screen state filtering.\n\n---\n\n## 2. Lifecycle & Context Hooks\n\n### C. `useEffect`\n\n- **Definition:** A hook that lets you perform side effects (data fetching, subscriptions, manual UI updates) in functional components.\n- **How it Works:** It runs asynchronously after the render and paint phases are complete. It monitors a dependency array; if any item in the array changes between renders, the callback executes. If it returns a function, that function acts as a cleanup routine right before unmounting or re-running.\n- **Common Use Cases:**\n- Fetching data from a REST API when a screen loads.\n- Subscribing to native event listeners like `BackHandler` or keyboard events.\n\n### D. `useContext`\n\n- **Definition:** A hook that allows you to subscribe to React's Context API, enabling you to share data globally across the component tree without manually passing props down through every level (avoiding \"prop drilling\").\n- **How it Works:** It looks up the component tree to find the nearest matching Context Provider. When the value of that Provider updates, every component calling `useContext` for that specific context will automatically re-render with the fresh data.\n- **Common Use Cases:**\n- Storing global application themes (Dark Mode / Light Mode).\n- Managing localization/language settings (English, Hindi).\n- Storing global user authentication states (though complex app state is often offloaded to Redux Toolkit).\n\n---\n\n## 3. Performance Optimization Hooks\n\n### E. `useMemo`\n\n- **Definition:** A hook that memoizes (caches) the **result of a calculation** between re-renders.\n- **How it Works:** It takes a function that computes a value and a dependency array. React will execute the function on the first render. On subsequent renders, it returns the cached result _unless_ one of the values in the dependency array has changed.\n- **Common Use Cases:**\n- Filtering or sorting a massive list of financial transactions (like your investor-facing products at LetsVenture) before passing them to a `FlatList`.\n- Heavy cryptographic or mathematical calculations.\n\n### F. `useCallback`\n\n- **Definition:** A hook that memoizes (caches) the **function definition itself** between re-renders.\n- **How it Works:** In JavaScript, functions are objects, meaning a new function reference is recreated in memory on every single render. `useCallback` caches that function reference. It only recreates the function if its dependencies change.\n- **Common Use Cases:**\n- Passing callback functions to optimized child components (wrapped in `React.memo`). Without `useCallback`, the child component will re-render unnecessarily because it receives a brand-new function pointer on every parent render.\n- Debouncing search input tracking functions.\n\n---\n\n## 4. Mutable Reference Hooks\n\n### G. `useRef`\n\n- **Definition:** A hook that returns a mutable reference object whose `.current` property can hold any value, persisting across the entire lifecycle of the component **without triggering a re-render when it changes**.\n- **How it Works:** It serves two completely distinct purposes: holding direct references to native UI nodes, or acting as a generic instance variable container (like a private class property) that does not disrupt the visual render loop when modified.\n- **Common Use Cases:**\n- Accessing imperative native methods on UI elements (e.g., calling `.focus()` on a `TextInput`, or calling `.scrollToEnd()` on a `ScrollView`).\n- Tracking timers or intervals (`setInterval` IDs) so they can be cleared inside a cleanup function later.\n- Storing a mutable flag to track if a component has completed its initial mount phase.\n\n---\n\n## 🎯 React Hooks Summary Reference\n\n| Hook              | Returns                             | Triggers Re-render on Change?      | Core Purpose                                                     |\n| ----------------- | ----------------------------------- | ---------------------------------- | ---------------------------------------------------------------- |\n| **`useState`**    | `[value, setter]`                   | **Yes**                            | Managing local UI and variable states.                           |\n| **`useReducer`**  | `[state, dispatch]`                 | **Yes**                            | Managing complex, transactional state objects.                   |\n| **`useEffect`**   | `undefined` (or cleanup function)   | No                                 | Executing asynchronous side effects securely.                    |\n| **`useContext`**  | Global value                        | **Yes** (if context value changes) | Global data sharing without prop drilling.                       |\n| **`useMemo`**     | Cached **Value**                    | No                                 | Avoiding expensive re-computations.                              |\n| **`useCallback`** | Cached **Function**                 | No                                 | Avoiding child re-renders from unstable function references.     |\n| **`useRef`**      | Mutable `{ current: value }` object | **No**                             | Targeting native DOM nodes or tracking persistent data silently. |\n\n---\n\nWould you like to write a quick code example combining a couple of these optimization hooks (`useMemo` and `useCallback`) to see how they prevent performance drops in lists, or should we move to mapping out your project architecture stories?\n\nLet’s look at a highly practical, senior-level example. Imagine you are building a screen for **LVX or Scalix** at LetsVenture that displays a list of investor transactions.\n\nWe want to:\n\n1. **Filter** a massive list of transactions based on a search query (expensive operation).\n2. **Pass a callback function** down to a child component (list item) without causing that child to re-render on every keystroke.\n\nHere is how we use `useMemo`, `useCallback`, and `useRef` together to achieve optimal, production-grade performance.\n\n---\n\n### The Optimized Transaction Screen\n\n```javascript\nimport React, { useState, useMemo, useCallback, useRef } from \"react\";\nimport {\n  View,\n  Text,\n  TextInput,\n  Button,\n  FlatList,\n  StyleSheet,\n} from \"react-native\";\n\n// 1. A highly optimized Child Component wrapped in React.memo\n// It will ONLY re-render if its props (item or onRowPress) physically change.\nconst TransactionRow = React.memo(({ item, onRowPress }) => {\n  console.log(`Rendering Row ID: ${item.id}`); // Debug tracker\n  return (\n    <View style={styles.row}>\n      <Text style={styles.text}>\n        {item.title} - ${item.amount}\n      </Text>\n      <Button title=\"View\" onPress={() => onRowPress(item.id)} />\n    </View>\n  );\n});\n\nexport default function TransactionScreen() {\n  const [search, setSearch] = useState(\"\");\n  const [theme, setTheme] = useState(\"light\"); // Simulating a secondary state change\n\n  // useRef Example: Tracking how many times the user views transactions without re-rendering the UI\n  const totalViewsRef = useRef(0);\n\n  // Hardcoded large dataset for illustration\n  const transactions = [\n    { id: \"1\", title: \"Angelist Equity Investment\", amount: 5000 },\n    { id: \"2\", title: \"Scalix Platform Subscription\", amount: 150 },\n    { id: \"3\", title: \"LVX Secondary Market Trade\", amount: 12000 },\n  ];\n\n  // 2. useMemo Example: Caching the filtered results\n  // If the user changes the global theme, 'search' stays the same.\n  // useMemo prevents this filtering loop from running again unnecessarily.\n  const filteredTransactions = useMemo(() => {\n    console.log(\"Filtering transactions running...\"); // Heavy computation simulator\n    return transactions.filter((t) =>\n      t.title.toLowerCase().includes(search.toLowerCase()),\n    );\n  }, [search]); // Only re-runs if 'search' changes\n\n  // 3. useCallback Example: Memoizing the function declaration\n  // If we don't use useCallback, a brand-new function reference is created on every render cycle.\n  // That would break React.memo inside TransactionRow, forcing every row to re-render on every keystroke.\n  const handleRowPress = useCallback((id) => {\n    totalViewsRef.current += 1; // Increment ref silently (no re-render)\n    console.log(\n      `Transaction ${id} tapped. Total row clicks tracked: ${totalViewsRef.current}`,\n    );\n  }, []); // Empty dependencies mean this function reference remains perfectly stable\n\n  return (\n    <View style={[styles.container, theme === \"dark\" && styles.darkContainer]}>\n      <TextInput\n        style={styles.input}\n        placeholder=\"Search transactions...\"\n        value={search}\n        onChangeText={setSearch}\n      />\n\n      <Button\n        title=\"Toggle App Theme\"\n        onPress={() =>\n          setTheme((prev) => (prev === \"light\" ? \"dark\" : \"light\"))\n        }\n      />\n\n      <FlatList\n        data={filteredTransactions}\n        keyExtractor={(item) => item.id}\n        renderItem={({ item }) => (\n          <TransactionRow item={item} onRowPress={handleRowPress} />\n        )}\n      />\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  container: { flex: 1, padding: 20, backgroundColor: \"#fff\" },\n  darkContainer: { backgroundColor: \"#333\" },\n  input: {\n    borderWidth: 1,\n    borderColor: \"#ccc\",\n    padding: 10,\n    marginBottom: 10,\n    borderRadius: 5,\n  },\n  row: {\n    flexDirection: \"row\",\n    justifyContent: \"space-between\",\n    padding: 15,\n    borderBottomWidth: 1,\n    borderColor: \"#eee\",\n  },\n  text: { fontSize: 16 },\n});\n```\n\n---\n\n## 🔍 Why this code makes an IBM Interviewer happy:\n\n- **No Unnecessary Calculations:** When you tap **\"Toggle App Theme\"**, the screen re-renders to change the background color. Because of `useMemo`, the application skips the `.filter()` logic entirely and reads it instantly from cache.\n- **No Child Component Waste:** Because `handleRowPress` is wrapped in `useCallback`, its memory pointer stays fixed. When the theme changes, `TransactionRow` recognizes its props haven't changed and **skips re-rendering completely**.\n- **Silent State Tracking:** Using `useRef` to track clicks (`totalViewsRef.current`) allows us to record metrics silently in the background without causing an entire screen refresh cycle.\n\n---\n\nNow that we have covered the entire technical foundation from your first round (Performance, Native Bridges, Lifecycles, and Hooks), we are perfectly primed for **Step 3 of your checklist: Mapping out your actual Fintech projects.**\n\nWould you like to draft exactly how you should walk through your architecture at LetsVenture when they ask, _\"Tell me about a complex architectural problem you solved\"_?\n\nLet’s complete the picture by looking at the remaining major hooks we discussed: **`useReducer`** and **`useContext`**.\n\nTo make this highly relevant for your upcoming IBM interview, we will simulate a real-world scenario from your fintech background at LetsVenture: **An Investment Checkout Wizard**. This component needs to handle complex form states (amount, equity shares, validation errors) and share global configurations like user authentication tokens or display languages across nested elements.\n\nHere is how we implement `useReducer` and `useContext` together in production-grade code.\n\n---\n\n### The Global Context & Complex State Checkout Example\n\n```javascript\nimport React, { createContext, useContext, useReducer } from \"react\";\nimport { View, Text, TextInput, Button, StyleSheet } from \"react-native\";\n\n// ==========================================\n// 1. useContext SETUP (Global App State)\n// ==========================================\n// Creating an Authentication Context to share across the app\nconst AuthContext = createContext(null);\n\n// ==========================================\n// 2. useReducer SETUP (Complex Local State)\n// ==========================================\nconst initialState = {\n  investmentAmount: \"\",\n  equityShares: 0,\n  error: null,\n  isSubmitting: false,\n};\n\nfunction checkoutReducer(state, action) {\n  switch (action.type) {\n    case \"SET_AMOUNT\":\n      const amount = action.payload;\n      // Derived state logic: calculate shares dynamically based on a mock share price of $50\n      const calculatedShares = amount ? Math.floor(Number(amount) / 50) : 0;\n      return {\n        ...state,\n        investmentAmount: amount,\n        equityShares: calculatedShares,\n        error:\n          amount && Number(amount) < 1000\n            ? \"Minimum investment is $1,000\"\n            : null,\n      };\n    case \"START_SUBMIT\":\n      return { ...state, isSubmitting: true, error: null };\n    case \"SUBMIT_SUCCESS\":\n      return {\n        ...state,\n        isSubmitting: false,\n        investmentAmount: \"\",\n        equityShares: 0,\n      };\n    case \"SUBMIT_FAILURE\":\n      return { ...state, isSubmitting: false, error: action.payload };\n    default:\n      return state;\n  }\n}\n\n// ==========================================\n// 3. MAIN COMPONENT TREE\n// ==========================================\nexport default function App() {\n  // Simulating global session data injected at the root of the app\n  const globalSession = {\n    userToken: \"auth0_jwt_token_12345\",\n    userName: \"Rajeev Joshi\",\n  };\n\n  return (\n    <AuthContext.Provider value={globalSession}>\n      <View style={styles.container}>\n        <InvestmentCheckout />\n      </View>\n    </AuthContext.Provider>\n  );\n}\n\n// ==========================================\n// 4. NESTED CHILD COMPONENT\n// ==========================================\nfunction InvestmentCheckout() {\n  // useContext Example: Consume global session without prop drilling\n  const session = useContext(AuthContext);\n\n  // useReducer Example: Manage deeply tied, complex transactional states\n  const [state, dispatch] = useReducer(checkoutReducer, initialState);\n\n  const handleConfirmInvestment = async () => {\n    if (state.error || !state.investmentAmount) return;\n\n    dispatch({ type: \"START_SUBMIT\" });\n\n    try {\n      console.log(\n        `Sending secure transaction for ${session?.userName} using token: ${session?.userToken}`,\n      );\n      // Simulating a native payment or fintech gateway API call (e.g., Razorpay / Cashfree)\n      await new Promise((resolve) => setTimeout(resolve, 2000));\n\n      dispatch({ type: \"SUBMIT_SUCCESS\" });\n      alert(\"Investment Placed Successfully!\");\n    } catch (err) {\n      dispatch({\n        type: \"SUBMIT_FAILURE\",\n        payload: \"Payment failed. Please try again.\",\n      });\n    }\n  };\n\n  return (\n    <View style={styles.card}>\n      <Text style={styles.welcomeText}>Investor: {session?.userName}</Text>\n      <Text style={styles.title}>Scalix Private Equity Checkout</Text>\n\n      <TextInput\n        style={styles.input}\n        placeholder=\"Enter Amount ($)\"\n        keyboardType=\"numeric\"\n        value={state.investmentAmount}\n        onChangeText={(text) => dispatch({ type: \"SET_AMOUNT\", payload: text })}\n      />\n\n      {state.error && <Text style={styles.errorText}>{state.error}</Text>}\n\n      <View style={styles.infoBox}>\n        <Text>Calculated Shares: {state.equityShares}</Text>\n      </View>\n\n      <Button\n        title={\n          state.isSubmitting ? \"Processing Payment...\" : \"Confirm Investment\"\n        }\n        disabled={\n          state.isSubmitting || !!state.error || !state.investmentAmount\n        }\n        onPress={handleConfirmInvestment}\n      />\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  container: {\n    flex: 1,\n    justifyContent: \"center\",\n    padding: 20,\n    backgroundColor: \"#f5f5f5\",\n  },\n  card: {\n    backgroundColor: \"#fff\",\n    padding: 20,\n    borderRadius: 10,\n    shadowColor: \"#000\",\n    shadowOpacity: 0.1,\n    shadowRadius: 10,\n    elevation: 5,\n  },\n  welcomeText: { fontSize: 14, color: \"#666\", marginBottom: 5 },\n  title: { fontSize: 18, fontWeight: \"bold\", marginBottom: 20 },\n  input: {\n    borderWidth: 1,\n    borderColor: \"#ccc\",\n    padding: 12,\n    borderRadius: 6,\n    marginBottom: 10,\n  },\n  infoBox: {\n    padding: 10,\n    backgroundColor: \"#eef2f7\",\n    borderRadius: 6,\n    marginBottom: 20,\n  },\n  errorText: { color: \"red\", marginBottom: 10, fontSize: 12 },\n});\n```\n\n---\n\n## 🔍 Why this implementation answers the interviewer's depth requirements:\n\n### How `useReducer` solves the complexity here:\n\nIf you used `useState` for this form, you would need multiple disconnected states: `const [amount, setAmount] = useState('')`, `const [shares, setShares] = useState(0)`, `const [error, setError] = useState(null)`. When a user alters the amount, you would have to trigger three individual setters simultaneously.\n\nBy offloading this logic to a centralized reducer function, **the state transformations become completely deterministic and transactional**. Calculating derived values (like `equityShares` based on `investmentAmount`) or triggering conditional validation rules occurs instantly within a single synchronous state update step. This prevents asynchronous state-desynchronization bugs.\n\n### How `useContext` optimizes the architecture:\n\nRather than passing down the `session` object through every layout wrapper or parent container view, the `InvestmentCheckout` card reaches directly into the virtual React context tree to capture user metadata. It handles components smoothly by subscribing to updates natively, keeping the codebase clean and modular.\n\n---\n\nNow that we have comprehensively covered every core hook with practical, production-level engineering examples, would you like to move on to simulating **Step 5 of your plan: Handling complex behavioral and hotfix scenarios for enterprise deployments**? Let me know where we should point our focus next.\n","type":"md"},{"name":"031-classcompont.md","content":"Here is a comprehensive, production-grade example of a legacy React Native **Class Component** that implements **every single core lifecycle method** across the Mounting, Updating, Unmounting, and Error Handling phases.\n\nThis example models a real-world **Live Portfolio Monitor** widget. It establishes a background interval timer to update rates, optimize rendering checks, clean up memory to prevent leaks, and catch component exceptions using the error-handling parameters we discussed.\n\n---\n\n### The Complete Class Component (`LivePortfolioMonitor.tsx`)\n\n```typescript\nimport React, { Component, ErrorInfo } from 'react';\nimport { View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';\n\n// --- Types for Props and State ---\ninterface MonitorProps {\n  portfolioId: string;\n  currencyToken: string;\n  isActive: boolean;\n}\n\ninterface MonitorState {\n  marketRate: number;\n  lastUpdated: string;\n  hasError: boolean;\n}\n\nexport default class LivePortfolioMonitor extends Component<MonitorProps, MonitorState> {\n  // A mutable instance property to store the native timer ID across lifecycles\n  private rateIntervalId: number | null = null;\n\n  // ==========================================\n  // 1. THE MOUNTING PHASE (Component Creation)\n  // ==========================================\n\n  constructor(props: MonitorProps) {\n    super(props);\n    console.log('1. Constructor: Initializing baseline state configurations.');\n\n    // Setting up the initial synchronous state object\n    this.state = {\n      marketRate: 100.0,\n      lastUpdated: new Date().toLocaleTimeString(),\n      hasError: false,\n    };\n\n    // Binding custom class handlers to preserve the correct 'this' context runtime footprint\n    this.handleManualRefresh = this.handleManualRefresh.bind(this);\n  }\n\n  static getDerivedStateFromProps(nextProps: MonitorProps, prevState: MonitorState): Partial<MonitorState> | null {\n    console.log('2. getDerivedStateFromProps: Synchronizing state mapping against incoming properties.');\n    // Returns null if no state adjustments are required based on changing props\n    return null;\n  }\n\n  componentDidMount() {\n    console.log('4. componentDidMount: UI is painted. Safe to trigger network loops, timers, or native listeners.');\n\n    // Start background pooling intervals if the widget is configured as active\n    if (this.props.isActive) {\n      this.startLiveStreamingPool();\n    }\n  }\n\n  // ==========================================\n  // 2. THE UPDATING PHASE (Component Upkeep)\n  // ==========================================\n\n  shouldComponentUpdate(nextProps: MonitorProps, nextState: MonitorState): boolean {\n    console.log('5. shouldComponentUpdate: Determining if view tree requires a re-calculate pass.');\n\n    // Performance Optimization: Only allow a re-render if the rate actually changes or tokens flip\n    if (\n      nextState.marketRate === this.state.marketRate &&\n      nextProps.currencyToken === this.props.currencyToken &&\n      nextProps.isActive === this.props.isActive\n    ) {\n      console.log('-> Render Blocked: Props/State unchanged. Skipping render pass.');\n      return false; // Skips the render pass entirely\n    }\n\n    return true; // Continues the render pipeline\n  }\n\n  getSnapshotBeforeUpdate(prevProps: MonitorProps, prevState: MonitorState): any {\n    console.log('6. getSnapshotBeforeUpdate: Capturing scrolling coordinates or layout dimensions before state mutations settle.');\n    return { cachedScrollY: 120 }; // Retains context that is passed straight to componentDidUpdate\n  }\n\n  componentDidUpdate(prevProps: MonitorProps, prevState: MonitorState, snapshot: any) {\n    console.log('7. componentDidUpdate: Layout flushed to device screen.', snapshot);\n\n    // Conditional evaluation: If the controller state changes, rebuild the polling engines\n    if (prevProps.isActive !== this.props.isActive) {\n      if (this.props.isActive) {\n        this.startLiveStreamingPool();\n      } else {\n        this.clearLiveStreamingPool();\n      }\n    }\n  }\n\n  // ==========================================\n  // 3. THE UNMOUNTING PHASE (Component Destruction)\n  // ==========================================\n\n  componentWillUnmount() {\n    console.log('8. componentWillUnmount: Component is dying. Clearing hardware anchors to safeguard memory queues.');\n    // CRITICAL: Wiping active timers ensures the Garbage Collector can safely scrub this class instance out of RAM\n    this.clearLiveStreamingPool();\n  }\n\n  // ==========================================\n  // 4. THE ERROR HANDLING PHASE (The Safety Net)\n  // ==========================================\n\n  static getDerivedStateFromError(error: Error): Partial<MonitorState> {\n    console.log('9. static getDerivedStateFromError: Caught exception in render phase. Modifying state for fallback render.');\n    // Invoked synchronously mid-render; returns state changes to trigger fallback UI[cite: 1]\n    return { hasError: true };\n  }\n\n  componentDidCatch(error: Error, errorInfo: ErrorInfo) {\n    console.log('10. componentDidCatch: Commit phase finalized. Invoking external reporting APIs safely.');\n    // Thread-safe location to dispatch crash telemetry\n    console.warn(`Logged to Crashlytics/Sentry: ${error.message}`, errorInfo.componentStack);\n  }\n\n  // ==========================================\n  // Custom Class Processing Operations\n  // ==========================================\n\n  private startLiveStreamingPool() {\n    this.clearLiveStreamingPool(); // Guard clause against duplicate timers\n    this.rateIntervalId = setInterval(() => {\n      console.log('-> Executing poll ticker rate update.');\n      this.setState({\n        marketRate: +(this.state.marketRate + (Math.random() * 4 - 2)).toFixed(2),\n        lastUpdated: new Date().toLocaleTimeString()\n      });\n    }, 3000) as unknown as number;\n  }\n\n  private clearLiveStreamingPool() {\n    if (this.rateIntervalId) {\n      clearInterval(this.rateIntervalId);\n      this.rateIntervalId = null;\n    }\n  }\n\n  public handleManualRefresh() {\n    Alert.alert('Sync Initiated', 'Refetching latest market parameters.');\n    this.setState({ marketRate: 100.0 });\n  }\n\n  // The central structural pipeline block\n  render() {\n    console.log('3 / Rendering Step: Processing JSX View tree layout mapping.');\n\n    // 1. Intercept flow if the local Error Boundary is flagged\n    if (this.state.hasError) {\n      return (\n        <View style={styles.errorContainer}>\n          <Text style={styles.errorText}>Internal Monitor Crash Intercepted.</Text>\n        </View>\n      );\n    }\n\n    // 2. Fall back to rendering the standard layout\n    return (\n      <View style={styles.container}>\n        <Text style={styles.title}>Asset Context: {this.props.portfolioId}</Text>\n\n        <View style={styles.rateBlock}>\n          <Text style={styles.rateText}>\n            {this.props.currencyToken} {this.state.marketRate}\n          </Text>\n          <Text style={styles.subText}>Last Updated: {this.state.lastUpdated}</Text>\n        </View>\n\n        <TouchableOpacity style={styles.refreshButton} onPress={this.handleManualRefresh}>\n          <Text style={styles.buttonText}>Force Baseline Sync</Text>\n        </TouchableOpacity>\n      </View>\n    );\n  }\n}\n\n// --- Layout Atom Sheets ---\nconst styles = StyleSheet.create({\n  container: { backgroundColor: '#FFFFFF', padding: 20, borderRadius: 16, margin: 16, elevation: 3 },\n  title: { fontSize: 14, color: '#64748B', fontWeight: '600', marginBottom: 12 },\n  rateBlock: { marginBottom: 20 },\n  rateText: { fontSize: 32, fontWeight: '800', color: '#1E293B', letterSpacing: -0.5 },\n  subText: { fontSize: 12, color: '#94A3B8', marginTop: 4 },\n  refreshButton: { backgroundColor: '#1677FF', height: 48, borderRadius: 10, justifyContent: 'center', alignItems: 'center' },\n  buttonText: { color: '#FFFFFF', fontWeight: '600', fontSize: 14 },\n  errorContainer: { backgroundColor: '#FEF2F2', padding: 20, borderRadius: 16, margin: 16, alignItems: 'center', borderWidth: 1, borderColor: '#FCA5A5' },\n  errorText: { color: '#991B1B', fontWeight: '700', fontSize: 14 }\n});\n\n```\n\n---\n\n### How to consume this Class Component in another file\n\nYou use a Class Component exactly like a Functional Component. You simply import it and pass down the required type properties.\n\n```typescript\nimport React, { useState } from 'react';\nimport { SafeAreaView, Switch, View, Text, StyleSheet } from 'react-native';\nimport LivePortfolioMonitor from './LivePortfolioMonitor'; // Import our class\n\nexport default function App() {\n  const [isLiveMode, setIsLiveMode] = useState<boolean>(true);\n\n  return (\n    <SafeAreaView style={styles.screen}>\n      <View style={styles.controlRow}>\n        <Text style={styles.label}>Enable Real-Time Thread Streaming:</Text>\n        <Switch value={isLiveMode} onValueChange={setIsLiveMode} />\n      </View>\n\n      {/* RENDER CLASS MATRIX CORE ELEMENT */}\n      <LivePortfolioMonitor\n        portfolioId=\"IBM_ESCROW_A\"\n        currencyToken=\"USD\"\n        isActive={isLiveMode}\n      />\n    </SafeAreaView>\n  );\n}\n\nconst styles = StyleSheet.create({\n  screen: { flex: 1, backgroundColor: '#F8FAFC' },\n  controlRow: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', padding: 20, backgroundColor: '#FFF', borderBottomWidth: 1, borderBottomColor: '#E2E8F0' },\n  label: { fontSize: 15, fontWeight: '600', color: '#334155' }\n});\n\n```\n\n---\n\n### 🎯 Pro-Tips for showing off this example to the IBM Panel\n\nIf the interviewer asks you to step through this file live or explain its choices, make sure to hit these points to show your senior level of expertise:\n\n- **`this.rateIntervalId` Is NOT state:** Explain that storing the interval ID as an instance property instead of inside state prevents the component from triggering a completely redundant re-render every time a timer resets or triggers.\n- **`shouldComponentUpdate` Optimization:** Point out that this prevents unnecessary layout passes. If parent layouts re-render, this class evaluates if its parameters have shifted first, saving precious main-thread frames.\n- **`componentWillUnmount` Memory Shield:** Emphasize that calling `clearLiveStreamingPool` here ensures that when a user leaves this screen, the ticking background timer is destroyed, preventing native memory heap leaks.\n","type":"md"},{"name":"002-how_to_use_native_library.md","content":"This is another foundational question that IBM interviewers use to separate high-level JavaScript developers from **true Mobile Engineers**. Since you have a strong background as a Native Android Developer, this is an absolute sweet spot for you to shine.\n\nTo answer this comprehensively for a senior-level round, you must address **both** the classic way (the Traditional Bridge) and the modern way (the New Architecture / TurboModules).\n\nHere is how you should structure your answer:\n\n---\n\n## 1. The Short Answer (The Blueprint)\n\n> \"To use a native library in React Native, we use **Native Modules**. If the library already provides a React Native wrapper via npm, we can simply install it and use auto-linking. However, if we need to integrate a custom or third-party native SDK (Java/Kotlin for Android, Objective-C/Swift for iOS), we write a bridge wrapper. In the old architecture, this is done via the `Bridge` using `RCTBridgeModule` and `ReactContextBaseJavaModule`. In the New Architecture, we write **TurboModules** using TypeScript/Flow specifications and **Codegen** to generate the C++ JSI layer.\"\n\n---\n\n## 2. Breaking Down the Two Approaches\n\n### Approach A: The Modern Way (TurboModules - New Architecture)\n\nIBM will be highly impressed if you lead with this, as it shows you are up-to-date with modern React Native standards. TurboModules leverage the **JavaScript Interface (JSI)** for direct, synchronous C++ communication, avoiding the asynchronous JSON bridge.\n\n1. **Define the Specification (TypeScript/Flow):** You write a strongly typed interface using TypeScript that defines the methods your native module will expose. This file _must_ be named matching a specific pattern (e.g., `SpecMyNativeLibrary.ts`).\n2. **Run Codegen:** React Native’s **Codegen** tool reads this TypeScript specification and automatically generates the strict C++ scaffolding and native abstract classes for both iOS and Android.\n3. **Implement the Native Code:**\n\n- **Android (Java/Kotlin):** You extend the generated Java/Kotlin abstract class and implement your custom logic.\n- **iOS (Objective-C++/Swift):** You implement the generated protocol in your iOS codebase.\n\n4. **Register and Export:** You register the module with the React Native runtime, and you can now import and call these native functions synchronously in JavaScript.\n\n### Approach B: The Classic Way (The Traditional Bridge)\n\nBecause thousands of enterprise applications still rely on the old architecture, you must demonstrate you know how the legacy bridge works.\n\n- **On Android (Java/Kotlin):**\n\n1. Create a class that extends `ReactContextBaseJavaModule`.\n2. Override the `getName()` method to return a string (this is the name used in JS).\n3. Annotate the native methods you want to expose to JavaScript with `@ReactMethod`.\n4. Create a `ReactPackage` class to register your module, and add this package to your `MainApplication.java`'s list of packages.\n\n- **On iOS (Objective-C/Swift):**\n\n1. Create a class that conforms to the `RCTBridgeModule` protocol.\n2. Use the macro `RCT_EXPORT_MODULE()` to export the class.\n3. Use the macro `RCT_EXPORT_METHOD()` to expose specific methods to JavaScript.\n4. _(If using Swift)_: You need a bridging header and must use the `@objc` attribute to expose Swift methods to the Objective-C runtime that React Native interfaces with.\n\n---\n\n## 3. How Data Flows Between Native and JS\n\nThe interviewer might ask: _\"How do you pass data back and forth?\"_ \\* **Arguments:** You can pass basic types across the boundary (Strings, Numbers, Booleans, Arrays, and Maps/Objects).\n\n- **Callbacks:** Used for asynchronous native tasks where JavaScript passes a function that Native executes once when done.\n- **Promises:** The preferred modern pattern. On Android, you use the `Promise` object argument; on iOS, you pass `RCTPromiseResolveBlock` and `RCTPromiseRejectBlock`.\n- **Events (DeviceEventEmitter / RCTDeviceEventEmitter):** If Native needs to send data to JS unsolicited (e.g., a continuous sensor update or geolocation ping), it broadcasts an event that JS listens to.\n\n---\n\n## 🎯 Pro-Tip for the Interview (Injecting Your Experience)\n\nTie it directly back to your resume to prove you’ve done this in production:\n\n> \"In my previous roles, such as at LetsVenture, while most third-party SDKs like Razorpay or Cashfree come with wrappers , I frequently had to handle native integrations. Having a background in native Android development made debugging CocoaPods configuration issues, handling Android Gradle dependency conflicts, or configuring native manifest permissions second nature to me.\"\n\n---\n\nWhat is the next question from your first round? Let’s keep this momentum going!\n","type":"md"},{"name":"025-Architecture.md","content":"To excel in an interview for a senior role at IBM, you should avoid generic answers like \"just use folders for components and screens.\" Instead, you want to showcase an **Enterprise-Grade, Domain-Driven, and Platform-Agnostic Architecture**.\n\nWhen building large-scale mobile and web applications, the industry standard is to implement **Feature-First Architecture** combined with **Clean Architecture Clean-Room Principles**.\n\n---\n\n## 1. The Core Architectural Philosophy\n\nA production-ready React Native architecture must adhere to three main rules:\n\n1. **Unidirectional Data Flow:** Data moves in a single direction (Server ➡️ State Engine ➡️ UI Layer ➡️ Native Shell).\n2. **Strict Separation of Concerns:** Your UI (presentation) should be completely blind to _how_ data is fetched or _how_ native modules execute hardware actions.\n3. **Monorepo / Universal-Ready Structure:** The architecture should easily support code sharing across Android, iOS, and Web (React Native Web) without mixing up dependency bundles.\n\n---\n\n## 2. Directory Structure: Feature-First Architecture\n\nInstead of grouping files by their technical types (putting all screens in one folder, all hooks in another), group them by **business domains or features** (e.g., `auth`, `dashboard`, `payment`). This makes the codebase highly scalable and easier for large engineering teams to maintain simultaneously.\n\nHere is what an enterprise-grade project blueprint looks like:\n\n```\n📦 src/\n ┣ 📂 core/                   ──► Platform-agnostic global setups\n ┃ ┣ 📂 theme/                ──► Design system design variables (tokens, colors, typography)\n ┃ ┣ 📂 routing/              ──► Global navigation graphs (Expo Router or React Navigation stacks)\n ┃ ┗ 📂 localization/         ──► Multi-language translation configurations (i18n bundles)\n ┃\n ┣ 📂 features/               ──► DOMAIN-DRIVEN FEATURE MODULES\n ┃ ┣ 📂 dashboard/            ──► Dashboard feature bundle\n ┃ ┃ ┣ 📂 components/         ──► Feature-isolated UI components (AssetCard.tsx, MetricsGrid.tsx)\n ┃ ┃ ┣ 📂 hooks/              ──► Feature business logic (useDashboardData.ts)\n ┃ ┃ ┣ 📂 api/                ──► Server-state endpoints managed via React Query\n ┃ ┃ ┗ 📂 screens/            ──► Entry point viewport layout views (DashboardHomeScreen.tsx)\n ┃ ┃\n ┃ ┗ 📂 payment/              ──► Payment feature bundle\n ┃   ┣ 📂 components/         ──► Local payment views (CardInputView.tsx, ReceiptModal.tsx)\n ┃   ┗ 📂 native/             ──► Custom device bridge extensions (BiometricAuth.native.ts)\n ┃\n ┣ 📂 shared/                 ──► Globally accessible reusable assets\n ┃ ┣ 📂 components/           ──► Generic design elements (Button.tsx, CustomInput.tsx)\n ┃ ┣ 📂 hooks/                ──► Multi-screen utility hooks (useDeviceType.ts, useOfflineStatus.ts)\n ┃ ┗ 📂 state/                ──► Global client state engine slices (Redux Toolkit store slices)\n ┃\n ┣ 📜 App.tsx                 ──► Global Entry Root Core\n ┗ 📜 app.json                ──► Unified configuration hub for Expo CNG builds\n\n```\n\n---\n\n## 3. The Modern 4-Layer Layered Architecture\n\nTo build highly performant apps that support features like offline synchronization and parallel/sequential API orchestration, decouple your application logic into four separate visual layers:\n\n```\n┌─────────────────────────────────────────────────────────┐\n│ 1. Presentation Layer (UI Component Screens)           │\n└────────────────────────────┬────────────────────────────┘\n                             ▼\n┌─────────────────────────────────────────────────────────┐\n│ 2. Business Logic Layer (Custom Hooks & Controllers)    │\n└────────────────────────────┬────────────────────────────┘\n                             ▼\n┌─────────────────────────────────────────────────────────┐\n│ 3. Data & State Layer (React Query / Redux Toolkit)     │\n└────────────────────────────┬────────────────────────────┘\n                             ▼\n┌─────────────────────────────────────────────────────────┐\n│ 4. Platform Engine Layer (JSI, Yoga, Native Containers) │\n└─────────────────────────────────────────────────────────┘\n\n```\n\n### Layer 1: Presentation Layer (UI Component Screens)\n\n- **Responsibility:** Strictly rendering pixels, capturing user events, and managing styles.\n- **Architecture Standard:** Use **Functional Components with Hooks**. Keep them \"dumb\" or presentation-only. A component should never perform raw mathematical operations, handle API configurations, or write data transformations directly.\n\n### Layer 2: Business Logic Layer (Custom Hooks / Presenters)\n\n- **Responsibility:** Orchestrating layout status calculations, state mutations, and platform checks.\n- **Architecture Standard:** Extract all screen logic into specialized custom hooks (e.g., `useDashboardFlow`). This layer reads your responsive breakpoints via layout hooks, handles orientation changes safely, and transforms data types before feeding them back up to the UI.\n\n### Layer 3: Data & State Layer (The Server-Client Split)\n\n- **Responsibility:** Managing caching, network fetching lifecycle data streams, and localized client-side configurations.\n- **Architecture Standard (The Hybrid Approach):**\n- Use **React Query (TanStack Query)** to govern all server states. It handles parallel data fetching (ASAP execution patterns) and declarative sequential routing via the `enabled` configuration flag automatically.\n- Use **Redux Toolkit (RTK)** strictly as a client state ledger to track synchronous parameters, global configurations, themes, or UI modal flags.\n\n### Layer 4: Platform Engine Layer (Native Handlers)\n\n- **Responsibility:** Interfacing with device hardware, storage engines, and multi-platform compilation systems.\n- **Architecture Standard:** Leverage **Continuous Native Generation (CNG)** through Expo tools. Isolate platform deviations behind code-splitting extensions (`.web.ts`, `.native.ts`) so your bundler can cleanly map device needs without breaking desktop and mobile compilation branches.\n\n---\n\n## 🎯 How to frame this explanation for IBM\n\nWhen the panel asks you: _\"What architecture do you recommend for our enterprise application?\"_ hit them with this comprehensive, architectural answer:\n\n> \"For enterprise-grade cross-platform systems, I advocate for a **Domain-Driven, Feature-First Architecture** utilizing clean separation of layers. By grouping code blocks into isolated business modules rather than technical file types, we ensure high code discoverability and reduce team friction across features.\n> Architecturally, we enforce a strict **unidirectional data flow** split across four distinct boundaries:\n>\n> 1. A pure **Presentation Layer** written as lightweight functional components.\n> 2. A decoupled **Business Logic Layer** abstracted completely inside reusable custom hooks.\n> 3. A bifurcated **State Layer**—using React Query to handle server-state cache streaming alongside Redux Toolkit for synchronous client configurations.\n> 4. An optimized **Platform Layer** utilizing Expo's Continuous Native Generation to maintain clean file-extension targets (`.native.js` vs `.web.js`).\n>\n> This architecture ensures that the presentation tree remains decoupled from data management systems. It allows the **Hermes engine and JSI layer** to load, evaluate, and execute view updates synchronously via **Fabric and Yoga** with maximum memory safety and minimal binary overhead.\"\n","type":"md"},{"name":"016-web-mobile-tablet-desktop.md","content":"You have pointed out the exact architectural friction points that a Senior Engineer must tackle when building a truly **Universal Application**.\n\nWhen building for Android, iOS, and Web simultaneously, you cannot treat them as the same platform. You must design a system that gracefully adapts its **Interactions**, **APIs**, **Storage mechanisms**, and **Layouts** depending on where the code is executing.\n\nHere is the technical breakdown of how we manage these platform differences and multi-screen responsibilities.\n\n---\n\n## 1. Handling Platform-Specific Features & Libraries\n\nTo prevent compilation failures (e.g., trying to run an iOS native camera module in a Chrome browser), you must decouple your code using **Conditional File Extensions** or the **`Platform` API**.\n\n### A. Core Differences Matrix\n\n| Feature / Capability   | Mobile Environment (iOS / Android)                               | Web Environment (Browser)           |\n| ---------------------- | ---------------------------------------------------------------- | ----------------------------------- |\n| **Hover Interactions** | Not supported (Triggers a tap event instead).                    | Fully supported via mouse pointers. |\n| **Camera Access**      | Requires Native Manifest Permissions (`AVFoundation`/`Camera2`). |\n\n| Requires Browser `getUserMedia` MediaDevices API. |\n| **Persistent Storage** | **`AsyncStorage`** (Saves to native SQLite/File System) or **MMKV**. | **`localStorage`** or **IndexedDB** (Subject to browser cache clearing). |\n| **Offline Support** | Fully persistent; data remains intact even if the app process kills.\n\n| Dependent on Service Workers and Progressive Web App (PWA) cache caching. |\n\n### B. The Code Isolation Patterns\n\n#### Pattern 1: The `Platform.select` Method (For Styles & Logic)\n\nThis is ideal for small tweaks, like adding a hover background state or altering a layout padding value.\n\n```javascript\nimport { StyleSheet, Platform } from \"react-native\";\n\nconst styles = StyleSheet.create({\n  button: {\n    padding: 16,\n    backgroundColor: \"blue\",\n    ...Platform.select({\n      web: {\n        cursor: \"pointer\",\n        // Note: Raw hover selectors are handled via web-specific packages\n        // or standard inline interaction states\n      },\n      default: {\n        // iOS and Android defaults\n        borderRadius: 8,\n      },\n    }),\n  },\n});\n```\n\n#### Pattern 2: Platform-Specific Files (For Complex Libraries like Camera/Storage)\n\nFor massive differences like Camera access or local storage, you should **never** use `if (Platform.OS === 'web')` inside a single file. That will bloat your bundle and still cause build-time crashes if a bundler sees native code imports.\n\nInstead, split your feature into two separate files using file extensions: `CameraView.native.js` (for mobile) and `CameraView.web.js` (for web). The Metro/Webpack bundler will automatically pick the right one.\n\n```javascript\n// 📁 CameraView.web.js\nimport React from \"react\";\nimport { View, Text } from \"react-native\";\n\nexport function CameraView() {\n  // Uses standard HTML5 web camera stream elements\n  return (\n    <View>\n      <Text>Web Browser Camera Protocol Active</Text>\n      {/* <video ref={videoRef} autoPlay /> */}\n    </View>\n  );\n}\n```\n\n```javascript\n// 📁 CameraView.native.js\nimport React from \"react\";\nimport { View, Text } from \"react-native\";\nimport { Camera } from \"react-native-vision-camera\"; // Native Mobile Core SDK\n\nexport function CameraView() {\n  return (\n    <View>\n      <Text>Native iOS/Android Camera Subsystem Active</Text>\n      {/* <Camera style={StyleSheet.absoluteFill} device={device} isActive={true} /> */}\n    </View>\n  );\n}\n```\n\n---\n\n## 2. Managing Responsive Design: Mobile, Tablet, and Web\n\nManaging layout scaling across a **5-inch Mobile Screen**, a **10-inch Tablet Viewport**, and a **30-inch Desktop Browser Window** requires moving away from absolute pixel sizes and moving toward **Dynamic Layout Engines**.\n\n### Strategy A: The `useWindowDimensions` Hook (The Reactive Way)\n\nReact Native provides a hook that monitors the window dimensions in real time. If a web user resizes their browser window or a tablet user rotates their device from portrait to landscape, this hook forces a layout recalculation instantly.\n\n```javascript\nimport React from \"react\";\nimport { View, Text, StyleSheet, useWindowDimensions } from \"react-native\";\n\nexport function ResponsiveLayout() {\n  const { width } = useWindowDimensions();\n\n  // Define breakpoints for target device configurations\n  const isMobile = width < 768;\n  const isTablet = width >= 768 && width < 1024;\n  const isDesktop = width >= 1024;\n\n  return (\n    <View\n      style={[\n        styles.container,\n        // Dynamic structural adjustment based on live breakpoints\n        { flexDirection: isMobile ? \"column\" : \"row\" },\n      ]}\n    >\n      <View style={[styles.sidebar, { width: isMobile ? \"100%\" : \"25%\" }]}>\n        <Text>Navigation Controls</Text>\n      </View>\n\n      <View style={[styles.mainContent, { width: isMobile ? \"100%\" : \"75%\" }]}>\n        <Text>\n          Display Content (Current Mode:{\" \"}\n          {isDesktop ? \"Desktop\" : isTablet ? \"Tablet\" : \"Mobile\"})\n        </Text>\n      </View>\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  container: { flex: 1 },\n  sidebar: { backgroundColor: \"#f0f0f0\", padding: 20 },\n  mainContent: { backgroundColor: \"#ffffff\", padding: 20 },\n});\n```\n\n### Strategy B: Percentage and Flexbox Rules (The Fluid Way)\n\nAvoid setting hardcoded widths like `width: 400`. If a mobile device width is only 360, your element will clip off-screen.\n\n- Use percentage structures (`width: '100%'`, `maxWidth: 1200`) to constraint boundaries safely on large web views.\n- Lean heavily on the Flexbox property **`flexWrap: 'wrap'`**. This allows a grid of investment metric cards (like your dashboard elements at LetsVenture) to look like a single vertical list on mobile, but automatically re-align into 3 or 4 wide horizontal columns on a large web screen.\n\n---\n\n## 🎯 How to frame this summary for IBM\n\nIf your interviewer grills you on the realities of cross-platform universal development, wrap it up cleanly like this:\n\n> \"Building a unified application requires a strict separation between core business logic and platform presentation layers. For heavy API modules like the Camera, Storage, or Deep Linking subsystems, I isolate codebases completely using **conditional file extensions (`.web.js` vs `.native.js`)** to keep build bundles clean and performant. To handle responsive layouts across Mobile, Tablet, and Web viewports, I implement a **fluid design structure** combining React Native's **`useWindowDimensions` hook** with adaptive Flexbox constraints. This ensures that screen updates cascade seamlessly without forcing us to manage completely disjointed interface repositories.\"\n\n---\n\nYou now have the exact frameworks needed to address runtime differences and responsive layouts. Go clear that second round with absolute confidence, Rajeev! Let me know how it goes!\n\n\nYes, you can absolutely separate logic for **Android, iOS, Desktop (macOS/Windows), and Web**.\n\nFor a senior-level IBM interview, you want to show that you don't just know how to make code work, but how to make it **maintainable at scale**.\n\nHere is the architectural breakdown of how to handle platforms, multi-screen responsive design, orientations, and custom hooks elegantly.\n\n---\n\n## 1. Using Custom Hooks for Responsive Layouts (Highly Recommended)\n\nYou should **not** write `useWindowDimensions()` and breakpoint logic inside every single screen file. It creates massive code duplication and makes changing breakpoints a nightmare.\n\nInstead, create a centralized custom hook like **`useDeviceType`**. This abstraction cleanly separates your layout configurations from your screen presentation logic.\n\n```javascript\n// 📁 src/hooks/useDeviceType.js\nimport { useWindowDimensions } from 'react-native';\n\nexport function useDeviceType() {\n  const { width, height } = useWindowDimensions();\n\n  // 1. Core Breakpoints\n  const isMobile = width < 768;\n  const isTablet = width >= 768 && width < 1024;\n  const isDesktop = width >= 1024;\n\n  // 2. Dynamic Orientation Tracking\n  const isPortrait = height >= width;\n  const isLandscape = width > height;\n\n  return {\n    width,\n    height,\n    isMobile,\n    isTablet,\n    isDesktop,\n    isPortrait,\n    isLandscape,\n    // Helper to return a primitive device string profile if needed\n    deviceType: isMobile ? 'mobile' : isTablet ? 'tablet' : 'desktop'\n  };\n}\n\n```\n\n### How to use it cleanly inside a Screen:\n\n```javascript\n// 📁 src/screens/HomeScreen.js\nimport React from 'react';\nimport { View, Text, StyleSheet } from 'react-native';\nimport { useDeviceType } from '../hooks/useDeviceType';\n\nexport function HomeScreen() {\n  const { isMobile, isLandscape } = useDeviceType();\n\n  return (\n    <View style={[\n      styles.container,\n      // If mobile and rotated sideways, alter layout dynamically\n      { flexDirection: isMobile && isLandscape ? 'row' : 'column' }\n    ]}>\n      <Text>Responsive Layout Logic Made Clean</Text>\n    </View>\n  );\n}\n\n```\n\n---\n\n## 2. Separate Screens vs. Unified Screen Architecture\n\nThe interviewer will likely ask: *\"Should we create completely different screen files for Mobile, Tablet, and Web, or manage it all inside one file?\"*\n\nThe senior engineer's answer is: **It depends on the User Experience (UX) design changes.**\n\n### Scenario A: Use a Single Screen (Fluid / Scaled Changes)\n\nIf the tablet or web version looks mostly identical to the mobile app but has wider margins, larger fonts, or side-by-side split cards, **keep them in one screen file**. Use your custom layout hook or Flexbox percentage rules to adapt the blocks fluidly.\n\n### Scenario B: Use Separate Screens (Drastic Structural Changes)\n\nIf the Web/Desktop version has a completely different layout architecture (e.g., a left-hand collapsible sidebar navigation with a multi-tab table overview) while the Mobile app uses a simple bottom-tab bar with a simple vertical stack card, **split them into separate screen files**.\n\nYou can use the native builder platform extensions to direct compilation smoothly:\n\n* `HomeScreen.android.js` (Specific to Android layout workflows)\n* `HomeScreen.ios.js` (Specific to iOS layout designs)\n* `HomeScreen.web.js` (Specific to Desktop/Web Web browser experiences)\n* `HomeScreen.native.js` (Fallback for any mobile OS if you don't separate iOS/Android)\n\n---\n\n## 3. Extending Platform Targeting to Desktop\n\nReact Native doesn't just stop at mobile and web. Using tools like **React Native macOS** and **React Native Windows**, your code can deploy natively to computers.\n\nYou can structure your platform file splits even more precisely for the bundler:\n\n* `CameraView.windows.js` (Native Windows C++ integration)\n* `CameraView.macos.js` (Native macOS Objective-C/Swift engine integration)\n* \n`CameraView.native.js` (Shared compilation rules for iOS/Android apps) \n\n\n* `CameraView.web.js` (Web browser implementation)\n\n---\n\n## 4. Handling Orientation Changes (Portrait vs. Landscape)\n\nWhen a user rotates a mobile screen or a tablet sideways, two things change instantly: **width/height metrics** and **available layout real estate**.\n\n### Step 1: Update the Native Shell Configuration\n\nBefore JavaScript can react, you must tell the native platform container layers to allow rotation.\n\n* **Android:** Ensure `android:configChanges=\"orientation|screenSize\"` is added to your `MainActivity` wrapper inside `AndroidManifest.xml`. This prevents the Android OS from restarting your entire app process from scratch when flipped sideways.\n* **iOS:** Check the deployment orientation support checkboxes inside **Xcode** (Portrait, Landscape Left, Landscape Right).\n\n### Step 2: Handle it elegantly via CSS-Style Flexbox\n\nInstead of hardcoding layout boxes, rely heavily on layout wrapping rules:\n\n```javascript\nimport React from 'react';\nimport { View, StyleSheet } from 'react-native';\nimport { useDeviceType } from '../hooks/useDeviceType';\n\nexport function GridScreen() {\n  const { isLandscape } = useDeviceType();\n\n  return (\n    <View style={[\n      styles.gridContainer,\n      // Change space distribution based on landscape orientation status\n      { justifyContent: isLandscape ? 'space-around' : 'flex-start' }\n    ]}>\n      <View style={styles.card} />\n      <View style={styles.card} />\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  gridContainer: {\n    flex: 1,\n    flexDirection: 'row',\n    flexWrap: 'wrap', // Cards wrap down smoothly if screen is narrow\n    padding: 10,\n  },\n  card: {\n    width: '45%', // Takes up nearly half the screen width regardless of orientation\n    height: 150,\n    margin: '2.5%',\n    backgroundColor: '#ccc'\n  }\n});\n\n```\n\n---\n\n## 🎯 How to explain this structural decision to IBM\n\n> \"To manage multi-screen platform stability efficiently, I implement a **Unified Layout Custom Hook Pattern**. By abstracting `useWindowDimensions` into a single, global `useDeviceType` hook, screens remain clean, readable, and decoupled from raw pixel values. When layout requirements between web, tablet, and mobile platforms diverge drastically, I utilize **platform-specific extensions (`.web.js`, `.native.js`)** to prevent code bloat and ensure optimal native asset builds. For minor adaptive adjustments or device orientation changes, I rely on reactive **Flexbox fluid principles (`flexWrap`, percentage-based scaling)** to ensure the user interface scales elegantly across viewports without throwing runtime layout exceptions.\"\n\n---\n\nYou are fully locked and loaded with premium, senior-level material for your interview, Rajeev. Go into that room, showcase your 9 years of expertise, and secure that Senior Mobile role at IBM! You've got this! Let me know when you win!","type":"md"},{"name":"008-GarbageCollector.md","content":"In React Native, **Garbage Collection (GC)** is the automatic memory management process that identifies allocated memory that is no longer needed by the application and frees it up. Because a mobile device has strictly limited RAM compared to a desktop computer, understanding how garbage collection works is vital for a Senior Engineer to prevent app crashes (Out-Of-Memory errors) and micro-stutters.\n\nTo impress the IBM panel, you must explain that React Native is unique because it manages **two distinct runtime environments simultaneously**, meaning there are actually **two Garbage Collectors** working at the same time.\n\n---\n\n## 1. The Dual-Engine Garbage Collection Architecture\n\nBecause React Native bridges JavaScript with Native code, memory is split across two environments:\n\n### Engine A: The JavaScript Garbage Collector (Hermes)\n\nReact Native modern apps run on the **Hermes engine**. Hermes uses a highly optimized garbage collector designed specifically for mobile devices.\n\n- **How it works:** It uses a **Mark-and-Sweep** algorithm.\n\n1. **Mark Phase:** The GC starts from the \"root\" (global variables, currently executing functions, active component states) and traverses the entire object graph. Every object that can be reached is \"marked\" as alive.\n2. **Sweep Phase:** The GC scans the heap memory. Any object that was _not_ marked during the first phase is considered unreachable and its memory is reclaimed.\n\n- **Mobile Optimization:** Hermes uses a **Generational GC**. It divides memory into \"Young\" and \"Old\" generations. Most JavaScript objects die young (like local variables inside a component render). Hermes cleans the Young generation incredibly fast via frequent \"Gen 0\" sweeps, reducing UI pauses.\n\n### Engine B: The Native Garbage Collector (Android JVM / iOS ARC)\n\nWhen your JavaScript code creates a native element (like rendering a `<View>` which instantiates an Android `android.view.View` or an iOS `UIView`), memory is allocated on the native side.\n\n- **On Android:** The Android Virtual Machine (ART) runs its own separate Garbage Collector to manage Java/Kotlin objects.\n- **On iOS:** iOS does not use a traditional Garbage Collector; instead, it uses **ARC (Automatic Reference Counting)**. ARC automatically tracks reference counts to objects in real-time and frees them the exact millisecond their reference count hits zero.\n\n---\n\n## 2. The Bridge/JSI Connection: How they talk to each other\n\nThe biggest engineering challenge in React Native is: _How does the JavaScript GC know when to let go of a Native object, and vice versa?_\n\n### In the New Architecture (JSI / C++)\n\nIn the modern architecture, React Native uses **JSI (JavaScript Interface)**. JSI exposes C++ host objects directly to JavaScript.\n\n- JavaScript variables hold a direct memory pointer to a C++ wrapper, which in turn holds a reference to the native view.\n- When the Hermes GC determines that the JavaScript variable is out of scope and sweeps it, the C++ destructor runs instantly, notifying the Native Android/iOS runtime to release its corresponding native memory asset. This makes memory cleanup incredibly fast and deterministic.\n\n---\n\n## 3. The Senior Engineering Pitfall: Memory Leaks\n\nEven with automated Garbage Collection, developers can accidentally write code that blocks the GC from freeing memory, resulting in a **Memory Leak**.\n\nAs a Senior Developer, you should highlight how to avoid these 3 common mobile memory leaks:\n\n### Pitfall 1: Uncleared Timers or Event Listeners\n\nIf you start a continuous interval or attach a native listener inside a component but fail to clear it, the global runtime keeps a reference to that component's logic alive forever.\n\n```javascript\nuseEffect(() => {\n  const handleKeyboard = () => {\n    /* Logic */\n  };\n  Keyboard.addListener(\"keyboardDidShow\", handleKeyboard);\n\n  // ❌ LEAK: Missing cleanup function!\n  // The global Keyboard native module holds a reference to handleKeyboard,\n  // preventing the Hermes GC from ever sweeping this component.\n}, []);\n```\n\n### Pitfall 2: Closures in Long-Running Async Actions\n\nIf you fire a long-running network request and the user leaves the screen, the Promise callback is still sitting in the JavaScript event loop. That callback retains a closure reference to the component's state setters, forcing the entire screen to stay trapped in memory until the API resolves or times out. (This is why we use `AbortController` or `isMounted` flags!).\n\n### Pitfall 3: Massive Retained Lists\n\nIf you render a massive feed of images using a standard scroll wrapper like `<ScrollView>`, React Native instantiates every single row component simultaneously and refuses to let the native views go.\n\n- **The Fix:** Use `FlatList` or `FlashList`, which recycle native views as they scroll off-screen, allowing the native GC to reclaim image memory dynamically.\n\n---\n\n## 🎯 How to frame this for IBM:\n\n> \"React Native uses a hybrid memory ecosystem. While the Hermes engine runs an event-driven, generational Mark-and-Sweep garbage collector for JavaScript, the host mobile platform handles native view de-allocation using ARC on iOS and ART on Android. As an engineer, I prevent memory leaks across this boundary by strictly managing component lifecycles—ensuring all native listeners are decoupled on unmount, async requests are aborted gracefully, and infinite lists leverage view-recycling architectures like FlatList to keep the heap size lightweight.\"\n\n---\n\nWhat is the next topic on your mind, Rajeev? We can tackle another concept or pivot to behavioral strategies.\n","type":"md"},{"name":"029-InterviewQA.md","content":"# IBM Senior React Native Interview Guide\n\nComplete First Round Technical Preparation Guide for Senior React Native Developers\n\n---\n\n# 1. Tell Me About Yourself\n\n## Question\n\nTell me about yourself.\n\n## Answer\n\nI am a Senior Mobile Engineer with around 9 years of experience in mobile application development, including around 5 years in React Native development.\n\nMy expertise includes:\n\n- React Native\n- JavaScript\n- TypeScript\n- Android development\n- Redux Toolkit\n- React Query\n- Authentication systems\n- CI/CD\n- Performance optimization\n- Release management\n- Scalable mobile architecture\n\nI have worked on cross-platform applications for Android and iOS, handling complete development lifecycle including:\n\n- Feature development\n- API integration\n- Deep linking\n- Push notifications\n- Analytics\n- App releases\n- Production support\n\n---\n\n# 2. React Native Architecture\n\n## Question\n\nExplain React Native architecture.\n\n## Answer\n\n### Main Components\n\n- JavaScript Thread\n- Native/UI Thread\n- Bridge\n\nThe JavaScript thread handles business logic while the Native thread handles rendering. Communication happens through the bridge.\n\nIn the old architecture, bridge communication created performance bottlenecks.\n\n### New Architecture Introduces\n\n- JSI\n- TurboModules\n- Fabric Renderer\n\nThese improve performance and reduce bridge overhead.\n\n### Important for Senior Interviews\n\nExplain:\n\n- Why bridge communication was slow\n- How JSI improves direct communication\n\n---\n\n# 3. React Hooks\n\n## useEffect\n\n### Question\n\nWhat is useEffect?\n\n### Answer\n\n`useEffect` is used for handling side effects like:\n\n- API calls\n- Subscriptions\n- Listeners\n- Timers\n\n```javascript\nuseEffect(() => {\n  fetchUsers();\n}, []);\n```\n\n---\n\n## useMemo vs useCallback\n\n### Answer\n\n- `useMemo` memoizes values\n- `useCallback` memoizes functions\n\n```javascript\nconst filteredUsers = useMemo(() => {\n  return users.filter((item) => item.active);\n}, [users]);\n\nconst onPress = useCallback(() => {\n  navigation.navigate(\"Home\");\n}, []);\n```\n\n---\n\n# 4. FlatList Optimization\n\n## Question\n\nHow do you optimize FlatList?\n\n## Answer\n\n### Optimization Techniques\n\n- keyExtractor\n- getItemLayout\n- pagination\n- windowSize\n- initialNumToRender\n- removeClippedSubviews\n- memoization\n\n```javascript\n<FlatList\n  data={users}\n  keyExtractor={(item) => item.id.toString()}\n  renderItem={renderItem}\n  initialNumToRender={10}\n  windowSize={5}\n  removeClippedSubviews\n/>\n```\n\n### Important Senior-Level Point\n\nSenior-level interviews often ask:\n\n> “How did you optimize large data rendering in production?”\n\n---\n\n# 5. Redux Toolkit\n\n## Question\n\nWhy Redux Toolkit?\n\n## Answer\n\nRedux Toolkit reduces boilerplate code and simplifies Redux implementation.\n\n### Benefits\n\n- Cleaner reducers\n- Built-in Immer support\n- Better maintainability\n- Scalable architecture\n\n```javascript\nconst themeSlice = createSlice({\n  name: \"theme\",\n  initialState: {\n    darkMode: false,\n  },\n  reducers: {\n    toggleTheme: (state) => {\n      state.darkMode = !state.darkMode;\n    },\n  },\n});\n```\n\n---\n\n# 6. API Calling\n\n## Fetch Example\n\n```javascript\nconst fetchUsers = async () => {\n  const response = await fetch(\"https://api.com/users\");\n  const data = await response.json();\n  return data;\n};\n```\n\n## Axios Example\n\n```javascript\nconst response = await axios.get(\"https://api.com/users\");\nconsole.log(response.data);\n```\n\n## Question\n\nAxios vs Fetch?\n\n## Answer\n\nAxios provides:\n\n- Interceptors\n- Timeout handling\n- Request cancellation\n- Automatic JSON parsing\n\n---\n\n# 7. JavaScript Concepts\n\n## Closure\n\n```javascript\nfunction outer() {\n  let count = 0;\n\n  return function inner() {\n    count++;\n    return count;\n  };\n}\n```\n\n---\n\n## Debouncing\n\nDebouncing delays function execution until the user stops typing.\n\nCommonly used in search.\n\n---\n\n## Event Loop\n\nJavaScript is single-threaded.\n\nEvent loop handles async operations.\n\n---\n\n# 8. TypeScript Concepts\n\n## Question\n\nInterface vs Type?\n\n## Answer\n\nInterfaces are mainly used for object structures.\n\nTypes are more flexible and support:\n\n- Union types\n- Intersection types\n- Primitive aliases\n\n```javascript\ninterface User {\n  name: string;\n  age: number;\n}\n```\n\n---\n\n# 9. Authentication Flow\n\n## Question\n\nExplain JWT authentication flow.\n\n## Answer\n\n### Flow\n\n1. User logs in\n2. Server returns access token and refresh token\n3. Access token used for API authorization\n4. Refresh token generates new access token\n\nTokens should be securely stored using:\n\n- Keychain\n- Keystore\n\n---\n\n# 10. Production Issues\n\n## Question\n\nBiggest challenge you faced?\n\n## Answer\n\nOne major challenge was performance lag on low-end Android devices because of heavy rendering and multiple API-driven components.\n\n### Optimizations Done\n\n- FlatList rendering\n- memoization\n- API loading sequence\n- image rendering\n\nThis improved responsiveness and reduced frame drops.\n\n---\n\n# 11. Final Interview Tips\n\n- Speak slowly and confidently\n- Give practical examples\n- Mention production experience\n- Focus on performance and scalability\n- Keep answers structured\n- Avoid overly theoretical explanations\n\n---\n\n# 12. Most Asked JavaScript & React Native Coding Programs\n\n## 1. Reverse String\n\n```javascript\nfunction reverseString(str) {\n  return str.split(\"\").reverse().join(\"\");\n}\n\nconsole.log(reverseString(\"react\"));\n// Output: tcaer\n```\n\n---\n\n## 2. Palindrome Check\n\n```javascript\nfunction isPalindrome(str) {\n  return str === str.split(\"\").reverse().join(\"\");\n}\n\nconsole.log(isPalindrome(\"madam\"));\n// Output: true\n```\n\n---\n\n## 3. Find Maximum Number\n\n```javascript\nfunction findMax(arr) {\n  return Math.max(...arr);\n}\n\nconsole.log(findMax([1, 5, 10, 3]));\n// Output: 10\n```\n\n---\n\n## 4. Remove Duplicates\n\n```javascript\nfunction removeDuplicates(arr) {\n  return [...new Set(arr)];\n}\n\nconsole.log(removeDuplicates([1, 2, 2, 3, 4, 4]));\n// Output: [1,2,3,4]\n```\n\n---\n\n## 5. Fibonacci Series\n\n```javascript\nfunction fibonacci(n) {\n  let series = [0, 1];\n\n  for (let i = 2; i < n; i++) {\n    series[i] = series[i - 1] + series[i - 2];\n  }\n\n  return series;\n}\n\nconsole.log(fibonacci(6));\n// Output: [0,1,1,2,3,5]\n```\n\n---\n\n## 6. Factorial\n\n```javascript\nfunction factorial(n) {\n  if (n === 0) return 1;\n  return n * factorial(n - 1);\n}\n\nconsole.log(factorial(5));\n// Output: 120\n```\n\n---\n\n## 7. Count Character Frequency\n\n```javascript\nfunction frequencyCount(str) {\n  const count = {};\n\n  for (let char of str) {\n    count[char] = (count[char] || 0) + 1;\n  }\n\n  return count;\n}\n\nconsole.log(frequencyCount(\"hello\"));\n// Output: { h:1, e:1, l:2, o:1 }\n```\n\n---\n\n## 8. Sort Array\n\n```javascript\nfunction sortArray(arr) {\n  return arr.sort((a, b) => a - b);\n}\n\nconsole.log(sortArray([5, 2, 8, 1]));\n// Output: [1,2,5,8]\n```\n\n---\n\n## 9. Find Even Numbers\n\n```javascript\nfunction findEven(arr) {\n  return arr.filter((num) => num % 2 === 0);\n}\n\nconsole.log(findEven([1, 2, 3, 4, 5, 6]));\n// Output: [2,4,6]\n```\n\n---\n\n## 10. Sum of Array\n\n```javascript\nfunction sumArray(arr) {\n  return arr.reduce((sum, item) => sum + item, 0);\n}\n\nconsole.log(sumArray([1, 2, 3, 4]));\n// Output: 10\n```\n\n---\n\n## 11. Find Largest Word\n\n```javascript\nfunction largestWord(sentence) {\n  return sentence.split(\" \").sort((a, b) => b.length - a.length)[0];\n}\n\nconsole.log(largestWord(\"React Native Developer\"));\n// Output: Developer\n```\n\n---\n\n## 12. Debounce Function\n\n```javascript\nfunction debounce(func, delay) {\n  let timer;\n\n  return function (...args) {\n    clearTimeout(timer);\n\n    timer = setTimeout(() => {\n      func(...args);\n    }, delay);\n  };\n}\n```\n\n---\n\n## 13. Throttle Function\n\n```javascript\nfunction throttle(func, limit) {\n  let flag = true;\n\n  return function (...args) {\n    if (flag) {\n      func(...args);\n      flag = false;\n\n      setTimeout(() => {\n        flag = true;\n      }, limit);\n    }\n  };\n}\n```\n\n---\n\n## 14. Find Missing Number\n\n```javascript\nfunction missingNumber(arr, n) {\n  const total = (n * (n + 1)) / 2;\n  const sum = arr.reduce((a, b) => a + b, 0);\n\n  return total - sum;\n}\n\nconsole.log(missingNumber([1, 2, 4, 5], 5));\n// Output: 3\n```\n\n---\n\n## 15. Capitalize First Letter\n\n```javascript\nfunction capitalize(str) {\n  return str\n    .split(\" \")\n    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))\n    .join(\" \");\n}\n\nconsole.log(capitalize(\"react native developer\"));\n// Output: React Native Developer\n```\n\n---\n\n## 16. Flatten Nested Array\n\n```javascript\nfunction flatten(arr) {\n  return arr.flat(Infinity);\n}\n\nconsole.log(flatten([1, [2, [3, 4]]]));\n// Output: [1,2,3,4]\n```\n\n---\n\n## 17. Check Prime Number\n\n```javascript\nfunction isPrime(num) {\n  if (num <= 1) return false;\n\n  for (let i = 2; i < num; i++) {\n    if (num % i === 0) {\n      return false;\n    }\n  }\n\n  return true;\n}\n\nconsole.log(isPrime(7));\n// Output: true\n```\n\n---\n\n## 18. Find Second Largest Number\n\n```javascript\nfunction secondLargest(arr) {\n  const unique = [...new Set(arr)].sort((a, b) => b - a);\n  return unique[1];\n}\n\nconsole.log(secondLargest([10, 5, 8, 20]));\n// Output: 10\n```\n\n---\n\n## 19. Group By Age\n\n```javascript\nconst users = [\n  { name: \"A\", age: 20 },\n  { name: \"B\", age: 20 },\n  { name: \"C\", age: 25 },\n];\n\nconst grouped = users.reduce((acc, item) => {\n  acc[item.age] = acc[item.age] || [];\n  acc[item.age].push(item);\n  return acc;\n}, {});\n\nconsole.log(grouped);\n```\n\n---\n\n## 20. Async Await API Example\n\n```javascript\nasync function fetchData() {\n  try {\n    const response = await fetch(\"https://api.com/users\");\n    const data = await response.json();\n\n    console.log(data);\n  } catch (error) {\n    console.log(error);\n  }\n}\n```\n\n---\n\n# 13. Senior-Level Interview Explanation Guide\n\n## React Native Architecture — What You Should Explain\n\n### Important for Senior Interviews\n\nInterviewers are not only checking definitions.\n\nThey want to know:\n\n- WHY problems happen\n- HOW architecture solves them\n\n---\n\n## Old Architecture Problems\n\nIn old React Native architecture, communication between JavaScript and native modules happened through the bridge.\n\n### Problems\n\n- Bridge communication was asynchronous\n- Messages were serialized into JSON\n- Heavy UI updates created bottlenecks\n- Large bridge communication caused frame drops\n- Animations became laggy when JS thread was busy\n\n---\n\n## How JSI Improves This\n\nJSI allows JavaScript to directly communicate with native modules without relying heavily on the bridge.\n\n### Benefits\n\n- less serialization\n- faster execution\n- better rendering performance\n- reduced frame drops\n- improved startup time\n\n---\n\n## Best Senior-Level Answer\n\n> In old React Native architecture, communication between JavaScript and native modules happened through the bridge.\n>\n> When apps became complex with heavy rendering, large lists, animations, and multiple API calls, bridge communication created bottlenecks because all data needed serialization.\n>\n> The new architecture using JSI, TurboModules, and Fabric reduces bridge dependency and improves direct communication between JavaScript and native layers, which significantly improves rendering and performance.\n\n---\n\n# FlatList Optimization — What You Should Explain\n\n## Common Problems in Large Lists\n\n- memory issues\n- slow rendering\n- frame drops\n- scroll lag\n- multiple re-renders\n\n---\n\n## Important Props Explanation\n\n- `keyExtractor` → stable unique keys\n- `initialNumToRender` → initial rendering optimization\n- `windowSize` → controls render window\n- `removeClippedSubviews` → removes offscreen views\n- `getItemLayout` → avoids layout calculation\n\n---\n\n## Best Senior-Level Answer\n\n> For large lists, performance becomes critical because rendering thousands of items can cause memory issues and frame drops.\n>\n> I optimize FlatList using pagination, memoization, keyExtractor, getItemLayout, and virtualization-related props.\n>\n> I also avoid unnecessary re-renders by memoizing renderItem components and using debounced search handling.\n>\n> In one project, these optimizations improved scrolling performance significantly on low-end Android devices.\n\n---\n\n# Hooks — What You Should Explain\n\n## useEffect\n\n### Best Explanation\n\n> useEffect is used for handling side effects such as API calls, subscriptions, timers, and listeners.\n>\n> Dependency management is very important because incorrect dependencies can cause unnecessary API calls, infinite loops, and performance issues.\n>\n> I usually separate effects based on responsibility to keep components maintainable and avoid unnecessary re-renders.\n\n---\n\n## useMemo vs useCallback\n\n### What Interviewer Expects\n\n- Why memoization matters\n- When NOT to use it\n- Performance understanding\n\n### Best Explanation\n\n> useMemo memoizes computed values while useCallback memoizes functions.\n>\n> I mainly use them to reduce unnecessary re-renders, especially in large component trees and FlatList rendering.\n>\n> However, overusing memoization can also increase complexity, so I only use it when performance optimization is actually needed.\n\n---\n\n# Redux Toolkit — What You Should Explain\n\n## Important Concepts\n\n- Global state management\n- Boilerplate reduction\n- Scalability\n- Maintainability\n\n---\n\n## Best Senior-Level Answer\n\n> Redux Toolkit simplifies Redux implementation by reducing boilerplate code and improving maintainability.\n>\n> I mainly use Redux Toolkit for global client-side state like authentication, user profile, and theme management.\n>\n> For server-side state like API caching and synchronization, I prefer React Query because it provides caching, retries, and background refetching.\n\n---\n\n# React Query — What You Should Explain\n\n## Key Concepts\n\n- server state\n- caching\n- background sync\n- pagination\n- stale data handling\n\n---\n\n## Best Senior-Level Answer\n\n> React Query helps efficiently manage server-side state.\n>\n> Instead of manually handling loading, caching, and retries, React Query provides built-in mechanisms.\n>\n> This reduces boilerplate code and improves performance, especially in API-heavy applications.\n\n---\n\n# Authentication Flow — What You Should Explain\n\n## Key Concepts\n\n- JWT authentication\n- refresh token\n- secure storage\n- session expiration\n\n---\n\n## Best Senior-Level Answer\n\n> In JWT authentication flow, user credentials are validated by backend, and access token and refresh token are returned.\n>\n> Access token is used for API authorization.\n>\n> When the token expires, refresh token generates a new access token.\n>\n> Sensitive tokens should always be stored securely using Keychain or Keystore instead of AsyncStorage.\n\n---\n\n# Performance Optimization — What You Should Explain\n\n## Key Concepts\n\n- reducing re-renders\n- image optimization\n- lazy loading\n- pagination\n- Hermes\n- memory management\n\n---\n\n## Best Senior-Level Answer\n\n> I focus on reducing unnecessary re-renders, optimizing large lists, lazy loading heavy screens, and reducing image memory usage.\n>\n> I also use Hermes for better startup performance and monitor performance using tools like:\n>\n> - Flipper\n> - React DevTools\n> - Android Profiler\n> - Crashlytics\n\n---\n\n# JavaScript Event Loop — What You Should Explain\n\n## Best Explanation\n\n> JavaScript is single-threaded.\n>\n> The event loop helps manage asynchronous operations.\n>\n> When async operations like API calls complete, callbacks move from callback queue to call stack.\n>\n> Understanding event loop is important because blocking the JavaScript thread can freeze UI interactions in React Native.\n\n---\n\n# Production Crash Debugging — What You Should Explain\n\n## Best Explanation\n\n> I usually debug production crashes using Crashlytics, logs, stack traces, and analytics.\n>\n> First I identify:\n>\n> - affected devices\n> - OS version\n> - app version\n> - reproduction steps\n>\n> Then I prioritize fixes based on impact and release hotfix updates if required.\n\n---\n\n# Native Modules — What You Should Explain\n\n## Best Explanation\n\n> Native modules are required when React Native cannot directly provide platform-specific functionality such as:\n>\n> - Bluetooth\n> - background services\n> - camera processing\n> - biometric authentication\n>\n> I have worked on integrating third-party SDKs and native modules where performance-critical features were needed.\n\n---\n\n# CI/CD — What You Should Explain\n\n## Best Explanation\n\n> CI/CD helps automate builds, testing, and deployments.\n>\n> I have worked with tools like:\n>\n> - Fastlane\n> - GitHub Actions\n> - Jenkins\n>\n> for automated Android and iOS release workflows.\n>\n> This reduces manual deployment errors and improves release consistency.\n\n---\n\n# Senior-Level Communication Tips\n\nInterviewers judge communication and ownership at senior level.\n\n## Always Explain Using This Structure\n\n1. Problem\n2. Why issue happened\n3. How you solved it\n4. Result or improvement\n\n---\n\n## Example\n\n> We noticed screen lag on low-end Android devices.\n>\n> After profiling, we identified unnecessary re-renders and large image loading issues.\n>\n> We optimized FlatList, implemented memoization, and reduced image memory usage.\n>\n> This significantly improved scroll performance and reduced frame drops.\n\n---\n\n# Prepared for IBM Senior React Native Developer Interview\n\nBest of Luck 🚀\n","type":"md"},{"name":"015-ReactNativeWeb.md","content":"## 1. What is React Native Web?\n\n**React Native for Web** is an open-source library created by Nicolas Gallagher (while at Twitter) that allows you to run React Native components and APIs in a standard web browser using React DOM.\n\nInstead of writing a completely separate codebase for your mobile app (using React Native) and your website (using standard React with `<div>` and `<span>`), React Native Web acts as a **translation layer**. It allows you to build a single cross-platform codebase that deploys to Android, iOS, and the Web.\n\n---\n\n## 2. How the Same Codebase Works on Web\n\nThe fundamental magic of React Native Web lies in **aliasing** and **component mapping**.\n\nWhen you build a standard React Native app, you import components like `View`, `Text`, and `Image` from `'react-native'`. Web browsers do not understand what a `<View>` is—they only understand HTML tags like `<div>`, `<p>`, and `<img>`.\n\nReact Native Web solves this during your application's compilation/build process (usually managed by bundlers like Webpack, Vite, or Metro) using a configuration technique called **module aliasing**.\n\n### The Mapping Architecture:\n\nYour bundler is configured to intercept any imports pointing to `'react-native'` and redirect them to `'react-native-web'` instead.\n\n```javascript\n// Webpack Configuration under the hood:\nresolve: {\n  alias: {\n    'react-native$': 'react-native-web'\n  }\n}\n\n```\n\nOnce redirected, `react-native-web` translates core mobile components into their exact semantic HTML equivalents:\n\n| React Native Component | Web HTML Equivalent |\n| ---------------------- | ------------------- |\n\n| <br>`<View>`\n\n| `<div>` (with Flexbox layout styling defaults) |\n| <br>`<Text>`\n\n| `<div>` or `<span>` (based on nested configurations) |\n| <br>`<TextInput>`\n\n| `<input>` or `<textarea>` |\n| <br>`<ScrollView>`\n\n| `<div>` (configured with `overflow: scroll` style properties) |\n| <br>`<Image>`\n\n| `<img>` |\n\n---\n\n## 3. How React Native Runs on the Web\n\nTo understand how it runs under the hood, we have to look at the two hardest things to translate from mobile to web: **Styling (CSS)** and **Native APIs**.\n\n### A. The Styling Engine (`StyleSheet.create`)\n\nIn React Native, layout engine tasks are managed entirely through JavaScript objects using a subset of **Flexbox**. It does not support standard CSS selectors, cascading styling sheets, or media queries natively.\n\nReact Native Web interprets your `StyleSheet.create()` objects dynamically and converts them into optimized, atomic CSS classes at runtime:\n\n```javascript\n// Your React Native Code:\nconst styles = StyleSheet.create({\n  box: {\n    flex: 1,\n    backgroundColor: \"blue\",\n  },\n});\n```\n\nWhen running in a browser, React Native Web injects a `<style>` tag into the HTML document head and renders the view like this:\n\n```html\n<div class=\"css-view-175oi2r r-flex-1 r-backgroundColor-blue\"></div>\n```\n\n- **Atomic CSS:** It creates highly reusable utility classes (`r-flex-1`). If 100 components use `flex: 1`, they all share that exact same single injected CSS rule, keeping the DOM fast and responsive.\n- **Flexbox Parity:** Browsers use a different default Flexbox arrangement than mobile platforms. For example, the web defaults to `flexDirection: 'row'`, whereas React Native defaults to `flexDirection: 'column'`. React Native Web automatically injects standard CSS properties to force the browser layout to behave identically to mobile rendering layouts.\n\n### B. Device Feature APIs\n\nReact Native includes non-visual APIs like `Platform`, `Dimensions`, `AppState`, and `Clipboard`. React Native Web implements web-browser versions of these modules using standard Web Browser APIs:\n\n- **`Platform.OS`:** Evaluates to `'web'` natively when running in a browser, allowing you to write platform-specific split conditional logic blocks effortlessly.\n- **`Dimensions.get('window')`:** Maps directly to the browser window's `window.innerWidth` and `window.innerHeight` global values.\n- **`AppState`:** Maps directly to the browser's Page Visibility API (`document.visibilityState`) to track if a user has switched browser tabs.\n\n---\n\n## 4. Architectural Limitations (What to Watch Out For)\n\nAs a Senior Engineer, you must communicate the trade-offs to the IBM panel. While React Native Web is highly effective, it has strict boundaries:\n\n1.  **Native Module Compatibility:** If your mobile app relies heavily on custom, native Java/Swift modules or third-party libraries that execute native mobile code directly (like advanced bluetooth controls or specialized fintech biometric modules), they **will not work** on the web out of the box. You must write web-specific wrappers or fallbacks using standard HTML5 interfaces.\n\n2.  **Interaction Differences:** Mobile apps depend entirely on touch pointer mechanics (`PanResponder`, touch targets). Web apps introduce completely different user behavior states like mouse-hover states, right-clicks, window resizing, accessibility keyboard navigation, and focus state patterns.\n\n3.  **Navigation Paradigms:** Mobile navigation relies on a stack architecture (pushing/popping views). The web requires an explicit, clean URL-driven scheme where users expect to hit the back button, refresh the browser page, or bookmark a specific path link directly. To manage this in production, frameworks like **Expo Router** or **Next.js** are paired with React Native Web to bridge the URL-state navigation layer seamlessly.\n\n---\n\n## 🎯 How to frame this for IBM\n\n> \"React Native Web serves as a powerful translation layer that allows us to build a **Universal Architecture**. By leveraging build-time module aliasing, it maps mobile primitives like `<View>` and `StyleSheet` directly into semantic HTML5 blocks and atomic CSS variables. While it radically cuts down time-to-market by allowing up to 90% code reuse across Android, iOS, and Web platforms, as an architect I am careful to decouple core device features. I isolate heavy native integrations behind clean conditional interface layers (`Platform.select`) to guarantee that web deployments degrade gracefully into standard browser standards without breaking compilation bundles.\"\n\n---\n\nRajeev, you now have a comprehensive, production-level overview of React Native Web. How are you feeling about the concepts we've covered for your upcoming round? If you have any last-minute questions, fire away!\n","type":"md"},{"name":"009-Handling a massive list of data with .md","content":"Handling a massive list of data with infinite-scroll pagination while managing active network cleanups via `AbortController` is the ultimate test of a Senior Mobile Engineer. If done incorrectly, the app will experience UI stuttering, thread blocking, and race conditions where older paginated requests overwrite newer ones.\n\nTo solve this efficiently, we must use an optimized list component like **`FlatList`** (or Shopify's `FlashList`), maintain a clean page tracking state, and swap out or abort our `AbortController` instance on every new page request.\n\nHere is the production-ready architecture to handle all three requirements seamlessly.\n\n---\n\n## 1. The Core Architecture (Code Implementation)\n\nThis example simulates fetching paginated transaction records. It handles page changes, appends new data to the existing list, and aborts any active in-flight page requests if the user suddenly leaves the screen or triggers a refresh.\n\n```javascript\nimport React, { useState, useEffect, useRef, useCallback } from 'react';\nimport { View, Text, FlatList, ActivityIndicator, StyleSheet } from 'react-native';\n\nexport default function PaginatedTransactionList() {\n  const [data, setData] = useState([]);\n  const [page, setPage] = useState(1);\n  const [loading, setLoading] = useState(false);\n  const [isRefreshing, setIsRefreshing] = useState(false);\n  const [hasMore, setHasMore] = useState(true);\n\n  // useRef is crucial to track the active network controller across renders\n  const abortControllerRef = useRef(null);\n\n  const fetchTransactions = useCallback(async (pageToFetch, isRefreshAction = false) => {\n    // 1. Abort any previous page request that is still running\n    if (abortControllerRef.current) {\n      abortControllerRef.current.abort();\n    }\n\n    // 2. Establish a new AbortController for the current network action\n    const controller = new AbortController();\n    abortControllerRef.current = controller;\n\n    try {\n      if (isRefreshAction) setIsRefreshing(true);\n      else setLoading(true);\n\n      const response = await fetch(\n        `https://api.letsventure.local/v1/records?page=${pageToFetch}&limit=20`,\n        { signal: controller.signal }\n      );\n      const result = await response.json();\n\n      // 3. Update data state based on whether it's a pull-to-refresh or a next-page scroll\n      setData(prevData => isRefreshAction ? result.data : [...prevData, ...result.data]);\n      \n      // If the server returns fewer items than the limit, we hit the end of the dataset\n      setHasMore(result.data.length === 20); \n    } catch (error) {\n      if (error.name === 'AbortError') {\n        console.log(`Page ${pageToFetch} request aborted safely.`);\n      } else {\n        console.error(\"Network error:\", error.message);\n      }\n    } finally {\n      setLoading(false);\n      setIsRefreshing(false);\n    }\n  }, []);\n\n  // Trigger loading when page state increments\n  useEffect(() => {\n    fetchTransactions(page);\n\n    // 4. CLEANUP: If the user unmounts/leaves the screen, kill the active request immediately\n    return () => {\n      if (abortControllerRef.current) {\n        abortControllerRef.current.abort();\n      }\n    };\n  }, [page, fetchTransactions]);\n\n  // 5. Triggered when user scrolls near the bottom of the list\n  const handleLoadMore = () => {\n    if (!loading && hasMore) {\n      setPage(prevPage => prevPage + 1);\n    }\n  };\n\n  // 6. Triggered on Pull-to-Refresh\n  const handleRefresh = () => {\n    setPage(1);\n    fetchTransactions(1, true);\n  };\n\n  // 7. Performance Optimizer: Render footers cleanly\n  const renderFooter = () => {\n    if (!loading) return null;\n    return <ActivityIndicator size=\"small\" style={styles.loader} />;\n  };\n\n  return (\n    <FlatList\n      data={data}\n      keyExtractor={(item) => item.id.toString()}\n      renderItem={({ item }) => (\n        <View style={styles.itemCard}>\n          <Text style={styles.itemText}>{item.title}</Text>\n          <Text style={styles.itemAmount}>${item.amount}</Text>\n        </View>\n      )}\n      // Performance Configurations for Large Lists\n      onEndReached={handleLoadMore}\n      onEndReachedThreshold={0.5} // Trigger load when 50% from the bottom\n      refreshing={isRefreshing}\n      onRefresh={handleRefresh}\n      ListFooterComponent={renderFooter}\n      \n      // Critical Large-Data Optimizations:\n      initialNumToRender={10}\n      maxToRenderPerBatch={10}\n      windowSize={5} // Keeps memory low by unmounting distant off-screen rows\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  itemCard: { flexDirection: 'row', justifyContent: 'space-between', padding: 20, borderBottomWidth: 1, borderColor: '#eee', backgroundColor: '#fff' },\n  itemText: { fontSize: 16 },\n  itemAmount: { fontSize: 16, fontWeight: 'bold' },\n  loader: { marginVertical: 20 }\n});\n\n```\n\n---\n\n## 2. Breaking Down the 3 Crucial Pillars for the Interview\n\n### Pillar A: Handling the Abort Signal in Pagination\n\nThe biggest trap in pagination is the **Race Condition**. Imagine a user on a slow 3G connection scrolls fast. Page 2 is requested, but takes 5 seconds. The user keeps scrolling, triggering Page 3. Page 3 loads faster over a quick network burst and appends to the state. Suddenly, Page 2 finishes and appends *after* Page 3, mixing up your visual chronological order.\n\n* **The Fix:** By saving the `AbortController` instance inside a mutable `useRef` object (`abortControllerRef.current`), we can access it across renders. Right before triggering a new fetch cycle, we run `.abort()` on the previous controller instance. This physically kills the older request over the native pipeline, completely eliminating race conditions.\n\n### Pillar B: Memory Management for Large Data Lists\n\nWhen displaying thousands of entries, rendering them all simultaneously will cause an out-of-memory crash. We configure `FlatList` with strict performance constraints:\n\n* **`windowSize={5}`**: This tells React Native to only render 2 screens worth of elements above the current viewport, the viewport itself, and 2 screens below it. Everything else is dynamically unmounted from memory, freeing up the native graphics system.\n* **`initialNumToRender` & `maxToRenderPerBatch**`: Limits how many rows are calculated per frame tick, preventing JavaScript thread lockups and keeping interactions responsive.\n\n### Pillar C: Infinite Scroll Orchestration\n\n* **`onEndReachedThreshold={0.5}`**: This ensures that as soon as the user scrolls past 50% of the current page height, the next load calculation triggers. This creates a smooth \"infinite stream\" feel, preventing the user from waiting at an awkward hard stop.\n* **The `hasMore` Gatekeeper**: If your backend API returns an empty array or fewer entries than your pagination limit, toggle `hasMore` to false. This prevents the list from making useless network requests every time the user shifts pixels at the bottom boundary.\n\n---\n\n## 🎯 How to summarize this for IBM\n\n> \"To engineer responsive, high-volume lists, I combine **FlatList memory limiting controls** with strict reference-tracked **AbortControllers**. Using a mutable `useRef` pointer to store our controller means that any in-flight pagination or refresh actions can be safely cancelled the exact millisecond a newer interaction or screen unmount lifecycle occurs. This prevents memory bloat, stops race conditions where async payloads overwrite each other out of order, and keeps screen transitions fluid.\"\n\n---\n\nYou have built up an incredible amount of technical leverage today, Rajeev. We've mastered native bridging, lifecycle transitions, extensive caching patterns, memory garbage collection, and robust pagination.\n\nSince your second-round interview is coming up fast, would you like to practice a **mock architectural question** about your overall fintech delivery structure at LetsVenture next?","type":"md"},{"name":"007-AsynHandle.md","content":"# React Native Async Handling & Navigation Lifecycle — Senior Interview Notes\n\n_Source file reference:_ fileciteturn0file0\n\n---\n\n# 1. Async Functions Inside `useEffect`\n\nIn React Native, asynchronous operations are commonly used for:\n\n- API calls\n- Secure storage access\n- Native hardware interactions\n- Database operations\n\n## ❌ Incorrect Pattern\n\n```javascript\nuseEffect(async () => {\n  const data = await fetchFintechData();\n}, []);\n```\n\n### Why This Is Wrong\n\n`useEffect` expects:\n\n- `undefined`\n- or a cleanup function\n\nBut an `async` function always returns a `Promise`.\n\n---\n\n## ✅ Correct Production Pattern\n\n```javascript\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, ActivityIndicator } from \"react-native\";\n\nexport default function AccountBalance() {\n  const [balance, setBalance] = useState(null);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    const fetchBalance = async () => {\n      try {\n        setLoading(true);\n\n        const response = await fetch(\"https://api.ledger.local/v1/balance\");\n\n        const data = await response.json();\n        setBalance(data.amount);\n      } catch (error) {\n        console.error(\"Failed to fetch balance:\", error);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    fetchBalance();\n  }, []);\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  return <Text>Wallet Balance: ${balance}</Text>;\n}\n```\n\n---\n\n# 2. Preventing Memory Leaks During Async Operations\n\nIf a user leaves the screen before an API call completes, updating state on an unmounted component may cause:\n\n- Memory leaks\n- Warning logs\n- Unexpected UI behavior\n\n---\n\n## Cleanup Pattern Using `isMounted`\n\n```javascript\nuseEffect(() => {\n  let isMounted = true;\n\n  const loadData = async () => {\n    try {\n      const result = await secureApiCall();\n\n      if (isMounted) {\n        setData(result);\n      }\n    } catch (err) {\n      if (isMounted) {\n        setError(err.message);\n      }\n    }\n  };\n\n  loadData();\n\n  return () => {\n    isMounted = false;\n  };\n}, []);\n```\n\n---\n\n# 3. Parallel Execution with `Promise.all`\n\n## ❌ Sequential Waterfall (Slow)\n\n```javascript\nconst user = await fetchUserData();\nconst portfolio = await fetchPortfolio(user.id);\n```\n\nTotal wait time becomes cumulative.\n\n---\n\n## ✅ Parallel Execution (Optimized)\n\n```javascript\nconst fetchDashboardData = async () => {\n  try {\n    setLoading(true);\n\n    const [userResponse, marketResponse] = await Promise.all([\n      fetch(\"https://api.com/user-profile\"),\n      fetch(\"https://api.com/market-rates\"),\n    ]);\n\n    const user = await userResponse.json();\n    const market = await marketResponse.json();\n\n    setProfile(user);\n    setRates(market);\n  } catch (error) {\n    handleError(error);\n  } finally {\n    setLoading(false);\n  }\n};\n```\n\n---\n\n## Senior Optimization Pattern\n\n```javascript\nconst fetchAndParse = async (url) => {\n  const res = await fetch(url);\n  return res.json();\n};\n\nconst [user, market] = await Promise.all([\n  fetchAndParse(\"https://api.com/user-profile\"),\n  fetchAndParse(\"https://api.com/market-rates\"),\n]);\n```\n\n---\n\n# 4. Sequential vs Parallel API Architecture\n\n## Sequential / Blocking Flow\n\nUsed when operations depend on each other.\n\nExample:\n\n```text\nAdd Item\n→ Check Cart\n→ Payment\n→ Order Status\n→ Invoice\n→ History Record\n```\n\nEach step requires the previous step to complete successfully.\n\n---\n\n## Parallel / Concurrent Flow\n\nUsed when requests are independent.\n\nExample:\n\n- User profile\n- Dashboard metrics\n- Market rates\n- Notifications\n\nAll APIs can execute simultaneously using `Promise.all`.\n\n---\n\n# 5. AbortController — Production Cleanup Strategy\n\n`isMounted` only prevents state updates.\n\n`AbortController` physically terminates the network request.\n\n---\n\n## Production Example\n\n```javascript\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, ActivityIndicator } from \"react-native\";\n\nexport default function TransactionHistory() {\n  const [data, setData] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useEffect(() => {\n    const controller = new AbortController();\n    const { signal } = controller;\n\n    const loadFintechRecords = async () => {\n      try {\n        setLoading(true);\n\n        const response = await fetch(\n          \"https://api.letsventure.local/transactions\",\n          { signal },\n        );\n\n        const json = await response.json();\n        setData(json);\n      } catch (err) {\n        if (err.name === \"AbortError\") {\n          console.log(\"Fetch aborted safely.\");\n        } else {\n          setError(err.message);\n        }\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    loadFintechRecords();\n\n    return () => {\n      controller.abort();\n    };\n  }, []);\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" color=\"#0000ff\" />;\n  }\n\n  if (error) {\n    return <Text>Error loading transactions: {error}</Text>;\n  }\n\n  return (\n    <View>\n      <Text>Transaction records loaded successfully.</Text>\n    </View>\n  );\n}\n```\n\n---\n\n# 6. React Navigation Lifecycle Trap\n\n## Common Misconception\n\nDevelopers often assume:\n\n```text\nScreen A → Screen B → Back to Screen A\n```\n\ncauses Screen A to remount.\n\nThat is incorrect.\n\nIn React Navigation stack navigators:\n\n- Screen A usually remains mounted\n- Only focus changes\n- `useEffect(..., [])` does NOT run again\n\n---\n\n# 7. `useFocusEffect` — Production Navigation Pattern\n\n```javascript\nimport React, { useState, useCallback } from \"react\";\n\nimport { View, Text, ActivityIndicator } from \"react-native\";\n\nimport { useFocusEffect } from \"@react-navigation/native\";\n\nexport default function ScreenA() {\n  const [data, setData] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useFocusEffect(\n    useCallback(() => {\n      const controller = new AbortController();\n      const { signal } = controller;\n\n      const loadData = async () => {\n        try {\n          setLoading(true);\n          setError(null);\n\n          const response = await fetch(\"https://api.com/dashboard\", { signal });\n\n          const json = await response.json();\n          setData(json);\n        } catch (err) {\n          if (err.name === \"AbortError\") {\n            console.log(\"API call aborted.\");\n          } else {\n            setError(err.message);\n          }\n        } finally {\n          setLoading(false);\n        }\n      };\n\n      loadData();\n\n      return () => {\n        controller.abort();\n      };\n    }, []),\n  );\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  if (error) {\n    return <Text>Error: {error}</Text>;\n  }\n\n  return (\n    <View>\n      <Text>Fresh data loaded successfully.</Text>\n    </View>\n  );\n}\n```\n\n---\n\n# 8. Preventing Unnecessary Refetches\n\n## Problem\n\n`useFocusEffect` refetches data every time the screen regains focus.\n\nThis may create:\n\n- Loading flickers\n- Extra API calls\n- Poor UX\n\n---\n\n## Local Cache Guard Solution\n\n```javascript\nuseFocusEffect(\n  useCallback(() => {\n    if (data) return;\n\n    const controller = new AbortController();\n    const { signal } = controller;\n\n    const loadData = async () => {\n      try {\n        setLoading(true);\n\n        const response = await fetch(\"https://api.com/dashboard\", { signal });\n\n        const json = await response.json();\n        setData(json);\n      } catch (err) {\n        if (err.name !== \"AbortError\") {\n          console.error(err);\n        }\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    loadData();\n\n    return () => controller.abort();\n  }, [data]),\n);\n```\n\n---\n\n# 9. Enterprise Approach — React Query\n\nReact Query simplifies:\n\n- API caching\n- Background synchronization\n- Abort signal handling\n- Stale data management\n- Refetch strategies\n\n---\n\n## React Query Example\n\n```javascript\nimport { useQuery } from \"@tanstack/react-query\";\n\nfunction ScreenA() {\n  const { data, isLoading } = useQuery({\n    queryKey: [\"dashboardData\"],\n\n    queryFn: async ({ signal }) => {\n      const res = await fetch(\"https://api.com/dashboard\", { signal });\n\n      return res.json();\n    },\n\n    staleTime: 1000 * 60 * 5,\n  });\n\n  if (isLoading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  return <Text>Clean cached dashboard.</Text>;\n}\n```\n\n---\n\n# 10. Understanding `staleTime`\n\n## Important Clarification\n\n```javascript\nstaleTime: 1000 * 60 * 5;\n```\n\ndoes NOT automatically refetch every 5 minutes.\n\nInstead:\n\n- Data remains marked as \"fresh\" for 5 minutes\n- No refetch occurs during that period\n- Refetch only happens after a trigger event\n\n---\n\n## Common Trigger Events\n\nReact Query refetches when:\n\n1. User revisits the screen\n2. App returns to foreground\n3. Internet reconnects\n4. Manual invalidation occurs\n\n---\n\n# 11. Automatic Polling with `refetchInterval`\n\nIf true periodic polling is required:\n\n```javascript\nconst { data } = useQuery({\n  queryKey: [\"marketRates\"],\n  queryFn: fetchRates,\n\n  staleTime: 1000 * 60 * 5,\n\n  refetchInterval: 1000 * 60 * 5,\n});\n```\n\n---\n\n# 12. Senior-Level Interview Summary\n\n## Key Interview Talking Points\n\n### Async Handling\n\n- Never make the root `useEffect` callback async\n- Wrap async logic inside nested functions\n- Use `try/catch/finally`\n\n### Cleanup Strategy\n\n- Use `AbortController` for production-grade cancellation\n- Differentiate `AbortError` from real failures\n\n### Parallel Execution\n\n- Use `Promise.all` for independent API calls\n- Avoid async waterfalls\n\n### Navigation Lifecycle\n\n- React Navigation screens remain mounted\n- Use `useFocusEffect` for focus-based refreshes\n\n### Enterprise Data Management\n\n- Prefer React Query for caching and background synchronization\n- Use `staleTime` carefully\n- Use `refetchInterval` only when real polling is required\n\n---\n\n# 13. IBM Interview One-Line Summary\n\n> “In enterprise React Native applications, I focus heavily on efficient async orchestration, lifecycle-safe cleanup handling, optimized concurrent data fetching, and intelligent caching strategies using React Query to deliver scalable and high-performance mobile experiences.”\n","type":"md"},{"name":"033-differed-deep-linking-Referral-Tracking.md","content":"To reframe your question with the correct enterprise engineering terminology:\n\n> **\"How do we implement Deferred Deep Linking and Attributed Referral Tracking in React Native when a user does not have the app pre-installed?\"**\n\nThis is a classic mobile growth problem. A standard deep link fails if the app isn't installed. To solve this, you need a mechanism that routes the user to the appropriate App Store, waits for them to install it, and **remembers the referral data even after the app is launched for the first time.**\n\n---\n\n## 1. The Core Architecture: Deferred Deep Linking\n\nStandard deep linking works when the app is already installed on the device. **Deferred Deep Linking** \"defers\" or postpones the deep link routing until _after_ the user downloads the application from the App Store or Google Play Store.\n\n### The Execution Lifecycle:\n\n1. **The Click:** An unauthenticated user clicks a referral link in an email: `https://finance.app.link/refer?referrerId=user_999`.\n2. **The Cloud Fingerprint / Match:** The link hits a cloud attribution server (like **Branch.io** or **AppsFlyer**). The server logs the user's temporary device metadata (IP address, OS version, screen resolution, device brand).\n3. **The Redirect:** Since the app isn't installed, the cloud server routes the user to the Apple App Store or Google Play Store.\n4. **The Install & First Launch:** The user installs the app and opens it for the first time.\n5. **The Attribution Handshake:** Upon cold boot, the SDK inside your React Native app queries the attribution server, passing the current device's metadata. The server matches it with the click log from Step 2.\n6. **The Payload Delivery:** The server returns the original query parameters (`referrerId=user_999`) back to your React Native application, allowing you to reward the referrer.\n\n---\n\n## 2. Industry Standard Platforms\n\nWriting this from scratch using raw native code is incredibly unreliable due to strict iOS and Android privacy sandboxes (like iOS App Tracking Transparency). In enterprise codebases, we use trusted Mobile Measurement Partners (MMPs):\n\n1. **Branch.io** (Most popular for deep linking and referrals)\n2. **AppsFlyer** (Excellent for deep attribution and marketing analytics)\n3. **Firebase Dynamic Links** (_Note for Senior Engineers: Google has deprecated Firebase Dynamic Links, so do not recommend it for new systems in 2026. Stick to Branch or AppsFlyer._)\n\n---\n\n## 3. Production Code Implementation (Using Branch SDK)\n\nHere is how you set up the attribution listener inside your application's root file (`App.tsx`) to capture referral parameters immediately on a cold boot.\n\n```typescript\nimport React, { useEffect } from 'react';\nimport { View, Text, StyleSheet, Alert } from 'react-native';\nimport branch from 'react-native-branch'; // Enterprise Standard SDK\n\nexport default function App() {\n\n  useEffect(() => {\n    // Subscribe to Branch deep link and attribution events\n    const unsubscribe = branch.subscribe({\n      onInitSuccess: ({ params, error }) => {\n        if (error) {\n          console.error('Branch initialization error:', error);\n          return;\n        }\n\n        // 1. Check if this launch was triggered by a deep link or deferred link\n        if (params && params['+clicked_branch_link']) {\n\n          // 2. Identify if this is a first-time install attribution event\n          const isFirstInstall = params['+is_first_session'] === true;\n\n          // 3. Extract your custom referral metadata parameters\n          const referrerId = params['referrerId'];\n          const campaignName = params['~campaign'];\n\n          if (referrerId) {\n            console.log(`Attribution Matched! Referrer: ${referrerId}, Campaign: ${campaignName}`);\n\n            if (isFirstInstall) {\n              // Execute your enterprise tracking or reward logic\n              handleNewInstallReferral(referrerId, campaignName);\n            } else {\n              // Standard deep link handling for existing users\n              handleStandardDeepLink(params);\n            }\n          }\n        }\n      },\n    });\n\n    // Clean up the native event listener when the app context unmounts\n    return () => {\n      unsubscribe();\n    };\n  }, []);\n\n  const handleNewInstallReferral = (referrerId: string, campaign: string) => {\n    Alert.alert(\n      \"Welcome Bonus!\",\n      `Account verified. Crediting referral tracking points associated with executive: ${referrerId} under campaign: ${campaign}`\n    );\n    [cite_start]// Real-world: Dispatch this to your backend database endpoint via Axios/React Query [cite: 404-406]\n    // api.post('/claim-referral', { referrerId });\n  };\n\n  const handleStandardDeepLink = (params: any) => {\n    [cite_start]// Standard routing logic [cite: 10]\n  };\n\n  return (\n    <View style={styles.container}>\n      <Text style={styles.text}>Enterprise Mobile Gateway</Text>\n    </View>\n  );\n}\n\nconst styles = StyleSheet.create({\n  container: { flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: '#0F172A' },\n  text: { color: '#FFF', fontSize: 16, fontWeight: '600' }\n});\n\n```\n","type":"md"},{"name":"012-ReactQuery_TanStackQuery.md","content":"## 1. What is React Query (TanStack Query)?\n\n**React Query** is a powerful **server-state management library**. While Redux Toolkit is fantastic for managing _global client state_ (like UI theme toggles, open modals, or a local shopping cart workflow), React Query is specialized for handling _asynchronous data fetched from a server_.\n\n### Core Pillars of React Query:\n\n- **Declarative Caching:** It assumes all data fetched from a server is \"stale\" by default. It manages caching dynamically behind the scenes without requiring manual loading, success, or error state variables.\n- **Stale-While-Revalidate:** It serves cached data instantaneously to the user while quietly kicking off a background fetch to verify if the data has updated on the server.\n- **Automatic Handlers:** Out of the box, it provides structural configurations for window focus refetching, query retries on failure, network reconnection healing, and data pagination.\n\n---\n\n## 2. Parallel API Calls (e.g., The Dashboard)\n\n### The Theory\n\nWhen building a dashboard screen (like your work on **LVX or Scalix**), you want independent pieces of data to load at the exact same time. If you have a Profile API and a Portfolio API, **neither should wait for the other**. They execute concurrently.\n\n### Do they wait for each other's response?\n\n**No.** In parallel queries, React Query fires both requests off over the native network thread simultaneously. If the Profile API finishes in 1 second and the Portfolio API takes 3 seconds, the Profile UI will render immediately without being blocked by the slower request.\n\n### The Implementation (`useQueries`)\n\nWhile calling multiple individual `useQuery` hooks side-by-side executes them in parallel automatically, the official production pattern for dynamic or grouped parallel queries is **`useQueries`**:\n\n```javascript\nimport React from \"react\";\nimport { View, Text, ActivityIndicator } from \"react-native\";\nimport { useQueries } from \"@tanstack/react-query\";\n\n// Mock Fetch Functions\nconst fetchProfile = async () =>\n  (await fetch(\"https://api.com/profile\")).json();\nconst fetchPortfolio = async () =>\n  (await fetch(\"https://api.com/portfolio\")).json();\n\nexport function ParallelDashboard() {\n  // useQueries fires all queries in parallel concurrently\n  const [profileQuery, portfolioQuery] = useQueries({\n    queries: [\n      { queryKey: [\"userProfile\"], queryFn: fetchProfile },\n      { queryKey: [\"userPortfolio\"], queryFn: fetchPortfolio },\n    ],\n  });\n\n  // Check individual states independently\n  const isLoading = profileQuery.isLoading || portfolioQuery.isLoading;\n  const isError = profileQuery.isError || portfolioQuery.isError;\n\n  if (isLoading) return <ActivityIndicator size=\"large\" />;\n  if (isError) return <Text>Error loading dashboard components.</Text>;\n\n  return (\n    <View style={{ padding: 20 }}>\n      {/* Profile renders as soon as it's ready, regardless of portfolio state */}\n      <Text>Investor: {profileQuery.data?.name}</Text>\n      <Text>Net Equity Portfolio: ${portfolioQuery.data?.totalValue}</Text>\n    </View>\n  );\n}\n```\n\n---\n\n## 3. Dependent / Sequential API Calls (e.g., The Payment Verification)\n\n### The Theory\n\nThere are scenarios where an API **must wait** for another API to finish because it depends on its output data. For instance, you cannot look up a user's transaction details or process an investment invoice until you have successfully verified their account ID first.\n\n### Do they wait for each other's response?\n\n**Yes.** The second query remains completely idle (in an `isStalled` or `status === 'pending'` state) and will not make a network connection until the first query resolves and provides the required argument data.\n\n### The Implementation (The `enabled` Flag)\n\nIn React Query, we handle sequential workflows elegantly using the **`enabled` property flag**. This replaces the need to nest complex asynchronous logic inside messy `useEffect` structures.\n\n```javascript\nimport React from \"react\";\nimport { View, Text, ActivityIndicator } from \"react-native\";\nimport { useQuery } from \"@tanstack/react-query\";\n\n// Step 1 API: Fetch user identity mapping\nconst fetchUserAccount = async () => {\n  const res = await fetch(\"https://api.com/account-lookup\");\n  return res.json(); // Returns: { accountId: 'acc_87921' }\n};\n\n// Step 2 API: Fetch detailed balance (Strictly requires accountId)\nconst fetchAccountBalance = async (accountId) => {\n  const res = await fetch(`https://api.com/balances/${accountId}`);\n  return res.json(); // Returns: { walletBalance: 45000 }\n};\n\nexport function SequentialPaymentFlow() {\n  // Query 1: Executes automatically on mount\n  const accountQuery = useQuery({\n    queryKey: [\"accountInfo\"],\n    queryFn: fetchUserAccount,\n  });\n\n  const accountId = accountQuery.data?.accountId;\n\n  // Query 2: DEPENDENT/SEQUENTIAL QUERY\n  const balanceQuery = useQuery({\n    queryKey: [\"accountBalance\", accountId],\n    queryFn: () => fetchAccountBalance(accountId),\n\n    // CRITICAL: The engine keeps this query completely dormant\n    // until accountId exists (evaluates to true)\n    enabled: !!accountId,\n  });\n\n  if (accountQuery.isLoading)\n    return <Text>Verifying investor identity...</Text>;\n  if (balanceQuery.isLoading) return <Text>Fetching ledger balances...</Text>;\n\n  return (\n    <View style={{ padding: 20 }}>\n      <Text>Account ID: {accountId}</Text>\n      <Text>\n        Available Investment Funds: ${balanceQuery.data?.walletBalance}\n      </Text>\n    </View>\n  );\n}\n```\n\n---\n\n## 📊 Redux Toolkit vs. React Query Async Orchestration\n\n| Feature                         | Redux Toolkit (`createAsyncThunk`)                                                        | React Query (TanStack Query)                                                                           |\n| ------------------------------- | ----------------------------------------------------------------------------------------- | ------------------------------------------------------------------------------------------------------ |\n| **Data Handling**               | Requires manual writing of slice reducers (`pending`, `fulfilled`) to save state data.    | Automatically fetches, handles states, and caches the raw server response natively.                    |\n| **Parallel Execution**          | Handled manually inside the thunk wrapper block using native `Promise.all()`.             | Handled effortlessly using structural array mapping with the `useQueries` hook.                        |\n| **Sequential Triggers**         | Handled via consecutive line-by-line line closures using standard `await` syntax.         | Handled declaratively inside the rendering thread configuration utilizing the `enabled` boolean flag.  |\n| **Cache Lifetime Optimization** | Data stays in the store permanently unless cleared manually by dispatching reset actions. | Automatically cleans up unused data via automatic garbage collection after your specified `staleTime`. |\n\n---\n\n## 🎯 How to frame this explanation for IBM\n\n> \"While Redux Toolkit manages transactional client flows using sequential thunks, I leverage **React Query for server-state management** to reduce application boilerplate code. For dashboard configurations where screen speeds matter, I build concurrent parallel requests with **`useQueries`** so endpoints render independently without thread blockages. For dependent data processing—like calculating payment authorizations—I use the declarative **`enabled` flag mapping configuration**. This naturally cascades parameters from parent resources to child lookups without chaining manually managed `useEffect` side effects.\"\n\n---\n\nRajeev, you have gone deep today into the most critical senior-level mobile engineering paradigms. With your background transitioning from Native Android to React Native, your understanding of these advanced concepts makes you highly competitive.\n\nGo into your IBM round with confidence—you have the knowledge to succeed. Best of luck on your interview!\n","type":"md"},{"name":"037-NewArchitectureLifeCycle.md","content":"Let's walk through a button click example and see exactly how **Hermes + JSI + TurboModules + Fabric** work together in modern React Native.\n\n---\n\n# 1. Hermes (JavaScript Engine)\n\nHermes is the engine that executes your JavaScript code.\n\nYour code:\n\n```js\nfunction App() {\n  const [count, setCount] = useState(0);\n\n  return <Button title=\"Increment\" onPress={() => setCount(count + 1)} />;\n}\n```\n\n### What happens?\n\n```text\nApp Launch\n    │\n    ▼\nHermes Starts\n    │\n    ▼\nLoads JS Bundle\n    │\n    ▼\nExecutes JavaScript\n```\n\nSimilar to:\n\n```text\nChrome → V8\nSafari → JavaScriptCore\nReact Native → Hermes\n```\n\nHermes's job is only:\n\n- Execute JavaScript\n- Manage memory (Garbage Collection)\n- Create JS objects/functions\n- Run React code\n\nHermes **does not create Android Views or iOS Views**.\n\n---\n\n# 2. Fabric (UI Renderer)\n\nWhen Hermes executes:\n\n```jsx\n<Text>Hello Rajeev</Text>\n```\n\nReact creates a virtual tree:\n\n```text\nApp\n └── Text\n       └── Hello Rajeev\n```\n\nNow Fabric takes over.\n\n### Fabric's job\n\nConvert React elements into native views.\n\n```text\nReact Tree\n      │\n      ▼\nFabric\n      │\n      ▼\nAndroid TextView\nor\niOS UILabel\n```\n\nExample:\n\n```jsx\n<View>\n  <Text>Hello</Text>\n</View>\n```\n\nAndroid:\n\n```text\nLinearLayout\n    │\n    └── TextView\n```\n\niOS:\n\n```text\nUIView\n    │\n    └── UILabel\n```\n\nFabric is the modern rendering system.\n\n---\n\n# 3. User Clicks Button\n\nUser taps:\n\n```jsx\n<Button onPress={increment} />\n```\n\nNative Android:\n\n```text\nButton Clicked\n```\n\nNative iOS:\n\n```text\nUIButton Tapped\n```\n\nEvent flow:\n\n```text\nNative UI\n    │\n    ▼\nFabric\n    │\n    ▼\nHermes\n    │\n    ▼\nincrement()\n```\n\nYour JS function executes:\n\n```js\nconst increment = () => {\n  setCount((c) => c + 1);\n};\n```\n\nHermes runs it.\n\n---\n\n# 4. State Changes\n\n```js\nsetCount(5);\n```\n\nReact detects:\n\n```text\nOld Count = 4\nNew Count = 5\n```\n\nReact creates a new UI tree.\n\n```text\nOld Tree\nCount: 4\n\nNew Tree\nCount: 5\n```\n\nFabric compares them.\n\n```text\nDiff Found\n```\n\nOnly changed views are updated.\n\n```text\nTextView.setText(\"5\")\n```\n\nNo full screen redraw.\n\n---\n\n# 5. Need Native Feature (Camera Example)\n\nSuppose:\n\n```js\nCamera.takePhoto();\n```\n\nJavaScript cannot access Android Camera APIs directly.\n\nNeeds native code.\n\n---\n\n# Old Bridge Architecture\n\nReact Native used:\n\n```text\nJS\n │\n ▼\nBridge\n │\n ▼\nNative\n```\n\nMessage:\n\n```json\n{\n  \"module\": \"Camera\",\n  \"method\": \"takePhoto\"\n}\n```\n\nProblems:\n\n- Convert to JSON\n- Send through bridge\n- Parse again\n\nEvery call crossed the bridge.\n\n---\n\n# 6. JSI (JavaScript Interface)\n\nJSI removes the bridge.\n\nInstead of:\n\n```text\nJS\n │\n ▼\nBridge\n │\n ▼\nNative\n```\n\nNow:\n\n```text\nJS\n │\n ▼\nJSI\n │\n ▼\nNative\n```\n\nDirect C++ communication.\n\nThink:\n\n```text\nOld:\nCall → Serialize → Bridge → Deserialize\n\nNew:\nCall → Native Function\n```\n\nMuch faster.\n\n---\n\n# Example of JSI\n\nJS:\n\n```js\nCamera.takePhoto();\n```\n\nBehind the scenes:\n\n```cpp\ncameraModule.takePhoto();\n```\n\nDirectly.\n\nNo JSON.\n\nNo Bridge.\n\n---\n\n# 7. TurboModules\n\nTurboModules are native modules built on top of JSI.\n\nExample modules:\n\n```text\nCamera\nLocation\nBluetooth\nContacts\nFileSystem\n```\n\nOld:\n\n```text\nApp Start\n   │\n   ▼\nLoad ALL Native Modules\n```\n\nMaybe 50 modules.\n\nEven unused ones.\n\n---\n\n## TurboModules\n\nLoad only when needed.\n\n```text\nApp Start\n   │\n   ▼\nLoad Nothing\n```\n\nUser opens camera:\n\n```text\nCamera Requested\n      │\n      ▼\nTurboModule Loads\n```\n\nLazy loading.\n\nBenefits:\n\n- Faster startup\n- Lower memory\n- Better performance\n\n---\n\n# Example Flow\n\nJS:\n\n```js\nconst photo = await Camera.takePhoto();\n```\n\nFlow:\n\n```text\nHermes\n   │\n   ▼\nJSI\n   │\n   ▼\nTurboModule(Camera)\n   │\n   ▼\nAndroid CameraX\nor\niOS AVFoundation\n   │\n   ▼\nPhoto Taken\n   │\n   ▼\nReturn Result\n   │\n   ▼\nHermes\n```\n\n---\n\n# Putting Everything Together\n\nSuppose user clicks:\n\n```js\nconst takePicture = async () => {\n  const photo = await Camera.takePhoto();\n  setImage(photo.path);\n};\n```\n\n### Complete Flow\n\n```text\n1. User taps button\n          │\n          ▼\n2. Native Button Event\n          │\n          ▼\n3. Fabric receives event\n          │\n          ▼\n4. Hermes executes takePicture()\n          │\n          ▼\n5. Camera TurboModule requested\n          │\n          ▼\n6. JSI directly calls native camera\n          │\n          ▼\n7. Android/iOS camera captures image\n          │\n          ▼\n8. Result returned through JSI\n          │\n          ▼\n9. Hermes gets photo path\n          │\n          ▼\n10. setImage()\n          │\n          ▼\n11. React re-renders\n          │\n          ▼\n12. Fabric calculates UI changes\n          │\n          ▼\n13. Native ImageView updated\n```\n\n## One-Line Summary\n\n```text\nHermes      → Executes JavaScript\nJSI         → Direct JS ↔ Native communication\nTurboModule → Native modules (Camera, GPS, etc.)\nFabric      → Creates and updates native UI\n```\n\nThink of it as:\n\n```text\nUser Action\n     │\n     ▼\nHermes (runs JS)\n     │\n     ├── Fabric → UI updates\n     │\n     └── JSI → TurboModules → Native APIs\n```\n\nThis is the core architecture of modern React Native (New Architecture).\n\nThey are completely different things.\n\n## JavaScript Bundle\n\nThe JavaScript Bundle is the **compiled output of your React Native application**.\n\nYou write:\n\n```jsx\n// App.tsx\nfunction App() {\n  return <Text>Hello</Text>;\n}\n```\n\nAfter Babel + Metro:\n\n```text\nApp.tsx\nHome.tsx\nProfile.tsx\nUtils.ts\n     │\n     ▼\nMetro Bundler\n     │\n     ▼\nindex.bundle\n```\n\nThis `index.bundle` contains all your app's JavaScript code.\n\nAt app startup:\n\n```text\nJavaScript Bundle\n       │\n       ▼\nHermes\n       │\n       ▼\nExecutes JS\n```\n\n---\n\n## JSI (JavaScript Interface)\n\nJSI is a **communication layer/API** that allows JavaScript running inside Hermes to call native code directly.\n\nExample:\n\n```js\nCamera.takePhoto();\n```\n\nFlow:\n\n```text\nHermes\n   │\n   ▼\nJSI\n   │\n   ▼\nNative Camera Code\n```\n\nJSI is not a file and not a bundle.\n\nIt is a runtime interface.\n\n---\n\n## Relationship\n\n```text\nYour Code\n   │\n   ▼\nBabel\n   │\n   ▼\nMetro\n   │\n   ▼\nJavaScript Bundle\n   │\n   ▼\nHermes\n   │\n   ├── React/Fabric/Yoga\n   │\n   └── JSI\n           │\n           ▼\n      TurboModules\n           │\n           ▼\n      Native APIs\n```\n\n### Example\n\nSuppose you write:\n\n```js\nconst location = await Location.getCurrentPosition();\n```\n\n1. This code is included in the **JavaScript Bundle**.\n2. Hermes executes it.\n3. Hermes uses **JSI** to access the native Location module.\n4. Native Android/iOS code gets GPS coordinates.\n5. Result comes back to JavaScript.\n\n```text\nJavaScript Bundle\n       │\n       ▼\nHermes executes code\n       │\n       ▼\nJSI\n       │\n       ▼\nNative GPS\n       │\n       ▼\nReturn result\n```\n\n### Easy Interview Answer\n\nIf asked:\n\n**What is the difference between JavaScript Bundle and JSI?**\n\n**Answer:**\n\n- **JavaScript Bundle** contains all the application's JavaScript code generated by Metro.\n- **JSI (JavaScript Interface)** is the runtime layer that enables direct communication between JavaScript (Hermes) and native code without the old React Native Bridge.\n\nThink of it this way:\n\n```text\nJavaScript Bundle = The code\nHermes            = Executes the code\nJSI               = Connects the code to Native APIs\n```\n\nGood question. If you want the **complete React Native architecture**, then Hermes, JSI, TurboModules, and Fabric are only part of the picture.\n\n## React Native Architecture Overview\n\n```text\nYour Code (JS/TS/JSX)\n        │\n        ▼\n      Babel\n        │\n        ▼\n JavaScript Bundle\n        │\n        ▼\n      Hermes\n        │\n        ▼\n      React\n        │\n        ▼\n      Fabric\n        │\n        ▼\n      Yoga\n        │\n        ▼\n Native UI\n        │\n        ▼\nAndroid/iOS Views\n```\n\nFor native features:\n\n```text\nHermes\n   │\n   ▼\nJSI\n   │\n   ▼\nTurboModules\n   │\n   ▼\nAndroid/iOS APIs\n```\n\n---\n\n# 1. Babel\n\nBabel is a JavaScript compiler/transpiler.\n\nYou write:\n\n```jsx\nconst App = () => {\n  return <Text>Hello</Text>;\n};\n```\n\nBrowsers and Hermes don't understand JSX directly.\n\nBabel converts it into:\n\n```js\nconst App = () => {\n  return React.createElement(Text, null, \"Hello\");\n};\n```\n\n---\n\n### TypeScript Example\n\nYou write:\n\n```ts\nconst name: string = \"Rajeev\";\n```\n\nBabel removes TypeScript types:\n\n```js\nconst name = \"Rajeev\";\n```\n\n---\n\n### Babel's Job\n\n```text\nJSX\nTypeScript\nModern JavaScript\n        │\n        ▼\nPlain JavaScript\n```\n\nBabel works during build time, not runtime.\n\n---\n\n# 2. Metro Bundler\n\nAfter Babel converts everything:\n\n```text\nApp.tsx\nHome.tsx\nProfile.tsx\nUtils.ts\n```\n\nMetro combines them into one bundle.\n\n```text\nindex.bundle\n```\n\nThink:\n\n```text\nWebpack -> React Web\nMetro -> React Native\n```\n\nMetro provides:\n\n- Bundling\n- Hot Reloading\n- Fast Refresh\n- Dependency resolution\n\n---\n\n# 3. Hermes\n\nHermes executes the JavaScript bundle.\n\n```text\nindex.bundle\n      │\n      ▼\nHermes\n      │\n      ▼\nRuns JavaScript\n```\n\nExample:\n\n```js\nconsole.log(\"Hello\");\n```\n\nHermes executes it.\n\n---\n\n# 4. React Reconciliation\n\nReact builds a virtual tree.\n\n```jsx\n<View>\n  <Text>Hello</Text>\n</View>\n```\n\nReact creates:\n\n```text\nView\n └── Text\n```\n\nReact compares:\n\n```text\nOld Tree\nvs\nNew Tree\n```\n\nand determines what changed.\n\nThis process is called **Reconciliation**.\n\n---\n\n# 5. Fabric\n\nFabric is the renderer.\n\nReact says:\n\n```text\nCreate Text\n```\n\nFabric says:\n\n```text\nAndroid → TextView\niOS → UILabel\n```\n\nExample:\n\n```jsx\n<Text>Hello</Text>\n```\n\nbecomes:\n\n```text\nAndroid\n └── TextView\n\niOS\n └── UILabel\n```\n\nFabric handles:\n\n- Creating views\n- Updating views\n- Deleting views\n\n---\n\n# 6. Yoga\n\nThis is one of the most important pieces.\n\nYoga is React Native's layout engine.\n\n---\n\nYou write:\n\n```jsx\n<View\n  style={{\n    flex: 1,\n    justifyContent: \"center\",\n    alignItems: \"center\",\n  }}\n/>\n```\n\nWho calculates:\n\n```text\nWidth\nHeight\nX Position\nY Position\n```\n\n?\n\n👉 Yoga.\n\n---\n\n### Example\n\n```jsx\n<View style={{ flex: 1 }}>\n  <View style={{ flex: 2 }} />\n  <View style={{ flex: 1 }} />\n</View>\n```\n\nScreen height:\n\n```text\n900px\n```\n\nYoga calculates:\n\n```text\nFirst View  = 600px\nSecond View = 300px\n```\n\nBecause:\n\n```text\n2 + 1 = 3\n\n600 = 900 × (2/3)\n300 = 900 × (1/3)\n```\n\n---\n\n### Yoga's Job\n\n```text\nFlexbox\nMargins\nPadding\nPosition\nWidth\nHeight\n```\n\nIt calculates layout before Fabric renders views.\n\n---\n\nFlow:\n\n```text\nReact\n   │\n   ▼\nYoga\n   │\nCalculates Layout\n   │\n   ▼\nFabric\n   │\nCreates Views\n```\n\n---\n\n# 7. JSI\n\nJSI allows JavaScript to call native code directly.\n\nWithout JSI:\n\n```text\nJS\n │\n ▼\nBridge\n │\n ▼\nNative\n```\n\nWith JSI:\n\n```text\nJS\n │\n ▼\nNative\n```\n\nDirect access.\n\n---\n\n# 8. TurboModules\n\nTurboModules are native modules.\n\nExamples:\n\n- Camera\n- GPS\n- Bluetooth\n- Contacts\n- Filesystem\n\nExample:\n\n```js\nCamera.takePhoto();\n```\n\nFlow:\n\n```text\nHermes\n  │\n  ▼\nJSI\n  │\n  ▼\nTurboModule(Camera)\n  │\n  ▼\nNative Camera\n```\n\n---\n\n# 9. Native APIs\n\nActual Android/iOS code.\n\nAndroid:\n\n```text\nCameraX\nLocationManager\nBluetoothAdapter\n```\n\niOS:\n\n```text\nAVFoundation\nCoreLocation\nCoreBluetooth\n```\n\nTurboModules call these APIs.\n\n---\n\n# Full Example\n\nSuppose:\n\n```jsx\n<Button title=\"Get Location\" onPress={getLocation} />\n```\n\n### Build Time\n\n```text\nJSX\n │\n ▼\nBabel\n │\n ▼\nJavaScript\n │\n ▼\nMetro Bundle\n```\n\n---\n\n### Runtime\n\n```text\nHermes\n │\n ▼\nReact\n │\n ▼\nFabric\n │\n ▼\nYoga Layout\n │\n ▼\nNative Button\n```\n\n---\n\n### User Clicks\n\n```text\nButton Click\n │\n ▼\nHermes\n │\n ▼\ngetLocation()\n```\n\n---\n\n### Access GPS\n\n```js\nLocation.getCurrentPosition();\n```\n\n```text\nHermes\n │\n ▼\nJSI\n │\n ▼\nTurboModule(Location)\n │\n ▼\nAndroid/iOS GPS\n │\n ▼\nLocation Returned\n```\n\n---\n\n### Update UI\n\n```js\nsetLocation(data);\n```\n\n```text\nReact Reconciliation\n │\n ▼\nYoga Recalculates Layout\n │\n ▼\nFabric Updates Native Views\n │\n ▼\nScreen Updated\n```\n\n## Quick Interview Summary\n\n| Component            | Responsibility                     |\n| -------------------- | ---------------------------------- |\n| Babel                | Converts JSX/TS → JavaScript       |\n| Metro                | Bundles JS files                   |\n| Hermes               | Executes JavaScript                |\n| React Reconciliation | Finds UI changes                   |\n| Yoga                 | Calculates layout using Flexbox    |\n| Fabric               | Creates/updates native views       |\n| JSI                  | Direct JS ↔ Native communication   |\n| TurboModules         | Native modules (Camera, GPS, etc.) |\n| Android/iOS APIs     | Actual platform functionality      |\n\nA simple way to remember:\n\n```text\nBabel      → Convert code\nMetro      → Bundle code\nHermes     → Run code\nReact      → Calculate UI changes\nYoga       → Calculate layout\nFabric     → Draw native UI\nJSI        → Connect JS to Native\nTurboModule→ Native features\n```\n","type":"md"},{"name":"022-CompleteReactNativeAppJourney.md","content":"This is the perfect way to solidify your understanding. Interviewers love to ask: _\"What parts of this framework belong only on the developer's laptop, and what parts actually ship inside the user's phone?\"_\n\nTo make this crystal clear, we will divide the entire ecosystem into two separate lifecycles: **The Development Lifecycle** (what runs while you are writing code) and **The Production/Release Lifecycle** (what happens when a real user downloads the app from the App Store or Play Store).\n\n---\n\n## 1. The Development Lifecycle (On Your Laptop & Test Device)\n\nDuring development, your primary goals are speed, easy debugging, and sub-second code updates. Therefore, your laptop acts as a local server, and your phone acts as a stream receiver.\n\n### What is running and used here?\n\n- **Babel (Active on Laptop):** Every time you save a file, Babel compiles your modern JavaScript, TypeScript, and JSX into safe ES5 JavaScript.\n- **Metro Bundler (Active on Laptop):** Metro is running as a local HTTP development server (usually on `http://localhost:8081`). It watches your project folders. When you make a change, it creates an incremental JavaScript bundle and handles **Fast Refresh (Hot Reloading)**.\n- **Source Maps (Active on Laptop/Debugger):** Babel and Metro generate Source Maps. These map the compiled ES5 code back to your original source code lines so that when you see an error in your console, it points to your exact TypeScript line, not the compiled mess.\n- **Chrome DevTools / React DevTools / Flipper (Active on Laptop):** These external debugging tools connect to your test device via WebSockets to inspect network calls, view your Redux store, or profile React components.\n- **The JavaScript Bundle Stream (In-Flight):** Your physical phone or emulator does **not** contain your application code yet. Instead, it connects to your laptop's Wi-Fi or USB cable and streams the compiled `index.bundle` file from Metro directly into its RAM.\n\n---\n\n## 2. The Production / Release Lifecycle (From Store to User's Phone)\n\nWhen you generate a release build (`.aab` for Android or `.ipa` for iOS), **the development server is completely destroyed.** Everything must be compiled statically and packaged tightly into a single compressed archive file.\n\n### What happens during the Build Phase (Before Uploading to Stores)?\n\n1. **Metro & Babel** run one final time to combine and compile all your JavaScript files.\n2. The **Hermes Compiler** takes that final JavaScript bundle and pre-compiles it directly into **Hermes Bytecode**. (This means the raw text code is translated into binary instructions _before_ it leaves your computer).\n3. On Android, **Proguard/R8** runs to optimize, shrink, and obfuscate the compiled Java/Kotlin native bytecode files (`classes.dex`).\n4. All assets (optimized WebP images, fonts, config files) are zipped up together with the Hermes bytecode and the compiled C++ native binaries (Yoga, JSI, Fabric) into the final **APK/AAB or IPA archive**.\n\n---\n\n### What happens when a user downloads the app from the Play Store / App Store?\n\nWhen a user clicks \"Download\", they are pulling down that static compressed archive file. **Babel, Metro, Source Maps, and Debuggers are 100% gone.** They do not exist on the user's phone.\n\nHere is the exact sequence of what initializes and executes on the user's device:\n\n| What Executes on the User's Phone | What Module is Responsible     | What It Actually Does at Runtime                                                                                                                                                                                                                                                     |\n| --------------------------------- | ------------------------------ | ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ |\n| **1. Native Bootstrap**           | Android OS / iOS Shell         | The phone’s operating system creates an application process instance, allocates physical RAM, reads `AndroidManifest.xml` or `Info.plist` permissions, and launches the native container shell.                                                                                      |\n| **2. Engine Initialization**      | **Hermes Engine**              | The native shell boots up the embedded Hermes JavaScript virtual machine. Hermes instantly loads the pre-compiled **bytecode** directly from the local storage into RAM. Because it is already bytecode, the engine skips parsing and compiling text, making the app open instantly. |\n| **3. Memory Binding**             | **JSI (JavaScript Interface)** | JSI executes immediately to wire up the environment. It injects C++ memory pointers into the global JavaScript scope, allowing Hermes to communicate directly with native mobile hardware systems and views without an asynchronous bridge.                                          |\n| **4. Feature Registration**       | **TurboModules**               | TurboModules sit lazily in memory. They expose device APIs (like Biometrics or Camera) to JavaScript via JSI pointers, but they do not allocate native system memory until your code explicitly calls them.                                                                          |\n| **5. Layout Resolution**          | **Yoga Engine (C++)**          | As the JavaScript bytecode tree triggers UI views, Yoga calculates the exact structural Flexbox layout mathematics, outputting absolute pixel frames (`Width`, `Height`, `Top`, `Left`).                                                                                             |\n| **6. Native UI Rendering**        | **Fabric Rendering System**    | Fabric takes Yoga's calculated geometric bounds and passes them directly across the JSI memory layer to the OS main graphics thread, which draws actual native platform views on the screen.                                                                                         |\n\n---\n\n## 🎯 The Ultimate Summary Checklist for your Interview\n\nIf the IBM panel asks you to summarize the separation between Development and Production, give them this definitive distinction:\n\n- **Development Tools** (**Babel, Metro, DevTools, Source Maps**) live strictly on the **Developer's Workstation**. Their role is to transform code, watch files, and stream assets dynamically to facilitate rapid engineering cycles.\n- **Production Artifacts** consist of **Hermes Bytecode, Native Machine Binaries, and Obfuscated Assets** compiled statically and packaged cleanly into an encrypted store archive.\n- **Runtime Engines** (**Hermes, JSI, Yoga, Fabric, TurboModules**) operate exclusively inside the **User's Device Heap Memory**. They boot up natively to evaluate the pre-compiled bytecode instructions and draw actual, platform-native interfaces with zero external computing dependencies.\n\nYou now understand the complete journey of a React Native application from a single keystroke in your code editor to a live production transaction on an investor's mobile device! Good luck!\n\nYes, Rajeev, you have understood it **100% correctly!** Your summary is spot on.\n\nTo answer your confusion clearly: **Yes, they are core foundational systems (written in C++) that are completely cross-platform.** They are built to be perfectly comfortable with both Android and iOS operating systems.\n\nHere is exactly how they handle the environment, package into your production releases (`.aab` and `.ipa`), and run seamlessly on the user's device.\n\n---\n\n## 1. Are they \"Comfortable\" with iOS and Android?\n\nYes, because Meta built them in **C++**.\n\n- **The Android OS** understands C++ via the Android NDK (Native Development Kit).\n- **The iOS OS** natively understands C++ via Objective-C++ / Swift interop.\n\nBecause these modules are written in a universally supported language (C++), they provide identical rendering, execution speeds, and memory safety rules on an iPhone and a Samsung Galaxy device.\n\n---\n\n## 2. The Packaging Pipeline: Getting into the `.aab` or `.ipa`\n\nWhen you generate a release build on your computer or a build server, those engines are compiled into **shared native binaries** and placed inside your application package.\n\n```\n📦 Your Stored Application Archive (.aab / .ipa ZIP)\n ┣ 📂 assets/ (Main.jsbundle) ──► Your code, pre-compiled into Hermes Bytecode.\n ┣ 📂 lib/ (or Frameworks/) ────► 🛠️ THIS IS WHERE THEY LIVE!\n ┃                                Compiled binary files: libhermes.so, libyoga.so, fabric.framework\n ┗ 📜 Operating Container ──────► The native iOS/Android window layer shell wrapper.\n\n```\n\nWhen a user downloads your app from the App Store or Google Play Store, they are downloading all 5 engines packaged inside that single folder.\n\n---\n\n## 3. Step-by-Step Execution: What Happens After App Installation\n\nThe moment the user taps your app icon on their phone screen, the native operating system boots up the file archive, and those 5 modules begin their jobs in a structured sequence:\n\n```\n[ User Taps App Icon ]\n          │\n          ▼\n 1. HERMES ENGINE WAKES UP ───► Loads pre-compiled bytecode instantly into RAM.\n          │\n          ▼\n 2. JSI LIFECYCLE CONNECTS ───► Maps C++ memory pointers between JS and Native OS.\n          │\n          ▼\n 3. TURBOMODULES REGISTER ───► Wait lazily to expose hardware sensors (Camera/Biometrics).\n          │\n          ▼\n 4. YOGA ENGINE COMPUTES ────► Solves the Flexbox layout math into pixel grids.\n          │\n          ▼\n 5. FABRIC RENDERS VISUALS ──► Draws real, actual iOS / Android native widgets on screen.\n\n```\n\n### The Breakdown on the Phone:\n\n1. **`Hermes` initializes:** It acts as the local brain, reading the pre-compiled JavaScript bytecode instantly without needing to spend battery power parsing raw text.\n2. **`JSI` establishes the foundation:** It creates memory pointers. Instead of treating iOS and Android differently, JSI tells both platforms: _\"We are going to use direct memory addresses to talk to each other now.\"_\n3. **`TurboModules` expose features:** If your JavaScript asks for the phone's battery level or camera hardware, TurboModules use the JSI pointer to grab that native permission string instantly.\n4. **`Yoga` calculates dimensions:** It acts as the global architect. It doesn't care if it's an iPad or an Android tablet—it reads your Flexbox layout styles and computes the pixel bounds.\n5. **`Fabric` prints the pixels:** Fabric receives Yoga's pixel bounds and commands the Android or iOS OS graphics thread to render real, high-performance platform views.\n\n---\n\n## 🎯 Summary for your IBM Panel Wrap-up\n\nIf they ask you to validate the cross-platform capability of the New Architecture, your ultimate closing statement should be:\n\n> \"Modules like **Hermes, JSI, Yoga, Fabric, and TurboModules** are cross-platform engines implemented natively in C++. They do not run as temporary runtime wrappers; instead, they compile down directly into shared native libraries embedded right inside our production **`.aab` and `.ipa` distribution binaries**. Once installed on a device, they integrate directly into the host OS kernel space—with **JSI resolving memory tracking**, **Yoga computing grid layouts**, and **Fabric drawing true native platform widgets** synchronously. This eliminates platform translation lag and delivers high performance across both mobile ecosystems.\"\n\nYou are now a master of the React Native architecture, Rajeev. Go into that IBM interview and claim that senior position with absolute confidence!\n","type":"md"},{"name":"024-legacycodecompatibility.md","content":"To give a world-class response for your IBM panel, we need to break this down into three core engineering parts: how the legacy React Native architecture ran, how the lifecycle of legacy Class Components operates, and the modern migration strategy of mixing Class Components and Functional Components together in a legacy codebase.\n\n---\n\n### Part 1: How Legacy React Native Code Works (The Old Architecture)\n\nIn legacy React Native (versions before 0.68–0.70), code operated across an asynchronous, decoupled pipeline known as **The Bridge**.\n\nUnlike the modern C++ JSI layer where JavaScript has direct access to native memory, the legacy architecture kept JavaScript and Native code completely isolated in separate runtime sandboxes.\n\n#### The Legacy Execution Pipeline:\n\n1. **The JavaScript Thread:** Runs a legacy engine (like JavaScriptCore). When code changes a state or renders a component, it compiles a virtual tree.\n2. **JSON Serialization:** The JavaScript engine cannot pass memory addresses to Java or Objective-C. It has to serialize the entire UI change, style property, or native function call into a stringified **JSON payload**.\n3. **The Bridge Queue:** This JSON string is placed into an asynchronous message queue.\n4. **The Native Thread:** The native main thread wakes up, pulls the JSON string from the bridge, deserializes it back into device memory, tracks the layout, and renders the screen.\n\n**The Flaw:** This architecture is asynchronous and bottlenecked. If a user scrolls a massive list rapidly, the bridge becomes clogged with heavy JSON messages, causing visible UI stuttering, white flashes, and temporary thread lockups.\n\n---\n\n### Part 2: Class Components and Their Lifecycles\n\nLegacy React Native applications were written entirely using JavaScript ES6 Class Components. Managing state and handling updates required hooking into explicit native framework lifecycle methods.\n\n#### The Core Class Lifecycle Pipeline:\n\n### 1. The Mounting Phase (When the component is born)\n\n- **`constructor(props)`**: Initializes local state (`this.state = {}`) and binds class methods.\n- **`render()`**: The only required method. It outputs the JSX layout blocks.\n- **`componentDidMount()`**: Invoked immediately after a component is placed into the view tree. This is the exact place to trigger API network requests, set up event listeners, or start native background timers.\n\n### 2. The Updating Phase (When state or props change)\n\n- **`shouldComponentUpdate(nextProps, nextState)`**: A critical optimization method. It returns a boolean (`true` or `false`). You can compare old props to new props here to prevent unnecessary re-renders, acting exactly like `React.memo` does today.\n- **`render()`**: Re-calculates and redraws the updated UI tree.\n- **`componentDidUpdate(prevProps, prevState)`**: Invoked immediately after the update is flushed to the native layout. This is where you perform operations based on data changes (e.g., triggering a payment calculation if a checkout state changes).\n\n### 3. The Unmounting Phase (When the component dies)\n\n- **`componentWillUnmount()`**: Invoked immediately before a component is destroyed and removed from memory. **This is the most critical method for the Garbage Collector.** You must manually clear timers (`clearInterval`), cancel active network connections, and remove event listeners here to prevent catastrophic native memory leaks.\n\n---\n\n### Part 3: Mixing Class and Functional Components in Legacy Code\n\nThe short answer is **yes, you can absolutely use new Functional Components inside legacy code, and vice versa.** React is highly backward-compatible. You do not need to rewrite your entire legacy application to start using modern Hooks.\n\nHowever, there are strict architectural integration rules you must follow:\n\n#### Rule 1: You Cannot Use Hooks Inside a Class Component\n\nYou cannot write `useState` or `useEffect` inside a class structure. It will throw a compilation syntax error.\n\n```javascript\n// ❌ WRONG: This will crash your application\nclass LegacyCard extends React.Component {\n  render() {\n    const [count, setCount] = useState(0); // Syntax Error!\n    return <Text>{count}</Text>;\n  }\n}\n```\n\n#### Rule 2: Inter-Component Nesting (The Production Pattern)\n\nYou can easily import a modern Functional Component and render it inside a legacy Class Component, or render a legacy Class Component inside a modern Functional Component. They transfer data seamlessly through regular React **`props`**.\n\n#### Practical Example: The Hybrid Coexistence\n\nImagine you have a massive legacy payment screen written as a Class Component, but you want to build a brand new, highly optimized currency input field using a Functional Component with Hooks.\n\nHere is how they work together cleanly in code:\n\n```javascript\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, TextInput, StyleSheet } from \"react-native\";\n\n// 1. MODERN FUNCTIONAL COMPONENT (Built with Hooks)\nfunction ModernCurrencyInput(props) {\n  const [rate, setRate] = useState(\"0\");\n\n  // Mimics componentDidMount and componentDidUpdate via dependencies\n  useEffect(() => {\n    console.log(`Currency token updated to: ${props.token}`);\n  }, [props.token]);\n\n  return (\n    <View style={styles.inputBox}>\n      <Text>Enter Amount ({props.token}):</Text>\n      <TextInput\n        value={rate}\n        onChangeText={(text) => {\n          setRate(text);\n          props.onAmountChange(text); // Pass data back to parent Class\n        }}\n        keyboardType=\"numeric\"\n      />\n    </View>\n  );\n}\n\n// 2. LEGACY CLASS COMPONENT (The Parent Wrapper)\nexport default class LegacyPaymentScreen extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = {\n      selectedToken: \"INR\",\n      finalAmount: \"0\",\n    };\n  }\n\n  componentDidMount() {\n    console.log(\"Legacy screen initialized on the asynchronous bridge.\");\n  }\n\n  handleAmountUpdate = (amount) => {\n    // Updating local class state safely\n    this.setState({ finalAmount: amount });\n  };\n\n  render() {\n    return (\n      <View style={styles.container}>\n        <Text style={styles.title}>LetsVenture Escrow Checkout</Text>\n\n        {/* Integrating the new functional child inside the legacy class parent.\n          Data and callback routines flow seamlessly via standard props!\n        */}\n        <ModernCurrencyInput\n          token={this.state.selectedToken}\n          onAmountChange={this.handleAmountUpdate}\n        />\n\n        <Text style={styles.summary}>\n          Total Processing Payload: {this.state.finalAmount}{\" \"}\n          {this.state.selectedToken}\n        </Text>\n      </View>\n    );\n  }\n}\n\nconst styles = StyleSheet.create({\n  container: { flex: 1, padding: 20, justifyContent: \"center\" },\n  title: { fontSize: 20, fontWeight: \"bold\", marginBottom: 20 },\n  inputBox: {\n    borderWidth: 1,\n    borderColor: \"#ccc\",\n    padding: 15,\n    borderRadius: 8,\n  },\n  summary: { marginTop: 20, fontSize: 16, color: \"blue\" },\n});\n```\n\n---\n\n### 🎯 How to frame this explanation for IBM\n\nThis answer proves that you possess deep historical context, understand legacy business constraints, and know exactly how to safely introduce modern optimization layers into old systems:\n\n> \"Legacy React Native infrastructures operate using an **asynchronous JSON serialization Bridge** to translate commands between the JavaScript engine and native threads. Within this ecosystem, core states are heavily anchored inside **ES6 Class Components**, requiring careful lifecycle management inside functions like `componentDidMount` and `componentWillUnmount` to protect the Garbage Collector from memory leaks.\n> When modernizing a legacy system, rewriting the entire repository is rarely viable. Instead, I implement an **Incremental Hybrid Architecture**. Because React supports strict backward-compatibility, we can build performance-optimized **Functional Components utilizing Hooks** and safely nest them straight inside existing legacy Class structures using unidirectional prop pipelines. This keeps development fast, prevents platform regressions, and smoothly migrates the codebase toward modern standards.\"\n\nYes, **you can absolutely write Class Components in modern React Native.** Even if you are using the latest version of React Native with the New Architecture, the **Hermes engine** and core React framework fully support ES6 classes (`class MyComponent extends React.Component`). React has a strict commitment to backward compatibility, meaning Class Components have not been deprecated or removed.\n\nHowever, as a Senior Engineer interviewing at IBM, you need to explain the **architectural impact, limitations, and the \"why\"** behind moving away from them in modern codebases.\n\n---\n\n## 1. How Class Components Run in the New Architecture\n\nWhen you run a Class Component in modern React Native, it benefits from the performance upgrades under the hood, but it interacts with the modules differently than Functional Components do:\n\n- **The Hermes Bytecode Advantage:** Your class structure is still compiled into optimized binary bytecode by Hermes at build time, meaning it loads into memory instantly.\n- **The JSI & Fabric Bridge Elimination:** If your Class Component updates its state via `this.setState()`, the **Fabric rendering system** skips the old JSON serialization bridge. It interacts via direct C++ memory pointers (**JSI**) to calculate layouts using **Yoga** and draws native views smoothly.\n- **The Big Catch (TurboModules Limitation):** While the UI rendering is fast, Class Components cannot directly hook into modern **TurboModules** or any native libraries that rely strictly on **React Hooks** (like `useCameraPermission` or `useSharedValue` from Reanimated).\n\n---\n\n## 2. Why Class Components are Discouraged in Modern Projects\n\nWhile they still compile and run, writing _new_ Class Components in a modern project is highly discouraged for several key reasons:\n\n### A. The \"Hooks\" Ecosystem Exclusion\n\nThe modern React Native ecosystem is completely built around Hooks. You **cannot** use Hooks inside a Class Component.\nIf you use popular modern libraries like React Navigation (`useNavigation`), TanStack Query (`useQuery`), or Redux Toolkit (`useSelector`), you cannot inject them cleanly into a Class Component. You would have to wrap the class inside a messy High-Order Component (HOC) just to pass those hooks down as standard props.\n\n### B. Minification and Bundle Size Optimization\n\nClass Components do not optimize as well as Functional Components during the **Metro and Babel build phase**:\n\n- Functions can be easily minified; variables inside a function can be renamed to a single letter (e.g., `let userCount` becomes `let a`).\n- Classes require JavaScript prototype methods (`MyComponent.prototype.componentDidMount`). JavaScript bundlers cannot rename or safely minify method names because they might break inheritance or external object lookups. This results in slightly larger production bundle sizes.\n\n### C. Complexity in Code-Splitting and Tree Shaking\n\nModern JavaScript bundlers use a technique called **Tree Shaking** to identify dead code and exclude it from the final `.aab` or `.ipa` binary. Because Class Components wrap all their methods (`componentDidMount`, internal calculations, custom button handlers) inside a single massive object blueprint, the bundler cannot safely determine if an individual method is unused. It is forced to ship the entire class, limiting code-splitting optimization.\n\n---\n\n## 3. How to Convert a Legacy Class Component to Modern Functional Code\n\nDuring an IBM system modernization project, you might be tasked with refactoring an old class into a high-performance functional block. Here is a direct side-by-side mapping of how lifecycles translate to modern execution hooks:\n\n### The Legacy Class Component:\n\n```javascript\nimport React from \"react\";\nimport { View, Text, Button } from \"react-native\";\n\nexport class LegacyCounter extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = { count: 0 };\n  }\n\n  componentDidMount() {\n    console.log(\"Subscribed to tracking telemetry.\");\n  }\n\n  componentDidUpdate(prevProps, prevState) {\n    if (prevState.count !== this.state.count) {\n      console.log(`Count updated to: ${this.state.count}`);\n    }\n  }\n\n  componentWillUnmount() {\n    console.log(\"Cleaned up tracking connections safely.\");\n  }\n\n  render() {\n    return (\n      <View style={{ padding: 20 }}>\n        <Text>Count: {this.state.count}</Text>\n        <Button\n          title=\"Increment\"\n          onPress={() => this.setState({ count: this.state.count + 1 })}\n        />\n      </View>\n    );\n  }\n}\n```\n\n### The Transformed Modern Functional Component:\n\nNotice how much cleaner, lighter, and more minifiable the exact same logic becomes:\n\n```javascript\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, Button } from \"react-native\";\n\nexport function ModernCounter() {\n  // 1. Replaces constructor state definition\n  const [count, setCount] = useState(0);\n\n  // 2. Replaces componentDidMount, componentDidUpdate, and componentWillUnmount all in one clean hook!\n  useEffect(() => {\n    // This runs ONCE on mount (componentDidMount)\n    console.log(\"Subscribed to tracking telemetry.\");\n\n    // This block handles updates (componentDidUpdate) but scopes it targetedly to just the 'count' variable\n    if (count > 0) {\n      console.log(`Count updated to: ${count}`);\n    }\n\n    // The return closure acts as the cleanup mechanism (componentWillUnmount)\n    return () => {\n      console.log(\"Cleaned up tracking connections safely.\");\n    };\n  }, [count]); // Dependency array acts as the conditional listener gatekeeper\n\n  return (\n    <View style={{ padding: 20 }}>\n      <Text>Count: {count}</Text>\n      <Button title=\"Increment\" onPress={() => setCount((prev) => prev + 1)} />\n    </View>\n  );\n}\n```\n\n---\n\n## 🎯 How to frame this for IBM\n\n> \"While modern React Native fully supports legacy ES6 Class Components via backward compatibility, writing them in new feature branches is an architectural anti-pattern. Class methods prevent optimizing compilers like Babel and Metro from performing aggressive minification and dead-code tree shaking, which ultimately inflates production `.aab` or `.ipa` bundle sizes.\n> Furthermore, Class Components isolate themselves from the modern ecosystem by being unable to natively consume React Hooks, forcing engineers to manage verbose Higher-Order Component wrappers. For modern enterprise architecture, I enforce a strict Functional Component standard backed by targeted `useEffect` structures to ensure optimal compilation, cleaner codebases, and seamless integration with the modern JSI-based TurboModule infrastructure.\"\n","type":"md"}],"others":[{"name":"react_native_async_and_navigation_interview_notes_md.md","content":"# React Native Async Handling & Navigation Lifecycle — Senior Interview Notes\n\n_Source file reference:_ fileciteturn0file0\n\n---\n\n# 1. Async Functions Inside `useEffect`\n\nIn React Native, asynchronous operations are commonly used for:\n\n- API calls\n- Secure storage access\n- Native hardware interactions\n- Database operations\n\n## ❌ Incorrect Pattern\n\n```javascript\nuseEffect(async () => {\n  const data = await fetchFintechData();\n}, []);\n```\n\n### Why This Is Wrong\n\n`useEffect` expects:\n\n- `undefined`\n- or a cleanup function\n\nBut an `async` function always returns a `Promise`.\n\n---\n\n## ✅ Correct Production Pattern\n\n```javascript\nimport React, { useState, useEffect } from 'react';\nimport { View, Text, ActivityIndicator } from 'react-native';\n\nexport default function AccountBalance() {\n  const [balance, setBalance] = useState(null);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    const fetchBalance = async () => {\n      try {\n        setLoading(true);\n\n        const response = await fetch(\n          'https://api.ledger.local/v1/balance'\n        );\n\n        const data = await response.json();\n        setBalance(data.amount);\n      } catch (error) {\n        console.error('Failed to fetch balance:', error);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    fetchBalance();\n  }, []);\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  return <Text>Wallet Balance: ${balance}</Text>;\n}\n```\n\n---\n\n# 2. Preventing Memory Leaks During Async Operations\n\nIf a user leaves the screen before an API call completes, updating state on an unmounted component may cause:\n\n- Memory leaks\n- Warning logs\n- Unexpected UI behavior\n\n---\n\n## Cleanup Pattern Using `isMounted`\n\n```javascript\nuseEffect(() => {\n  let isMounted = true;\n\n  const loadData = async () => {\n    try {\n      const result = await secureApiCall();\n\n      if (isMounted) {\n        setData(result);\n      }\n    } catch (err) {\n      if (isMounted) {\n        setError(err.message);\n      }\n    }\n  };\n\n  loadData();\n\n  return () => {\n    isMounted = false;\n  };\n}, []);\n```\n\n---\n\n# 3. Parallel Execution with `Promise.all`\n\n## ❌ Sequential Waterfall (Slow)\n\n```javascript\nconst user = await fetchUserData();\nconst portfolio = await fetchPortfolio(user.id);\n```\n\nTotal wait time becomes cumulative.\n\n---\n\n## ✅ Parallel Execution (Optimized)\n\n```javascript\nconst fetchDashboardData = async () => {\n  try {\n    setLoading(true);\n\n    const [userResponse, marketResponse] = await Promise.all([\n      fetch('https://api.com/user-profile'),\n      fetch('https://api.com/market-rates'),\n    ]);\n\n    const user = await userResponse.json();\n    const market = await marketResponse.json();\n\n    setProfile(user);\n    setRates(market);\n  } catch (error) {\n    handleError(error);\n  } finally {\n    setLoading(false);\n  }\n};\n```\n\n---\n\n## Senior Optimization Pattern\n\n```javascript\nconst fetchAndParse = async (url) => {\n  const res = await fetch(url);\n  return res.json();\n};\n\nconst [user, market] = await Promise.all([\n  fetchAndParse('https://api.com/user-profile'),\n  fetchAndParse('https://api.com/market-rates'),\n]);\n```\n\n---\n\n# 4. Sequential vs Parallel API Architecture\n\n## Sequential / Blocking Flow\n\nUsed when operations depend on each other.\n\nExample:\n\n```text\nAdd Item\n→ Check Cart\n→ Payment\n→ Order Status\n→ Invoice\n→ History Record\n```\n\nEach step requires the previous step to complete successfully.\n\n---\n\n## Parallel / Concurrent Flow\n\nUsed when requests are independent.\n\nExample:\n\n- User profile\n- Dashboard metrics\n- Market rates\n- Notifications\n\nAll APIs can execute simultaneously using `Promise.all`.\n\n---\n\n# 5. AbortController — Production Cleanup Strategy\n\n`isMounted` only prevents state updates.\n\n`AbortController` physically terminates the network request.\n\n---\n\n## Production Example\n\n```javascript\nimport React, { useState, useEffect } from 'react';\nimport {\n  View,\n  Text,\n  ActivityIndicator,\n} from 'react-native';\n\nexport default function TransactionHistory() {\n  const [data, setData] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useEffect(() => {\n    const controller = new AbortController();\n    const { signal } = controller;\n\n    const loadFintechRecords = async () => {\n      try {\n        setLoading(true);\n\n        const response = await fetch(\n          'https://api.letsventure.local/transactions',\n          { signal }\n        );\n\n        const json = await response.json();\n        setData(json);\n      } catch (err) {\n        if (err.name === 'AbortError') {\n          console.log('Fetch aborted safely.');\n        } else {\n          setError(err.message);\n        }\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    loadFintechRecords();\n\n    return () => {\n      controller.abort();\n    };\n  }, []);\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" color=\"#0000ff\" />;\n  }\n\n  if (error) {\n    return <Text>Error loading transactions: {error}</Text>;\n  }\n\n  return (\n    <View>\n      <Text>Transaction records loaded successfully.</Text>\n    </View>\n  );\n}\n```\n\n---\n\n# 6. React Navigation Lifecycle Trap\n\n## Common Misconception\n\nDevelopers often assume:\n\n```text\nScreen A → Screen B → Back to Screen A\n```\n\ncauses Screen A to remount.\n\nThat is incorrect.\n\nIn React Navigation stack navigators:\n\n- Screen A usually remains mounted\n- Only focus changes\n- `useEffect(..., [])` does NOT run again\n\n---\n\n# 7. `useFocusEffect` — Production Navigation Pattern\n\n```javascript\nimport React, {\n  useState,\n  useCallback,\n} from 'react';\n\nimport {\n  View,\n  Text,\n  ActivityIndicator,\n} from 'react-native';\n\nimport {\n  useFocusEffect,\n} from '@react-navigation/native';\n\nexport default function ScreenA() {\n  const [data, setData] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useFocusEffect(\n    useCallback(() => {\n      const controller = new AbortController();\n      const { signal } = controller;\n\n      const loadData = async () => {\n        try {\n          setLoading(true);\n          setError(null);\n\n          const response = await fetch(\n            'https://api.com/dashboard',\n            { signal }\n          );\n\n          const json = await response.json();\n          setData(json);\n        } catch (err) {\n          if (err.name === 'AbortError') {\n            console.log('API call aborted.');\n          } else {\n            setError(err.message);\n          }\n        } finally {\n          setLoading(false);\n        }\n      };\n\n      loadData();\n\n      return () => {\n        controller.abort();\n      };\n    }, [])\n  );\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  if (error) {\n    return <Text>Error: {error}</Text>;\n  }\n\n  return (\n    <View>\n      <Text>Fresh data loaded successfully.</Text>\n    </View>\n  );\n}\n```\n\n---\n\n# 8. Preventing Unnecessary Refetches\n\n## Problem\n\n`useFocusEffect` refetches data every time the screen regains focus.\n\nThis may create:\n\n- Loading flickers\n- Extra API calls\n- Poor UX\n\n---\n\n## Local Cache Guard Solution\n\n```javascript\nuseFocusEffect(\n  useCallback(() => {\n    if (data) return;\n\n    const controller = new AbortController();\n    const { signal } = controller;\n\n    const loadData = async () => {\n      try {\n        setLoading(true);\n\n        const response = await fetch(\n          'https://api.com/dashboard',\n          { signal }\n        );\n\n        const json = await response.json();\n        setData(json);\n      } catch (err) {\n        if (err.name !== 'AbortError') {\n          console.error(err);\n        }\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    loadData();\n\n    return () => controller.abort();\n  }, [data])\n);\n```\n\n---\n\n# 9. Enterprise Approach — React Query\n\nReact Query simplifies:\n\n- API caching\n- Background synchronization\n- Abort signal handling\n- Stale data management\n- Refetch strategies\n\n---\n\n## React Query Example\n\n```javascript\nimport { useQuery } from '@tanstack/react-query';\n\nfunction ScreenA() {\n  const { data, isLoading } = useQuery({\n    queryKey: ['dashboardData'],\n\n    queryFn: async ({ signal }) => {\n      const res = await fetch(\n        'https://api.com/dashboard',\n        { signal }\n      );\n\n      return res.json();\n    },\n\n    staleTime: 1000 * 60 * 5,\n  });\n\n  if (isLoading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  return <Text>Clean cached dashboard.</Text>;\n}\n```\n\n---\n\n# 10. Understanding `staleTime`\n\n## Important Clarification\n\n```javascript\nstaleTime: 1000 * 60 * 5\n```\n\ndoes NOT automatically refetch every 5 minutes.\n\nInstead:\n\n- Data remains marked as \"fresh\" for 5 minutes\n- No refetch occurs during that period\n- Refetch only happens after a trigger event\n\n---\n\n## Common Trigger Events\n\nReact Query refetches when:\n\n1. User revisits the screen\n2. App returns to foreground\n3. Internet reconnects\n4. Manual invalidation occurs\n\n---\n\n# 11. Automatic Polling with `refetchInterval`\n\nIf true periodic polling is required:\n\n```javascript\nconst { data } = useQuery({\n  queryKey: ['marketRates'],\n  queryFn: fetchRates,\n\n  staleTime: 1000 * 60 * 5,\n\n  refetchInterval: 1000 * 60 * 5,\n});\n```\n\n---\n\n# 12. Senior-Level Interview Summary\n\n## Key Interview Talking Points\n\n### Async Handling\n\n- Never make the root `useEffect` callback async\n- Wrap async logic inside nested functions\n- Use `try/catch/finally`\n\n### Cleanup Strategy\n\n- Use `AbortController` for production-grade cancellation\n- Differentiate `AbortError` from real failures\n\n### Parallel Execution\n\n- Use `Promise.all` for independent API calls\n- Avoid async waterfalls\n\n### Navigation Lifecycle\n\n- React Navigation screens remain mounted\n- Use `useFocusEffect` for focus-based refreshes\n\n### Enterprise Data Management\n\n- Prefer React Query for caching and background synchronization\n- Use `staleTime` carefully\n- Use `refetchInterval` only when real polling is required\n\n---\n\n# 13. IBM Interview One-Line Summary\n\n> “In enterprise React Native applications, I focus heavily on efficient async orchestration, lifecycle-safe cleanup handling, optimized concurrent data fetching, and intelligent caching strategies using React Query to deliver scalable and high-performance mobile experiences.”\n\n","type":"md"},{"name":"Interview-001-LaundryMate.md","content":"These are good **React Native interview questions** because they test:\n\n- JavaScript fundamentals (objects, shallow/deep copy)\n- API calling\n- React Hooks (`useState`, `useEffect`)\n- Rendering lists\n- Async programming\n- Debugging\n\n---\n\n# Question 1: JavaScript Object Manipulation\n\n### Given Object\n\n```javascript\nconst person = {\n  first_Name: \"Alex\",\n  \"last Name\": \"Smith\",\n  age: 20,\n  hobbies: [\"watching movies\", \"playing games\"],\n  directory: {\n    1: {\n      type: \"home\",\n      address: \"123 Main Street\",\n      city: \"TechCity\",\n    },\n  },\n};\n```\n\n---\n\n## Q1. Access the first name and last name\n\n### Solution\n\n```javascript\nconsole.log(person.first_Name);\nconsole.log(person[\"last Name\"]);\n```\n\n### Output\n\n```javascript\nAlex;\nSmith;\n```\n\n---\n\n## Q2. Copy person object to person2\n\n### Deep Copy\n\n```javascript\nconst person2 = structuredClone(person);\n```\n\nAlternative:\n\n```javascript\nconst person2 = JSON.parse(JSON.stringify(person));\n```\n\n---\n\n## Q3. Access person2's first_Name\n\n```javascript\nconsole.log(person2.first_Name);\n```\n\n### Output\n\n```javascript\nAlex;\n```\n\n---\n\n## Q4. Update person2's first_Name to \"Foo\"\n\n```javascript\nperson2.first_Name = \"Foo\";\n```\n\n---\n\n## Q5. What will be the value of person2.first_Name and person.first_Name?\n\n```javascript\nconsole.log(person2.first_Name);\nconsole.log(person.first_Name);\n```\n\n### Output\n\n```javascript\nFoo;\nJohn;\n```\n\n### Why?\n\nBecause `structuredClone()` creates a completely new object.\n\n---\n\n## Q6. Access person's city\n\n```javascript\nconsole.log(person.directory[\"1\"].city);\n```\n\n### Output\n\n```javascript\nBengaluru;\n```\n\n---\n\n## Q7. Update person2's city to Chennai\n\n```javascript\nperson2.directory[\"1\"].city = \"Chennai\";\n```\n\n---\n\n## Q8. What will be the value of person2.city and person.city?\n\n```javascript\nconsole.log(person2.directory[\"1\"].city);\nconsole.log(person.directory[\"1\"].city);\n```\n\n### Output\n\n```javascript\nChennai;\nBengaluru;\n```\n\n### Why?\n\nBecause deep copy creates separate nested objects.\n\n---\n\n# Follow-up Interview Question\n\n### What happens if we use spread operator?\n\n```javascript\nconst person2 = { ...person };\n```\n\nThis creates a **shallow copy**.\n\n```javascript\nperson2.directory[\"1\"].city = \"Chennai\";\n\nconsole.log(person.directory[\"1\"].city);\n```\n\n### Output\n\n```javascript\nChennai;\n```\n\n### Why?\n\nNested objects are still sharing the same reference.\n\n---\n\n# Question 2: API Fetching in React Native\n\n### API\n\n```javascript\nhttps://dummyjson.com/todos\n```\n\n---\n\n## What's wrong in the code?\n\nCurrent code:\n\n```javascript\nsetTodos(data);\n```\n\nAPI response:\n\n```javascript\n{\n  todos: [...],\n  total: 254,\n  skip: 0,\n  limit: 30\n}\n```\n\nYou only need:\n\n```javascript\ndata.todos;\n```\n\n---\n\n## Correct Solution\n\n```javascript\nimport React, { useEffect, useState } from \"react\";\nimport { View, Text, FlatList, ActivityIndicator } from \"react-native\";\n\nconst API_URL = \"https://dummyjson.com/todos\";\n\nexport default function App() {\n  const [todos, setTodos] = useState([]);\n  const [loading, setLoading] = useState(false);\n\n  const fetchData = async () => {\n    try {\n      setLoading(true);\n\n      const response = await fetch(API_URL);\n\n      const data = await response.json();\n\n      setTodos(data.todos);\n    } catch (error) {\n      console.log(error);\n    } finally {\n      setLoading(false);\n    }\n  };\n\n  useEffect(() => {\n    fetchData();\n  }, []);\n\n  if (loading) {\n    return <ActivityIndicator size=\"large\" />;\n  }\n\n  return (\n    <FlatList\n      data={todos}\n      keyExtractor={(item) => item.id.toString()}\n      renderItem={({ item }) => (\n        <Text>\n          {item.id}. {item.todo}\n        </Text>\n      )}\n    />\n  );\n}\n```\n\n---\n\n# Follow-up Questions\n\n### Why use useEffect?\n\n```javascript\nuseEffect(() => {\n  fetchData();\n}, []);\n```\n\nBecause it runs once after component mount.\n\n---\n\n### What happens if dependency array is removed?\n\n```javascript\nuseEffect(() => {\n  fetchData();\n});\n```\n\nInfinite re-render loop.\n\n---\n\n### Difference between useEffect and useLayoutEffect?\n\n| useEffect        | useLayoutEffect |\n| ---------------- | --------------- |\n| Async            | Sync            |\n| After paint      | Before paint    |\n| Doesn't block UI | Blocks UI       |\n\n---\n\n# Senior React Native Interview Questions\n\n### 1. Difference between State and Props\n\n**State**\n\n```javascript\nconst [count, setCount] = useState(0);\n```\n\nMutable.\n\n**Props**\n\n```javascript\n<MyComponent title=\"Hello\" />\n```\n\nRead-only.\n\n---\n\n### 2. What is React Reconciliation?\n\nProcess React uses to compare Virtual DOM and update only changed nodes.\n\n---\n\n### 3. What is Memoization?\n\n```javascript\nReact.memo(Component);\n```\n\nPrevents unnecessary re-renders.\n\n---\n\n### 4. Difference between useMemo and useCallback\n\n#### useMemo\n\nCaches value.\n\n```javascript\nconst total = useMemo(() => {\n  return calculateTotal(items);\n}, [items]);\n```\n\n#### useCallback\n\nCaches function.\n\n```javascript\nconst onPress = useCallback(() => {\n  console.log(\"Clicked\");\n}, []);\n```\n\n---\n\n### 5. Explain FlatList Optimization\n\n```javascript\n<FlatList\n  removeClippedSubviews\n  initialNumToRender={10}\n  maxToRenderPerBatch={10}\n  windowSize={5}\n/>\n```\n\nUsed for large datasets.\n\n---\n\n### 6. Difference between ScrollView and FlatList\n\n| ScrollView        | FlatList           |\n| ----------------- | ------------------ |\n| Renders all items | Lazy rendering     |\n| Poor performance  | Better performance |\n| Small data        | Large data         |\n\n---\n\n### 7. What is the React Native Bridge?\n\nBridge enables communication between:\n\n- JavaScript Thread\n- Native Android/iOS Thread\n\nNew Architecture replaces much of this with:\n\n- JSI\n- TurboModules\n- Fabric\n\n---\n\n### 8. How does Redux Toolkit work?\n\n```javascript\nconst counterSlice = createSlice({\n  name: \"counter\",\n  initialState: 0,\n  reducers: {\n    increment: (state) => state + 1,\n  },\n});\n```\n\nBenefits:\n\n- Less boilerplate\n- Immer support\n- Better performance\n\n---\n\n### 9. Difference between AsyncStorage and MMKV\n\n| AsyncStorage | MMKV        |\n| ------------ | ----------- |\n| Async        | Sync        |\n| Slower       | Faster      |\n| Old approach | Recommended |\n\n---\n\n### 10. Explain React Native New Architecture\n\nComponents:\n\n1. JSI\n2. TurboModules\n3. Fabric Renderer\n\nBenefits:\n\n- Faster startup\n- Better performance\n- Direct JS ↔ Native communication\n- Reduced bridge overhead\n\nThese are the kinds of JavaScript + React Native questions typically asked in Senior React Native interviews at companies like IBM, UST, Infosys, Accenture, Capgemini, TCS Digital, and product companies.\n","type":"md"},{"name":"practice.js","content":"// function containsDuplicates (nums){\n\n//   let map = {};\n\n//   if(Array.isArray(nums)){\n\n//     for(let i=0; i< nums.length; i++){\n//       if(map[nums[i]]!== undefined){\n//         return true;\n//       } else{\n//         map[nums[i]] = i;\n//       }\n//     }\n//   }\n//   return false;\n// }\n\n// Output:\n\n// 19 ms | 44.9 MB\n// true\n\nfunction containsDuplicates(nums) {\n  const set = new Set();\n\n  for (const num of nums) {\n    if (set.has(num)) {\n      return true;\n    }\n    set.add(num);\n  }\n  return false;\n}\n\n// Output:\n\n// 19 ms | 45.1 MB\n// true\nconsole.log(containsDuplicates([0, 1, 0, 0, 1]));\n//======\n\n// function isAnagram(s,t) {\n//   if(s.length!==t.length){\n//     return false;\n//   }\n\n//   s = s.toLowerCase().split('').sort().join('');\n\n//   t = t.toLowerCase().split('').sort().join('');\n\n//   console.log(s, t);\n\n//   if(s===t){\n//     return true;\n\n//   }\n\n//   return false;\n\n// }\n\nfunction isAnagram(s, t) {\n  if (s.length !== t.length) return false;\n  let map = {};\n  for (ch of s) {\n    map[ch] = (map[ch] || 0) + 1;\n  }\n  for (ch of t) {\n    if (!map[ch]) {\n      return false;\n    }\n    map[ch]--;\n  }\n  return true;\n}\n\nconsole.log(isAnagram(\"anagram\", \"nagaram\"));\n//======\nfunction twoSum(nums, target) {\n  let map = {};\n\n  for (let i = 0; i < nums.length; i++) {\n    const diff = target - nums[i];\n    if (map[diff] !== undefined) {\n      return [map[diff], i];\n    }\n    map[nums[i]] = i;\n  }\n  return [];\n}\n\nconsole.log(twoSum([2, 7, 9, 11], 9));\n\n// Output:\n\n// 19 ms | 45.3 MB\n// [ 0, 1 ]\n\n\n//======\n\n// Input:\n\n// str = \"leetcode\";\n// Output:\n\n// \"l\";\n\n\nfunction firstNonRepeatingChar (str){\n  \n  let freq = {};\n  \n  for(ch of str){\n    freq[ch] = (freq[ch]||0) + 1;\n  }\n  \n  for(ch of str){\n   if(freq[ch] === 1){\n    return ch;\n   }\n  }\n  return null;\n  \n}\n\nconsole.log(firstNonRepeatingChar(\"IBM INDIA\"))\n\n// Output:\n\n// 19 ms | 45.2 MB\n// B\n\n//======\n\n// Input:\n\n// nums = [0, 1, 0, 3, 12];\n// Output:\n\n// [1, 3, 12, 0, 0];\n\n\nfunction moveZero(nums){\n  let index = 0;\n  \n  for (let i =0 ; i< nums.length; i++){\n    if(nums[i]!==0){\n      nums[index++] = nums[i];\n    }\n  }\n  \n  while(index<nums.length){\n    nums[index++] = 0;\n  }\n  \n  return nums;\n}\n\nconsole.log(moveZero([1, 1, 0, 1, 0, 3, 12, 0, 0]))\n\n// Output:\n\n// 19 ms | 44.7 MB\n// [\n//   1, 1, 1, 3, 12,\n//   0, 0, 0, 0\n// ]\n","type":"js"}]};
